(function() {
var mo_ch_1_Verses = [
  {num:1,words:[["Ma o lenei sa lē toe i ai se finauga i le nuu atoa o Sara'emila,", "And now there was no more contention in all the land of Zarahemla,"], ["i totonu o tagata uma sa o le tupu o Peniamina,", "among all the people who belonged to king Benjamin,"], ["o lea na maua ai e le tupu o Peniamina le filemu e lē aunoa i ona aso uma na totoe.", "so that king Benjamin had continual peace all the remainder of his days."]]},
  {num:2,words:[["Ma sa ia te ia ni atalii se toatolu;", "And it came to pass that he had three sons;"], ["ma sa ia faaigoa ia te i latou o Mosaea,", "and he called their names Mosiah,"], ["ma Heloruma,", "and Helorum,"], ["ma Helamana. Ma sa ia faatonuina ia aoaoina i latou i le gagana atoa a ona tamā,", "and Helaman. And he caused that they should be taught in all the language of his fathers,"], ["ina ia mafai ona avea i latou ma tagata malamalama;", "that thereby they might become men of understanding;"], ["ma ia latou iloa e uiga i valoaga na tautalaina e fofoga o o latou tamā,", "and that they might know concerning the prophecies which had been spoken by the mouths of their fathers,"], ["ia na tuuina mai ia te i latou e le aao o le Alii.", "which were delivered them by the hand of the Lord."]]},
  {num:3,words:[["Ma sa ia aoaoina foi i latou e uiga i talafaamaumau sa togitogia i luga o papatusi apamemea,", "And he also taught them concerning the records which were engraven on the plates of brass,"], ["ua fai atu:", "saying:"], ["O'u atalii e,", "My sons,"], ["ou te manao ia outou manatua a na leai nei papatusi ,", "I would that ye should remember that were it not for these plates,"], ["ia ua i ai nei talafaamaumau ma nei poloaiga,", "which contain these records and these commandments,"], ["po ua tatou mafatia i le valelea ,", "we must have suffered in ignorance,"], ["i le taimi nei lava,", "even at this present time,"], ["i le lē iloaina o mealilo a le Atua.", "not knowing the mysteries of God."]]},
  {num:4,words:[["Aua e lē mafai e lo tatou tamā,", "For it were not possible that our father,"], ["o Liae,", "Lehi,"], ["ona manatua nei mea uma,", "could have remembered all these things,"], ["ma aoao atu i ana fanau,", "to have taught them to his children,"], ["vagana ai le fesoasoani a nei papatusi; auā ona sa aoaoina o ia i le gagana a tagata Aikupito,", "except it were for the help of these plates;"], ["o lea na mafai ai ona ia faitauina o nei togitogiga,", "for he having been taught in the language of the Egyptians therefore he could read these engravings,"], ["ma aoao atu i ana fanau,", "and teach them to his children,"], ["ina ia mafai ona latou aoao atu ia latou fanau,", "that thereby they could teach them to their children,"], ["ma faapea ona faataunuu ai o poloaiga a le Atua,", "and so fulfilling the command– ments of God,"], ["e oo mai lava i lalo i le taimi nei.", "even down to this present time."]]},
  {num:5,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["o'u atalii e,", "my sons,"], ["a na leai nei mea,", "were it not for these things,"], ["ia sa tausia ma faasaoina e le aao o le Atua,", "which have been kept and preserved by the hand of God,"], ["ina ia mafai ona tatou faitau ma malamalama ai i ana mealilo ,", "that we might read and understand of his mysteries,"], ["ma ina ia i ai pea ana poloaiga i luma o o tatou mata,", "and have his commandments always before our eyes,"], ["e oo i o tatou tamā po ua faaitiitia i le lē talitonu,", "that even our fathers would have dwindled in unbelief,"], ["ma po ua pei i tatou o o tatou uso,", "and we should have been like unto our brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["o e ua latou lē iloaina se mea e uiga i nei mea,", "who know nothing concerning these things,"], ["pe ua lē talitonu foi i ai pe a aoao atu ia te i latou,", "or even do not believe them when they are taught them,"], ["ona o uputuu a o latou tamā,", "because of the traditions of their fathers,"], ["ia ua lē sa'o.", "which are not correct."]]},
  {num:6,words:[["E,", "O my sons,"], ["o'u atalii e, ou te manao ia outou manatua ua moni nei upu,", "I would that ye should remember that these sayings are true,"], ["ma ua moni foi nei talafaamaumau.", "and also that these records are true."], ["Ma faauta,", "And behold,"], ["o papatusi foi a Nifae,", "also the plates of Nephi,"], ["ia ua i ai talafaamaumau ma upu a o tatou tamā mai le taimi na latou tuua ai Ierusalema seia oo mai i le taimi nei,", "which contain the records and the sayings of our fathers from the time they left Jerusalem until now,"], ["ua moni i latou;", "and they are true;"], ["ma e mafai ona tatou iloa lo latou moni ona ua i ai i luma o o tatou mata.", "and we can know of their surety because we have them before our eyes."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["o'u atalii e,", "my sons,"], ["ou te manao ia outou manatua ia suesue i ai ma le filiga,", "I would that ye should remember to search them diligently,"], ["ina ia mafai ona outou manuia ai;", "that ye may profit thereby;"], ["ma ou te manao ia outou tausi i poloaiga a le Atua,", "and I would that ye should keep the commandments of God,"], ["ina ia mafai ona outou manuia i le laueleele e tusa ma folafolaga na faia e le Alii i o tatou tamā.", "that ye may prosper in the land according to the promises which the Lord made unto our fathers."]]},
  {num:8,words:[["Ma e tele isi mea sa aoao atu e le tupu o Peniamina i ona atalii,", "And many more things did king Benjamin teach his sons,"], ["ua lē tusia i lenei tusi.", "which are not written in this book."]]},
  {num:9,words:[["Ma sa oo ina ua uma ona faaiu e le tupu o Peniamina le aoaoga o ona atalii,", "And it came to pass that after king Benjamin had made an end of teaching his sons,"], ["sa faasolo ina toeaina o ia,", "that he waxed old,"], ["ma sa vaai o ia ua lata ona alu o ia i le ala o le lalolagi uma;", "and he saw that he must very soon go the way of all the earth;"], ["o lea,", "therefore,"], ["sa manatu ai o ia ua tatau ona ia faaee atu le malo i luga o se tasi o ona atalii.", "he thought it expedient that he should confer the kingdom upon one of his sons."]]},
  {num:10,words:[["O lea,", "Therefore,"], ["na faia ai e ia ia aumai Mosaea i ona luma;", "he had Mosiah brought before him;"], ["ma o upu nei sa tautala atu ia ia te ia,", "and these are the words which he spake unto him,"], ["ua fai atu:", "saying:"], ["Lo'u atalii e,", "My son,"], ["ou te manao ia e faia se folafolaga i lenei laueleele atoa i totonu o nei tagata uma, po o le nuu o Sara'emila,", "I would that ye should make a proclamation throughout all this land among all this people,"], ["ma le nuu o Mosaea o e o nonofo i le laueleele,", "or the people of Zarahemla,"], ["ina ia mafai ona latou faapotopoto mai faatasi;", "and the people of Mosiah who dwell in the land,"], ["ona o le aso a taeao o le a ou faasilasila atu ai ia te i latou nei o lo'u nuu mai lo'u lava gutu,", "that thereby they may be gathered together;"], ["o oe o le tupu ma le pule i luga o lenei nuu,", "for on the morrow I shall proclaim unto this my people out of mine own mouth that thou art a king and a ruler over this people,"], ["o e ua tuuina mai e le Alii lo tatou Atua ia te i tatou.", "whom the Lord our God hath given us."]]},
  {num:11,words:[["Ma e lē gata i lea,", "And moreover,"], ["o le a ou tuu atu i lenei nuu se igoa ,", "I shall give this people a name,"], ["e mafai ona faailoga ese ai i latou i luga o tagata uma na aumai i fafo e le Alii le Atua mai le laueleele o Ierusalema;", "that thereby they may be distinguished above all the people which the Lord God hath brought out of the land of Jerusalem;"], ["ma ou te faia lenei mea ona sa avea i latou ma tagata filiga i le tausiga o poloaiga a le Alii.", "and this I do because they have been a diligent people in keeping the commandments of the Lord."]]},
  {num:12,words:[["Ma ou te tuu atu ia te i latou se igoa o le a lē soloia ese lava,", "And I give unto them a name that never shall be blotted out,"], ["vagana ai i le solitulafono .", "except it be through trans– gression."]]},
  {num:13,words:[["Ioe,", "Yea,"], ["o lenei foi ou te fai atu ia te oe,", "and moreover I say unto you,"], ["afai e pauu atu i le solitulafono nei tagata faapitoa tele o le Alii,", "that if this highly favored people of the Lord should fall into transgression,"], ["ma avea ma tagata amioleaga ma mulilulua,", "and become a wicked and an adulterous people,"], ["o le a tuuina atu i latou e le Alii,", "that the Lord will deliver them up,"], ["ia latou vaivai e pei o o latou uso;", "that thereby they become weak like unto their brethren;"], ["ma o le a lē toe faasaoina i latou e ia i lona mana lē mafaatusalia ma ofoofogia,", "and he will no more preserve them by his matchless and marvelous power,"], ["e pei ona sa ia faasaoina o tatou tamā e oo mai i le taimi nei.", "as he has hitherto preserved our fathers."]]},
  {num:14,words:[["Aua ou te fai atu ia te oe,", "For I say unto you,"], ["ana ia lē faaloaloa mai lona aao i le faasaoga o o tatou tamā po ua latou pauu atu i lima o sa Lamanā,", "that if he had not extended his arm in the preservation of our fathers they must have fallen into the hands of the Lamanites,"], ["ma avea ma iuga o lo latou ita.", "and become victims to their hatred."]]},
  {num:15,words:[["Ma sa oo ina ua uma ona faaiu e le tupu o Peniamina nei upu i lona atalii,", "And it came to pass that after king Benjamin had made an end of these sayings to his son,"], ["sa ia tuu atu ia te ia le matafaioi e faatatau i mea uma o le malo.", "that he gave him charge concerning all the affairs of the kingdom."]]},
  {num:16,words:[["Ma e lē gata i lea,", "And moreover,"], ["sa ia tuu atu foi ia te ia le matafaioi e faatatau i talafaamaumau sa togitogia i luga o papatusi apamemea;", "he also gave him charge concerning the records which were engraven on the plates of brass;"], ["ma papatusi foi a Nifae;", "and also the plates of Nephi;"], ["ma le pelu foi a Lapana,", "and also,"], ["ma le polo ,", "the sword of Laban,"], ["po o le faasinoala,", "and the ball or director,"], ["lea sa taitaia ai o matou tamā i le vao,", "which led our fathers through the wilderness,"], ["lea sa saunia e le aao o le Alii ina ia mafai ona taitaia ai i latou,", "which was prepared by the hand of the Lord that thereby they might be led,"], ["i latou uma taitoatasi e tusa ma le gauai ma le filiga sa latou tuu atu ia te ia.", "every one according to the heed and diligence which they gave unto him."]]},
  {num:17,words:[["O lea,", "Therefore,"], ["ina ua latou lē faamaoni sa latou lē manuia pe alualu i luma i la latou malaga,", "as they were unfaithful they did not prosper nor progress in their journey,"], ["ae sa toe tafefea i tua,", "but were driven back,"], ["ma oo mai ai le toasa o le Atua i o latou luga;", "and incurred the displeasure of God upon them;"], ["ma o lea na taia ai i latou i le oge ma puapuaga tiga,", "and therefore they were  smitten with famine and sore afflictions,"], ["e faaosoina ai i latou i le manatuaina o lo latou tiute.", "to stir them up in remembrance of their duty."]]},
  {num:18,words:[["Ma o lenei,", "And now,"], ["sa oo ina alu atu Mosaea ma faia e pei ona poloaiina ai o ia e lona tamā,", "it came to pass that Mosiah went and did as his father had commanded him,"], ["ma folafola atu i tagata uma o e sa i le laueleele o Sara'emila ina ia mafai ona latou faapotopoto faatasi i latou lava,", "and proclaimed unto all the people who were in the land of Zarahemla that thereby they might gather themselves together,"], ["e o a'e i le malumalu e faalogo i upu o le a tautala mai ai lona tamā ia te i latou.", "to go up to the temple to hear the words which his father should speak unto them."]]},
];
renderVerseSet(mo_ch_1_Verses, 'mo-ch1-verses');

var mo_ch_2_Verses = [
  {num:1,words:[["Ma sa oo ina ua uma ona faia e Mosaea e pei ona poloaiina ai o ia e lona tamā,", "And it came to pass that after Mosiah had done as his father had commanded him,"], ["ma ia faia se folafolaga i le nuu atoa,", "and had made a proclamation throughout all the land,"], ["sa oo ina faapotopoto faatasi e le nuu i latou lava i le laueleele atoa,", "that the people gathered themselves together throughout all the land,"], ["ina ia mafai ona latou o a'e i le malumalu e faalogo i upu o le a tautala mai ai le tupu o Peniamina ia te i latou.", "that they might go up to the temple to hear the words which king Benjamin should speak unto them."]]},
  {num:2,words:[["Ma sa toatele lava le aofai,", "And there were a great number,"], ["sa matua toatele lava sa latou lē faitauina i latou;", "even so many that they did not number them;"], ["ona ua latou matua uluola lava ma faasolo toatele i le laueleele.", "for they had multiplied exceedingly and waxed great in the land."]]},
  {num:3,words:[["Ma sa latou ave foi manu mai uluai manu o a latou lafu,", "And they also took of the firstlings of their flocks,"], ["ina ia mafai ona latou osi atu o taulaga ma taulaga mu e tusa ma le tulafono a Mose.", "that they might offer sacrifice and burnt offerings according to the law of Moses;"]]},
  {num:4,words:[["Ma ina ia mafai ai foi ona latou avatu o le faafetai i le Alii lo latou Atua,", "And also that they might give thanks to the Lord their God,"], ["o lē na ia aumaia i latou i fafo mai le laueleele o Ierusalema,", "who had brought them out of the land of Jerusalem,"], ["ma o lē na laveaiina i latou i fafo mai lima o o latou fili,", "and who had delivered them out of the hands of their enemies,"], ["ma tofia tagata amiotonu e avea ma o latou aoao ,", "and had appointed just men to be their teachers,"], ["ma se tagata amiotonu foi e avea ma o latou tupu,", "and also a just man to be their king,"], ["o lē na faatuina le filemu i le laueleele o Sara'emila,", "who had established peace in the land of Zarahemla,"], ["ma o lē na aoaoina i latou ia tausi i poloaiga a le Atua,", "and who had taught them to keep the commandments of God,"], ["ina ia mafai ona latou olioli ma faatumuina i le alofa i le Atua ma tagata uma.", "that they might rejoice and be filled with love towards God and all men."]]},
  {num:5,words:[["Ma sa oo ina ua latou o a'e i le malumalu,", "And it came to pass that when they came up to the temple,"], ["sa latou faatutu o latou faleie faataamilo ai,", "they pitched their tents round about,"], ["o tagata taitoatasi e tusa ma lona aiga ,", "every man according to his family,"], ["ua i ai lana avā,", "consisting of his wife,"], ["ma ona atalii,", "and his sons,"], ["ma ona afafine,", "and his daughters,"], ["ma o latou atalii,", "and their sons,"], ["ma o latou afafine,", "and their daughters,"], ["mai le ulumatua e oo ifo i lalo i le uii;", "from the eldest down to the youngest,"], ["o aiga taitasi ua nonofo eseese mai le tasi.", "every family being separate one from another."]]},
  {num:6,words:[["Ma sa latou faatutu o latou faleie faataamilo i le malumalu,", "And they pitched their tents round about the temple,"], ["sa taitoatasi le tagata ma faatu lona faleie ma lona faitotoa faasaga i le malumalu,", "every man having his tent with the door thereof towards the temple,"], ["ina ia mafai ona latou nonofo i o latou faleie ma faalogologo atu i upu o le a saunoa mai ai le tupu o Peniamina ia te i latou.", "that thereby they might remain in their tents and hear the words which king Benjamin should speak unto them;"]]},
  {num:7,words:[["Ona sa matua toatele lava le motu o tagata sa lē mafai e le tupu o Peniamina ona aoao atu ia te i latou uma i totonu o puipui o le malumalu,", "For the multitude being so great that king Benjamin could not teach them all within the walls of the temple,"], ["o lea na faia ai e ia ia faatuina se fatafatāmanu,", "therefore he caused a tower to be erected,"], ["ina ia mafai e ona tagata ona lagona mai upu o le a tautala atu ai o ia ia te i latou.", "that thereby his people might hear the words which he should speak unto them."]]},
  {num:8,words:[["Ma sa oo ina amata ona tautala atu o ia i lona nuu mai le fatafatāmanu;", "And it came to pass that he began to speak to his people from the tower;"], ["ma sa lē mafai e i latou uma ona lagona mai ana upu ona o le toatele naua o le motu o tagata;", "and they could not all hear his words because of the greatness of the multitude;"], ["o lea na faia ai e ia ia tusia upu na ia tautala atu ai ma auina atu i a i latou o e sa latou lē lagona mai lona leo,", "therefore he caused that the words which he spake should be written and sent forth among those that were not under the sound of his voice,"], ["ina ia mafai foi ona latou maua o ana upu.", "that they might also receive his words."]]},
  {num:9,words:[["Ma o upu nei sa tautalaina e ia ma faia ia tusia,", "And these are the words which he spake and caused to be written,"], ["ua fai atu:", "saying:"], ["O'u uso e,", "My brethren,"], ["outou uma ua outou faapotopoto faatasi mai outou lava,", "all ye that have assembled yourselves together,"], ["outou na ua mafai ona outou lagona mai a'u upu o le a ou tautala atu ai ia te outou i le asō;", "you that can hear my words which I shall speak unto you this day;"], ["ona ou te lei poloai atu ia te outou ia outou o mai iinei ina ia outou faatauvaaina upu o le a ou tautala atu ai,", "for I have not commanded you to come up hither to trifle with the words which I shall speak,"], ["ae ia outou faalogo mai ia te a'u,", "but that you should hearken unto me,"], ["ma tatala mai o outou taliga ina ia mafai ona outou lagona mai,", "and open your ears that ye may hear,"], ["ma o outou loto ina ia mafai ona outou malamalama,", "and your hearts that ye may understand,"], ["ma o outou mafaufau ina ia mafai ona tatalaina o mealilo a le Atua i la outou vaai.", "and your minds that the mysteries of God may be unfolded to your view."]]},
  {num:10,words:[["Ou te lei poloai atu ia te outou ia outou o mai iinei ina ia outou matata'u mai ia te a'u,", "I have not commanded you to come up hither that ye should fear me,"], ["pe ina ia outou manatu ai ua sili atu a'u lava ia i lo se tagata soifua.", "or that ye should think that I of myself am more than a mortal man."]]},
  {num:11,words:[["Ae ua pei lava a'u o outou,", "But I am like as yourselves,"], ["e oo i ai vaivaiga eseese uma o le tino ma le mafaufau;", "subject to all manner of infirmities in body and mind;"], ["peitai ua filifilia a'u e lenei nuu,", "yet I have been chosen by this people,"], ["ma faapaiaina e lo'u tamā,", "and consecrated by my father,"], ["ma tuu mai e le aao o le Alii ia avea a'u o se pule ma se tupu i luga o lenei nuu; ma sa tausia ma faasaoina e lona mana lē mafaatusalia,", "and was suffered by the hand of the Lord that I should be a ruler and a king over this people;"], ["e auauna atu ia te outou ma le manatu atoa,", "and have been kept and preserved by his matchless power,"], ["mafaufau,", "to serve you with all the might,"], ["ma le malosi atoa ua tuu mai e le Alii ia te a'u.", "mind and strength which the Lord hath granted unto me."]]},
  {num:12,words:[["Ou te fai atu ia te outou e pei ona sa tuu mai ia te a'u ia faaaoga o'u aso e auauna atu ai ia te outou,", "I say unto you that as I have been suffered to spend my days in your service,"], ["e oo mai lava i le taimi nei,", "even up to this time,"], ["ou te lei sailia lava se auro po o se ario po o soo se ituaiga o oloa mai ia te outou;", "and have not sought gold nor silver nor any manner of riches of you;"]]},
  {num:13,words:[["Pe na ou tuuina foi ia tuu outou i falepuipui,", "Neither have I suffered that ye should be confined in dungeons,"], ["pe ia outou faapologa le tasi i le isi,", "nor that ye should make slaves one of another,"], ["pe ia outou fasioti tagata,", "nor that ye should murder,"], ["pe fai le vete,", "or plunder,"], ["pe gaoi,", "or steal,"], ["pe mulilulua;", "or commit adultery;"], ["pe sa ou tuu foi ia outou faia soo se ituaiga o amioleaga,", "nor even have I suffered that ye should commit any manner of wickedness,"], ["ae sa ou aoao atu ia te outou ia outou tausi i poloaiga a le Alii,", "and have taught you that ye should keep the commandments of the Lord,"], ["i mea uma ua poloaiina ai outou e ia—", "in all things which he hath commanded you—"]]},
  {num:14,words:[["Ma e oo ia te a'u lava ia,", "And even I,"], ["sa ou galue i o'u lava lima ina ia mafai ona ou auauna atu ia te outou,", "myself,"], ["ma ina ia lē faafafaina ia te outou lafoga,", "have labored with mine own hands that I might serve you, and that ye should not be laden with taxes,"], ["ma ina ia leai se mea e oo mai i o outou luga e faigata ona tauaveina—ma o nei mea uma ua ou tautala atu ai,", "and that there should nothing come upon you which was grievous to be borne—and of all these things which I have spoken,"], ["o outou lava ua molimau i ai i le asō.", "ye yourselves are witnesses this day."]]},
  {num:15,words:[["Peitai o'u uso e,", "Yet,"], ["ou te lei faia nei mea ina ia ou mitamitavale ai,", "my brethren,"], ["pe ou te ta'u atu ia mea ina ia ou tuua'ia ai outou;", "I have not done these things that I might boast, neither do I tell these things that thereby I might accuse you;"], ["ae ua ou ta'u atu nei mea ia te outou ina ia mafai ona outou iloa ai e mafai ona ou tali atu ma le mafaufau mamā i luma o le Atua i le aso nei.", "but I tell you these things that ye may know that I can answer a clear conscience before God this day."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you that because I said unto you that I had spent my days in your service,"], ["ona ua ou fai atu ia te outou sa ou faaaoga o'u aso e auauna atu ai ia te outou, ou te lē fia mitamitavale,", "I do not desire to boast,"], ["ona sa nao lo'u auauna atu lava lea i le Atua.", "for I have only been in the service of God."]]},
  {num:17,words:[["Ma faauta, ua ou ta'u atu nei mea ia te outou ina ia mafai ona outou aoaoina le poto;", "And behold,"], ["ina ia mafai ona outou aoaoina,", "I tell you these things that ye may learn wisdom;"], ["pe a outou auauna atu i o outou uso-a-tagata , ua nao lo outou auauna atu lava lea i lo outou Atua.", "that ye may learn that when ye are in the service of your fellow beings ye are only in the service of your God."]]},
  {num:18,words:[["Faauta,", "Behold,"], ["ua outou ta'ua a'u o lo outou tupu;", "ye have called me your king;"], ["ma afai o a'u,", "and if I,"], ["o lē ua outou ta'ua o lo outou tupu,", "whom ye call your king,"], ["ua galue e auauna atu ia te outou,", "do labor to serve you,"], ["ona lē tatau 'ea lea ona outou galulue e auauna o le tasi i le isi?", "then ought not ye to labor to serve one another?"]]},
  {num:19,words:[["Ma faauta foi,", "And behold also,"], ["afai o a'u,", "if I,"], ["o lē ua outou ta'ua o lo outou tupu,", "whom ye call your king,"], ["o lē na faaaoga ona aso e auauna atu ai ia te outou, ae sa nao lona auauna atu lava lea i le Atua,", "who has spent his days in your service,"], ["ua agavaa mo se faafetai mai ia te outou,", "and yet has been in the service of God,"], ["E,", "do merit any thanks from you,"], ["ua matua tatau lava la ona outou faafetai atu i lo outou Tupu faalelagi!", "O how you ought to thank your heavenly King!"]]},
  {num:20,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["o'u uso e,", "my brethren,"], ["afai tou te avatu le faafetai ma le viiga atoa ua i ai i o outou agaga atoa le mana e maua ai,", "that if you should render all the thanks and praise which your whole soul has power to possess,"], ["i lena Atua o lē na foafoaina outou,", "to that God who has created you,"], ["ma sa tausia ma faasaoina outou,", "and has kept and preserved you,"], ["ma faia ia outou olioli,", "and has caused that ye should rejoice,"], ["ma tuu mai ia outou ola i le filemu ma le tasi—", "and has granted that ye should live in peace one with another—"]]},
  {num:21,words:[["Ou te fai atu ia te outou afai tou te auauna atu ia te ia o lē na foafoaina outou mai le amataga,", "I say unto you that if ye should serve him who has created you from the beginning,"], ["ma o loo faasaoina outou mai lea aso i lea aso,", "and is preserving you from day to day,"], ["i le tuuina mai ia te outou o le mānava, ina ia mafai ona outou ola ma gaoioi ma outou faia e tusa ai ma o outou lava loto ,", "by lending you breath,"], ["ma lagolagoina foi outou mai lea minute i lea minute—ou te fai atu,", "that ye may live and move and do according to your own will,"], ["afai tou te auauna atu ia te ia ma o outou agaga atoa,", "and even supporting you from one moment to another—I say,"], ["e avea pea outou o ni auauna lē aoga.", "if ye should serve him with all your whole souls yet ye would be unprofitable servants."]]},
  {num:22,words:[["Ma faauta,", "And behold,"], ["ona pau o le mea ua ia manaomia mai ia te outou o le tausi lea o ana poloaiga ;", "all that he requires of you is to keep his commandments;"], ["ma ua folafola mai e ia ia te outou afai tou te tausi i ana poloaiga o le a outou manuia i le laueleele;", "and he has promised you that if ye would keep his commandments ye should prosper in the land;"], ["ma e lē ese lava o ia mai le mea ua ia fetalai mai ai;", "and he never doth vary from that which he hath said;"], ["o lea,", "therefore,"], ["afai tou te tausi i ana poloaiga e faamanuia mai o ia ia te outou ma faatamaoaigaina outou.", "if ye do keep his commandments he doth bless you and prosper you."]]},
  {num:23,words:[["Ma o lenei,", "And now,"], ["o le mea muamua,", "in the first place,"], ["na ia foafoaina outou,", "he hath created you,"], ["ma tuu mai ia te outou o outou ola,", "and granted unto you your lives,"], ["o se mea ua outou nonofo aitalafu ai ia te ia.", "for which ye are indebted unto him."]]},
  {num:24,words:[["Ma lona lua,", "And secondly,"], ["ua ia manaomia ia outou faia e pei ona ia poloaiina ai outou;", "he doth require that ye should do as he hath commanded you;"], ["o se mea a outou faia,", "for which if ye do,"], ["e faamanuia vave mai lava o ia ia te outou;", "he doth immediately bless you;"], ["ma o lea ua ia totogi ai outou. Ma outou nonofo aitalafu ai pea ia te ia,", "and therefore he hath paid you. And ye are still indebted unto him,"], ["ma outou faapea lava,", "and are,"], ["ma o le a outou faapea lava,", "and will be,"], ["e faavavau faavavau lava;", "forever and ever;"], ["o lea,", "therefore,"], ["o se a se mea tou te mitamita ai?", "of what have ye to boast?"]]},
  {num:25,words:[["Ma o lenei ou te fesili atu,", "And now I ask,"], ["e mafai ea ona outou fai mai o se mea e uiga ia te outou lava? Ou te tali atu ia te outou,", "can ye say aught of yourselves? I answer you,"], ["E leai. E lē mafai ona outou fai mai ua tusa outou ma le efuefu o le eleele;", "Nay. Ye cannot say that ye are even as much as the dust of the earth;"], ["peitai na foafoaina outou mai le efuefu o le eleele;", "yet ye were created of the dust of the earth;"], ["ae faauta,", "but behold,"], ["o le efuefu ua ā ia foi o lē na foafoaina outou.", "it belongeth to him who created you."]]},
  {num:26,words:[["Ma o a'u,", "And I,"], ["e oo lava ia te a'u,", "even I,"], ["o lē ua outou ta'ua o lo outou tupu,", "whom ye call your king,"], ["ua lē sili atu a'u ia te outou;", "am no better than ye yourselves are;"], ["ona o a'u foi o le efuefu. Ma ua outou vaai mai ua ou toeaina,", "for I am also of the dust. And ye behold that I am old,"], ["ma ua lata ona ou tuu atu lenei tino faaletino i lona tinā o le eleele.", "and am about to yield up this mortal frame to its mother earth."]]},
  {num:27,words:[["O lea,", "Therefore,"], ["e pei ona ou fai atu ia te outou sa ou auauna atu ia te outou,", "as I said unto you that I had served you,"], ["ma ou savali ma le mafaufau mamā i luma o le Atua,", "walking with a clear conscience before God,"], ["ua faapea lava ona ou faia i le taimi nei ia outou faapotopoto faatasi mai outou lava,", "even so I at this time have caused that ye should assemble yourselves together,"], ["ina ia mafai ona maua a'u i le lē ponā,", "that I might be found blameless,"], ["ma ina ia lē oo mai o outou toto i o'u luga,", "and that your blood should not come upon me,"], ["pe a ou tu e faamasinoina a'u e le Atua e uiga i mea na ia poloaiina ai a'u e uiga ia te outou.", "when I shall stand to be judged of God of the things whereof he hath commanded me concerning you."]]},
  {num:28,words:[["Ou te fai atu ia te outou sa ou faia ia outou faapotopoto mai faatasi ina ia mafai ona ou tafi o'u ofu mai lo outou toto,", "I say unto you that I have caused that ye should assemble yourselves together that I might rid my garments of your blood,"], ["i le vaitaimi lenei o le taimi ua lata ai ona ou alu ifo i lalo i lo'u tuugamau,", "at this period of time when I am about to go down to my grave,"], ["ina ia mafai ona ou alu ifo i lalo i le filemu,", "that I might go down in peace,"], ["ma ina ia mafai e lo'u agaga ola pea ona auai i aufaipese i lugā i le lagiina o viiga o se Atua amiotonu.", "and my  immortal spirit may join the choirs above in singing the praises of a just God."]]},
  {num:29,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te fai atu ia te outou sa ou faia ia outou faapotopoto mai faatasi outou lava,", "I say unto you that I have caused that ye should assemble yourselves together,"], ["ina ia mafai ona ou ta'u atu ia te outou ua lē mafai ona toe avea o a'u mo o outou aoao,", "that I might declare unto you that I can no longer be your teacher,"], ["po o so outou tupu;", "nor your king;"]]},
  {num:30,words:[["Ona e oo lava i lenei taimi,", "For even at this time,"], ["ua gatete tele lava lou tino atoa a'o ou taumafai e tautala atu ia te outou;", "my whole frame doth tremble exceedingly while attempting to speak unto you;"], ["peitai ua lagolagoina a'u e le Alii le Atua,", "but the Lord God doth support me,"], ["ma ua ia tuu mai a'u ou te tautala atu ia te outou,", "and hath suffered me that I should speak unto you,"], ["ma ua ia poloaia a'u ia ou ta'u atu ia te outou i le asō,", "and hath commanded me that I should declare unto you this day,"], ["o lo'u atalii o Mosaea o se tupu ma se pule lea i luga o outou.", "that my son Mosiah is a king and a ruler over you."]]},
  {num:31,words:[["Ma o lenei,", "And now,"], ["o'u uso e,", "my brethren,"], ["ou te manao ia outou faia e pei ona outou faia e oo mai i le taimi nei. E pei ona outou tausi i a'u poloaiga,", "I would that ye should do as ye have hitherto done. As ye have kept my commandments,"], ["ma poloaiga foi a lo'u tamā,", "and also the commandments of my father,"], ["ma outou manuia ai,", "and have prospered,"], ["ma taofia ai outou mai le pauu atu i lima o o outou fili,", "and have been kept from falling into the hands of your enemies,"], ["e faapea lava ona outou manuia i le laueleele,", "even so if ye shall keep the commandments of my son,"], ["pe afai tou tausi i poloaiga a lo'u atalii,", "or the commandments of God which shall be delivered unto you by him,"], ["po o poloaiga a le Atua o le a tuu atu e ia ia te outou,", "ye shall prosper in the land,"], ["ma o le a leai se mana o o outou fili i o outou luga.", "and your enemies shall have no power over you."]]},
  {num:32,words:[["Peitai,", "But,"], ["lo'u nuu e,", "O my people,"], ["ia faaeteete nei tutupu a'e ni finauga i totonu o outou,", "beware lest there shall arise contentions among you,"], ["ma outou filifili ai e usiusitai i le agaga leaga,", "and ye list to obey the evil spirit,"], ["lea sa tautala i ai lo'u tamā o Mosaea.", "which was spoken of by my father Mosiah."]]},
  {num:33,words:[["Aua faauta,", "For behold,"], ["e i ai se mala ua folafola i luga o ia o lē e filifili e usiusitai i lena agaga;", "there is a wo pronounced upon him who listeth to obey that spirit;"], ["ona afai e filifili o ia e usiusitai ia te ia,", "for if he listeth to obey him, and remaineth and dieth in his sins,"], ["ma tumau ai ma oti i ana agasala,", "the same drinketh dam– nation to his own soul;"], ["o ia lava lea e inu i le malaia o lona lava agaga ona e maua e ia mo ona taui se faasalaga e faavavau ,", "for he receiveth for his wages an everlasting punishment,"], ["ona sa soli e ia le tulafono a le Atua e lē tusa ai ma lona lava malamalama.", "having transgressed the law of God contrary to his own knowledge."]]},
  {num:34,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["ua leai se tasi o i totonu ia te outou,", "that there are not any among you,"], ["vagana ai a outou fanau laiti e lei aoaoina e uiga i nei mea,", "except it be your little children that have not been taught concerning these things,"], ["ua ia lē iloa ua outou nonofo aitalafu e faavavau i lo outou Tama faalelagi,", "but what knoweth that ye are eternally indebted to your heavenly Father,"], ["e tuu atu ia te ia mea uma ua outou maua ma outou i ai;", "to render to him all that you have and are;"], ["ma ua aoaoina foi e uiga i talafaamaumau o loo i ai valoaga na fetalaia e perofeta paia,", "and also have been taught concerning the records which contain the prophecies which have been spoken by the holy prophets,"], ["e oo mai lava i lalo i le taimi na tuua ai e lo tatou tamā,", "even down to the time our father,"], ["o Liae,", "Lehi,"], ["Ierusalema.", "left Jerusalem;"]]},
  {num:35,words:[["O lenei foi,", "And also,"], ["o mea uma na tautalagia e o tatou tamā e oo mai i le taimi nei. Ma faauta,", "all that has been spoken by our fathers until now. And behold,"], ["foi,", "also,"], ["sa latou tautalagia mea sa poloaiina ai i latou e le Alii;", "they spake that which was commanded them of the Lord;"], ["o lea,", "therefore,"], ["ua tonu ma moni i latou.", "they are just and true."]]},
  {num:36,words:[["Ma o lenei,", "And now,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o'u uso e,", "my brethren,"], ["ona ua uma ona outou iloa ma aoao atu ia te outou nei mea uma,", "that after ye have known and have been taught all these things,"], ["afai tou te solia ma ō lē tusa ai ma mea ua fetalaia,", "if ye should transgress and go contrary to that which has been spoken,"], ["ma outou aveese outou lava mai le Agaga o le Alii,", "that ye do withdraw yourselves from the Spirit of the Lord,"], ["ina ia leai sona nofoaga i totonu ia te outou e taitai ai outou i ala o le poto ina ia mafai ona outou manuia ai,", "that it may have no place in you to guide you in wisdom’s paths that ye may be blessed,"], ["ma uluola,", "prospered,"], ["ma faasaoina—", "and preserved—"]]},
  {num:37,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["o le tagata na te faia lenei mea,", "that the man that doeth this,"], ["o ia lava lea e sau le fouvale aliali faasaga i le Atua;", "the same cometh out in open rebellion against God;"], ["o lea ua filifili o ia e usiusitai i le agaga leaga,", "therefore he listeth to obey the evil spirit,"], ["ma avea ma fili i le amiotonu uma;", "and becometh an enemy to all righteousness;"], ["o lea,", "therefore,"], ["ua leai se afioaga o le Alii i totonu ia te ia,", "the Lord has no place in him,"], ["ona e lē afio o ia i malumalu ua lē paia.", "for he dwelleth not in unholy temples."]]},
  {num:38,words:[["O lea afai e lē salamo lena tagata,", "Therefore if that man repenteth not,"], ["ae tumau ma oti o se fili i le Atua,", "and remaineth and dieth an enemy to God,"], ["o le a fagua e manaoga o le faamasinotonu paia lona agaga ola pea i se lagona olaola o lona lava sala ,", "the demands of divine justice do awaken his immortal soul to a lively sense of his own guilt,"], ["lea o le a ma'e'e ai o ia mai luma o le Alii,", "which doth cause him to shrink from the presence of the Lord,"], ["ma tumu ai lona fatafata i le lagona o ana sese,", "and doth fill his breast with guilt,"], ["ma le tiga,", "and pain,"], ["ma le mafatia,", "and anguish,"], ["lea ua pei o se afi lē matineia,", "which is like an unquenchable fire,"], ["o lona apeafi mumū e alu a'e pea i luga e faavavau ma faavavau lava.", "whose flame ascendeth up forever and ever."]]},
  {num:39,words:[["Ma o lenei ou te fai atu ia te outou,", "And now I say unto you,"], ["ua leai se aiā a le alofa mutimutivale i lena tagata;", "that mercy hath no claim on that man;"], ["o lea o lona malaia mulimuli o le tumau lea i le mafatia e lē gata.", "therefore his final doom is to endure a never– ending torment."]]},
  {num:40,words:[["E,", "O,"], ["outou e toeaina matutua uma,", "all ye old men,"], ["ma outou foi alii talavou,", "and also ye young men,"], ["ma outou fanau laiti o e ua mafai ona malamalama i a'u upu,", "and you little children who can understand my words,"], ["ona ua ou tautala manino atu ia te outou ina ia mafai ona outou malamalama,", "for I have spoken plainly unto you that ye might understand,"], ["ou te tatalo ia outou ala mai i le manatuaina o le tulaga leaga tele o i latou o e e pauu atu i le solitulafono.", "I pray that ye should awake to a remembrance of the awful situation of those that have fallen into transgression."]]},
  {num:41,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te manao ia outou manatunatu i le tulaga manuia ma le fiafia o i latou o e e tausi i poloaiga a le Atua.", "I would desire that ye should consider on the blessed and happy state of those that keep the commandments of God."], ["Aua faauta,", "For behold,"], ["e faamanuiaina i latou i mea uma,", "they are blessed in all things,"], ["i mea uma faaletino ma faaleagaga; ma afai latou te tutumau i le faamaoni e oo i le iuga,", "both temporal and spiritual;"], ["e talia i latou i le lagi ,", "and if they hold out faithful to the end they are received into heaven,"], ["ina ia mafai ona latou mau faatasi ma le Atua i se tulaga o le fiafia e lē gata.", "that thereby they may dwell with God in a state of never– ending happiness."], ["E,", "O remember,"], ["ia manatua, ia manatua lava ua moni nei mea;", "remember that these things are true;"], ["ona ua fetalai mai ai le Alii le Atua.", "for the Lord God hath spoken it."]]},
];
renderVerseSet(mo_ch_2_Verses, 'mo-ch2-verses');

var mo_ch_3_Verses = [
  {num:1,words:[["O lenei foi o'u uso e,", "And again my brethren,"], ["ou te manao ia outou ua'i mai,", "I would call your attention,"], ["ona e tele teisi atu ni isi mea ou te fia tautala atu ai ia te outou;", "for I have somewhat more to speak unto you;"], ["aua faauta,", "for behold,"], ["ua ia te a'u ni mea e faamatala atu ia te outou e uiga i mea o le a oo mai.", "I have things to tell you concerning that which is to come."]]},
  {num:2,words:[["Ma o mea o le a ou tau atu ia te outou sa faailoa mai ia te a'u e se agelu mai le Atua. Ma sa fetalai mai o ia ia te a'u:", "And the things which I shall tell you are made known unto me by an angel from God. And he said unto me:"], ["Ala mai ia;", "Awake;"], ["ma sa ou ala,", "and I awoke,"], ["ma faauta sa tu mai o ia i o'u luma.", "and behold he stood before me."]]},
  {num:3,words:[["Ma sa fetalai mai o ia ia te a'u:", "And he said unto me:"], ["Ala mai ia,", "Awake,"], ["ma faalogo mai i upu o le a ou ta'u atu ia te oe;", "and hear the words which I shall tell thee;"], ["aua faauta,", "for behold,"], ["ua ou sau e ta'u atu ia te oe tala fiafia o le olioli tele.", "I am come to declare unto you the glad tidings of great joy."]]},
  {num:4,words:[["Ona ua faafofoga le Alii i au talosaga,", "For the Lord hath heard thy prayers,"], ["ma ua faamasino e ia lou amiotonu,", "and hath judged of thy righteousness,"], ["ma ua ia auina mai a'u e ta'u atu ia te oe ina ia e olioli;", "and hath sent me to declare unto thee that thou mayest rejoice; and that thou mayest declare unto thy people,"], ["ma ina ia mafai ona e ta'u atu i ou tagata ina ia mafai foi ona faatumuina i latou i le olioli.", "that they may also be filled with joy."]]},
  {num:5,words:[["Aua faauta,", "For behold,"], ["e oo mai le taimi,", "the time cometh,"], ["ma ua lē o toe mamao atu,", "and is not far distant,"], ["o le a afio mai ai i lalo mai le lagi i totonu o le fanauga a tagata,", "that with power,"], ["ma le mana,", "the Lord Omnipotent who reigneth,"], ["le Alii Mamana Aoao o lē o nofotupu,", "who was,"], ["o lē sa i ai,", "and is from all eternity to all eternity,"], ["ma o loo i ai mai le faavavau atoa e oo i le faavavau atoa,", "shall come down from heaven among the children of men,"], ["ma o le a mau o ia i se fale apitaga omea,", "and shall dwell in a tabernacle of clay,"], ["ma o le a afio atu i totonu o tagata,", "and shall go forth amongst men,"], ["ma fai vavega tetele,", "working mighty miracles,"], ["e pei o le faamalologa o e mama'i,", "such as healing the sick,"], ["faatutuina mai o e ua oti,", "raising the dead,"], ["faasavavaliina o e ua pipili,", "causing the lame to  walk,"], ["ma faapupula e ua tauaso,", "the blind to receive their sight,"], ["ma faia ia faalologo e ua tutuli,", "and the deaf to hear,"], ["ma faamalolo ituaiga uma o ma'i eseese.", "and curing all manner of diseases."]]},
  {num:6,words:[["Ma o le a tutuli ese e ia tiapolo ,", "And he shall cast out devils,"], ["po o agaga leaga ua mau i loto o le fanauga a tagata.", "or the evil spirits which dwell in the hearts of the children of men."]]},
  {num:7,words:[["Ma faauta,", "And lo,"], ["o le a mafatia o ia i faaosoosoga ,", "he shall suffer temptations,"], ["ma tiga o le tino,", "and pain of body,"], ["ma le fia 'ai ma le fia inu,", "hunger,"], ["ma le lailoa,", "thirst, and fatigue,"], ["e sili atu i lo le mea e mafai e le tagata ona onosaia ,", "even more than man can suffer,"], ["vagana ai ua oti;", "except it be unto death;"], ["aua faauta,", "for behold,"], ["e sau le toto mai ona pu afu uma,", "blood cometh from every pore,"], ["ona o le a tele naua o lona mafatia mo le amioleaga ma mea inosia a ona tagata.", "so great shall be his anguish for the wickedness and the abominations of his people."]]},
  {num:8,words:[["Ma o le a ta'ua o ia o Iesu Keriso,", "And he shall be called Jesus Christ,"], ["o le Alo o le Atua,", "the Son of God,"], ["o le Tamā o le lagi ma le lalolagi,", "the Father of heaven and earth,"], ["o le Foafoa o mea uma mai le amataga;", "the Creator of all things from the beginning;"], ["ma o lona tinā o le a ta'ua o Maria .", "and his mother shall be called Mary."]]},
  {num:9,words:[["Ma faauta,", "And lo,"], ["e afio mai o ia i ona lava tagata,", "he cometh unto his own,"], ["ina ia mafai ona oo mai o le olataga i le fanauga a tagata e ala lava i le faatuatua i lona suafa;", "that salvation might come unto the children of men even through faith on his name;"], ["ma e ui lava i nei mea uma o le a latou manatu ia te ia o ia o se tagata,", "and even after all this they shall consider him a man,"], ["ma fai mai ua ia te ia se tiapolo ,", "and say that he hath a devil,"], ["ma o le a latou sasa ia te ia,", "and shall scourge him,"], ["ma o le a latou faasatauroina o ia.", "and shall crucify him."]]},
  {num:10,words:[["Ma o le a toetu mai o ia i le aso lona tolu mai e ua oti;", "And he shall rise the third day from the dead;"], ["ma faauta,", "and behold,"], ["ua tu o ia e faamasino le lalolagi;", "he standeth to judge the world;"], ["ma faauta,", "and behold,"], ["ua faia nei mea uma ina ia oo mai ai se faamasinoga amiotonu i luga o le fanauga a tagata.", "all these things are done that a righteous judgment might come upon the children of men."]]},
  {num:11,words:[["Aua faauta,", "For behold,"], ["e togiola foi lona toto mo agasala a i latou o e na pauu i le solitulafono a Atamu,", "and also his blood atoneth for the sins of those who have fallen by the transgression of Adam,"], ["o e na maliliu e aunoa ma le iloa o le finagalo o le Atua e uiga ia te i latou,", "who have died not knowing the will of God concerning them,"], ["po o e na agasala i le lē iloa.", "or who have ignorantly sinned."]]},
  {num:12,words:[["Ae talofa,", "But wo,"], ["talofa i lē e iloa ua fouvale o ia faasaga i le Atua! Ona e lē oo mai le olataga i se tasi faapena vagana ai e ala i le salamo ma le faatuatua i le Alii o Iesu Keriso.", "wo unto him who knoweth that he rebelleth against God! For salvation cometh to none such except it be through repentance and faith on the Lord Jesus Christ."]]},
  {num:13,words:[["Ma ua auina mai e le Alii le Atua ana perofeta paia i totonu o le fanauga uma a tagata,", "And the Lord God hath sent his holy prophets among all the children of men,"], ["e ta'u atu nei mea i ituaiga uma,", "to declare these things to every kindred,"], ["malo,", "nation,"], ["ma gagana,", "and tongue,"], ["ina ia mafai e soo se tasi o i latou lava ia o e e talitonu o le a afio mai Keriso,", "that thereby whosoever should believe that Christ should come,"], ["ona maua le faamagaloina o a latou agasala,", "the same might receive remission of their sins,"], ["ma olioli i le olioli tele,", "and rejoice with exceedingly great joy,"], ["e pei lava ua uma ona afio mai o ia i totonu o i latou.", "even as though he had already come among them."]]},
  {num:14,words:[["Peitai sa silasila le Alii le Atua o ona tagata o ni tagata ua ua maaa,", "Yet the Lord God saw that his people were a stiffnecked people,"], ["ma sa tofia e ia mo i latou se tulafono,", "and he appointed unto them a law,"], ["o le tulafono lava lea a Mose.", "even the law of Moses."]]},
  {num:15,words:[["Ma e tele faailoga,", "And many signs,"], ["ma mea ofoofogia,", "and wonders,"], ["ma faatusa ,", "and types,"], ["ma faaataataga sa faaali mai e ia ia te i latou e uiga i lona afio mai;", "and shadows showed he unto them, concerning his coming;"], ["ma sa fetalai atu foi perofeta paia ia te i latou e uiga i lona afio mai;", "and also holy prophets spake unto them concerning his coming;"], ["ma peitai sa latou faamaaa o latou loto,", "and yet they hardened their hearts,"], ["ma latou lē malamalama ua leai se aoga o le tulafono a Mose vagana ai ua ala mai i le togiola a lona toto.", "and understood not that the law of Moses availeth nothing except it were through the atonement of his blood."]]},
  {num:16,words:[["Ma e tusa pe a na mafai ona agasala fanau laiti e lē mafai ona faaolaina i latou;", "And even if it were possible that little children could sin they could not be saved;"], ["ae ou te fai atu ia te outou ua faamanuiaina i latou;", "but I say unto you they are blessed;"], ["aua faauta,", "for behold,"], ["e pei o Atamu,", "as in Adam,"], ["po o i le natura,", "or by nature,"], ["e pauu i latou,", "they fall,"], ["ae faapea lava ona togiola o le toto o Keriso mo a latou agasala.", "even so the blood of Christ atoneth for their sins."]]},
  {num:17,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o le a lē i ai se isi igoa e tuuina mai po o se isi lava ala po o ni auala e mafai ona oo mai ai le olataga i le fanauga a tagata,", "that there shall be no other name given nor any other way nor means whereby salvation can come unto the  children of men,"], ["ua nao i le suafa lava ma ala i le suafa lava o Keriso ,", "only in and through the name of Christ,"], ["le Alii Mamana Aoao.", "the Lord Omnipotent."]]},
  {num:18,words:[["Aua faauta e faamasino mai o ia,", "For behold he judgeth,"], ["ma ua tonu lana faamasinoga;", "and his judgment is just;"], ["ma e lē fano le tamaitiitimeamea e oti i lona tamameamea;", "and the infant perisheth not that dieth in his infancy;"], ["ae e inu e tagata matutua le malaia i o latou lava agaga vagana ai ua latou faalotomaualaloina i latou lava ma avea e pei o fanau laiti,", "but men drink damnation to their own souls except they humble themselves and become as little children,"], ["ma talitonu sa oo mai,", "and believe that salvation was, and is,"], ["ma ua oo mai,", "and is to come,"], ["ma o le a oo mai le olataga i le toto togiola ma ala mai i le toto togiola o Keriso,", "in and through the atoning blood of Christ,"], ["le Alii Mamana Aoao.", "the Lord Omnipotent."]]},
  {num:19,words:[["Ona o le tagata natura o se fili i le Atua,", "For the natural man is an enemy to God,"], ["ma sa faapea lava mai le pa'ū o Atamu,", "and has been from the fall of Adam,"], ["ma o le a faapea lava,", "and will be,"], ["e faavavau faavavau lava,", "forever and ever,"], ["vagana ai ua gaua'i atu o ia i uunaiga a le Agaga Paia,", "unless he yields to the enticings of the Holy Spirit,"], ["ma tuu ese le tagata natura ma avea ma tagata paia e ala i le togiola a Keriso le Alii,", "and putteth off the natural man and becometh a saint through the atonement of Christ the Lord,"], ["ma avea e pei o se tamaitiiti ,", "and becometh as a child,"], ["e usiusitai,", "submissive,"], ["agamalu,", "meek,"], ["lotomaualalo,", "humble,"], ["onosai,", "patient,"], ["ma tumu i le alofa,", "full of love,"], ["loto ina usitai uma ua silafia e le Alii e tatau ona faaoo mai i ona luga,", "willing to submit to all things which the Lord seeth fit to inflict upon him,"], ["e pei ona usitai atu se tamaitiiti i lona tamā.", "even as a child doth submit to his father."]]},
  {num:20,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o le a oo mai le taimi e salalau atu ai le malamalama o se Faaola i atunuu uma,", "that the time shall come when the knowledge of the Savior shall spread throughout every nation,"], ["ituaiga,", "kindred,"], ["gagana,", "tongue,"], ["ma tagata.", "and people."]]},
  {num:21,words:[["Ma faauta,", "And behold,"], ["a oo mai lena taimi,", "when that time cometh,"], ["o le a leai se tasi e maua i le lē pona i luma o le Atua,", "none shall be found blameless before God,"], ["vagana ai fanau laiti,", "except it be little children,"], ["na o i le salamo ma le faatuatua i le suafa o le Alii le Atua Mamana Aoao.", "only through repentance and faith on the name of the Lord God Omnipotent."]]},
  {num:22,words:[["Ma e oo i le taimi nei,", "And even at this time,"], ["a uma ona e aoao atu i lou nuu mea ua poloaiina ai oe e le Alii lou Atua,", "when thou shalt have taught thy people the things which the Lord thy God hath commanded thee,"], ["o lena lava taimi e lē toe maua ai i latou i le lē pona i le silafaga a le Atua,", "even then are they found no more blameless in the sight of God,"], ["nao i le tusa ai ma upu na ou tautala atu ai ia te oe.", "only according to the words which I have spoken unto thee."]]},
  {num:23,words:[["Ma o lenei ua ou tautala atu i upu na poloaiina ai a'u e le Alii le Atua.", "And now I have spoken the words which the Lord God hath commanded me."]]},
  {num:24,words:[["Ma ua faapea ona fetalai mai o le Alii:", "And thus saith the Lord:"], ["O le a tutu ia upu o se molimau susulu e faasaga i lenei nuu,", "They shall stand as a bright testimony against this people,"], ["i le aso faamasino;", "at the judgment day;"], ["o le mea lea o le a faamasino ai i latou,", "whereof they shall be judged,"], ["o tagata taitoatasi e tusa ma ana galuega,", "every man according to his works,"], ["pe lelei,", "whether they be good,"], ["pe leaga.", "or whether they be evil."]]},
  {num:25,words:[["Ma afai ua leaga a latou galuega e tuu i latou i se vaaiga leaga matautia o lo latou lava sala ma a latou mea inosia,", "And if they be evil they are consigned to an awful view of their own guilt and abominations,"], ["ia o le a latou ma'e'e ai mai luma o le Alii i se tulaga o le pagatia ma le mafatia e lē gata,", "which doth cause them to shrink from the presence of the Lord into a state of misery and endless torment,"], ["e lē mafai ona latou toe foi mai ai;", "from whence they can no more return;"], ["o lea ua latou inu ai le malaia i o latou lava agaga.", "therefore they have drunk damnation to their own souls."]]},
  {num:26,words:[["O lea,", "Therefore,"], ["ua latou inu ai mai le ipu o le toasa o le Atua,", "they have drunk out of the cup of the wrath of God,"], ["o se faamasinotonu e lē mafai ona faafitia mai ia te i latou e pei ona lē mafai ona faafitia e ia le tatau ai o le pa'ū o Atamu ona o lona 'ai o le fua faasaina;", "which justice could no more deny unto them than it could deny that Adam should fall because of his partaking of the forbidden fruit;"], ["o lea,", "therefore,"], ["e lē toe mafai ai ona maua e le alofa mutimutivale se aiā ia te i latou e faavavau.", "mercy could have claim on them no more forever."]]},
  {num:27,words:[["Ma o lo latou mafatia e pei o se lepa afi ma le teiō,", "And their torment is as a lake of fire and brimstone,"], ["o ona apeafi mumū e lē matineia,", "whose flames are unquenchable,"], ["ma o lona asu e alu a'e pea i luga e faavavau ma faavavau lava. Sa faapea ona poloaiina o a'u e le Alii. Amene.", "and whose smoke ascendeth up forever and ever. Thus hath the Lord commanded me. Amen."]]},
];
renderVerseSet(mo_ch_3_Verses, 'mo-ch3-verses');

var mo_ch_4_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo ina ua uma ona fai atu e le tupu o Peniamina o upu na tuu mai e le agelu a le Alii ia te ia,", "it came to pass that when king Benjamin had made an end of speaking the words which had been delivered unto him by the angel of the Lord,"], ["sa tepa atu ona fofoga faataamilo i le motu o tagata,", "that he cast his eyes round about on the multitude,"], ["ma faauta ua pauu i latou uma i le eleele,", "and behold they had fallen to the earth,"], ["ona ua oo mai i o latou luga le mata'u i le Alii.", "for the fear of the Lord had come upon them."]]},
  {num:2,words:[["Ma ua latou vaaia i latou lava i lo latou lava tulaga faaletino ,", "And they had viewed themselves in their own carnal state,"], ["ua maualalo lava nai lo le efuefu o le eleele.", "even less than the dust of the earth."], ["Ma sa latou alalaga uma leotele i le leo e tasi,", "And they all cried aloud with one voice,"], ["fai mai:", "saying:"], ["E,", "O have mercy,"], ["ia alofa mutimutivale mai ia,", "and apply the atoning blood of Christ that we may receive forgiveness of our sins,"], ["ma faaaoga le toto togiola o Keriso ina ia mafai ai ona matou maua le faamagaloga o a matou agasala, ma mafai ona faamamāina o matou loto;", "and our hearts may be purified;"], ["ona ua matou talitonu ia Iesu Keriso,", "for we believe in Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["o lē na foafoaina le lagi ma le fogeleele,", "who created heaven and earth,"], ["ma mea uma lava;", "and all things;"], ["o lē o le a afio mai i lalo i totonu o le fanauga a tagata.", "who shall come down among the children of men."]]},
  {num:3,words:[["Ma sa oo ina ua uma ona latou tautatalaina o nei upu sa afio ifo i o latou luga le Agaga o le Alii,", "And it came to pass that after they had spoken these words the Spirit of the Lord came upon them,"], ["ma faatumuina i latou i le olioli,", "and they were filled with joy,"], ["ina ua latou mauaina se faamagaloga o a latou agasala, ma ina ua latou maua le filemu o le mafaufau ,", "having received a remission of their sins,"], ["ona o le faatuatua tele ia Iesu Keriso sa ia te i latou,", "and having peace of conscience,"], ["o lē o le a afio mai,", "because of the exceeding faith which they had in Jesus Christ who should come,"], ["e tusa ma upu na tautala mai e le tupu o Peniamina ia te i latou.", "according to the words which king Benjamin had spoken unto them."]]},
  {num:4,words:[["Ma sa toe tatala e le tupu o Peniamina lona fofoga ma amata ona tautala mai ia te i latou,", "And king Benjamin again opened his mouth and began to speak unto them,"], ["ua fai mai:", "saying:"], ["A'u uo e ma o'u uso,", "My friends and my brethren,"], ["lo'u aiga e ma lo'u nuu,", "my kindred and my people,"], ["ou te manao ia outou toe ua'i mai,", "I would again call your attention,"], ["ina ia mafai ona outou faalogo mai ma malamalama i le toega o a'u upu o le a ou tautala atu ai ia te outou.", "that ye may hear and understand the remainder of my words which I shall speak unto you."]]},
  {num:5,words:[["Aua faauta,", "For behold,"], ["afai ua fagua outou i le taimi nei e le malamalama i le agalelei o le Atua i se lagona o lo outou noa,", "if the knowledge of the goodness of God at this time has awakened you to a sense of your nothingness,"], ["ma lo outou tulaga lē aoga ma pa'ū—", "and your worthless and fallen state—"]]},
  {num:6,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["afai ua outou oo mai i se malamalama o le agalelei o le Atua,", "if ye have come to a knowledge of the goodness of God,"], ["ma lona mana lē faatusalia,", "and his matchless power,"], ["ma lona poto,", "and fhis wisdom,"], ["ma lona onosai,", "and his patience,"], ["ma lona tali-tiga i le fanauga a tagata;", "and his long– suffering towards the children of men;"], ["ma,", "and also,"], ["le togiola foi na saunia mai le faavaega o le lalolagi,", "the atonement which has been prepared from the foundation of the world,"], ["ina ia mafai ona oo mai o le olataga ia te ia o lē e tuu atu lona faalagolago i le Alii,", "that thereby salvation might come to him that should put his trust in the Lord,"], ["ma filiga i le tausiga o ana poloaiga,", "and should be diligent in keeping his commandments,"], ["ma faatuatua pea e oo lava i le iuga o lona ola,", "and continue in the faith even unto the end of his life,"], ["o le uiga o la'u tala o le ola lea o le tino faaletino—", "I mean the life of the mortal body—"]]},
  {num:7,words:[["Ou te fai atu,", "I say,"], ["o le tagata lena o lē e mauaina le olataga,", "that this is the man who receiveth salvation,"], ["e ala i le togiola na saunia mai le faavaega o le lalolagi mo le fanauga uma a tagata,", "through the atonement which was prepared from the foundation of the world for all mankind,"], ["o e sa i ai talu mai le pa'ū o Atamu,", "which ever were since the fall of Adam,"], ["po o e o i ai,", "or who are,"], ["po o soo se tasi o le a i ai,", "or whoever shall be,"], ["e oo lava i le iuga o le lalolagi.", "even unto the end of the world."]]},
  {num:8,words:[["Ma o le ala lenei e oo mai ai le olataga. Ma ua leai se isi olataga vagana ai lenei ua fetalaia;", "And this is the means whereby salvation cometh. And there is  none other salvation save this which hath been spoken of;"], ["pe ua i ai foi ni isi tulaga e mafai ona faaolaina ai o le tagata vagana ai tulaga ua ou ta'u atu ia te outou.", "neither are there any conditions whereby man can be saved except the conditions which I have told you."]]},
  {num:9,words:[["Ia talitonu i le Atua;", "Believe in God;"], ["ia talitonu o loo soifua o ia,", "believe that he is,"], ["ma o ia na foafoaina mea uma,", "and that he created all things,"], ["i le lagi ma le lalolagi;", "both in heaven and in earth;"], ["ia talitonu ua ia te ia le poto uma,", "believe that he has all wisdom,"], ["ma le mana uma,", "and all power,"], ["i le lagi ma le lalolagi;", "both in heaven and in earth;"], ["ia talitonu e lē mafai e le tagata ona malamalama i mea uma e mafai ona malamalama i ai le Alii.", "believe that man doth not comprehend all the things which the Lord can comprehend."]]},
  {num:10,words:[["Ma ou te toe fai atu,", "And again,"], ["ia talitonu e ao ina outou salamo ia outou agasala ma lafoai i ai,", "believe that ye must repent of your sins and forsake them,"], ["ma outou faamaualalo outou lava i luma o le Atua; ma ole atu ma le faamaoni o le loto ia faamagaloina e ia outou;", "and humble yourselves before God;"], ["ma o lenei,", "and ask in sincerity of heart that he would forgive you;"], ["afai tou te talitonu i nei mea uma,", "and now,"], ["vaai ia outou faia .", "if you believe all these things see that ye do them."]]},
  {num:11,words:[["Ma ou te toe fai atu ia te outou e pei ona ou fai atu muamua,", "And again I say unto you as I have said before,"], ["ona ua outou o mai i le malamalama o le mamalu o le Atua,", "that as ye have come to the knowledge of the glory of God,"], ["pe afai ua outou iloa e uiga i lona agalelei ma ua outou tofo i lona alofa,", "or if ye have known of his goodness and have tasted of his love,"], ["ma ua outou maua se faamagaloga o a outou agasala,", "and have received a remission of your sins,"], ["lea ua tupu ai le olioli matua tele faapea i o outou agaga,", "which causeth such exceedingly great joy in your souls,"], ["e faapea lava ona ou manao ia outou manatua,", "even so I would that ye should remember,"], ["ma manatua pea lava pea,", "and always retain in remembrance,"], ["le silisiliese o le Atua,", "the greatness of God,"], ["ma lo outou lava noa ,", "and your own nothingness,"], ["ma lona agalelei ma lona tali-tiga ia te outou,", "and his goodness and long– suffering towards you,"], ["o tagata lē aoga,", "unworthy creatures,"], ["ma faamaualaloina outou lava e oo ifo i loloto o le lotomaualalo ,", "and humble yourselves even in the depths of humility,"], ["ma valaau atu i le suafa o le Alii i aso taitasi,", "calling on the name of the Lord daily,"], ["ma tutu mausali i le faatuatua i le mea o le a oo mai,", "and standing steadfastly in the faith of that which is to come,"], ["lea na fetalai mai e le fofoga o le agelu.", "which was spoken by the mouth of the angel."]]},
  {num:12,words:[["Ma faauta,", "And behold,"], ["ou te fai atu ia te outou afai tou te faia lenei mea o le a outou olioli pea,", "I say unto you that if ye do this ye shall always rejoice,"], ["ma faatumuina i le alofa o le Atua,", "and be filled with the love of God,"], ["ma taofi pea le faamagaloina o a outou agasala;", "and always retain a remission of your sins;"], ["ma o le a outou tutupu a'e i le malamalama o le mamalu o ia na foafoaina outou,", "and ye shall grow in the knowledge of the glory of him that created you,"], ["po o i le malamalama o le mea ua tonu ma moni.", "or in the knowledge of that which is just and true."]]},
  {num:13,words:[["Ma o le a lē i ai ia te outou se manatu e faamanu'a i le tasi,", "And ye will not have a mind to injure one another,"], ["ae outou nonofo i le filemu ,", "but to live peaceably,"], ["ma faia i tagata taitoatasi e tusa ma le mea e tatau ai mo ia.", "and to render to every man according to that which is his due."]]},
  {num:14,words:[["Ma o le a outou lē tuu a outou fanau ia latou o fia aai,", "And ye will not suffer your children that they go hungry,"], ["pe lē lavalava;", "or naked;"], ["pe tou te tuu foi ia latou soli tulafono a le Atua,", "neither will ye suffer that they transgress the laws of God,"], ["ma misa ma fefinaua'i ma le tasi,", "and fight and quarrel one with another,"], ["ma auauna i le tiapolo,", "and serve the devil,"], ["o lē o le matai o le agasala,", "who is the master of sin,"], ["po o lē o le agaga leaga lea na tautatala i ai o tatou tamā,", "or who is the evil spirit which hath been spoken of by our fathers,"], ["o ia o se fili i le amiotonu uma.", "he being an enemy to all righteousness."]]},
  {num:15,words:[["Ae tou te aoao i latou ia savavali i ala o le upumoni ma le faamamalu;", "But ye will teach them to walk in the ways of truth and soberness;"], ["tou te aoao i latou ia alofa le tasi i le isi,", "ye will teach them to love one another,"], ["ma auauna le tasi i le isi.", "and to serve one another."]]},
  {num:16,words:[["O lenei foi,", "And also,"], ["o outou lava o le a outou fesoasoani atu i e manaomia la outou fesoasoani;", "ye yourselves will succor those that stand in need of your succor;"], ["o le a outou avatu ni isi o a outou mea ia te ia o lē ua lē tagolima;", "ye will administer of your substance unto him that standeth in need;"], ["ma o le a outou lē tuuina le tagata 'aisi ia lē aoga lana aioi mai ia te outou,", "and ye will not suffer that the beggar putteth up his petition to you in vain,"], ["ma auina ese atu o ia i fafo ia fano.", "and turn him out to perish."]]},
  {num:17,words:[["Atonu e te faapea ane:", "Perhaps thou shalt say:"], ["Ua aumai e lea tagata i ona lava luga lona pagatia;", "The man has brought upon himself his misery;"], ["o lea o le a ou taofi ai lo'u lima,", "therefore I will stay my hand,"], ["ma lē avatua ia te ia ni a'u meaai,", "and will not give unto him of my food,"], ["pe faasoa atu ia te ia a'u mea ina ia lē mafatia o ia,", "nor impart unto him of my substance that he may not suffer,"], ["ona ua tonu ona faasalaga—", "for his punishments are just—"]]},
  {num:18,words:[["Peitai ou te fai atu ia te oe,", "But I say unto you,"], ["le tagata e, soo se tasi na te faia lenei mea,", "O man,"], ["o ia lava lea ua i ai se pogai tele e tatau ona salamo ai;", "whosoever doeth this the same hath great cause to repent;"], ["ma vagana ai ua salamo o ia i lena mea ua ia faia, e fano o ia e faavavau,", "and except he repenteth of that which he hath done he perisheth forever,"], ["ma ua leai sona sao i le malo o le Atua.", "and hath no interest in the kingdom of God."]]},
  {num:19,words:[["Aua faauta,", "For behold,"], ["pe lē o i tatou uma ea o ni tagata aisi? Pe ua tatou lē faalagolago uma ea i le Tagata e tasi,", "are we not all beggars? Do we not all depend upon the same Being,"], ["o le Atua lava lea,", "even God,"], ["mo mea uma ua tatou maua,", "for all the substance which we have,"], ["mo meaai ma lavalava,", "for both food and raiment,"], ["ma mo auro,", "and for gold,"], ["ma mo ario,", "and for silver,"], ["ma mo ituaiga uma o oloa eseese ua tatou maua?", "and for all the riches which we have of every kind?"]]},
  {num:20,words:[["Ma faauta,", "And behold,"], ["e oo i le taimi nei,", "even at this time,"], ["o loo outou valaau atu i lona suafa,", "ye have been calling on his name,"], ["ma aioi atu mo se faamagaloga o a outou agasala. Ma ua tuu ea e ia la outou aioi atu ia lē aoga? E leai;", "and begging for a remission of your sins. And has he suffered that ye have begged in vain? Nay;"], ["ua sasaa mai e ia lona Agaga i o outou luga,", "he has poured out his Spirit upon you,"], ["ma ua faia e ia ia tumu o outou loto i le olioli ,", "and has caused that your hearts should be filled with joy,"], ["ma faia e ia 'ia taofia o outou gutu ia lē mafafai ona outou tautatala,", "and has caused that your mouths should be stopped that ye could not find utterance,"], ["ona o le matua tele o lo outou olioli.", "so exceedingly great was your joy."]]},
  {num:21,words:[["Ma o lenei,", "And now,"], ["afai e tuu mai e le Atua,", "if God,"], ["o lē na foafoaina outou,", "who has created you,"], ["o lē ua outou faalagolago i ai mo o outou ola ma mea uma ua outou maua ma i ai,", "on whom you are dependent for your lives and for all that ye have and are,"], ["soo se mea ua sa'o tou te ole atu ai ia te ia,", "doth grant unto you whatsoever ye ask that is right,"], ["i le faatuatua,", "in faith,"], ["ma le talitonu o le a outou maua,", "believing that ye shall receive,"], ["E,", "O then,"], ["ua matua tatau lava la ona outou fefaasoaa'i o a outou mea ua maua o le tasi i le isi.", "how ye ought to impart of the substance that ye have one to another."]]},
  {num:22,words:[["Ma afai e te faamasino i le tagata e tuu mai lana talosaga ia te oe mo au mea ina ia lē fano o ia,", "And if ye judge the man who putteth up his petition to you for your substance that he perish not,"], ["ma e ta'usalaina o ia,", "and condemn him,"], ["pe o le a lē matua sili atu ea la ona tonu o lou ta'usalaga mo le taofi o au mea,", "how much more just will be your condemnation for withholding your substance,"], ["e lē o ni au ae o ā le Atua,", "which doth not belong to you but to God,"], ["o lē foi e ana le ola ua ia te oe;", "to whom also your life belongeth;"], ["peitai e te lei tuuina atu ai se talosaga,", "and yet ye put up no petition,"], ["pe salamo i le mea ua e faia.", "nor repent of the thing which thou hast done."]]},
  {num:23,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["oi talofa i lena tagata,", "wo be unto that man,"], ["ona o le a fano ana mea faatasi ma ia;", "for his substance shall perish with him;"], ["ma o lenei,", "and now,"], ["ua ou fai atu nei mea ia te i latou o e ua mauoa i mea o lenei lalolagi.", "I say these things unto those who are rich as pertaining to the things of this world."]]},
  {num:24,words:[["O lenei foi,", "And again,"], ["ou te fai atu i e matitiva,", "I say unto the poor,"], ["outou na ua lē tagolima ae ua lava mea ua outou maua,", "ye who have not and yet have sufficient,"], ["ua outou ola ai mai lea aso i lea aso;", "that ye remain from day to day;"], ["o le uiga o la'u tala o outou uma o e e teena le tagata 'aisi,", "I mean all you who deny the beggar,"], ["ona ua outou lē tagolima;", "because ye have not;"], ["ou te manao ia outou fai ifo i o outou loto e faapea:", "I would that ye say in your hearts that:"], ["Ua ou lē avatu se mea ona ua ou lē tagolima,", "I give not because I have not,"], ["ae a na ou tagolima ou te avatu lava.", "but if I had I would give."]]},
  {num:25,words:[["Ma o lenei,", "And now,"], ["afai tou te fai ifo lenei mea i o outou loto tou te tumau pea i le lē sala,", "if ye say this in your hearts ye remain guiltless,"], ["a lē o lea e ta'usalaina outou;", "otherwise ye are condemned;"], ["ma ua tonu lo outou ta'usalaga ona ua outou manumanu i mea tou te lei mauaina.", "and your condemnation is just for ye covet that which ye have not received."]]},
  {num:26,words:[["Ma o lenei,", "And now,"], ["ona o nei mea ua ou tautala atu ai ia te outou—o lona uiga,", "for the sake of these things which I have spoken unto you—that is,"], ["mo le taofia pea o le faamagaloina o a outou agasala mai lea aso i lea aso,", "for the sake of retaining a remission of your sins from day to day,"], ["ina ia outou savavali ma le lē sala i luma o le Atua—ou te manao ia outou faasoa atu a outou mea i e matitiva ,", "that ye may walk guiltless before God—I would that ye should impart of your substance to the poor,"], ["ia taitasi le tagata ma faia e tusa ma mea ua ia te ia,", "every man according to that which he hath,"], ["e pei o le fafagaina o e ua fia aai,", "such as feeding the hungry,"], ["faaoofuina o e ua lē lavalava,", "clothing the naked,"], ["asiasi atu i e mama'i ma auauna atu mo lo latou mapusaga,", "visiting the sick and administering to their relief,"], ["faaleagaga ma faaletino,", "both spiritually and temporally,"], ["e tusa ma o latou manaoga.", "according to their wants."]]},
  {num:27,words:[["Ma ia vaai ia faia nei mea uma i le poto ma le faatulagaga lelei;", "And see that all these things are done in wisdom and order;"], ["ona e lē tatau i se tagata ona momo'e televave atu nai lo le malosi ua ia te ia. O lenei foi,", "for it is not requisite that a man should run faster than he has strength. And again,"], ["e tatau ia te ia ona filiga,", "it is expedient that he should be diligent,"], ["ina ia mafai ona manumalo o ia i le taui;", "that thereby he might win the prize;"], ["o lea,", "therefore,"], ["e tatau ona faia mea uma i le faatulagaga tatau ai.", "all things must be done in order."]]},
  {num:28,words:[["Ma ou te manao ia outou manatua,", "And I would that ye should remember,"], ["soo se tasi o outou na te nonō se mea mai lē la te tuaoi e tatau ia te ia ona toe faafoi atu le mea na nonō mai e ia,", "that whosoever among you borroweth of his neighbor should return the thing that he borroweth,"], ["e tusa ma lana ioega,", "according as he doth agree,"], ["a lē o lea ua e faia le agasala;", "or else thou shalt commit sin;"], ["ma atonu o le a e faia ai ia fai ai foi e lē lua te tuaoi le agasala.", "and perhaps thou shalt cause thy neighbor to commit sin also."]]},
  {num:29,words:[["Ma mulimuli lava,", "And finally,"], ["e lē mafai ona ou ta'u atu ia te outou mea uma e mafai ona outou faia ai le agasala;", "I cannot tell you all the things whereby ye may commit sin;"], ["ona ua tele ala ma auala eseese,", "for there are divers ways and means,"], ["ua matua tele lava e lē mafai ona ou faitauina.", "even so many that I cannot number them."]]},
  {num:30,words:[["Ae o le mea lenei e mafai ona ou ta'u atu ia te outou,", "But this much I can tell you,"], ["afai tou te lē vaavaaia outou lava,", "that if ye do not watch yourselves,"], ["ma o outou mafaufauga ,", "and your thoughts,"], ["ma a outou upu ,", "and your words,"], ["ma a outou galuega,", "and your deeds,"], ["ma tausi i poloaiga a le Atua,", "and observe the commandments of God,"], ["ma tumau pea i le faatuatua i mea ua outou faalogo i ai e uiga i le afio mai o lo tatou Alii,", "and continue in the faith of what ye have heard concerning the coming of our Lord,"], ["e oo lava i le iuga o o outou ola,", "even unto the end of your lives,"], ["e fano lava outou.", "ye must perish."], ["Ma o lenei le tagata e,", "And now,"], ["ia manatua,", "O man, remember,"], ["ma lē fano ai.", "and perish not."]]},
];
renderVerseSet(mo_ch_4_Verses, 'mo-ch4-verses');

var mo_ch_5_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo ina ua uma ona saunoa atu faapea le tupu o Peniamina i lona nuu,", "it came to pass that when king Benjamin had thus spoken to his people,"], ["sa auina atu e ia ni avefeau i totonu ia te i latou,", "he sent among them,"], ["i le fia iloa mai lona nuu pe ua latou talitonu i upu na tautala atu e ia ia te i latou.", "desiring to know of his people if they believed the words which he had spoken unto them."]]},
  {num:2,words:[["Ma sa latou alalaga uma mai i le leo e tasi,", "And they all cried with one voice,"], ["fai mai:", "saying:"], ["Ioe,", "Yea,"], ["ua matou talitonu i upu uma na e saunoa mai ai ia te i matou;", "we believe all the words which thou hast spoken unto us;"], ["o lenei foi,", "and also,"], ["ua matou iloa lo latou mautinoa ma le moni,", "we know of their surety and truth,"], ["ona o le Agaga o le Alii Mamana Aoao,", "because of the Spirit of the Lord Omnipotent,"], ["lea ua ia faia se liuga tele i totonu o i matou,", "which has wrought a mighty change in us,"], ["po o i totonu o o matou loto,", "or in our hearts,"], ["ua lē toe i ai so matou manao e fai mea leaga,", "that we have no more disposition to do evil,"], ["ae ia faia mea lelei e lē aunoa.", "but to do good continually."]]},
  {num:3,words:[["Ma o i matou,", "And we,"], ["i matou lava foi,", "ourselves,"], ["ua matou maua ni vaaiga tetele o mea o le a oo mai,", "also,"], ["e ala i le agalelei aoao o le Atua,", "through the infinite goodness of God, and the manifestations of his Spirit,"], ["ma faaaliga a lona Agaga;", "have great views of that which is to come;"], ["ma a na tatau ai,", "and were it expedient,"], ["e mafai ona matou vavalo e uiga i mea uma.", "we could prophesy of all things."]]},
  {num:4,words:[["Ma o le faatuatua sa ia te i matou e uiga i mea na saunoa mai ai lo matou tupu ia te i matou ua aumai ai i matou i lenei malamalama tele,", "And it is the faith which we have had on the things which our king has spoken unto us that has brought us to this great know– ledge,"], ["lea ua matou olioli ai i se olioli tele lava faapea.", "whereby we do rejoice with such exceedingly great joy."]]},
  {num:5,words:[["Ma ua matou malilie e ulu atu i se feagaiga ma lo matou Atua e fai lona finagalo,", "And we are willing to enter into a covenant with our God to do his will,"], ["ma usiusitai i ana poloaiga i mea uma e poloaiina ai i matou e ia,", "and to be obedient to his commandments in all things that he shall command us,"], ["i o matou aso uma o totoe,", "all the remainder of our days,"], ["ina ia matou lē aumai i o matou lava luga le mafatia e lē gata,", "that we may not bring upon ourselves a never– ending torment,"], ["e pei ona fetalai i ai le agelu ,", "as has been spoken by the angel,"], ["ina ia matou lē inu mai le ipu o le toasa o le Atua.", "that we may not drink out of the cup of the wrath of God."]]},
  {num:6,words:[["Ma o lenei,", "And now,"], ["o upu nei na manao i ai le tupu o Peniamina mai ia te i latou;", "these are the words which king Benjamin desired of them;"], ["ma o lea na fai atu atu ai o ia ia te i latou:", "and therefore he said unto them:"], ["Ua outou fai mai upu na ou manao i ai;", "Ye have spoken the words that I desired;"], ["ma o le feagaiga ua outou faia o se feagaiga amiotonu.", "and the covenant which ye have made is a righteous covenant."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["ona o le feagaiga ua outou faia,", "because of the covenant which ye have made ye shall be called the children of Christ,"], ["o le a ta'ua ai outou o le fanau a Keriso ,", "his sons,"], ["o ona atalii,", "and his daughters;"], ["ma ona afafine; ona faauta,", "for behold,"], ["o le asō ua fanauina ai e ia outou faaleagaga;", "this day he hath spiritually begotten you;"], ["ona ua outou fai mai ua liua o outou loto e ala i le faatuatua i lona suafa;", "for ye say that your hearts are changed through faith on his name;"], ["o lea,", "therefore,"], ["ua fanauina ai outou e ia ma ua avea ai outou ma ona atalii ma ona afafine.", "ye are born of him and have become his sons and his daughters."]]},
  {num:8,words:[["Ma o lalo o lenei ao ua faasaoloto ai outou,", "And under this head ye are made free,"], ["ma ua leai se isi lava ao e mafai ona faasaoloto ai outou. Ua leai se isi lava suafa ua tuuina mai e mafai ona oo mai ai le olataga;", "and there is no other head whereby ye can be made free. There is no other name given whereby salvation cometh;"], ["o lea,", "therefore,"], ["ou te manao ai ia outou ave i o outou luga le suafa o Keriso,", "I would that ye should take upon you the name of Christ,"], ["outou uma ua ulu atu i le feagaiga ma le Atua o le a outou usiusitai e oo i le iuga o o outou ola.", "all you that have entered into the covenant with God that ye should be obedient unto the end of your lives."]]},
  {num:9,words:[["Ma o le a oo mai,", "And it shall come to pass that whosoever doeth this shall be found at the right hand of God,"], ["soo se tasi e faia lenei mea o le a maua o ia i le aao taumatau o le Atua, ona o le a iloa e ia le suafa o le a valaau ai o ia;", "for he shall know the name by which he is called;"], ["ona o le a valaau o ia i le suafa o Keriso.", "for he shall be called by the name of Christ."]]},
  {num:10,words:[["Ma o lenei foi o le a oo mai,", "And now it shall come to pass,"], ["soo se tasi e lē avea i ona luga le suafa o Keriso o le a valaauina i se isi igoa;", "that whosoever shall not take upon him the name of Christ must be called by some other name;"], ["o lea,", "therefore,"], ["o le a maua e ia o ia lava i le aao tauagavale o le Atua.", "he findeth himself on the left hand of God."]]},
  {num:11,words:[["Ma ou te manao ia outou manatua foi,", "And I would that ye should remember also,"], ["o le igoa lenei sa ou fai atu o le a ou avatu ia te outou e lē tatau lava ona soloiesea,", "that this is the name that I said I should give unto you that never should be blotted out,"], ["vagana ai i le solitulafono;", "except it be through transgression;"], ["o lea,", "therefore,"], ["ia outou faaeteete ai ia outou lē solitulafono,", "take heed that ye do not transgress,"], ["ina ia lē soloiesea le suafa mai o outou loto.", "that the name be not blotted out of your hearts."]]},
  {num:12,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["ou te manao ia outou manatua ia taofi le suafa ia tusia pea i o outou loto,", "I would that ye should remember to retain the name written always in your hearts,"], ["ina ia lē maua outou i le aao tauagavale o le Atua,", "that ye are not found on the left hand of God,"], ["ae ia outou lagona ma iloa le leo o le a valaau ai outou,", "but that ye hear and know the voice by which ye shall be called,"], ["ma le igoa foi,", "and also,"], ["o le a valaau ai outou e ia.", "the name by which he shall call you."]]},
  {num:13,words:[["Aua pe faapefea ona iloa e se tagata le matai e lei auauna i ai o ia,", "For how knoweth a man the master whom he has not served,"], ["ma o se foi o se tagata ese ia te ia,", "and who is a stranger unto him,"], ["ma ua mamao mai mafaufauga ma faamoemoega o lona loto?", "and is far from the thoughts and intents of his heart?"]]},
  {num:14,words:[["O lenei foi,", "And again,"], ["e ave ea e se tagata se asini e ā lona tua'oi ma taofi ia te ia? Ou te fai atu ia te outou,", "doth a man take an ass which belongeth to his neighbor,"], ["E leai;", "and keep him? I say unto you,"], ["e lē tuua lava e ia o ia,", "Nay;"], ["ia 'ai i totonu o lana lafu,", "he will not even suffer that he shall feed among his flocks,"], ["ae na te tuli ese o ia,", "but will drive him away,"], ["ma tuli o ia i fafo. Ou te fai atu ia te outou,", "and cast him out. I say unto you,"], ["o le a faapea lava i totonu ia te outou pe afai tou te lē iloa le suafa ua valaau ai outou.", "that even so shall it be among you if ye know not the name by which ye are called."]]},
  {num:15,words:[["O lea,", "Therefore,"], ["ou te manao ai ia outou tutumau ma lē masi'i'ese,", "I would that ye should be steadfast and immovable,"], ["ma tumu e lē aunoa i galuega lelei,", "always abounding in good works,"], ["ina ia mafai ona faamauina outou e Keriso,", "that Christ,"], ["le Alii le Atua Mamana Aoao,", "the Lord God Omnipotent,"], ["e fai mona,", "may seal you his,"], ["ina ia mafai ona aumai o outou i le lagi,", "that you may be brought to heaven,"], ["ina ia mafai ona outou maua le olataga tumau-faavavau ma le ola e faavavau,", "that ye may have everlasting salvation and eternal life,"], ["e ala i le poto,", "through the wisdom,"], ["ma le mana,", "and power,"], ["ma le faamasinotonu,", "and justice,"], ["ma le alofa mutimutivale o ia o lē na foafoaina mea uma,", "and mercy of him who created all  things,"], ["i le lagi ma le lalolagi,", "in heaven and in earth,"], ["o lē o le Atua o mea uma. Amene.", "who is God above all. Amen."]]},
];
renderVerseSet(mo_ch_5_Verses, 'mo-ch5-verses');

var mo_ch_6_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["ua manatu le tupu o Peniamina o se mea ua tatau,", "king Benjamin thought it was expedient,"], ["ina ua uma ona tautala atu o ia i le nuu,", "after having finished speaking to the people,"], ["ona ia faamaumau igoa o i latou uma o e na ulu i se feagaiga ma le Atua e tausi i ana poloaiga.", "that he should take the names of all those who had entered into a covenant with God to keep his command– ments."]]},
  {num:2,words:[["Ma sa oo ina sa leai se tagata e toatasi o i latou,", "And it came to pass that there was not one soul,"], ["vagana ai fanau laiti,", "except it were little children,"], ["sa lei ulu atu i le feagaiga ma latou ave i o latou luga le suafa o Keriso.", "but who had entered into the covenant and had taken upon them the name of Christ."]]},
  {num:3,words:[["O lenei foi,", "And again,"], ["sa oo ina ua uma ona faaiu e le tupu o Peniamina nei mea uma,", "it came to pass that when king Benjamin had made an end of all these things,"], ["ma uma ona faapaia o lona atalii o Mosaea e avea ma pule ma se tupu i lona nuu,", "and had consecrated his son Mosiah to be a ruler and a king over his people,"], ["ma uma ona tuu atu ia te ia o faatonuga uma e uiga i le malo,", "and had given him all the charges concerning the kingdom,"], ["ma ua uma foi ona tofia o faitaulaga e aoaoina le nuu,", "and also had appointed priests to teach the people,"], ["ina ia mafai ona latou faalogo ma iloa poloaiga a le Atua,", "that thereby they might hear and know the commandments of God,"], ["ma uuna'i i latou ia latou manatua le tautoga ua latou faia,", "and to stir them up in remembrance of the oath which they had made,"], ["sa faataape atu e ia le motu o tagata,", "he dismissed the multitude,"], ["ma sa latou foi atu,", "and they returned,"], ["o tagata taitoatasi,", "every one,"], ["e tusa ma o latou aiga,", "according to their families,"], ["i o latou lava fale.", "to their own houses."]]},
  {num:4,words:[["Ma sa amata ona nofotupu Mosaea e sui i lona tamā. Ma sa amata ona nofotupu o ia i le tolu sefulu o ona tausaga,", "And Mosiah began to reign in his father’s stead. And he began to reign in the thirtieth year of his age,"], ["o le atoa ai lea,", "making in the whole,"], ["o le tusa o le fa selau ma le fitu sefulu ma le ono o tausaga mai le taimi na tuua ai Ierusalema e Liae.", "about four hundred and seventy– six years from the time that Lehi left Jerusalem."]]},
  {num:5,words:[["Ma sa soifua le tupu o Peniamina i le tolu tausaga ona maliu ai lea o ia.", "And king Benjamin lived three years and he died."]]},
  {num:6,words:[["Ma sa oo ina savali le tupu o Mosaea i ala o le Alii,", "And it came to pass that king Mosiah did walk in the ways of the Lord,"], ["ma sa tausi e ia ana faamasinoga ma ana tulafono,", "and did observe his judgments and his statutes,"], ["ma sa tausi e ia ana poloaiga i soo se mea lava o mea uma na poloaiina ai e ia o ia.", "and did keep his commandments in all things whatsoever he commanded him."]]},
  {num:7,words:[["Ma sa faatonu e le tupu o Mosaea lona nuu ia latou galueaiina le eleele.", "And king Mosiah did cause his people that they should till the earth."], ["Ma o ia foi,", "And he also,"], ["sa galueaiina e ia lava le eleele,", "himself,"], ["ina ia mafai ona lē avea o ia ma avega mamafa i lona nuu,", "did till the earth, that thereby he might not become burdensome to his people,"], ["ina ia mafai ona faia e ia e tusa ma mea na faia e lona tamā i mea uma.", "that he might do according to that which his father had done in all things."], ["Ma sa leai se finauga i totonu o lona nuu atoa mo le va o tausaga e tolu.", "And there was no contention among all his people for the space of three years."]]},
];
renderVerseSet(mo_ch_6_Verses, 'mo-ch6-verses');

var mo_ch_7_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo ina ua mavae ona maua e le tupu o Mosaea le filemu sa faaauau pea mo le va o tausaga e tolu,", "it came to pass that after king Mosiah had had continual peace for the space of three years,"], ["sa ia fia iloa e uiga i tagata o e na o a'e e nonofo i le laueleele o Liae-Nifae,", "he was desirous to know concerning the people who went up to dwell in the land of Lehi– Nephi,"], ["po o le aai o Liae-Nifae;", "or in the city of Lehi– Nephi;"], ["ona sa leai se mea sa faalogoina e lona nuu mai ia te i latou mai le taimi na latou tuua ai le laueleele o Sara'emila ;", "for his people had heard nothing from them from the time they left the land of Zarahemla;"], ["o lea,", "therefore,"], ["sa latou faafiufiu ai ia te ia i lo latou fesili soo.", "they wearied him with their teasings."]]},
  {num:2,words:[["Ma sa oo ina tuu atu e le tupu o Mosaea se faatagaga e mafai ona o a'e ai ni o latou alii malolosi e toasefuluono i le laueleele o Liae-Nifae, e saili e uiga i o latou uso.", "And it came to pass that king Mosiah granted that sixteen of their strong men might go up to the land of Lehi– Nephi to inquire concerning their brethren."]]},
  {num:3,words:[["Ma sa oo ina amata ona latou o a'e i le aso na sosoo ai,", "And it came to pass that on the morrow they started to go up,"], ["ma sa faatasi ma i latou se tasi tagata e igoa ia Amona,", "having with them one Ammon,"], ["o ia o se tagata aumalosi ma le malosi tele,", "he being a strong and mighty man,"], ["ma o se na tupuga mai ia Sara'emila;", "and a descendant of Zarahemla;"], ["ma o ia foi sa taitai ia te i latou.", "and he was also their leader."]]},
  {num:4,words:[["Ma o lenei,", "And now,"], ["sa latou le iloa le ala sa tatau ona latou malaga ai i le vao e o a'e ai i le laueleele o Liae-Nifae;", "they knew not the course they should travel in the wilderness to go up to the land of Lehi– Nephi;"], ["o lea na latou fesēa'i ai i le vao i aso e tele,", "therefore they wandered many days in the wilderness,"], ["e fa sefulu lava aso na latou fesēa'i ai.", "even forty days did they wander."]]},
  {num:5,words:[["Ma ina ua mavae aso e fa sefulu o latou fesēa'i,", "And when they had wandered forty days they came to a hill,"], ["sa latou tau atu i se mauga, e i matu o le laueleele o Seloma ,", "which is north of the land of Shilom,"], ["ma o iina na latou faatutu ai o latou faleie.", "and there they pitched their tents."]]},
  {num:6,words:[["Ma sa ave e Amona ni ona uso e toatolu,", "And Ammon took three of his brethren,"], ["ma o o latou igoa o Amaleki,", "and their names were Amaleki,"], ["Helema,", "Helem,"], ["ma Hema,", "and Hem,"], ["ma latou o ifo i lalo i le laueleele o Nifae .", "and they went down into the land of Nephi."]]},
  {num:7,words:[["Ma faauta,", "And behold,"], ["sa latou fetaia'i ma le tupu o tagata o e sa i ai i le laueleele o Nifae,", "they met the king of the people who were in the land of Nephi,"], ["ma i le laueleele o Seloma;", "and in the land of Shilom;"], ["ma sa si'omia i latou e leoleo a le tupu,", "and they were surrounded by the king’s guard,"], ["ma ave i latou,", "and were taken,"], ["ma saisai,", "and were bound,"], ["ma tuu i le falepuipui.", "and were committed to prison."]]},
  {num:8,words:[["Ma sa oo ina ua mavae aso e lua o i ai i latou i le falepuipui sa toe aumai i latou i luma o le tupu,", "And it came to pass when they had been in prison two days they were again brought before the king,"], ["ma sa tatala o latou noanoaga;", "and their bands were loosed;"], ["ma sa latou tutū i luma o le tupu,", "and they stood before the king, and were permitted,"], ["ma faataga pe sa faatonuina i latou,", "or rather commanded,"], ["ia latou tali atu i fesili o le a fesili mai e ia ia te i latou.", "that they should answer the questions which he should ask them."]]},
  {num:9,words:[["Ma sa fai mai o ia ia te i latou:", "And he said unto them:"], ["Faauta,", "Behold,"], ["o a'u o Limae ,", "I am Limhi,"], ["o le atalii o Noa,", "the son of Noah,"], ["o ia o le atalii o Senifa,", "who was the son of Zeniff,"], ["o lē na sau i fafo mai le laueleele o Sara'emila e fai mo ona tofi le laueleele lenei,", "who came up out of the land of Zarahemla to inherit this land,"], ["o le laueleele lea o o latou tamā,", "which was the land of their fathers,"], ["o lē na faia o se tupu i le leo o le nuu.", "who was made a king by the voice of the people."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["ou te fia iloa le pogai ua outou totoa ai e o mai latalata i pa o le aai,", "I desire to know the cause whereby ye were so bold as to come near the walls of the city,"], ["a'o a'u lenei,", "when I, myself,"], ["ou te faatasi ma a'u leoleo i tua o le faitotoa?", "was with my guards without the gate?"]]},
  {num:11,words:[["Ma o lenei,", "And now,"], ["o le pogai lenei ua ou tuu atu ai ia faasaoina outou,", "for this cause have I suffered that ye should be preserved,"], ["ina ia mafai ona ou fesiligia outou,", "that I might inquire of you,"], ["a na leai po ua ou faia ia fasiotia outou e a'u leoleo. Ua faatagaina outou tou te tautatala mai.", "or else I should have caused that my guards should have put you to death. Ye are permitted to speak."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["ina ua vaai atu Amona ua faataga o ia e tautala atu,", "when Ammon saw that he was permitted to speak,"], ["sa alu atu o ia ma ifo atu o ia lava i luma o le tupu;", "he went forth and bowed himself before the king;"], ["ma ina ua toe tu a'e o ia sa ia fai atu:", "and rising again he said:"], ["Le tupu e,", "O king,"], ["ou te matua faafetai tele i luma o le Atua i lenei aso ona ua ou ola pea,", "I am very thankful before God this day that I am yet alive,"], ["ma ua faatagaina a'u ou te tautala atu;", "and am permitted to speak;"], ["ma o le a ou taumafai e tautala atu ma le lototele.", "and I will endeavor to speak with boldness;"]]},
  {num:13,words:[["Ona ua ou mautinoa a na e silafia a'u po ua e lē tuuina ia noatia a'u i nei maea. Ona o a'u o Amona,", "For I am assured that if ye had known me ye would not have suffered that I should have worn these bands. For I am Ammon,"], ["ma o a'u o se e tupuga mai ia Sara'emila ,", "and am a descendant of Zarahemla,"], ["ma ua ou sau mai le laueleele o Sara'emila e saili e uiga i o matou uso,", "and have come up out of the land of Zarahemla to inquire concerning our brethren,"], ["o e na aumai i fafo e Senifa mai le laueleele lena.", "whom Zeniff brought up out of that land."]]},
  {num:14,words:[["Ma o lenei,", "And now,"], ["sa oo ina ua uma ona faalogo mai o Limae i upu a Amona,", "it came to pass that after Limhi had heard the words of Ammon,"], ["sa matua fiafia tele lava o ia,", "he was exceedingly glad,"], ["ma fai mai:", "and said:"], ["O lenei,", "Now,"], ["ua ou iloa ma le mautinoa o loo ola pea o'u uso o e o i ai i le laueleele o Sara'emila. Ma o lenei,", "I know of a surety that my brethren who were in the land of Zarahemla are  yet alive. And now,"], ["o le a ou olioli;", "I will rejoice;"], ["ma o le aso a taeao o le a ou faia ai ia olioli foi lo'u nuu.", "and on the morrow I will cause that my people shall rejoice also."]]},
  {num:15,words:[["Aua faauta,", "For behold,"], ["o loo matou pologa nei ia sa Lamanā,", "we are in bondage to the Lamanites,"], ["ma ua tuulafoga i matou i se lafoga ua faigata lava ona tauave. Ma o lenei,", "and are taxed with a tax which is grievous to be borne. And now,"], ["faauta,", "behold,"], ["o le a laveaiina i tatou i fafo e o tatou uso mai lo tatou pologa,", "our brethren will deliver us out of our bondage,"], ["po o i fafo mai lima o sa Lamanā,", "or out of the hands of the Lamanites,"], ["ma o le a avea i tatou ma a latou pologa;", "and we will be their slaves;"], ["ona e sili lo tatou pologa i tagata sa Nifaē nai lo le totogi o lafoga i le tupu o sa Lamanā.", "for it is better that we be slaves to the Nephites than to pay tribute to the king of the Lamanites."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["sa faatonu e le tupu o Limae ana leoleo ia aua ne'i toe saisaia Amona po o ona uso,", "king Limhi commanded his guards that they should no more bind Ammon nor his brethren,"], ["ae faatonu i latou ia latou o atu i le maupu'epu'e sa i le itu i matu o Seloma,", "but caused that they should go to the hill which was north of Shilom,"], ["ma aumai o latou uso i le aai,", "and bring their brethren into the city,"], ["ina ia mafai ona latou aai,", "that thereby they might eat,"], ["ma feinu,", "and drink,"], ["ma malolo mai fita o la latou malaga;", "and rest themselves from the labors of their journey;"], ["ona sa latou mafatia i mea e tele;", "for they had suffered many things;"], ["sa latou mafatia i le fia 'ai,", "they had suffered hunger,"], ["ma le fia inu,", "thirst,"], ["ma le vaivai.", "and fatigue."]]},
  {num:17,words:[["Ma o lenei sa oo ina auina atu e le tupu o Limae i le aso na sosoo ai se folafolaga i lona nuu atoa,", "And now,"], ["ina ia mafai ona latou faapotopoto mai faatasi i latou lava i le malumalu ,", "it came to pass on the morrow that king Limhi sent a proclamation among all his people,"], ["e faalogo i upu o le a tautala atu ai o ia ia te i latou.", "that thereby they might gather themselves together to the temple to hear the words which he should speak unto them."]]},
  {num:18,words:[["Ma sa oo ina ua latou faapotopoto mai faatasi i latou lava,", "And it came to pass that when they had gathered themselves together that he spake unto them in this wise,"], ["sa tautala atu o ia ia te i latou e faapenei,", "saying:"], ["ua fai atu: E,", "O ye,"], ["outou e,", "my people,"], ["o lo'u nuu,", "lift up your heads and be comforted;"], ["ia ea ia i luga o outou ulu ma ia faamafanafanaina outou;", "for behold,"], ["aua faauta,", "the time is at hand,"], ["ua oo mai le taimi,", "or is not far distant,"], ["pe ua lē o mamao,", "when we shall no longer be in subjection to our enemies,"], ["le taimi o le a tatou lē toe i ai i le puleaga a o tatou fili, e ui i le tele o a tatou tauiviga,", "notwithstanding our many strugglings,"], ["ia sa lē aoga;", "which have been in vain;"], ["peitai ou te faalagolago o loo toe se tauiviga aoga e tatau ona faia.", "yet I trust there remaineth an effectual struggle to be made."]]},
  {num:19,words:[["O lea,", "Therefore,"], ["ia ea i luga o outou ulu,", "lift up your heads,"], ["ma ia olioli,", "and rejoice,"], ["ma tuu atu lo outou faalagolago i le Atua ,", "and put your trust in God,"], ["i lena Atua o lē na fai ma Atua o Aperaamo,", "in that God who was the God of Abraham,"], ["ma Isaako,", "and Isaac,"], ["ma Iakopo;", "and Jacob;"], ["ma i lena Atua foi,", "and also,"], ["o lē na aumaia le fanauga a Isaraelu i fafo o le laueleele o Aikupito,", "that God who brought the children of Israel out of the land of Egypt,"], ["ma faia e ia ia latou savavali i totonu o le Sami Ulaula i luga o le eleele matutu,", "and caused that they should walk through the Red Sea on dry ground,"], ["ma fafaga i latou i le manai ina ia latou lē fano i le vao;", "and fed them with manna that they might not perish in the wilderness;"], ["ma le tele o isi mea na faia e ia mo i latou.", "and many more things did he do for them."]]},
  {num:20,words:[["Ma lea foi,", "And again,"], ["o lena Atua e tasi na ia aumaia o tatou tamā i fafo mai le laueleele o Ierusalema,", "that same God has brought our fathers out of the land of Jerusalem,"], ["ma ia tausia ma faasaoina ona tagata e oo mai i le taimi nei;", "and has kept and preserved his people even until now;"], ["ma faauta,", "and behold,"], ["ona o a tatou amioletonu ma mea inosia ua aumai ai i tatou e ia i le pologa.", "it is because of our iniquities and abominations that he has brought us into bondage."]]},
  {num:21,words:[["Ma o outou uma o molimau i le asō,", "And ye all are witnesses this day,"], ["o Senifa,", "that Zeniff,"], ["o lē na fai ma tupu i luga o lenei nuu,", "who was made king over this people,"], ["ona o lona soona-naunau e fai mo ona tofi le laueleele o ona tamā,", "he being over– zealous to inherit the land of his fathers,"], ["o lea na faaseseina ai o ia i le poto ma le faitogafiti o le tupu o Lamana,", "therefore being deceived by the cunning and craftiness of king Laman,"], ["o lē na faasese ia te ia ina ua uma ona faia e ia o se ioega ma le tupu o Senifa,", "who having entered into a treaty with king Zeniff,"], ["ma ina ua uma ona ia tuuina mai i ona lima le mauaina o se vaega o le laueleele,", "and having yielded up into his hands the possessions of a part of the land,"], ["po o le aai o Liae-Nifae,", "or even the city of Lehi– Nephi,"], ["ma le aai o Seloma;", "and the city of Shilom;"], ["ma le laueleele faataamilo ai—", "and the land round about—"]]},
  {num:22,words:[["Ma sa faia e ia nei mea uma, mo le faamoemoe e tasi,", "And all this he did,"], ["o le aumai lea o lenei nuu i le toilalo po o i le pologa.", "for the sole purpose of bringing this people into subjection or into bondage."], ["Ma faauta,", "And behold,"], ["o tatou i le taimi nei o loo tatou totogi atu lafoga i le tupu o sa Lamanā,", "we at this time do pay tribute to the king of the Lamanites,"], ["o le aofai o le 'afa o a tatou saga,", "to the amount of one half of our corn,"], ["ma a tatou karite,", "and our barley,"], ["ma e oo lava ia tatou kuranuma o ituaiga eseese uma, ma le 'afa e tasi o faaopoopoga o a tatou lafu ma fagaga;", "and even all our grain of every kind,"], ["ma e oo lava i le 'afa o mea uma ua ia te i tatou po o mea ua tatou maua ua faamalosia e le tupu o sa Lamanā mai ia te i tatou,", "and one half of the increase of our flocks and our herds;"], ["a leai,", "and even one half of all we have or possess the king of the Lamanites doth exact of us,"], ["o o tatou ola.", "or our lives."]]},
  {num:23,words:[["Ma o lenei,", "And now, is not this grievous to be borne? And is not this,"], ["pe ua lē faigata ea ona tatou tauaveina lenei mea? Ma ua lē tele ea lo tatou nei puapuagatia? O lenei faauta,", "our affliction,"], ["ua telē lava le pogai ua tatou faanoanoa ai.", "great? Now behold, how great reason we have to mourn."]]},
  {num:24,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua tetele lava pogai ua ia te i tatou ua tatou faanoanoa ai;", "great are the reasons which we have to mourn;"], ["aua faauta ua matua toatele lava o tatou uso ua fasiotia,", "for behold how many of our brethren have been slain,"], ["ma ua faamaligiina lē aoga o latou toto,", "and their blood has been spilt in vain,"], ["ma ua oo mai nei mea uma ona o le amioletonu.", "and all because of iniquity."]]},
  {num:25,words:[["Ona a na le pauu atu lenei nuu i le solitulafono po ua lē tuua e le Alii lenei mea leaga tele ia oo mai i o latou luga. Ae faauta,", "For if this people had not fallen into transgression the Lord would not have suffered that this great evil should come upon them. But behold,"], ["sa latou lē fia faalogo i ana afioga;", "they would not hearken unto his words;"], ["ae sa tutupu a'e finauga i totonu o i latou,", "but there arose contentions among them,"], ["sa oo lava ina matua tetele sa oo ina latou faamaligi ai le toto i totonu o i latou lava.", "even so much that they did shed blood among themselves."]]},
  {num:26,words:[["Ma sa latou fasiotia se perofeta a le Alii;", "And a prophet of the Lord have they slain;"], ["ioe,", "yea,"], ["o se tagata filifilia o le Atua,", "a chosen man of God,"], ["o lē na ia ta'u atu ia te i latou a latou amioleaga ma mea inosia,", "who told them of their wickedness and abominations,"], ["ma vavalo atu e uiga i le tele o mea o le a oo mai,", "and prophesied of many things which are to come,"], ["ioe,", "yea,"], ["le afio mai lava lea o Keriso.", "even the coming of Christ."]]},
  {num:27,words:[["Ma ona sa fai atu o ia ia te i latou o Keriso o le Atua lea,", "And because he said unto them that Christ was the God,"], ["o le Tamā o mea uma lava,", "the Father of all things,"], ["ma fai atu o le a ave e ia i ona luga foliga o le tagata,", "and said that he should take upon him the image of man,"], ["ma o foliga lava ia na foafoa faatusa i ai le tagata i le amataga;", "and it should be the image after which man was created in the beginning;"], ["po o i ni isi upu,", "or in other words,"], ["na fai mai o ia na foafoaina le tagata i foliga o le Atua ,", "he said that man was created after the image of God,"], ["ma o le a afio mai i lalo le Atua i totonu o le fanauga a tagata,", "and that God should come down among the children of men,"], ["ma ave i ona luga le tino aano ma le toto,", "and take upon him flesh and blood,"], ["ma femaliua'i i luga o le lalolagi—", "and go forth upon the face of the earth—"]]},
  {num:28,words:[["Ma o lenei,", "And now,"], ["ona sa fai atu e ia nei mea,", "because he said this,"], ["sa latou fasioti ia te ia;", "they did put him to death;"], ["ma e tele atu isi mea na latou faia na aumai ai i lalo i o latou luga le toasa o le Atua. O lea,", "and many more things did they do which brought down the wrath of God upon them. Therefore,"], ["o ai e ofo ua latou i ai i le pologa,", "who wondereth that they are in bondage,"], ["ma ua taiaina i latou i puapuaga tiga?", "and that they are smitten with sore afflictions?"]]},
  {num:29,words:[["Aua faauta,", "For behold,"], ["na fetalai mai le Alii:", "the Lord hath said:"], ["Ou te lē fesoasoani i lo'u nuu i le aso o lo latou solitulafono;", "I will not succor my people in the day of their transgression;"], ["ae o le a Ou punia o latou ala ina ia latou lē manuia;", "but I will hedge up their ways that they prosper not;"], ["ma o a latou mea e fai o le a pei o se ma'a tu'ia i o latou luma.", "and their doings shall be as a stumbling block before them."]]},
  {num:30,words:[["Ma lea foi,", "And again,"], ["ua fetalai mai o ia:", "he saith:"], ["Afai e lulu e lo'u nuu le 'eleelea o le a latou selesele mai ai ia aputi i le asiosio;", "If my people shall sow filthiness they shall reap the chaff thereof in the whirlwind;"], ["ma o lona iuga o le vai 'ona.", "and the effect thereof is poison."]]},
  {num:31,words:[["Ma sa toe fetalai mai o ia:", "And again he saith:"], ["Afai e lulu e lo'u nuu le eleelea o le a latou selesele le matagi mai sasa'e,", "If my people shall sow filthiness they shall reap the east wind,"], ["lea e aumai ai le faafanoga vave.", "which bringeth immediate destruction."]]},
  {num:32,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ua faataunuuina le folafolaga a le Alii,", "the promise of the Lord is fulfilled,"], ["ma ua outou taia ma puapuagatia.", "and ye are smitten and afflicted."]]},
  {num:33,words:[["Ae afai tou te liliu atu i le Alii ma le faamoemoe atoa o le loto,", "But if ye will turn to the Lord with full purpose of heart,"], ["ma tuu atu lo outou faalagolago ia te ia,", "and put your trust in him,"], ["ma auauna atu ia te ia ma le filiga atoa o le mafaufau,", "and serve him with all diligence of mind, if ye do this,"], ["afai tou te faia lena mea,", "he will,"], ["o le a laveaiina outou e ia e tusa ma lona lava loto ma lona finagalo,", "according to his own will and pleasure,"], ["i fafo mai le pologa.", "deliver you out of bondage."]]},
];
renderVerseSet(mo_ch_7_Verses, 'mo-ch7-verses');

var mo_ch_8_Verses = [
  {num:1,words:[["Ma sa oo ina ua uma ona faaiu e le Tupu o Limae le tautala atu i lona nuu,", "And it came to pass that after king Limhi had made an end of speaking to his people,"], ["ona e tele mea sa tautala atu ai o ia ia te i latou ma ua nao ni nai mea itiiti o ia mea ua ou tusia i lenei tusi,", "for he spake many things unto them and only a few of them have I written in this book,"], ["sa ta'u atu e ia i lona nuu mea uma e uiga i o latou uso o e sa i le laueleele o Sara'emila.", "he told his people all the things concerning their brethren who were in the land of Zarahemla."]]},
  {num:2,words:[["Ma sa faia e ia ia tulai i luga Amona i luma o le motu o tagata,", "And he caused that Ammon should stand up before the multitude,"], ["ma faamatala atu ia te i latou mea uma sa tutupu i o latou uso mai le taimi na alu ese ai Senifa i fafo mai le laueleele seia oo mai lava i le taimi na alu ese ai o ia lava i fafo mai le lauelele.", "and rehearse unto them all that had happened unto their brethren from the time that Zeniff went up out of the land even until the time that he himself came up out of the land."]]},
  {num:3,words:[["Ma sa faamatala atu foi e ia ia te i latou upu mulimuli sa aoao mai e le tupu o Peniamina ia te i latou,", "And he also rehearsed unto them the last words which king Benjamin had taught them,"], ["ma faamalamalama atu i latou i le nuu o le tupu o Limae,", "and explained them to the people of king Limhi,"], ["ina ia mafai ona latou malamalama i upu uma na tautala ai o ia.", "so that they might understand all the words which he spake."]]},
  {num:4,words:[["Ma sa oo ina ua uma ona faia e ia nei mea uma,", "And it came to pass that after he had done all this,"], ["sa oo ina faataape atu e le tupu o Limae le motu o tagata,", "that king Limhi dismissed the multitude,"], ["ma faia ia latou taitoatasi ma foi atu le tagata i lona lava fale.", "and caused that they should return every one unto his own house."]]},
  {num:5,words:[["Ma sa oo ina faia e ia ia aumai papatusi ia sa i ai le talafaamaumau o lona nuu mai le taimi na latou tuua ai le laueleele o Sara'emila,", "And it came to pass that he caused that the plates which contained the record of his people from the time that they left the land of Zarahemla,"], ["i luma o Amona,", "should be brought before Ammon,"], ["ina ia mafai ona faitau e ia.", "that he might read them."]]},
  {num:6,words:[["O lenei,", "Now,"], ["ina ua uma ona faitau e Amona le talafaamaumau,", "as soon as Ammon had read the record,"], ["sa fesili mai le tupu ia te ia i le fia iloa pe mafai ona ia faaliliu gagana,", "the king inquired of him to know if he could interpret languages,"], ["ma sa fai atu Amona ia te ia e lē mafai e ia.", "and Ammon told him that he could not."]]},
  {num:7,words:[["Ma sa fai mai le tupu ia te ia:", "And the king said unto him:"], ["Ona o lo'u faanoanoa ona o puapuaga o lo'u nuu,", "Being grieved for the afflictions of my people,"], ["na ou faia ai ia alu se malaga a se toafa sefulu ma le tolu o tagata o lo'u nuu i le vao,", "I caused that forty and three of my people should take a journey into the wilderness,"], ["ina ia mafai ona latou maua o le laueleele o Sara'emila,", "that thereby they might find the land of Zarahemla,"], ["ina ia mafai ona matou tagi atu i o matou uso e laveai i matou i fafo mai le pologa.", "that we might appeal unto our brethren to deliver us out of bondage."]]},
  {num:8,words:[["Ma sa se i latou i le vao mo le va o aso e tele,", "And they were lost in the wilderness for the space of many days,"], ["peitai sa latou filiga,", "yet they were diligent,"], ["ma sa latou lē maua le laueleele o Sara'emila ae toe foi mai i le laueleele lenei,", "and found not the land of Zarahemla but returned to this land,"], ["i le latou malaga mai lea e ala mai i se laueleele sa tele ai vai i totonu,", "having traveled in a land among many waters,"], ["ma sa latou maua ai se laueleele sa ufitia i ivi o tagata,", "having discovered a land which was covered with bones of men,"], ["ma ivi o manu,", "and of beasts,"], ["ma sa ufitia foi i toega malepelepe o fale eseese,", "and was also covered with ruins of buildings of every kind,"], ["ina ua latou maua se laueleele sa 'ainā e ni tagata sa tusa lo latou toatele ma 'au o Isaraelu.", "having discovered a land which had been peopled with a people who were as numerous as the hosts of Israel."]]},
  {num:9,words:[["Ma ina ia fai ma molimau o le moni o mea na latou fai mai ai o lea na latou aumai ai ni papatusi e lua sefulu fa ua tumu i togitogiga,", "And for a testimony that the things that they had said are true they have brought twenty– four plates which are filled with engravings,"], ["ma ua gaosia mai le auro mao'i.", "and they are of pure gold."]]},
  {num:10,words:[["Ma faauta,", "And behold,"], ["sa latou aumai foi ufifatafata ,", "also,"], ["sa tetele,", "they have brought breastplates, which are large,"], ["ma sa gaosia mai le apamemea ma le kopa,", "and they are of brass and of copper,"], ["ma sa lelei atoatoa.", "and are perfectly sound."]]},
  {num:11,words:[["O lenei foi,", "And again,"], ["sa latou aumai pelu,", "they have brought swords,"], ["o o latou 'au sa pala,", "the hilts thereof have perished,"], ["ma o o latou lau sa 'ati'atia i le ele;", "and the blades thereof were cankered with rust;"], ["ma ua leai se tasi i le nuu e mafai ona ia faaliliuina le gagana po o togitogiga ua i ai i luga o papatusi. O lea na ou fai atu ai ia te oe:", "and there is no one in the land that is able to interpret the language or the engravings that are on the plates. Therefore I said unto thee:"], ["E mafai ona e faaliliu?", "Canst thou translate?"]]},
  {num:12,words:[["Ma ou te toe fai atu ia te oe:", "And I say unto thee again:"], ["E te silafia se tasi e mafai ona ia faaliliu? Ona ou te manao e faaliliu nei talafaamaumau i la matou gagana;", "Knowest thou of any one that can translate? For I am desirous that these records should be translated into our language;"], ["ona atonu,", "for,"], ["o le a tuu mai ai ia te i matou se malamalama e uiga i se toe vaega o tagata o le nuu o e ua faaumatia,", "perhaps,"], ["na sau ai nei talafaamaumau;", "they will give us a knowledge of a remnant of the people who have been destroyed, from whence these records came;"], ["pe,", "or,"], ["atonu,", "perhaps,"], ["o le a latou tuu mai ai ia te i matou se malamalama e uiga i nei lava tagata o e ua faaumatia;", "they will give us a knowledge of this very people who have been destroyed;"], ["ma ou te fia iloa le pogai o lo latou faafanoga.", "and I am desirous to know the cause of their destruction."]]},
  {num:13,words:[["O lenei sa fai atu Amona ia te ia:", "Now Ammon said unto him:"], ["E mafai ona ou ta'u atu faamaoni ia te oe,", "I can assuredly tell thee,"], ["le tupu e,", "O king,"], ["se tagata e mafai ona faaliliu e ia talafaamaumau;", "of a man that can translate the records;"], ["ona ua ia te ia ni mea e mafai ona ia tagai i ai,", "for he has wherewith that he can look,"], ["ma faaliliu ai talafaamaumau uma mai aso anamua;", "and translate all records that are of ancient date;"], ["ma o se meaalofa mai le Atua. Ma o ia mea ua ta'ua o faaliliu upu,", "and it is a gift from God. And the things are called interpreters,"], ["ma e leai se tasi e mafai ona vaai i ia mea vagana ai ua poloaiina ai o ia,", "and no man can look in them except he be commanded,"], ["ne'i vaai o ia i mea e lē tatau ona ia vaai i ai ma fano ai o ia. Ma o soo se tasi e poloaiina e taga'i i totonu o ia mea,", "lest he should look for that he ought not and he should perish. And whosoever is commanded to look in them,"], ["o ia lava lea ua ta'ua o le tagatavāai .", "the same is called seer."]]},
  {num:14,words:[["Ma faauta,", "And behold,"], ["o le tupu o tagata o e o loo i le lauleele o Sara'emila o le tagata lea ua poloaiina na te faia ia mea,", "the king of the people who are in the land of Zarahemla is the man that is commanded to do these things,"], ["ma o lē ua i ai lenei meaalofa maualuga mai le Atua.", "and who has this high gift from God."]]},
  {num:15,words:[["Ma sa fai mai le tupu ua sili atu le tagatavāai nai lo se perofeta.", "And the king said that a seer is greater than a prophet."]]},
  {num:16,words:[["Ma sa fai atu Amona o se tagatavāai o se talifaaaliga ma o se perofeta foi;", "And Ammon said that a seer is a revelator and a prophet also;"], ["ma e leai se tagata e mafai ona ia maua se meaalofa e sili atu,", "and a gift which is greater can no man have,"], ["vagana ai ua maua e ia le mana o le Atua,", "except he should possess the power of God,"], ["e lē mafai e se tagata ona maua;", "which no man can;"], ["peitai e mafai e se tagata ona maua le mana tele e tuu mai ia te ia mai le Atua.", "yet a man may have great power given him from God."]]},
  {num:17,words:[["Ae o se tagatavāai e mafai ona iloa e ia mea ua mavae,", "But a seer can know of things which are past,"], ["ma mea foi o le a oo mai,", "and also of things which are to come,"], ["ma o le a ala mai ia te i latou ona faaali mai o mea uma lava,", "and by them shall all things be revealed,"], ["po o,", "or,"], ["lona uiga,", "rather,"], ["o le a faaali mai ai mealilo,", "shall secret things be made manifest,"], ["ma o le a faamalamalama mai ai mea ua natia,", "and hidden things shall come to light,"], ["ma o mea ua lē iloa o le a faailoa mai e i latou,", "and things which are not known shall be made known by them,"], ["ma o le a faailoa mai foi e i latou mea semanu e lē mafai ona faailoa mai.", "and also things shall be made known by them which otherwise could not be known."]]},
  {num:18,words:[["Ua faapea ona saunia e le Atua se ala e mafai ona faia ai e le tagata vavega tetele,", "Thus God has provided a means that man,"], ["e ala i le faatuatua;", "through faith, might work mighty miracles;"], ["o lea e avea ai o ia ma manuia tele i ona uso-a-tagata.", "therefore he becometh a great benefit to his fellow beings."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["ina ua faai'u e Amona le tautala atu i nei upu sa olioli tele le tupu,", "when Ammon had made an end of speaking these words the king rejoiced exceedingly,"], ["ma faafetai atu i le Atua,", "and gave thanks to God,"], ["ua fai mai:", "saying:"], ["E le masalogia ua i ai se mealilo tele i totonu o nei papatusi,", "Doubtless a great mystery is contained within these plates,"], ["ma e lē masalogia sa saunia nei faaliliu upu mo le faamoemoe o le fofolaina mai o mealilo uma faapea i le fanauga a tagata.", "and these interpreters were doubtless prepared for the purpose of unfolding all such mysteries to the children of men."]]},
  {num:20,words:[["E,", "O how marvelous are the works of the Lord,"], ["ua matua ofoofogia lava galuega a le Alii,", "and how long doth he suffer with his people;"], ["ma ua matua loa lava lona tautiga mo ona tagata; ioe,", "yea,"], ["ma ua matua tauaso lava ma lē maulufia le malamalamaaga o le fanauga a tagata;", "and how blind and impenetrable are the understandings of the children of men;"], ["ona latou te lē saili le poto,", "for they will not seek wisdom,"], ["pe latou te mananao foi e pulea i latou e le poto.", "neither do they desire that she should rule over them!"]]},
  {num:21,words:[["Ioe,", "Yea,"], ["ua pei i latou o se lafu 'aivao ua sosola ese mai le leoleo mamoe,", "they are as a wild flock which fleeth from the shepherd,"], ["ma taapeape,", "and scattereth,"], ["ma ua tulia,", "and are driven,"], ["ma ua 'aia e manu feai o le vao.", "and are devoured by the beasts of the forest."]]},
];
renderVerseSet(mo_ch_8_Verses, 'mo-ch8-verses');

var mo_ch_9_Verses = [
  {num:1,words:[["O A'U,", "I,"], ["o Senifa,", "Zeniff,"], ["ona sa aoaoina a'u i le gagana uma sa Nifaē,", "having been taught in all the language of the Nephites,"], ["ma ona sa ia te a'u se malamalama e uiga i le laueleele o Nifae, po o le laueleele o le tofi muamua o o matou tamā,", "and having had a knowledge of the land of Nephi,"], ["ma ona sa auina atu a'u o se sipai i totonu o sa Lamanā ina ia mafai ona ou sipai a latou autau,", "or of the land of our fathers’ first inheritance,"], ["ina ia mafai ona o mai a matou autau i o latou luga ma faaumatia i latou—peitai ina ua ou vaai i mea lelei sa i ai i totonu o i latou,", "and having been sent as a spy among the Lamanites that I might spy out their forces,"], ["sa ou manao ia lē faaumatiaina i latou.", "that our army might come upon them and destroy them—but when I saw that which was good among them I was desirous that they should not be destroyed."]]},
  {num:2,words:[["O lea,", "Therefore,"], ["na ou finau ai ma o'u uso i le vao,", "I contended with my brethren in the wilderness for I would that our ruler should make a treaty with them;"], ["ona sa ou manao ia faia e lo matou pule se feagaiga ma i latou;", "but he being an austere and a bloodthirsty man commanded that I should be slain;"], ["ae ona o ia o se tagata sauā ma fia faamasaatoto o lea na faatonu ai e ia ia fasiotia a'u;", "but I was rescued by the shedding of much blood;"], ["peitai sa laveaiina a'u e ala i le faamasaatoto tele;", "for father fought against father,"], ["ona sa tau le tamā faasaga i le tamā, ma le uso faasaga i le uso,", "and brother against brother,"], ["seia oo ina faaumatia ai le vaega tele o la matou autau i le vao;", "until the greater number of our army was destroyed in the wilderness;"], ["ma sa matou toe foi mai,", "and we returned,"], ["i matou ia o e na totoe,", "those of us that were spared,"], ["i le laueleele o Sara'emila,", "to the land of Zarahemla,"], ["e ta'u atu lena tala ia latou avā ma a latou fanau.", "to relate that tale to their wives and their children."]]},
  {num:3,words:[["Ma e ui i lea,", "And yet,"], ["ona o lo'u soona-naunau tele i le fia fai mo o'u tofi le laueleele o o matou tamā,", "I being over– zealous to inherit the land of our fathers,"], ["o lea na ou faapotopoto ai le toatele o i latou o e na mananao e o a'e e nonofo i le laueleele,", "collected as many as were desirous to go up to possess the land,"], ["ma toe amata la matou malaga i le vao matou te o a'e ai i le laueleele;", "and started again on our journey into the wilderness to go up to the land;"], ["peitai sa taia i matou i le oge ma puapuaga tiga;", "but we were smitten with famine and sore afflictions;"], ["ona sa gese ona matou manatua o le Alii lo matou Atua.", "for we were slow to remember the Lord our God."]]},
  {num:4,words:[["E ui i lea,", "Nevertheless,"], ["ina ua mavae aso e tele o le fesēa'i i le vao sa matou faatutu o matou faleie i le nofoaga lea sa fasiotia ai o matou uso,", "after many days’ wandering in the wilderness we pitched our tents in the place where our brethren were slain,"], ["lea sa latalata i le laueleele o o matou tamā.", "which was near to the land of our fathers."]]},
  {num:5,words:[["Ma sa oo ina ou toe alu atu i le aai faatasi ma ni a'u tagata e toafa,", "And it came to pass that I went again with four of my men into the city,"], ["i le tupu,", "in unto the king,"], ["ina ia mafai ona ou iloa uiga o le tupu,", "that I might know of the disposition of the king,"], ["ma ina ia mafai ona ou iloa pe mafai ona ou alu atu i totonu faatasi ma o'u tagata ma fai mo matou le laueleele i le filemu.", "and that I might know if I might go in with my people and possess the land in peace."]]},
  {num:6,words:[["Ma sa ou alu atu i totonu i le tupu,", "And I went in unto the king,"], ["ma sa osifeagaiga o ia ma a'u e mafai ona fai mo a'u le laueleele o Liae-Nifae,", "and he covenanted with me that I might possess the land of Lehi– Nephi,"], ["ma le laueleele o Seloma.", "and the land of Shilom."]]},
  {num:7,words:[["Ma sa poloai atu foi o ia ia o ese atu i fafo tagata o lona nuu mai le laueleele, ma sa matou o atu loa,", "And he also commanded that his people should depart out of the land,"], ["o a'u ma o'u tagata, i le laueleele, ina ia mafai ona matou mauaina.", "and I and my people went into the land that we might possess it."]]},
  {num:8,words:[["Ma sa amata ona matou fausia o fale,", "And we began to build buildings,"], ["ma toe fai faalelei pa o le aai,", "and to repair the walls of the city,"], ["ioe,", "yea,"], ["o pa lava ia o le aai o Liae-Nifae,", "even the walls of the city of Lehi– Nephi,"], ["ma le aai o Seloma.", "and the city of Shilom."]]},
  {num:9,words:[["Ma sa amata ona matou galueaiina le eleele,", "And we began to till the ground,"], ["ioe,", "yea,"], ["i ituaiga uma o fatu,", "even with all manner of seeds,"], ["o fatu o saga,", "with seeds of corn,"], ["ma o saito,", "and of wheat,"], ["ma o karite,", "and of barley,"], ["ma nea,", "and with neas,"], ["ma seuma,", "and with sheum,"], ["ma fatu o laau 'aina o ituaiga eseese uma;", "and with seeds of all manner of fruits;"], ["ma sa amata ona matou fanafanau ma manuia i le laueleele.", "and we did begin to multiply and prosper in the land."]]},
  {num:10,words:[["O lenei o le poto ma le faitogafiti o le tupu o Lamana,", "Now it was the cunning and the craftiness of king Laman,"], ["e aumai ai lo'u nuu i le pologa,", "to bring my people into bondage,"], ["na tuu mai ai e ia le laueleele ina ia mafai ona matou mauaina.", "that he yielded up the land that we might possess it."]]},
  {num:11,words:[["O lea sa oo ina ua mavae ona matou nonofo i le laueleele mo le va o tausaga e sefulu ma le lua sa amata ona popole o le tupu o Lamana,", "Therefore it came to pass,"], ["ne'i solo tutupu malolosi a'e lo'u nuu i le laueleele,", "that after we had dwelt in the land for the space of twelve years that king Laman began to grow uneasy, lest by any means my people should wax strong in the land,"], ["ma lē mafai ai ona latou faatoilalo o i latou ma aumai i latou i le pologa.", "and that they could not overpower them and bring them into bondage."]]},
  {num:12,words:[["O lenei o i latou o ni tagata sa paie ma ifo i tupua;", "Now they were a lazy and an idolatrous people;"], ["o lea sa latou mananao ai e aumai i matou i le pologa,", "therefore they were desirous to bring us into bondage,"], ["ina ia mafai ai ona latou ola faaatuatuvale i galuega a o matou lima;", "that they might glut themselves with the labors of our hands;"], ["ioe,", "yea,"], ["ina ia mafai ai ona latou aai fiafia i lafu o o matou fanua.", "that they might feast themselves upon the flocks of our fields."]]},
  {num:13,words:[["O lea sa oo ai ina amata e le tupu o Lamana ona faaoso ona tagata ia latou finau ma o'u tagata;", "Therefore it came to pass that king Laman began to stir up his people that they should contend with my people;"], ["o lea na amata ai ona i ai o taua ma finauga i le laueleele.", "therefore there began to be wars and contentions in the land."]]},
  {num:14,words:[["Ona,", "For,"], ["i le sefulu tolu o tausaga o la'u nofoaiga i le nuu o Nifae,", "in the thirteenth year of my reign in the land of Nephi,"], ["a'o faainu ma fafaga e o'u tagata a latou lafu manu,", "away on the south of the land of Shilom,"], ["i le itu mamao i saute o le nuu o Seloma,", "when my people were watering and feeding their flocks,"], ["ma galueaiina o latou fanua,", "and tilling their lands,"], ["na o mai ai se autau toatele a sa Lamanā i luga o i latou ma amata ona fasioti i latou,", "a numerous host of Lamanites came upon them and began to slay them,"], ["ma ave a latou lafu,", "and to take off their flocks,"], ["ma saga o a latou faatoaga.", "and the corn of their fields."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["ma sa oo ina latou sosola,", "and it came to pass that they fled,"], ["i latou uma ia sa lei maua,", "all that were not overtaken,"], ["seia oo mai i le aai o Nifae,", "even into the city of Nephi,"], ["ma latou tagi mai ai ia te a'u mo se puipuiga.", "and did call upon me for protection."]]},
  {num:16,words:[["Ma sa oo ina 'ou faa'auupegaina i latou i aufana,", "And it came to pass that I did arm them with bows,"], ["ma ufanafana,", "and with arrows,"], ["ma pelu,", "with swords,"], ["ma simetea,", "and with cimeters,"], ["ma uatogi,", "and with clubs,"], ["ma ma'ata,", "and with slings,"], ["ma au'upega ituaiga eseese uma sa mafai ona matou faia,", "and with all manner of weapons which we could invent,"], ["ma o a'u ma lo'u nuu sa matou o atu loa e tau faasaga i sa Lamanā.", "and I and my people did go forth against the Lamanites to battle."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["sa matou o atu i le malosi o le Alii e tau faasaga i sa Lamanā;", "in the strength of the Lord did we go forth to battle against the Lamanites;"], ["ona o a'u ma lo'u nuu sa matou tagi malosi atu i le Alii ina ia laveai e ia i matou mai lima o o matou fili;", "for I and my people did cry mightily to the Lord that he would deliver us out of the hands of our enemies,"], ["ona sa fagua i matou i le manatuaina o le laveaiga o o matou tamā.", "for we were awakened to a remembrance of the deliverance of our fathers."]]},
  {num:18,words:[["Ma sa faafofoga mai le Atua ia matou tagi ma sa tali mai ia matou tatalo;", "And God did hear our cries and did answer our prayers;"], ["ma sa matou o atu i lona malosi;", "and we did go forth in his might;"], ["ioe,", "yea,"], ["sa matou o atu e faasaga ia sa Lamanā,", "we did go forth against the Lamanites,"], ["ma sa matou fasiotia i le aso e tasi ma le po e tasi le tolu afe ma le fa sefulu ma le tolu;", "and in one day and a night we did slay three thousand and forty– three;"], ["sa matou fasiotia i latou seia oo ina matou tutuliese i latou i fafo o lo matou laueleele.", "we did slay them even until we had driven them out of our land."]]},
  {num:19,words:[["Ma o a'u,", "And I,"], ["i o'u lava lima,", "myself, with mine own hands,"], ["sa ou fesoasoani e tanu o latou tagata oti.", "did help to bury their dead."], ["Ae faauta,", "And behold,"], ["sa ia te i matou le faanoanoa tele ma le tagiauē,", "to our great sorrow and lamentation,"], ["i le lua selau fitu sefulu ma le iva o o matou uso sa fasiotia.", "two hundred and seventy nine of our brethren were slain."]]},
];
renderVerseSet(mo_ch_9_Verses, 'mo-ch9-verses');

var mo_ch_10_Verses = [
  {num:1,words:[["Ma sa oo ina amata ona matou toe faatumauina le malo ma amata ona matou toe mauaina o le laueleele i le filemu. Ma sa ou faia ia tatau ona i ai ni auupega ituaiga eseese o taua e faia,", "And it came to pass that we again began to establish the kingdom and we again began to possess the land in peace. And I caused that there should be weapons of war made of every kind,"], ["ina ia mafai ona ou maua o ni auupega mo lo'u nuu auā le taimi e toe o mai ai sa Lamanā e faasagatau mai i lo'u nuu.", "that thereby I might have weapons for my people against the time the Lamanites should come up again to war against my people."]]},
  {num:2,words:[["Ma sa ou tuu ni leoleo faataamilo i le laueleele,", "And I set guards round about the land,"], ["ina ia lē toe o mai sa Lamanā ia te i matou e aunoa ma le iloa ma faaumatia i matou;", "that the Lamanites might not come upon us again unawares and destroy us;"], ["ma sa faapea ona ou leoleoina o lo'u nuu ma a'u lafu,", "and thus I did guard my people and my flocks,"], ["ma taofi i latou mai le pauu atu i lima o o matou fili.", "and keep them from falling into the hands of our enemies."]]},
  {num:3,words:[["Ma sa oo ina matou faia mo o matou tofi le laueleele o o matou tamā mo le tele o tausaga,", "And it came to pass that we did inherit the land of our fathers for many years,"], ["ioe,", "yea,"], ["mo le va o tausaga e lua sefulu ma le lua.", "for the space of twenty and two years."]]},
  {num:4,words:[["Ma sa ou faia e tatau i tane ona galueaiina le eleele,", "And I did cause that the men should till the ground,"], ["ma toto ituaiga uma o kuranuma ma fatu o laau 'aina o ituaiga eseese uma.", "and raise all manner of grain and all manner of fruit of every kind."]]},
  {num:5,words:[["Ma sa ou faia e tatau i fafine ona lagafilo,", "And I did cause that the women should spin,"], ["ma toaaga,", "and toil,"], ["ma galulue,", "and work,"], ["ma faia ituaiga uma o ie lino lelei,", "and work all manner of fine linen,"], ["ioe,", "yea,"], ["ma ie o ituaiga eseese uma,", "and cloth of every kind,"], ["ina ia mafai ona matou faaofuina lo matou lē lavalava;", "that we might clothe our nakedness;"], ["ma sa faapea ona matou manuia i le laueleele—sa faapea ona matou maua o le filemu e lē aunoa i le laueleele mo le va o le lua sefulu ma le lua tausaga.", "and thus we did prosper in the land—thus we did have continual peace in the land for the space of twenty and two years."]]},
  {num:6,words:[["Ma sa oo ina oti le tupu o Lamana ,", "And it came to pass that king Laman died,"], ["ma sa amata ona nofotupu lona atalii e suitulaga ia te ia. Ma sa amata ona faaoso e ia ona tagata i le fouvale faasaga mai i lo'u nuu;", "and his son began to reign in his stead. And he began to stir his people up in rebellion against my people;"], ["o lea na amata ai ona latou sauni mo taua,", "therefore they began to prepare for war,"], ["ma o mai e tau e faasaga mai i lo'u nuu.", "and to come up to battle against my people."]]},
  {num:7,words:[["Peitai sa ou auina atu a'u sipai faataamilo i le laueleele o Semulona ,", "But I had sent my spies out round about the land of Shemlon,"], ["ina ia mafai ona ou iloa a latou sauniuniga,", "that I might discover their preparations,"], ["ina ia mafai ona ou puipui faasaga ia te i latou,", "that I might guard against them,"], ["ina ia lē mafai ona latou o mai i lo'u nuu ma faaumatia i latou.", "that they might not come upon my people and destroy them."]]},
  {num:8,words:[["Ma sa oo ina latou o a'e i luga i le itu i matu o le laueleele o Seloma,", "And it came to pass that they came up upon the north of the land of Shilom,"], ["ma a latou autau e toatele,", "with their numerous hosts,"], ["o tane ua faaauupega i aufana ,", "men armed with bows,"], ["ma ufanafana,", "and with arrows,"], ["ma pelu,", "and with swords,"], ["ma simetea,", "and with cimeters,"], ["ma ma'a,", "and with stones,"], ["ma ma'ata;", "and with slings;"], ["ma sa latou tafi o latou ulu sa popoo i latou;", "and they had their heads shaved that they were naked;"], ["ma sa latou sulu i se fusi pa'u manu sa sulu faataamilo i o latou sulugatiti.", "and they were girded with a leathern girdle about their loins."]]},
  {num:9,words:[["Ma sa oo ina ou faia ia tatau ona faalalafi fafine ma tamaiti o lo'u nuu i le vao;", "And it came to pass that I caused that the women and children of my people should be hid in the wilderness;"], ["ma sa ou faia foi e tatau i a'u alii matutua uma o e e mafai ona faaaoga se auupega tau,", "and I also caused that all my old men that could bear arms,"], ["ma a'u alii talavou uma o e e mafai ona faaaoga se auupega tau,", "and also all my young men that were able to bear arms,"], ["ona latou faapotopoto faatasi i latou lava e o atu e faasagatau ia sa Lamanā;", "should gather themselves together to go to battle against the Lamanites;"], ["ma sa ou faatutu i latou i o latou tulaga,", "and I did place them in their ranks,"], ["o tagata taitoatasi e tusa ma ona tausaga.", "every man according to his age."]]},
  {num:10,words:[["Ma sa oo ina matou o atu e faasagatau ia sa Lamanā;", "And it came to pass that we did go up to battle against the Lamanites;"], ["ma o a'u,", "and I,"], ["e oo ia te a'u,", "even I,"], ["i o'u tausaga matua,", "in my old age,"], ["sa ou alu atu e faasagatau ia sa Lamanā.", "did go up to battle against the Lamanites."], ["Ma sa oo ina matou o a'e i le malosi o le Alii, e tau.", "And it came to pass that we did go up in the strength of the Lord to battle."]]},
  {num:11,words:[["O lenei,", "Now,"], ["sa le iloa e sa Lamanā se mea e uiga i le Alii,", "the Lamanites knew nothing concerning the Lord,"], ["po o le malosi o le Alii,", "nor the strength of the Lord,"], ["o lea sa latou faalagolago ai i lo latou lava malosi. Peitai o i latou o ni tagata malolosi,", "therefore they depended upon their own  strength. Yet they were a strong people,"], ["e tusa ma le malolosi o tagata.", "as to the strength of men."]]},
  {num:12,words:[["Sa avea i latou o ni tagata 'aivao ,", "They were a wild,"], ["ma fe'ai,", "and ferocious,"], ["ma le fia faamasaatoto,", "and a blood– thirsty people,"], ["ua talitonu i uputuu a o latou tamā,", "believing in the tradition of their fathers,"], ["e faapenei—Ua latou talitonu na tutuli ese i latou i fafo mai le laueleele o Ierusalema ona o amioletonu a o latou tamā;", "which is this—Believing that they were driven out of the land of Jerusalem because of the iniquities of their fathers,"], ["ma e faapea sa agaleagaina i latou i le vao e o latou uso,", "and that they were wronged in the wilderness by their brethren,"], ["ma sa agaleagaina foi i latou a'o latou sopoia le sami;", "and they were also wronged while crossing the sea;"]]},
  {num:13,words:[["Ma lea foi,", "And again,"], ["e faapea sa agaleagaina i latou a'o latou i ai i le laueleele o lo latou tofi muamua,", "that they were wronged while in the land of their first inheritance,"], ["ina ua mavae ona latou sopoia mai o le sami,", "after they had crossed the sea,"], ["ma o nei mea uma na faia ona e faapea sa sili atu le faamaoni o Nifae i le tausiga o poloaiga a le Alii—o lea na faapitoa ai o ia e le Alii,", "and all this because that Nephi was more faithful in keeping the command– ments of the Lord—therefore he was favored of the Lord,"], ["ona e faapea sa faafofoga mai le Alii i ana tatalo ma tali i latou,", "for the Lord heard his prayers and answered them,"], ["ma ave ai e ia le taitaiga o la latou malaga i le vao.", "and he took the lead of their journey in the wilderness."]]},
  {num:14,words:[["Ma e faapea sa feitai ona uso ia te ia ona sa latou lē malamalama i alofa'iga a le Alii;", "And his brethren were wroth with him because they understood not the dealings of the Lord;"], ["ma e faapea sa latou feitai foi ia te ia i luga o vai ona sa latou faamaaa o latou loto e faasaga i le Alii.", "they were also wroth with him upon the waters because they hardened their hearts against the Lord."]]},
  {num:15,words:[["Ma lea foi,", "And again,"], ["e faapea sa latou feitai ia te ia ina ua latou taunuu i le laueleele na folafolaina,", "they were wroth with him when they had arrived in the promised land,"], ["ona sa latou fai mai ua fao e ia le pulega o le nuu mai o latou lima;", "because they said that he had taken the ruling of the people out of their hands;"], ["ma ua latou saili e fasioti ia te ia.", "and they sought to kill him."]]},
  {num:16,words:[["O lenei foi,", "And again,"], ["e faapea sa latou feitai ia te ia ona ua alu ese atu o ia i le vao e pei ona sa poloaiina ai o ia e le Alii,", "they were wroth with him because he departed into the wilderness as the Lord had commanded him,"], ["ma ave talafaamaumau sa togitogia i luga o papatusi apamemea,", "and took the records which were engraven on the plates of brass,"], ["ona sa latou fai mai ua gaoia e i latou.", "for they said that he robbed them."]]},
  {num:17,words:[["Ma ua faapea ona latou aoao a latou fanau ia latou feitai ia te i latou,", "And thus they have taught their children that they should hate them,"], ["ma ia latou fasioti ia te i latou,", "and that they should murder them,"], ["ma ia latou gaoi ma fao faamalosi mai ia te i latou,", "and that they should rob and plunder them,"], ["ma fai mea uma e mafai ona latou faia e faaumatia ai i latou;", "and do all they could to destroy them;"], ["o lea ua ala ai ona i ai ia te i latou se ita e faavavau i le fanau a Nifae.", "therefore they have an eternal hatred towards the children of Nephi."]]},
  {num:18,words:[["O lenei lava le pogai na 'olegia ai a'u e le tupu o Lamana,", "For this very cause has king Laman,"], ["i lona poto,", "by his cunning,"], ["ma le faitogafiti pepelo,", "and lying craftiness,"], ["ma ana folafolaga logomalie,", "and his fair promises,"], ["ia ou aumai ai lo'u nuu nei i le laueleele lenei,", "deceived me, that I have brought this my people up into this land,"], ["ina ia mafai ona latou faaumatia ai o i latou;", "that they may destroy them;"], ["ioe,", "yea,"], ["ma ua matou mafatia i le tele o nei tausaga i le laueleele.", "and we have suffered these many years in the land."]]},
  {num:19,words:[["Ma o lenei o a'u,", "And now I,"], ["o Senifa,", "Zeniff,"], ["ina ua uma ona ou ta'u atu o nei mea uma i lo'u nuu e uiga ia sa Lamanā,", "after having told all these things unto my people concerning the Lamanites,"], ["sa ou tomatauina i latou e o atu e tau ma lo latou malosi,", "I did stimulate them to go to battle with their might,"], ["ma tuu atu lo latou faalagolago i le Alii;", "putting their trust in the Lord;"], ["o lea,", "therefore,"], ["sa matou tau ai ma i latou,", "we did contend with them,"], ["faafesagai lava.", "face to face."]]},
  {num:20,words:[["Ma sa oo ina matou toe tutuli i latou i fafo o lo matou laueleele;", "And it came to pass that we did drive them again out of our land;"], ["ma sa matou fasia i latou i se fasiga tele,", "and we slew them with a great slaughter,"], ["sa matua toatele lava sa matou lē faitauina i latou.", "even so many that we did not number them."]]},
  {num:21,words:[["Ma sa oo ina matou toe foi mai i lo matou lava laueleele,", "And it came to pass that we returned again to our own land,"], ["ma sa amata e lo'u nuu ona toe tausia a latou lafu,", "and my people again began to tend their flocks,"], ["ma galueaiina o latou eleele.", "and to till their ground."]]},
  {num:22,words:[["Ma o lenei ona o a'u,", "And now I,"], ["ua ou toeaina,", "being old,"], ["sa ou faaee atu le malo i se tasi o o'u atalii;", "did confer the kingdom upon one of my sons;"], ["o lea,", "therefore,"], ["ou te lē toe fai atu se isi upu. Ma talosia ia faamanuia mai le Alii i lo'u nuu. Amene.", "I say no more. And may the Lord bless my people. Amen."]]},
];
renderVerseSet(mo_ch_10_Verses, 'mo-ch10-verses');

var mo_ch_11_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina faaee e Senifa le malo i luga o Noa,", "And now it came to pass that Zeniff conferred the kingdom upon Noah,"], ["o se tasi o ona atalii;", "one of his sons;"], ["o lea na amata ai ona nofotupu o Noa i lona tulaga;", "therefore Noah began to reign in his stead;"], ["ma sa lē savali o ia i ala o lona tamā.", "and he did not walk in the ways of his father."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["sa lē tausia e ia poloaiga a le Atua,", "he did not keep the command– ments of God,"], ["ae sa savali o ia e tusa ma manaoga o lona lava loto. Ma sa i ai ia te ia ni avā e toatele ma palake . Ma sa faia e ia ia fai e lona nuu le agasala,", "but he did walk after the desires of his own heart. And he had many wives and concubines. And he did cause his people to commit sin,"], ["ma fai mea ua inosia i le silafaga a le Alii. Ioe,", "and do that which was abominable in the sight of the Lord. Yea,"], ["ma sa latou faia le faitaaga ma ituaiga uma o amioleaga eseese.", "and they did commit whoredoms and all manner of wicked– ness."]]},
  {num:3,words:[["Ma sa faataatia e ia se lafoga o le tasi vaelima o mea uma ua latou maua,", "And he laid a tax of one fifth part of all they possessed,"], ["o le tasi vaelima o a latou auro ma a latou ario,", "a fifth part of their gold and of their silver,"], ["ma le tasi vaelima o a latou sifa ,", "and a fifth part of their ziff,"], ["ma a latou kopa, ma a latou apamemea,", "and of their copper,"], ["ma a latou u'amea;", "and of their brass and their iron;"], ["ma le tasi vaelima o a latou manu pepeti;", "and a fifth part of their fatlings;"], ["ma le tasi vaelima foi o a latou kuranuma uma.", "and also a fifth part of all their grain."]]},
  {num:4,words:[["Ma sa ave e ia nei mea uma e tausi ai o ia lava,", "And all this did he take to support himself,"], ["ma ana avā ma ana palake;", "and his wives and his concubines;"], ["ma ana faitaulaga foi,", "and also his priests,"], ["ma a latou avā ma a latou palake;", "and their wives and their concubines;"], ["ma sa faapea ona sui e ia mataupu o le malo.", "thus he had changed the affairs of the kingdom."]]},
  {num:5,words:[["Ona sa ia tuu i lalo faitaulaga uma na faapaia e lona tamā,", "For he put down all the priests that had been consecrated by his father,"], ["ma ia faapaia ni faitaulaga fou e sui i o latou tulaga,", "and consecrated new ones in their stead,"], ["e i ai i latou sa faafefeteina i le faamaualuluga o o latou loto.", "such as were lifted up in the pride of their hearts."]]},
  {num:6,words:[["Ioe,", "Yea,"], ["ma sa faapea ona tausia o i latou i lo latou paie,", "and thus they were supported in their laziness,"], ["ma lo latou ifo i tupua,", "and in their idolatry,"], ["ma lo latou faitaaga,", "and in their whoredoms,"], ["i lafoga na tuu e le tupu o Noa i luga o lona nuu;", "by the taxes which king Noah had put upon his people;"], ["sa faapea ona galulue malolosi ai o le nuu e lagolago le amioletonu.", "thus did the people labor exceedingly to support iniquity."]]},
  {num:7,words:[["Ioe,", "Yea,"], ["ma sa oo foi ina avea i latou ma tagata ifo i tupua,", "and they also became idolatrous,"], ["ona ua faaseseina i latou i upu lē aoga ma taufaasee a le tupu ma ana faitaulaga;", "because they were deceived by the vain and flattering words of the king and priests;"], ["ona sa latou tautala atu mea taufaasee ia te i latou.", "for they did speak flattering things unto them."]]},
  {num:8,words:[["Ma sa oo ina fausia e le tupu o Noa ni fale mata'ina ma ateatea e tele;", "And it came to pass that king Noah built many elegant and spacious buildings;"], ["ma sa ia teuteuina i galuega taulima matagofie o laau,", "and he ornamented them with fine work of wood,"], ["ma ituaiga uma o mea taugata,", "and of all manner of precious things,"], ["o le auro,", "of gold,"], ["ma le ario,", "and of silver,"], ["ma le uamea,", "and of iron,"], ["ma le apamamea,", "and of brass,"], ["ma le sifa,", "and of ziff,"], ["ma le kopa.", "and of copper;"]]},
  {num:9,words:[["Ma sa ia fausia foi se maota ateatea mo ia lava,", "And he also built him a spacious palace,"], ["ma se nofoalii i lona totonugalemu,", "and a throne in the midst thereof,"], ["o nei mea uma sa fai mai i laau lelei ma sa teuteu i le auro ma le ario ma mea taugata.", "all of which was of fine wood and was ornamented with gold and silver and with precious things."]]},
  {num:10,words:[["Ma sa faia foi e ia ia faia e ana tagata faigaluega ituaiga uma o galuega lelei eseese i totonu o pa o le malumalu,", "And he also caused that his workmen should work all manner of fine work within the walls of the temple,"], ["i laau lelei,", "of fine wood,"], ["ma i le kopa,", "and of copper,"], ["ma i le apamemea.", "and of brass."]]},
  {num:11,words:[["Ma o nofoa sa faatutu ese mo faitaulaga sili,", "And the seats which were set apart for the high priests,"], ["ia sa faatutu maualuga a'e i lo o isi nofoa uma,", "which were above all the other seats,"], ["sa teuteu e ia i le auro mao'i;", "he did ornament with pure gold;"], ["ma sa faia e ia ia fai se pafatafata i o latou luma,", "and he caused a breastwork to be built before them,"], ["ina ia mafai ona faalagolago i ai i luga o latou tino ma o latou lima a'o latou tautala atu i upu pepelo ma lē aoga i lona nuu.", "that they might rest their bodies and their arms upon  while they should speak lying and vain words to his people."]]},
  {num:12,words:[["Ma sa oo ina fausia e ia se olo latalata i le malumalu;", "And it came to pass that he built a tower near the temple;"], ["ioe,", "yea,"], ["o se olo maualuga lava,", "a very high tower,"], ["sa matua maualuga tele lava sa mafai ona tu ai o ia i ona luga ma vaai atu i le laueleele o Seloma,", "even so high that he could stand upon the top thereof and overlook the land of Shilom,"], ["ma le laueleele foi o Semulona,", "and also the land of Shemlon,"], ["ia sa maua e sa Lamanā;", "which was possessed by the Lamanites;"], ["ma sa mafai foi ona vaai atu ai o ia i le laueleele atoa faataamilo.", "and he could even look over all the land round about."]]},
  {num:13,words:[["Ma sa oo ina faia e ia ia fausia ni fale e tele i le laueleele o Seloma;", "And it came to pass that he caused many buildings to be built in the land Shilom;"], ["ma sa faia e ia ia fausia se olo tele i luga o le maupu'epu'e i matu o le laueleele o Seloma,", "and he caused a great tower to be built on the hill north of the land Shilom,"], ["lea sa fai ma mapusaga mo le fanau a Nifae i le taimi na latou sosola ese ai i fafo mai le laueleele;", "which had been a resort for the children of Nephi at the time they fled out of the land;"], ["ma sa faapea ona faia e ia i 'oa na ia maua mai i lafoga a lona nuu.", "and thus he did do with the riches which he obtained by the taxation of his people."]]},
  {num:14,words:[["Ma sa oo ina tuu atu e ia lona loto i ana 'oa,", "And it came to pass that he placed his heart upon his riches,"], ["ma ia faaalu lona taimi i le olaga faasoesā faatasi ma ana avā ma ana palake;", "and he spent his time in riotous living with his wives and his concubines;"], ["ma sa faapea foi ona faaalu e ana faitaulaga o latou taimi ma fafine talitane.", "and so did also his priests spend their time with harlots."]]},
  {num:15,words:[["Ma sa oo ina toto e ia tovine faataamilo i le laueleele;", "And it came to pass that he planted vineyards round about in the land;"], ["ma sa fausia e ia soli-uaina,", "and he built wine– presses,"], ["ma faia le uaina tele;", "and made wine in abundance;"], ["ma o lea na avea ai o ia ma se tagata-inuuaina tele,", "and therefore he became a wine– bibber,"], ["ma sa faapea foi lona nuu.", "and also his people."]]},
  {num:16,words:[["Ma sa oo ina amata ona o mai o sa Lamanā i luga o lona nuu,", "And it came to pass that the Lamanites began to come in upon his people,"], ["i luga o vaega toaitiiti o tagata,", "upon small numbers,"], ["ma fasioti i latou i o latou fanua,", "and to slay them in their fields,"], ["a'o latou leoleo a latou lafu.", "and while they were tending their flocks."]]},
  {num:17,words:[["Ma sa auina atu e le tupu o Noa leoleo faataamilo i le laueleele e taofi ese i latou;", "And king Noah sent guards round about the land to keep them off;"], ["peitai sa lē lava le toatele o e na auina atu e ia,", "but he did not send a sufficient number,"], ["ma sa o mai sa Lamanā i o latou luga ma fasioti i latou,", "and the Lamanites came upon them and killed them,"], ["ma tutuli le tele o a latou lafu i fafo mai le laueleele;", "and drove many of their flocks out of the land;"], ["sa faapea ona amata e sa Lamanā ona faaumatia o i latou,", "thus the Lamanites began to destroy them,"], ["ma faaoo lo latou ita i luga o i latou.", "and to exercise their hatred upon them."]]},
  {num:18,words:[["Ma sa oo ina auina atu e le tupu o Noa ana autau e faasaga atu ia te i latou,", "And it came to pass that king Noah sent his armies against them,"], ["ma sa latou tutuli i latou i tua,", "and they were driven back,"], ["pe sa latou tutuli i latou i tua mo se taimi;", "or they drove them back for a time;"], ["o lea,", "therefore,"], ["na latou foi mai ai ma le olioli ia latou vete o le taua.", "they returned rejoicing in their spoil."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["ona o lenei manumalo tele,", "because of this great victory they were lifted up in the pride of their hearts;"], ["sa faafefeteina i latou i le faamaualuluga o o latou loto;", "they did boast in their own strength,"], ["sa latou mitamitavale i lo latou lava malosi,", "saying that their fifty could stand against thousands of the Lamanites;"], ["fai mai e mafai e lo latou toalimagafulu ona tutū faasaga atu i le afe ma afe o sa Lamanā; ma sa faapena ona latou mitamitavale,", "and thus they did boast,"], ["ma fiafia i le toto,", "and did delight in blood,"], ["ma le faamasaaina o le toto o o latou uso,", "and the shedding of the blood of their brethren,"], ["ma o lenei ona o le amioleaga o lo latou tupu ma o latou faitaulaga.", "and this because of the wickedness of their king and priests."]]},
  {num:20,words:[["Ma sa oo ina sa i ai i totonu o i latou se tagata o lona igoa o Apinati ;", "And it came to pass that there was a man among them whose name was Abinadi;"], ["ma sa alu atu o ia i totonu o i latou,", "and he went forth among them,"], ["ma amata ona vavalo,", "and began to prophesy,"], ["ua fai atu:", "saying:"], ["Faauta,", "Behold,"], ["ua faapea ona fetalai mai o le Alii,", "thus saith the Lord,"], ["ma ua faapea ona ia poloaiina o a'u,", "and thus hath he commanded me,"], ["ua fetalai mai, Alu atu ia,", "saying,"], ["ma fai atu i lenei nuu,", "Go forth,"], ["ua faapea ona fetalai mai o le Alii—Oi talofa i lenei nuu,", "and say unto this people,"], ["ona ua Ou vaai ia latou mea inosia,", "thus saith the Lord—Wo be unto this people,"], ["ma a latou amioleaga,", "for I have seen their abominations,"], ["ma a latou faitaaga;", "and their wickedness,"], ["ma o le a Ou asiasi atu ia te i latou i lo'u toasa,", "and their whoredoms;"], ["vagana ai ua latou salamo.", "and except they repent I will visit them in mine anger."]]},
  {num:21,words:[["Ma e vagana ai ua latou salamo ma liliu mai i le Alii lo latou Atua,", "And except they repent and turn to the Lord their God,"], ["faauta,", "behold,"], ["o le a ou tuuina atu i latou i lima o o latou fili;", "I will deliver them into the hands of their enemies;"], ["ioe,", "yea,"], ["ma o le a aumai i latou i le pologa ;", "and they shall be brought into bondage;"], ["ma o le a faapuapuagatiaina i latou i lima o o latou fili.", "and they shall be afflicted by the hand of their enemies."]]},
  {num:22,words:[["Ma o le a oo mai,", "And it shall come to pass that they shall know that I am the Lord their God,"], ["o le a latou iloa o A'u o le Alii lo latou Atua, ma o A'u o se Atua fuā,", "and am a jealous God,"], ["e asiasi atu i lo'u nuu ia latou amioletonu.", "visiting the iniquities of my people."]]},
  {num:23,words:[["Ma o le a oo mai,", "And it shall come to pass that except this people repent and turn unto the Lord their God,"], ["se'i vagana ua salamo lenei nuu ma liliu mai i le Alii lo latou Atua,", "they shall be brought into bondage;"], ["o le a aumai i latou i le pologa; ma o le a leai se tasi e laveaia i latou,", "and none shall deliver them,"], ["vagana ai lava le Alii le Atua Malosi Aoao.", "except it be the Lord the Almighty God."]]},
  {num:24,words:[["Ioe,", "Yea,"], ["ma o le a oo mai,", "and it shall come to pass that when they shall cry unto me I will be slow to hear their cries;"], ["a latou tagi mai ia te a'u o le a faagesegese ona Ou faalogo atu ia latou tagi; ioe,", "yea,"], ["ma o le a Ou tuu i latou ia taia i latou e o latou fili.", "and I will suffer them that they be smitten by their enemies."]]},
  {num:25,words:[["Ma vagana ai ua latou salamo i le ie talatala ma le lefulefu,", "And except they repent in sackcloth and ashes,"], ["ma tagi malosi mai i le Alii lo latou Atua,", "and cry mightily to the Lord their God,"], ["o le a Ou lē faalogo atu ia latou tatalo,", "I will not hear their prayers,"], ["pe Ou te laveaia i latou mai o latou puapuaga;", "neither will I deliver them out of their afflictions;"], ["ma ua faapea ona fetalai mai o le Alii,", "and thus saith the Lord,"], ["ma ua faapea ona ia poloaiina o a'u.", "and thus hath he commanded me."]]},
  {num:26,words:[["O lenei sa oo ina ua uma ona tautala atu Apinati i nei upu ia te i latou,", "Now it came to pass that when Abinadi had spoken these words unto them they were wroth with him,"], ["sa latou feitai ia te ia, ma saili e aveese lona ola;", "and sought to take away his life;"], ["peitai sa laveaiina o ia e le Alii mai o latou lima.", "but the Lord delivered him out of their hands."]]},
  {num:27,words:[["O lenei ina ua faalogo le tupu o Noa i upu na tautala atu e Apinati i le nuu,", "Now when king Noah had heard of the words which Abinadi had spoken unto the people,"], ["sa ita foi o ia,", "he was also wroth;"], ["ma sa fai mai o ia:", "and he said:"], ["O ai Apinati,", "Who is Abinadi,"], ["ua ia faamasinoina ai a'u ma lo'u nuu,", "that I and my people should be judged of him,"], ["po o ai foi le Alii,", "or who is the Lord,"], ["o le a aumaia i luga o lo'u nuu le puapuaga tele faapea?", "that shall bring upon my people such great affliction?"]]},
  {num:28,words:[["Ou te poloai atu ia te outou ia aumai Apinati iinei,", "I command you to bring Abinadi hither,"], ["ina ia mafai ona ou fasioti ia te ia,", "that I may slay him,"], ["ona ua fai mai e ia nei mea ia mafai ona faaoso ai e ia lo'u nuu ia ita le tasi i le isi,", "for he has said these things that he might stir up my people to anger one with another,"], ["ma faatutupu ai finauga i totonu o lo'u nuu;", "and to raise contentions among my people;"], ["o lea o le a ou fasioti ia te ia.", "therefore I will slay him."]]},
  {num:29,words:[["O lenei sa faatauasoina mata o le nuu;", "Now the eyes of the people were blinded;"], ["o lea sa latou faamaaa ai o latou loto e faasaga i upu a Apinati,", "therefore they hardened their hearts against the words of Abinadi,"], ["ma sa latou saili mai le taimi lena i luma e pu'e o ia. Ma sa faamaaa e le tupu o Noa lona loto e faasaga i le afioga a le Alii,", "and they sought from that time forward to take him. And king Noah hardened his heart against the word of the Lord,"], ["ma sa lē salamo o ia i ana mea leaga.", "and he did not repent of his evil doings."]]},
];
renderVerseSet(mo_ch_11_Verses, 'mo-ch11-verses');

var mo_ch_12_Verses = [
  {num:1,words:[["Ma sa oo ina ua mavae atu le va o tausaga e lua sa oo ina sau Apinati i totonu o i latou ua faafoliga ese,", "And it came to pass that after the space of two years that Abinadi came among them in disguise,"], ["sa latou lē iloa ai o ia,", "that they knew him not,"], ["ma amata ona vavalo atu i totonu o i latou,", "and began to prophesy among them,"], ["ua fai atu:", "saying:"], ["Ua faapea ona poloaiina o a'u e le Alii,", "Thus has the Lord commanded me,"], ["ua fetalai mai—Apinati e,", "saying—Abinadi,"], ["alu atu ia ma vavalo atu i lo'u nuu nei,", "go and prophesy unto this my people,"], ["ona ua latou faamaaa o latou loto e faasaga mai i a'u upu;", "for they have hardened their hearts against my words;"], ["ua latou lē salamo ia latou mea leaga ua fai;", "they have repented not of their evil doings;"], ["o lea,", "therefore,"], ["o le a Ou asiasi atu ai ia te i latou i lo'u toasa,", "I will visit them in my anger,"], ["ioe,", "yea,"], ["o lo'u toasa tele o le a Ou asiasi atu ai ia te i latou ia latou amioletonu ma a latou mea inosia.", "in my fierce anger will I visit them in their iniquities and abominations."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["oi talofa i lenei tupulaga! Ma sa fetalai mai le Alii ia te a'u:", "wo be unto this generation! And the Lord said unto me:"], ["Faaloaloa atu lou lima ma vavalo atu,", "Stretch forth thy hand and prophesy saying:"], ["fai atu:", "Thus saith the Lord,"], ["Ua faapea ona fetalai mai o le Alii,", "it shall  come to pass that this generation,"], ["o le a oo mai lenei tupulaga i le pologa ,", "because of their iniquities,"], ["ona o a latou amioletonu,", "shall be brought into bondage,"], ["ma o le a taia i latou i le alafau ;", "and shall be smitten on the cheek; yea,"], ["ioe,", "and shall be driven by men,"], ["ma o le a tutulia e tagata,", "and shall be slain;"], ["ma o le a fasiotia,", "and the vultures of the air,"], ["ma o le a 'aina o latou aano e taie o le ea,", "and the dogs,"], ["ma 'ulī,", "yea,"], ["ioe,", "and the wild beasts,"], ["ma manu fe'ai.", "shall devour their flesh."]]},
  {num:3,words:[["Ma o le a oo mai o le ola o le tupu o Noa o le a pei le aoga o se ofu i totonu o se ogaumu aasa;", "And it shall come to pass that the life of king Noah shall be valued even as a garment in a hot furnace;"], ["ona o le a iloa e ia o A'u o le Alii.", "for he shall know that I am the Lord."]]},
  {num:4,words:[["Ma o le a oo mai o le a Ou taiaina lo'u nuu lenei i puapuaga tiga,", "And it shall come to pass that I will smite this my people with sore afflictions,"], ["ioe,", "yea,"], ["i le oge ma i faama'i ;", "with famine and with pestilence;"], ["ma o le a Ou faia ia latou tagiauueuē i le aso atoa.", "and I will cause that they shall howl all the day long."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["ma o le a Ou faia ia saisai avega i luga o o latou papatua;", "and I will cause that they shall have burdens lashed upon their backs;"], ["ma o le a tulituli i latou i luma e pei o se asini gūgū.", "and they shall be driven before like a dumb ass."]]},
  {num:6,words:[["Ma o le a oo mai o le a Ou auina atu uato'a a o i latou,", "And it shall come to pass that I will send forth hail among them,"], ["ma o le a taia ai i latou;", "and it shall smite them;"], ["ma o le a taia foi i latou i le matagi mai sasa'e;", "and they shall also be smitten with the east wind;"], ["ma o le a faatama'ia foi lo latou laueleele e iniseti ,", "and insects shall pester their land also,"], ["ma 'aia a latou kuranuma.", "and devour their grain."]]},
  {num:7,words:[["Ma o le a taia i latou i se faama'i tele—ma o nei mea uma o le a Ou faia ona o a latou amioletonu ma a latou mea inosia.", "And they shall be smitten with a great pestilence—and all this will I do because of their iniquities and abominations."]]},
  {num:8,words:[["Ma o le a oo mai se'i vagana ua latou salamo,", "And it shall come to pass that except they repent I will utterly destroy them from off the face of the earth;"], ["o le a Ou faaumatia ese atoa i latou mai luga o le lalolagi;", "yet they shall leave a record behind them,"], ["peitai o le a latou tuua se talafaamaumau pe a mavae atu i latou, ma o le a Ou faasaoina ia talafaamaumau mo isi atunuu o le a mauaina le laueleele;", "and I will preserve them for other nations which shall possess the land;"], ["ioe,", "yea,"], ["o le a Ou faia lava lenei mea ina ia mafai ona Ou faaali atu mea inosia a lenei nuu i isi atunuu.", "even this will I do that I may discover the abominations of this people to other nations."], ["Ma e tele mea na vavalo atu ai Apinati e faasaga i lenei nuu.", "And many things did Abinadi prophesy against this people."]]},
  {num:9,words:[["Ma sa oo ina latou feitai ia te ia;", "And it came to pass that they were angry with him;"], ["ma sa latou pu'e o ia ma avatu noanoatia o ia i luma o le tupu,", "and they took him and carried him bound before the king,"], ["ma fai atu i le tupu:", "and said unto the king:"], ["Faauta,", "Behold,"], ["ua matou aumai i ou luma se tagata o lē sa ia valoia mea leaga e uiga i lou nuu,", "we have brought a man before thee who has prophesied evil concerning thy people,"], ["ma fai mai o le a faaumatia i latou e le Atua.", "and saith that God will destroy them."]]},
  {num:10,words:[["Ma sa valoia foi e ia mea leaga e uiga i lou soifua,", "And he also prophesieth evil concerning thy life,"], ["ma fai mai o le a pei lou soifua o se ofu e i totonu o se ogaumu o le afi.", "and saith that thy life shall be as a garment in a furnace of fire."]]},
  {num:11,words:[["Ma lea foi,", "And again,"], ["sa fai mai o ia o le a pei oe o se 'ausaito,", "he saith that thou shalt be as a stalk,"], ["o se 'ausaito mago lava o le fanua,", "even as a dry stalk of the field,"], ["e taufetuli ai i luga manu vaefa ma soli i lalo o vae.", "which is run over by the beasts and trodden under foot."]]},
  {num:12,words:[["Ma lea foi,", "And again,"], ["ua fai mai o ia o le a pei oe o se fuga o se laau tuitui,", "he saith thou shalt be as the blossoms of a thistle,"], ["lea,", "which,"], ["a oo ina matua atoatoa,", "when it is fully ripe,"], ["a ula e le matagi,", "if the wind bloweth,"], ["e lelea atu i luga o le laueleele. Ma ua ia faatagā fai mai ua fetalai mai ai le Alii. Ma ua fai mai o ia o le a oo mai nei mea uma i ou luga vagana ai ua e salamo,", "it is driven forth upon the face of the land. And he pretendeth the Lord hath spoken it. And he saith all this shall come upon thee except thou repent,"], ["ma o le a oo mai nei mea ia te oe ona o au amioletonu.", "and this because of thine iniquities."]]},
  {num:13,words:[["Ma o lenei,", "And now,"], ["le tupu e,", "O king,"], ["o se a se leaga tele ua e faia,", "what great evil hast thou done,"], ["pe o a foi ni agasala tetele ua faia e lou nuu,", "or what great sins have thy people committed,"], ["o le a ta'usala ai i tatou e le Atua pe ua faamasinoina ai e lenei tagata?", "that we should be condemned of God or judged of this man?"]]},
  {num:14,words:[["Ma o lenei,", "And now,"], ["le tupu e,", "O king,"], ["faauta,", "behold,"], ["ua matou lē sala,", "we are guiltless,"], ["ma o oe,", "and thou,"], ["le tupu e,", "O king,"], ["e te lei agasala;", "hast not sinned;"], ["o lea,", "therefore,"], ["ua pepelo le tagata lenei e uiga ia te oe,", "this man has lied concerning you,"], ["ma ua vavalo fua o ia.", "and he has prophesied in vain."]]},
  {num:15,words:[["Ma faauta,", "And behold,"], ["ua tatou malolosi,", "we are strong,"], ["o le a lē faapologaina i tatou,", "we shall not come into bondage,"], ["pe ave faatagataotaua e o tatou fili;", "or be taken captive by our enemies;"], ["ioe,", "yea,"], ["ma ua e manuia i le laueleele,", "and thou hast prospered in the land,"], ["ma o le a e manuia foi.", "and thou shalt also prosper."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["o le tagata lenei,", "here is the man,"], ["matou te tuu atu o ia i ou aao;", "we deliver him into thy hands;"], ["e mafai ona e faia ia te ia e pei ona lelei ia te oe.", "thou mayest do with him as seemeth thee good."]]},
  {num:17,words:[["Ma sa oo ina faia e le tupu o Noa ia lafo Apinati i le falepuipui;", "And it came to pass that king Noah caused that Abinadi should be cast into prison;"], ["ma sa poloai atu o ia i faitaulaga ia latou faapotopoto faatasi i latou lava ina ia mafai e ia ona faia se fono faatasi ma i latou po o se a se mea e tatau ona ia faia ia te ia.", "and he commanded that the priests should gather themselves together that he might hold a council with them what he should do with him."]]},
  {num:18,words:[["Ma sa oo ina latou fai atu i le tupu:", "And it came to pass that they said unto the king:"], ["Aumai o ia iinei, ina ia mafai ona tatou fesili atu ia te ia;", "Bring him hither that we may question him;"], ["ma sa poloai atu le tupu ia aumai o ia i o latou luma.", "and the king commanded that he should be brought before them."]]},
  {num:19,words:[["Ma sa amata ona latou tuufesili atu ia te ia,", "And they began to question him,"], ["ina ia mafai ona latou faafesasia'i o ia,", "that they might cross him,"], ["ina ia mafai ona latou maua o se mea e tuua'i ai o ia;", "that thereby they might have wherewith to accuse him;"], ["peitai sa tali atu o ia ia te i latou ma le lotoa,", "but he answered them boldly,"], ["ma tali a latou fesili uma,", "and withstood all their questions,"], ["ioe,", "yea,"], ["sa latou ofo tele;", "to their astonishment;"], ["ona sa ia talituina i latou ia latou fesili uma,", "for he did withstand them in all their questions,"], ["ma faafemēmēa'i i latou ia latou upu uma.", "and did confound them in all their words."]]},
  {num:20,words:[["Ma sa oo ina fai mai se tasi o i latou ia te ia:", "And it came to pass that one of them said unto him:"], ["O le a le uiga o upu ua tusia,", "What meaneth the words which are written,"], ["ma ia sa aoao mai e o tatou tamā,", "and which have been taught by our fathers,"], ["fai mai:", "saying:"]]},
  {num:21,words:[["E matua matagofie lava i luga o mauga vae o ia o lē na te aumai tala e lelei;", "How beautiful upon the mountains are the feet of him that bringeth good tidings;"], ["o lē na te talai atu le filemu;", "that publisheth peace;"], ["o lē na te aumai tala e lelei o mea lelei;", "that bringeth good tidings of good;"], ["o lē na te talai atu le olataga;", "that publisheth salvation;"], ["o lē e fai atu ia Siona,", "that saith unto Zion,"], ["Ua nofotupu lou Atua;", "Thy God reigneth;"]]},
  {num:22,words:[["O le a sii i luga e au leoleo le leo;", "Thy watchmen shall lift up the voice;"], ["o le a latou pepese faatasi i le leo,", "with the voice together shall they sing;"], ["ona o le a latou vaai mata i le mata pe a toe aumai Siona e le Alii;", "for they shall see eye to eye when the Lord shall bring again Zion;"]]},
  {num:23,words:[["Alalaga ia i le olioli;", "Break forth into joy;"], ["pepese faatasi ia outou nofoaga tuufua o Ierusalema;", "sing together ye waste places of Jerusalem;"], ["ona ua faamafanafanaina e le Alii lona nuu,", "for the Lord hath comforted his people,"], ["ua togiola e ia Ierusalema;", "he hath redeemed Jerusalem;"]]},
  {num:24,words:[["Ua afe e le Alii lona aao paia i mata o atunuu uma,", "The Lord hath made bare his holy arm in the eyes of all the nations,"], ["ma o le a vaai tulu'iga uma o le lalolagi i le olataga a lo tatou Atua?", "and all the ends of the earth shall see the salvation of our God?"]]},
  {num:25,words:[["Ma o lenei sa fai atu Apinati ia te i latou:", "And now Abinadi said unto them:"], ["O outou o faitaulaga ,", "Are you priests,"], ["ua manatu e faapea ua outou aoaoina lenei nuu,", "and pretend to teach this people,"], ["ma malamalama i le agaga o valoaga,", "and to understand the spirit of prophesying,"], ["ae ua outou fia iloa mai ia te a'u le uiga o nei mea?", "and yet desire to know of me what these things mean?"]]},
  {num:26,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["oi talofa ia te outou i lo outou faapi'opi'o o ala o le Alii! Ona afai ua outou malamalama i nei mea,", "wo be unto you for perverting the ways of the Lord! For if ye understand these things ye have not taught them;"], ["tou te lei aoaoina atu; o lea,", "therefore,"], ["ua outou faapi'opi'o ai ala o le Alii.", "ye have perverted the ways of the Lord."]]},
  {num:27,words:[["Tou te lei faaaogaina o outou loto tou te malamalama ai;", "Ye have not applied your hearts to under– standing;"], ["o lea,", "therefore,"], ["sa outou lē popoto. O lea,", "ye have not been wise. Therefore,"], ["o ni a ua outou aoao atu i lenei nuu?", "what teach ye this people?"]]},
  {num:28,words:[["Ma sa latou fai mai:", "And they said:"], ["Ua matou aoao atu le tulafono a Mose.", "We teach the law of Moses."]]},
  {num:29,words:[["Ma sa toe fai atu o ia ia te i latou:", "And again he said unto them:"], ["Afai ua outou aoao atu le tulafono a Mose aisea ua outou lē tausia ai? Aisea ua outou faaū atu ai o outou loto i luga o 'oa? Aisea ua outou faia ai le faitaaga ma faaalu lo outou malosi i le faatasi ma fafine talitane,", "If ye teach the law of Moses why do ye not keep it? Why do ye set your hearts upon riches? Why do ye commit whoredoms and spend your strength with harlots,"], ["ioe,", "yea,"], ["ma faaoso lenei nuu e fai le agasala,", "and cause this people to commit sin,"], ["ua faia ai e le Alii e auina mai a'u e vavalo faasaga atu i lenei nuu,", "that the Lord has cause to send me to prophesy against this people,"], ["ioe,", "yea,"], ["se leaga tele e faasaga i lenei nuu?", "even a great evil against this people?"]]},
  {num:30,words:[["Tou te le iloa ea ua ou tautala atu i le upumoni? Ioe,", "Know ye not that I speak the truth? Yea,"], ["ua outou iloa ua ou tautala atu i le upumoni;", "ye know that I speak the truth;"], ["ma ua tatau ona outou tetete i luma o le Atua.", "and you ought to tremble before God."]]},
  {num:31,words:[["Ma o le a oo mai o le a taina outou mo a outou amioletonu,", "And it shall come to pass that ye shall be smitten for your iniquities,"], ["ona ua outou fai mai ua outou aoao atu le tulafono a Mose. Ma o se a se mea ua outou iloa e uiga i le tulafono a Mose? E ala mai ea le olataga i le tulafono a Mose? O ni a fa a outou?", "for ye have said that ye teach the law of Moses. And what know ye concerning the law of Moses? Doth salvation come by the law of Moses? What say ye?"]]},
  {num:32,words:[["Ma sa latou tali mai ma fai mai o le olataga e ala mai i le tulafono a Mose.", "And they answered and said that salvation did come by the law of Moses."]]},
  {num:33,words:[["Ae o lenei sa fai atu Apinati ia te i latou:", "But now Abinadi said unto them:"], ["Ua ou iloa afai tou te tausi i poloaiga a le Atua e faaolaina outou;", "I know if ye keep the commandments of God ye shall be saved;"], ["ioe,", "yea,"], ["pe afai tou te tausi i tulafono na tuu mai e le Alii ia Mose i le mauga o Sinai ,", "if ye keep the commandments which the Lord delivered unto Moses in the mount of Sinai,"], ["fai mai:", "saying:"]]},
  {num:34,words:[["O A'u o le Alii lou Atua,", "I am the Lord thy God,"], ["o lē na aumaia oe i fafo mai le nuu o Aikupito,", "who hath brought thee out of the land of Egypt,"], ["i fafo mai le fale o le pologa.", "out of the house of bondage."]]},
  {num:35,words:[["Aua e te fai mo oe se Atua ese i o'u luma.", "Thou shalt have no other God before me."]]},
  {num:36,words:[["Aua e te fai mo oe se tupua ua ta,", "Thou shalt not make unto thee any graven image,"], ["po o se faatusa o se mea o i le lagi i luga,", "or any likeness of any thing in heaven above,"], ["po o mea o loo i le lalolagi o i lalo.", "or things which are in the earth beneath."]]},
  {num:37,words:[["O lenei sa fai atu Apinati ia te i latou,", "Now Abinadi said unto them,"], ["ua outou faia ea nei mea uma? Ou te fai atu ia te outou,", "Have ye done all this? I say unto you,"], ["E leai,", "Nay,"], ["tou te lei faia. Ma ua outou aoaoina ea lenei nuu ia latou faia nei mea uma? Ou te fai atu ia te outou,", "ye have not. And have ye taught this people that they should do all these things? I say unto you,"], ["E leai,", "Nay,"], ["tou te lei aoaoina.", "ye have not."]]},
];
renderVerseSet(mo_ch_12_Verses, 'mo-ch12-verses');

var mo_ch_13_Verses = [
  {num:1,words:[["Ma o lenei ina ua uma ona faalogo mai le tupu i nei upu,", "And now when the king had heard these words,"], ["sa fai atu o ia i ana faitaulaga:", "he said unto his priests:"], ["Aveese atu ia lenei tagata,", "Away with this fellow,"], ["ma fasioti ia te ia;", "and slay him;"], ["ona o le a sa tatou mea e fai ia te ia,", "for what have we to do with him,"], ["ona ua fasa o ia.", "for he is mad."]]},
  {num:2,words:[["Ma sa latou tutu mai ma taumafai e fetagofi mai o latou lima ia te ia;", "And they stood forth and attempted to lay their hands on him;"], ["peitai sa tu tetee atu o ia ia te i latou,", "but he withstood them,"], ["ma fai atu ia te i latou:", "and said unto them:"]]},
  {num:3,words:[["Aua tou te pai mai ia te a'u,", "Touch me not,"], ["ona o le a taia outou e le Atua pe a fetagofi mai o outou lima ia te a'u,", "for God shall smite you if ye lay your hands upon me,"], ["ona ou te lei tuuina atu le savali na auina mai a'u e le Alii e tuu atu;", "for I have not delivered the message which the Lord sent me to deliver;"], ["pe ua ou ta'u atu foi le mea na outou talosaga mai ou te ta'u atu;", "neither have I told you that which ye requested that I should tell;"], ["o lea,", "therefore,"], ["o le a lē tuu ai e le Atua ia faaumatia a'u i le taimi nei.", "God will not suffer that I shall be destroyed at this time."]]},
  {num:4,words:[["Ae e ao ina ou faataunuuina poloaiga na poloaiina ai a'u e le Atua; ma ona ua ou ta'u atu ia te outou le upumoni,", "But I must fulfil the commandments wherewith God has commanded me;"], ["ua outou feitai mai ia te a'u.", "and because I have told you the truth ye are angry with me."], ["O lenei foi,", "And again,"], ["ona ua ou tautala atu le afioga a le Atua ua outou faamasino mai ia te a'u fai mai ua ou fasa.", "because I have spoken the word of God ye have judged me that I am mad."]]},
  {num:5,words:[["O lenei sa oo ina ua uma ona tautala atu e Apinati nei upu sa fefefe le nuu o le tupu o Noa e fetagofi mai o latou lima ia te ia,", "Now it came to pass after Abinadi had spoken these words that the people of king Noah durst not lay their hands on him,"], ["ona sa i luga o ia le Agaga o le Alii;", "for the Spirit of the Lord was upon him;"], ["ma sa susulu ona fofoga i se malamalama tele,", "and his face shone with exceeding luster,"], ["sa pei lava o fofoga o Mose a'o i ai i le mauga o Sinai,", "even as Moses’ did while in  the mount of Sinai,"], ["a'o fetautalatalaa'i ma le Alii.", "while speaking with the Lord."]]},
  {num:6,words:[["Ma sa tautala atu o ia ma le mana ma le pule mai le Atua;", "And he spake with power and authority from God;"], ["ma sa faaauau atu pea e ia ana upu,", "and he continued his words,"], ["ua fai atu:", "saying:"]]},
  {num:7,words:[["Ua outou vaai ua leai so outou mana e fasioti ai a'u,", "Ye see that ye have not power to slay me,"], ["o lea o le a ou faauma atu ai la'u savali. Ioe,", "therefore I finish my message. Yea,"], ["ma ua ou iloa ua seleia ai outou i o outou loto ona ua ou ta'u atu ia te outou le moni e uiga ia outou amioletonu.", "and I perceive that it cuts you to your hearts because I tell you the truth concerning your iniquities."]]},
  {num:8,words:[["Ioe,", "Yea,"], ["ma o a'u upu foi ua faatumuina ai outou i le ofo ma le meia,", "and my words fill you with wonder and amazement,"], ["ma le ita.", "and with anger."]]},
  {num:9,words:[["Peitai ou te faauma atu la'u savali;", "But I finish my message;"], ["ma ona lē afaina ai lea po o fea ou te alu i ai,", "and then it matters not whither I go,"], ["pe afai e faapea e faaolaina a'u.", "if it so be that I am saved."]]},
  {num:10,words:[["Ae o le tele lenei o le mea ou te ta'u atu ia te outou,", "But this much I tell you,"], ["o le mea tou te faia ia te a'u,", "what you do with me,"], ["pe a uma atu lenei,", "after this,"], ["o le a avea o se faatusa ma se ata o mea o le a oo mai.", "shall be as a type and a shadow of things which are to come."]]},
  {num:11,words:[["Ma o lenei ou te faitau atu ia te outou poloaiga a le Atua o totoe,", "And now I read unto you the remainder of the commandments of God,"], ["ona ua ou iloa ua lē o tusia i latou i o outou loto;", "for I perceive that they are not written in your hearts;"], ["ua ou iloa foi sa outou suesue ma aoao atu le amioletonu i le vaega tele o o outou olaga.", "I perceive that ye have studied and taught iniquity the most part of your lives."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["tou te manatua sa ou fai atu ia te outou:", "ye remember that I said unto you:"], ["Aua e te fai mo oe se tupua ua ta,", "Thou shall not make unto thee any graven image,"], ["po o se faatusa o mea o i le lagi i lugā,", "or any likeness of things which are in heaven above,"], ["po o mea o i le lalolagi o i lalo,", "or which are in the earth beneath,"], ["po o mea o i vai o i lalo o le lalolagi.", "or which are in the water under the earth."]]},
  {num:13,words:[["Ma lea foi:", "And again:"], ["Aua e te ifo i ai,", "Thou shalt not bow down thyself unto them,"], ["aua foi e te auauna i ai; aua o A'u o le Alii lou Atua,", "nor serve them;"], ["o se Atua fuā,", "for I the Lord thy God am a jealous God,"], ["e asiasi atu i amioletonu a tamā i luga o fanau,", "visiting the iniquities of the fathers upon the children,"], ["i tupulaga e tolu ma le fa o i latou o e inoino mai ia te a'u;", "unto the third and fourth generations of them that hate me;"]]},
  {num:14,words:[["Ma faaali atu le alofa mutimutivale i afe o i latou o e e alolofa mai ia te a'u ma tausi i a'u poloaiga.", "And showing mercy unto thousands of them that love me and keep my commandments."]]},
  {num:15,words:[["Aua e te ta'u fua le suafa o le Alii lou Atua;", "Thou shalt not take the name of the Lord thy God in vain;"], ["ona o le a ta'usalaina e le Alii o ia o lē na te ta'u fua lona suafa.", "for the Lord will not hold him guiltless that taketh his name in vain."]]},
  {num:16,words:[["Ia manatua le aso sapati,", "Remember the sabbath day,"], ["ia tausi lona paia.", "to keep it holy."]]},
  {num:17,words:[["O aso e ono e te galue ai,", "Six days shalt thou labor,"], ["ma fai ai au galuega uma lava;", "and do all thy work;"]]},
  {num:18,words:[["Ae o le aso fitu,", "But the seventh day,"], ["o le sapati o le Alii lou Atua,", "the sabbath of the Lord thy God,"], ["aua e te fai ai se galuega,", "thou shalt not do any work,"], ["o oe,", "thou,"], ["po o lou atalii,", "nor thy son,"], ["po o lou afafine,", "nor thy daughter,"], ["o lau auauna-tane,", "thy man– servant,"], ["po o lau auauna-fafine,", "nor thy maid– servant,"], ["po o au manu,", "nor thy cattle,"], ["po o le tagata ese o i totonu o ou faitotoa;", "nor thy stranger that is within thy gates;"]]},
  {num:19,words:[["Ona o aso e ono na faia ai e le Alii le lagi ma le lalolagi,", "For in six days the Lord made heaven and earth,"], ["ma le sami,", "and the sea,"], ["ma mea uma o i ai;", "and all that in them is;"], ["o le mea lea na faamanuia ai e le Alii le aso sapati,", "wherefore the Lord blessed the sabbath day,"], ["ma faapaia i ai.", "and hallowed it."]]},
  {num:20,words:[["Ia e ava i lou tamā ma lou tinā,", "Honor thy father and thy mother,"], ["ina ia faalevalevaina ou aso i luga o le laueleele ua foaiina mai e le Alii lou Atua ia te oe.", "that thy days may be long upon the land which the Lord thy God giveth thee."]]},
  {num:21,words:[["Aua e te fasioti tagata.", "Thou shalt not kill."]]},
  {num:22,words:[["Aua e te mulilua . Aua e te gaoi .", "Thou shalt not commit adultery. Thou shalt not steal."]]},
  {num:23,words:[["Aua e te molimau pepelo aga'i i lē lua te tuaoi.", "Thou shalt not bear false witness against thy neighbor."]]},
  {num:24,words:[["Aua e te manao i le fale o lē lua te tuaoi,", "Thou shalt not covet thy neighbor’s house,"], ["aua e te manao i le avā a lē lua te tuaoi,", "thou shalt not covet thy neighbor’s wife,"], ["po o lana auauna tane,", "nor his man– servant,"], ["po o lana auauna fafine,", "nor his maid– servant,"], ["po o lana povi,", "nor his ox,"], ["po o lana asini,", "nor his ass,"], ["po o soo se mea lava a lē lua te tuaoi.", "nor anything that is thy neighbor’s."]]},
  {num:25,words:[["Ma sa oo ina ua uma ona faai'u e Apinati le fai atu o ia upu sa fai atu o ia ia te i latou:", "And it came to pass that after Abinadi had made an end of these sayings that he said unto them:"], ["Pe ua outou aoaoina ea lenei nuu e tatau ona latou tausisi i le faia o nei mea uma ina ia tausia nei poloaiga?", "Have ye taught this people that they should observe to do all these things for to keep these commandments?"]]},
  {num:26,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["E leai;", "Nay;"], ["aua a na outou aoaoina i latou,", "for if ye had,"], ["po ua lē faia e le Alii ou te sau ma vavalo atu le leaga e uiga i lenei nuu.", "the Lord would not have caused me to come forth and to prophesy evil concerning this people."]]},
  {num:27,words:[["Ma o lenei ua outou fai mai e ala mai le olataga i le tulafono a Mose. Ou te fai atu ia te outou e tatau ona outou tausia pea le tulafono a Mose mo le taimi nei;", "And now ye have said that salvation cometh by the law of Moses. I say unto you that it is expedient that ye should keep the law of Moses as yet;"], ["ae ou te fai atu ia te outou,", "but I say unto you,"], ["e oo mai le taimi o le a lē toe tatau ai ona tausia o le tulafono a Mose.", "that the time shall come when it shall no more be expedient to keep the law of Moses."]]},
  {num:28,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e lē ala mai le olataga i le nao le tulafono ;", "that salvation doth not come by the law alone;"], ["ma a na leai le togiola ,", "and were it not for the atonement,"], ["lea o le a faia e le Atua lava ia mo agasala ma amioletonu a ona tagata,", "which God himself shall make for the sins and iniquities of his people,"], ["e lē ma'alofia lava le tatau ai ona latou fano,", "that they must unavoidably perish,"], ["e ui i le tulafono a Mose.", "notwithstanding the law of Moses."]]},
  {num:29,words:[["Ma o lenei ou te fai atu ia te outou sa tatau ona i ai se tulafono e tuu mai i le fanauga a Isaraelu,", "And now I say unto you that it was expedient that there should be a law given to the children of Israel,"], ["ioe,", "yea,"], ["o se tulafono sa'olele lava;", "even a very strict law;"], ["ona o i latou o se nuu sa ua maaa,", "for they were a stiffnecked people,"], ["sa vave ona latou faia o le amioletonu,", "quick to do iniquity,"], ["ma gese ona latou manatua o le Alii lo latou Atua;", "and slow to remember the Lord their God;"]]},
  {num:30,words:[["O lea sa i ai se tulafono sa tuuina mai ia te i latou,", "Therefore there was a law given them,"], ["ioe,", "yea,"], ["o se tulafono o tu ma sauniga ,", "a law of performances and of ordinances,"], ["o se tulafono sa tatau ona latou tausisi tonu i ai mai lea aso i lea aso,", "a law which they were to observe strictly from day to day,"], ["e taofi ai i latou i le manatua o le Atua ma lo latou tiute ia te ia.", "to keep them in remembrance of God and their duty towards him."]]},
  {num:31,words:[["Ae faauta,", "But behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o nei mea uma o ni faatusa o mea o le a oo mai.", "that all these things were types of things to come."]]},
  {num:32,words:[["Ma o lenei,", "And now,"], ["pe sa latou malamalama ea i le tulafono? Ou te fai atu ia te outou,", "did they understand the law? I say unto you,"], ["E leai,", "Nay,"], ["sa latou lē malamalama uma i le tulafono;", "they did not all understand the law;"], ["ma o lenei ona o le maaa o o latou loto;", "and this because of the hardness of their hearts;"], ["ona sa latou lē malamalama e lē mafai ona faaolaina o soo se tagata vagana e ala i le togiola a le Atua.", "for they understood not that there could not any man be saved except it were through the redemption of God."]]},
  {num:33,words:[["Aua faauta,", "For behold,"], ["sa lei vavalo atu ea Mose ia te i latou e uiga i le afio mai o le Mesia,", "did not Moses prophesy unto them concerning the coming of the Messiah,"], ["ma o le a togiola e le Atua ona tagata? Ioe,", "and that God should redeem his people? Yea,"], ["ma e oo i perofeta uma o e sa vavalo talu mai le amataga o le lalolagi—sa latou lei tautatala tetele pe itiiti mai ea e uiga i nei mea?", "and even all the prophets who have prophesied ever since the world began—have they not spoken more or less concerning these things?"]]},
  {num:34,words:[["Latou te lei fai mai ea o le a afio mai le Atua lava ia i lalo i totonu o le fanauga a tagata,", "Have they not said that God himself should come down among the children of men,"], ["ma ave i ona luga foliga o le tagata,", "and take upon him the form of man,"], ["ma afio atu i le mana tele i luga o le lalolagi?", "and go forth in mighty power upon the face of the earth?"]]},
  {num:35,words:[["Ioe,", "Yea,"], ["ma latou te lei fai mai foi ea o le a faataunuuina e ia le toetutu mai o e ua oti,", "and have they not said also that he should bring to pass the resurrection of the dead,"], ["ma o ia,", "and that he,"], ["o ia lava,", "himself,"], ["o le a sauaina ma faapuapuagatia?", "should be oppressed and afflicted?"]]},
];
renderVerseSet(mo_ch_13_Verses, 'mo-ch13-verses');

var mo_ch_14_Verses = [
  {num:1,words:[["Ioe,", "Yea,"], ["e oo ia Isaia pe lei fai mai ea:", "even doth not Isaiah say:"], ["O ai ea ua talitonu i la matou tala,", "Who hath believed our report,"], ["ma o ai ua faaali i ai le aao o le Alii?", "and to whom is the arm of the Lord revealed?"]]},
  {num:2,words:[["Ona o le a tupu a'e o ia i ona luma e pei o se laau mu'amu'a,", "For he shall grow up before him as a tender plant,"], ["ma pei o se a'a ua totogo a'e i fafo mai le eleele mātūtū;", "and as a root out of dry ground;"], ["ua leai sona aulelei po o se manaia;", "he hath no form nor comeliness;"], ["ma a tatou vaai ia te ia e leai sona lalelei tatou te mananao ai ia te ia.", "and when we shall see him there is no beauty that we should desire him."]]},
  {num:3,words:[["Ua inosia ma teena o ia e tagata;", "He is despised and rejected of men;"], ["o se tagata o faanoanoa,", "a man of sorrows,"], ["ma ua masani ma le tiga;", "and acquainted with grief;"], ["ma sa tatou natia e pei o lea tala o tatou mata mai ia te ia;", "and we hid as it were our faces from him;"], ["sa inosia o ia,", "he was despised,"], ["ae sa tatou lē manatu ia te ia.", "and we esteemed him not."]]},
  {num:4,words:[["E moni lava ua tauave e ia o tatou tiga ,", "Surely he has borne our griefs,"], ["ma tauave o tatou faanoanoa;", "and carried our sorrows;"], ["peitai sa tatou manatu ia te ia ua taia,", "yet we did esteem him stricken,"], ["ua fasia e le Atua,", "smitten of God,"], ["ma faapuapuagatia.", "and afflicted."]]},
  {num:5,words:[["Peitai sa manu'a o ia mo a tatou solitulafono ,", "But he was wounded for our transgressions,"], ["sa totolia o ia mo a tatou amioletonu;", "he was bruised for our iniquities;"], ["sa i ona luga le a'oa'iga mo lo tatou filemu;", "the chastisement of our peace was upon him;"], ["ma o ona faalavalava ua faamaloloina ai i tatou.", "and with his stripes we are healed."]]},
  {num:6,words:[["O i tatou uma,", "All we,"], ["e pei o mamoe ,", "like sheep,"], ["ua se ese;", "have gone astray;"], ["ua tatou taitasi ma liliu atu le tagata i lona lava ala;", "we have turned every one to his own way;"], ["ma ua faafafa e le Alii i ona luga amioletonu a i tatou uma.", "and the Lord hath laid on him the iniquities of us all."]]},
  {num:7,words:[["Na sauaina o ia,", "He was oppressed,"], ["ma sa faapuapuagatiaina o ia,", "and he was afflicted,"], ["ae sa lē tatalaina e ia lona fofoga;", "yet he opened not his mouth;"], ["ua aumai o ia e pei o se tamai mamoe a fasia,", "he is brought as a lamb to the slaughter,"], ["ma e pei o se mamoe gūgū i luma o ona selefulufulu ua faapea ona lē tatalaina e ia lona fofoga.", "and as a sheep before her shearers is dumb so he opened not his mouth."]]},
  {num:8,words:[["Sa aveese atu o ia mai le falepuipui ma mai le faamasinoga;", "He was taken from prison and from judgment;"], ["ma o ai na te tala atu lona tupulaga? Ona sa vavae ese o ia i fafo mai le laueleele o tagata ola;", "and who shall declare his generation? For he was cut off out of the land of the living;"], ["sa taia o ia mo solitulafono a lo'u nuu.", "for the transgressions of my people was he stricken."]]},
  {num:9,words:[["Ma sa fai e ia lona tuugamau faatasi ma le amioleaga,", "And he made his grave with the wicked,"], ["ma faatasi ma le mau'oa i lona maliu;", "and with the rich in his death;"], ["ona sa lei faia e ia se mea leaga,", "because he had done no evil,"], ["pe sa i ai se taufaasese i lona fofoga.", "neither was any deceit in his mouth."]]},
  {num:10,words:[["Peitai sa finagalo malie le Alii e faamanu'a o ia;", "Yet it pleased the Lord to bruise him;"], ["ua ia tuu o ia ia faanoanoa;", "he hath put him to grief;"], ["pe a e faia lona agaga o se taulaga mo agasala, o le a vaai o ia i ana fanau ,", "when thou shalt make his soul an offering for sin he shall see his seed,"], ["o le a ia faalevalevaina ona aso,", "he shall prolong his days,"], ["ma o le a manuia le finagalo o le Alii i lona aao.", "and the pleasure of the Lord shall prosper in his hand."]]},
  {num:11,words:[["O le a silasila o ia i le mafatia o lona agaga,", "He shall see the travail of his soul,"], ["ma o le a malie i ai;", "and shall be satisfied;"], ["o lona malamalama o le a ta'uamiotonu ai e la'u auauna amiotonu le toatele;", "by his knowledge shall my righteous servant justify many;"], ["ona o le a tauave e ia a latou amioletonu.", "for he shall bear their iniquities."]]},
  {num:12,words:[["O lea o le a ou vavae atu ai ia te ia se vaega faatasi ma e ua silisili,", "Therefore will I divide him a portion with the great,"], ["ma o le a ia vaevaeina le vete faatasi ma e malolosi;", "and he shall divide the spoil with the strong;"], ["ona sa sasaa atu e ia lona agaga e oo i le oti;", "because he hath poured out his soul unto death;"], ["ma sa faitauina o ia faatasi ma e solitulafono;", "and he was numbered with the transgressors;"], ["ma sa ia tauaveina agasala a le toatele,", "and he bore the sins of many,"], ["ma faia le 'ai'oiga mo e solitulafono.", "and made intercession for the transgressors."]]},
];
renderVerseSet(mo_ch_14_Verses, 'mo-ch14-verses');

var mo_ch_15_Verses = [
  {num:1,words:[["Ma o lenei sa fai atu Apinati ia te i latou:", "And now Abinadi said unto them:"], ["Ou te manao ia outou malamalama o le a afio mai i lalo le Atua lava ia i totonu o le fanauga a tagata,", "I would that ye should understand that God himself shall come down among the children of men,"], ["ma o le a togiola e ia ona tagata.", "and shall redeem his people."]]},
  {num:2,words:[["Ma ona e soifua o ia i le tino o le a ta'ua o ia o le Alo o le Atua,", "And because he dwelleth in flesh he shall be called the Son of God,"], ["ma ona ua tuu atu e ia le tino i lalo o le puleaga a le finagalo o le Tamā ,", "and having subjected the flesh to the will of the Father,"], ["ona o ia o le Tamā ma le Alo—", "being the Father and the Son—"]]},
  {num:3,words:[["O le Tama,", "The Father,"], ["ona sa fanauina o ia i le mana o le Atua;", "because he was conceived by the power of God;"], ["ma o le Alo,", "and the Son,"], ["ona o le tino;", "because of the flesh;"], ["ua faapea ona avea ai o ia o le Tamā ma le Alo—", "thus becoming the Father and Son—"]]},
  {num:4,words:[["Ma o i laua o se Atua e tasi,", "And they are one God,"], ["ioe,", "yea,"], ["o le Tamā Faavavau lava lea o le lagi ma le lalolagi.", "the very Eternal Father of heaven and of earth."]]},
  {num:5,words:[["Ma ua faapea ona aumai ai o le tino i lalo o le pule a le Agaga,", "And thus the flesh becoming subject to the Spirit,"], ["po o le Alo i le Tamā,", "or the Son to the Father,"], ["o se Atua e tasi,", "being one God,"], ["e mafatia i tofotofoga,", "suffereth temptation,"], ["ae lē gaua'i atu i le tofotofoga,", "and yieldeth not to the temptation,"], ["ae tuu atu o ia lava e tauemuina,", "but suffereth himself to be mocked,"], ["ma sasa ,", "and scourged,"], ["ma tuli i fafo,", "and cast out,"], ["ma faato e ona tagata.", "and disowned by his people."]]},
  {num:6,words:[["Ma a mavae nei mea uma,", "And after all this,"], ["a uma ona faia e ia vavega tetele i totonu o le fanauga a tagata,", "after working many mighty miracles among the children of men,"], ["o le a taitai atu o ia,", "he shall be led,"], ["ioe,", "yea,"], ["e pei lava ona fai mai Isaia,", "even as Isaiah said,"], ["e pei o se mamoe gūgū i luma o le selefulufulu,", "as a sheep before the shearer is dumb,"], ["ua faapea ona lē tatalaina e ia lona fofoga.", "so he opened not his mouth."]]},
  {num:7,words:[["Ioe,", "Yea,"], ["o le a faapea lava ona taitai atu o ia,", "even so he shall be led,"], ["e faasatauroina ,", "crucified,"], ["ma fasia,", "and slain,"], ["ma avea ai foi le oti ma pule i le tino,", "the flesh becoming subject even unto death,"], ["ua tofatumoanaina le loto o le Alo i le finagalo o le Tamā.", "the will of the Son being swallowed up in the will of the Father."]]},
  {num:8,words:[["Ma e faapea ona motusia e le Atua noataga o le oti,", "And thus God breaketh the bands of death,"], ["ina ua manumalo o ia i le oti;", "having gained the victory over death;"], ["ma tuu atu ai i le Alo le mana e fai ai le ai'oiga mo le fanauga a tagata—", "giving the Son power to make intercession for the children of men—"]]},
  {num:9,words:[["Ina ua afio a'e i le lagi,", "Having ascended into heaven,"], ["ua ia te ia loto o le alofa mutimutivale;", "having the bowels of mercy;"], ["ua faatumuina i le agaalofa i le fanauga a tagata;", "being filled with compassion towards the children of men;"], ["ua tu i lo latou va ma le faamasinotonu;", "standing betwixt them and justice;"], ["ona ua motusia e ia fusi o le oti,", "having broken the bands of death,"], ["ma ua ave e ia i ona luga a latou amioletonu ma a latou solitulafono,", "taken upon himself their iniquity and their transgressions,"], ["ina ua ia togiolaina i latou,", "having redeemed them,"], ["ma faamalie manaoga o le faamasinotonu.", "and satisfied the demands of justice."]]},
  {num:10,words:[["Ma o lenei ou te fai atu ia te outou,", "And now I say unto you,"], ["o ai na te tala atu lona tupulaga? Faauta,", "who shall declare his generation? Behold,"], ["ou te fai atu ia te outou, pe a faia lona agaga o se taulaga mo agasala,", "I say unto you,"], ["o le a silasila o ia i ana fanau .", "that when his soul has been made an offering for sin he shall see his seed."], ["Ma o lenei pe ni a fa a outou? Ma o ai o le a avea ma ana fanau?", "And now what say ye? And who shall be his seed?"]]},
  {num:11,words:[["Faauta ou te fai atu ia te outou,", "Behold I say unto you,"], ["soo se tasi na faalogo i fetalaiga a perofeta ,", "that whosoever has heard the words of the prophets,"], ["ioe,", "yea,"], ["o perofeta paia uma o e sa vavalo e uiga i le afio mai o le Alii—Ou te fai atu ia te outou,", "all the holy prophets who have prophesied concerning the coming of the Lord—I say unto you,"], ["o i latou uma o e na faalogo ia latou upu,", "that all those who have hearkened unto their words,"], ["ma ua talitonu o le a togiola e le Alii ona tagata,", "and believed that the Lord would redeem his people,"], ["ma sa tulimatai i lena aso mo se faamagaloga o a latou agasala,", "and have looked forward to that day for a remission of their sins,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o i latou ia o ana fanau,", "that these are his seed,"], ["po o i latou ia o suli o le malo o le Atua.", "or they are heirs of the kingdom of God."]]},
  {num:12,words:[["Ona o i latou ia na tauave e ia a latou agasala;", "For these are they whose sins he has borne;"], ["e mo i latou ia na maliu ai o ia,", "these are they for whom he has died,"], ["e togiola i latou mai ia latou solitulafono. Ma o lenei,", "to redeem them from their transgressions. And now,"], ["pe lē o i latou ea ia o ana fanau?", "are they not his seed?"]]},
  {num:13,words:[["Ioe,", "Yea,"], ["ma pe lē o perofeta ea,", "and are not the prophets,"], ["i latou taitoatasi ia sa tatala lona fofoga e vavalo atu, o e e lei pauu atu i le solitulafono,", "every one that has opened his mouth to prophesy,"], ["o le uiga o la'u tala o perofeta uma lava ia na soifua talu mai le amataga o le lalolagi? Ou te fai atu ia te outou,", "that has not fallen into transgression,"], ["o i latou ia o ana fanau.", "I mean all the holy prophets ever since the world began? I say unto you that they are his seed."]]},
  {num:14,words:[["Ma o i latou ia o e na latou 'talai atu le filemu,", "And these are they who have published peace,"], ["o e na latou aumai tala e lelei o mea lelei,", "who have brought good tidings of good,"], ["o e na latou talai atu le olataga;", "who have published salvation;"], ["ma fai atu ia Siona:", "and said unto Zion:"], ["Ua nofotupu lou Atua!", "Thy God reigneth!"]]},
  {num:15,words:[["Ma ua matagofie naua o latou vae i luga o mauga!", "And O how beautiful upon the mountains were their feet!"]]},
  {num:16,words:[["Ma lea foi,", "And again,"], ["ua matagofie naua i luga o mauga vae o i latou o loo latou talai atu pea le filemu!", "how beautiful upon the mountains are the feet of those that are still publishing peace!"]]},
  {num:17,words:[["O lenei foi,", "And again,"], ["e matagofie na'uā i luga o mauga vae o i latou o e o le a latou talai atu le filemu i le lumanai,", "how beautiful upon the mountains are the feet of those who shall hereafter publish peace,"], ["ioe,", "yea,"], ["mai i le taimi nei e oo i le faavavau!", "from this time henceforth and forever!"]]},
  {num:18,words:[["Ma faauta,", "And behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua lē ona pau lea. Ona ua matagofie naua i luga o mauga vae o ia o lē na te aumai tala e lelei,", "this is not all. For O how beautiful upon the mountains are the feet of him that bringeth good tidings,"], ["o lē o le faavae o le filemu ,", "that is the founder of peace,"], ["ioe,", "yea,"], ["o le Alii lava lea,", "even the Lord,"], ["o lē ua togiola e ia ona tagata;", "who has redeemed his people;"], ["ioe,", "yea,"], ["o ia o lē ua tuuina mai e ia le olataga i ona tagata;", "him who has granted salvation unto his people;"]]},
  {num:19,words:[["Ona a na leai le togiola ua faia e ia mo ona tagata,", "For were it not for the redemption which he hath made for his people,"], ["lea na saunia mai le faavaega o le lalolagi,", "which was prepared from the foundation of the world,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["a na leai lenei togiola,", "were it not for this,"], ["po ua fano tagata uma.", "all mankind must have perished."]]},
  {num:20,words:[["Ae faauta,", "But behold,"], ["o le a motusia noataga o le oti,", "the bands of death shall be broken,"], ["ma nofotupu le Alo,", "and the Son reigneth,"], ["ma ua ia te ia le pule i luga o e ua oti;", "and hath power over the dead;"], ["o lea,", "therefore,"], ["ua aumai e ia le toetutu mai o e ua oti.", "he bringeth to pass the resurrection of the dead."]]},
  {num:21,words:[["Ma e i ai se toetutu e oo mai,", "And there cometh a resurrection,"], ["o se ulua'i toetutu mai lea;", "even a first resurrection;"], ["ioe,", "yea,"], ["o se toetutu mai lea o i latou o e na i ai,", "even a resurrection of those that have been,"], ["ma e o loo i ai,", "and who are,"], ["ma e o le a i ai,", "and who shall be,"], ["seia oo mai lava i le toetu mai o Keriso—ona o le a faapea ona ta'ua o ia.", "even until the resurrection of Christ—for so shall he be called."]]},
  {num:22,words:[["Ma o lenei,", "And now,"], ["o le toetutu mai o perofeta uma,", "the resurrection of all the prophets,"], ["ma i latou uma o e na talitonu ia latou upu,", "and all those that have believed in their words,"], ["po o i latou uma o e sa tausi i poloaiga a le Atua,", "or all those that have kept the commandments of God,"], ["o le a oo mai i le ulua'i toetutu;", "shall come forth in the first resurrection;"], ["o lea,", "therefore,"], ["o i latou ia o le ulua'i toetutu mai.", "they are the first resurrection."]]},
  {num:23,words:[["E faatutu mai i latou e mau faatasi ma le Atua o lē na togiolaina i latou;", "They are raised to dwell with God who has redeemed them;"], ["o lea ua latou maua ai le ola e faavavau e ala ia Keriso,", "thus they have eternal life through Christ,"], ["o lē na ia motusia noataga o le oti.", "who has broken the bands of death."]]},
  {num:24,words:[["Ma o i latou ia o e ua i ai se vaega i le ulua'i toetutu;", "And these are those who have part in the first resurrection;"], ["ma o i latou ia o e na maliliu ae lei afio mai Keriso,", "and these are they that have died before Christ came,"], ["i lo latou lē malamalama,", "in their ignorance,"], ["ona sa lei folafoa atu ia te i latou le olataga . Ma e faapea ona faataunuu e le Alii le toefuataiga o i latou ia;", "not having salvation declared unto them. And thus the Lord bringeth about the restoration of these;"], ["ma ua i ai sa latou vaega i le ulua'i toetutu,", "and they have a part in the first resurrection,"], ["pe ua maua le ola e faavavau,", "or have eternal life,"], ["ona ua togiolaina e le Alii.", "being redeemed by the Lord."]]},
  {num:25,words:[["Ma ua maua foi e fanau laiti le ola e faavavau.", "And little children also have eternal life."]]},
  {num:26,words:[["Ae faauta,", "But behold,"], ["ma matata'u ,", "and fear,"], ["ma tetete i luma o le Atua,", "and tremble before God,"], ["ona ua tatau ona outou tetete;", "for ye ought to tremble;"], ["ona e lē togiolaina e le Alii soo se tasi faapea o e e fouvale ia te ia ma oti ia latou agasala;", "for the Lord redeemeth none such that rebel against him and die in their sins;"], ["ioe,", "yea,"], ["i latou uma ia o e na fano ia latou agasala talu mai le amataga o le lalolagi,", "even all those that have perished in their sins ever since the world began,"], ["o e na fouvale ma le loto i ai e faasaga i le Atua,", "that have wilfully rebelled against God,"], ["o e sa latou iloa poloaiga a le Atua,", "that have known the commandments of God,"], ["ae sa latou lē fia tausiaina;", "and would not keep them;"], ["o i latou ia e leai sa latou vaega i le ulua'i toetutu.", "these are they that have no part in the first resurrection."]]},
  {num:27,words:[["O lea pe ua lē tatau ai ea ona outou tetete? Ona e lē oo mai le olataga i ni tagata faapea;", "Therefore ought ye not to tremble? For salvation cometh to none such;"], ["ona e lei togiolaina e le Alii se tagata faapea;", "for the Lord hath redeemed none such;"], ["ioe, pe mafai foi e le Alii ona togiola ni tagata faapea;", "yea,"], ["ona e lē mafai e ia ona teena o ia lava;", "neither can the Lord redeem such;"], ["ona e le mafai ona teena e ia le faamasinotonu ,", "for he cannot deny himself;"], ["a ua i ai ana aiā.", "for he cannot deny justice when it has its claim."]]},
  {num:28,words:[["Ma o lenei ou te fai atu ia te outou e oo mai le taimi o le a folafola atu ai le olataga a le Alii i atunuu uma,", "And now I say unto you that the time shall come that the salvation of the Lord shall be declared to every nation,"], ["ituaiga,", "kindred,"], ["gagana,", "tongue,"], ["ma nuu.", "and people."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["le Alii e,", "Lord,"], ["o le a sii a'e e au leoleo o latou leo;", "thy watchmen shall lift up their voice;"], ["ma o le a latou pepese faatasi i le leo e tasi;", "with the voice together shall they sing;"], ["ona o le a latou vaai mata i le mata,", "for they shall see eye to eye,"], ["pe a toe aumai Siona e le Alii.", "when the Lord shall bring again Zion."]]},
  {num:30,words:[["Alalaga ia i le olioli,", "Break forth into joy,"], ["pepese faatasi,", "sing together,"], ["outou nofoaga tuufua o Ierusalema;", "ye waste places of Jerusalem;"], ["ona ua faamafanafanaina e le Alii ona tagata,", "for the Lord hath comforted his people,"], ["ua togiola e ia Ierusalema.", "he hath redeemed Jerusalem."]]},
  {num:31,words:[["Ua afe e le Alii lona aao paia i mata o atunuu uma;", "The Lord hath made bare his holy arm in the eyes of all the nations;"], ["ma o le a vaai tuluiga uma o le lalolagi i le olataga a lo tatou Atua.", "and all the ends of the earth shall see the salvation of our God."]]},
];
renderVerseSet(mo_ch_15_Verses, 'mo-ch15-verses');

var mo_ch_16_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona tautala atu e Apinati nei upu sa faaloaloa atu e ia lona lima ma fai atu:", "And now,"], ["E oo mai le taimi o le a vaai ai tagata uma i le olataga a le Alii;", "it came to pass that after Abinadi had spoken these words he stretched forth his hand and said:"], ["pe a oo ina vaai mata i le mata atunuu uma,", "The time shall come when all shall see the salvation of the Lord; when every nation,"], ["ituaiga,", "kindred,"], ["gagana,", "tongue,"], ["ma nuu ma latou ta'utino atu i luma o le Atua ua tonu ana faamasinoga.", "and people shall see eye to eye and shall confess before God that his judgments are just."]]},
  {num:2,words:[["Ma ona tutuli ai lea i fafo o e amioleaga,", "And then shall the wicked be cast out,"], ["ma o le a i ai se pogai o le a latou uiō ai,", "and they shall have cause to howl,"], ["ma tagitu'i ,", "and weep,"], ["ma tagiauē,", "and wail,"], ["ma lilivau ai o latou nifo;", "and gnash their teeth;"], ["ma o lenei ona sa latou lē fia faalogo i le siufofoga o le Alii;", "and this because they would not hearken unto the voice of the Lord;"], ["o lea ua lē togiolaina ai i latou e le Alii.", "therefore the Lord redeemeth them not."]]},
  {num:3,words:[["Ona ua latou faaletino ma faaletiapolo,", "For they are carnal and devilish,"], ["ma ua i ai i le tiapolo le mana i luga o i latou;", "and the devil has power over them;"], ["ioe,", "yea,"], ["lena lava gata tuai o lē na faaseseina o tatou uluai matua,", "even that old serpent that did beguile our first parents,"], ["le pogai lea o lo laua pauu ;", "which was the cause of their fall;"], ["o le pogai lea na avea ai tagata uma ma tagata faaletino,", "which was the cause of all mankind becoming carnal,"], ["nautino,", "sensual,"], ["faaletiapolo,", "devilish,"], ["ua iloa le leaga mai le lelei,", "knowing evil from good,"], ["ma tuu atu i latou lava e pulea e le tiapolo.", "subjecting themselves to the devil."]]},
  {num:4,words:[["Sa faapea ona se ai o tagata uma;", "Thus all mankind were lost;"], ["ma faauta, po ua latou se ai e lē gata,", "and behold,"], ["pe a na lē togiolaina e le Atua ona tagata mai lo latou tulaga se ma pa'ū.", "they would have been endlessly lost were it not that God redeemed his people from their lost and fallen state."]]},
  {num:5,words:[["Ae ia manatua o lē e tumau pea i lona lava natura faaletino,", "But remember that he that persists in his own carnal nature,"], ["ma alu pea i ala o le agasala ma le fouvale faasaga i le Atua,", "and goes on in the ways of sin and rebellion against God,"], ["e tumau pea i lona tulaga pa'ū ma ua i ai i le tiapolo le mana uma i ona luga.", "remaineth in his fallen state and the devil hath all power over him."], ["O lea e pei ai o ia e lei faia se togiola mo ia,", "Therefore,"], ["ona ua avea o ia ma fili i le Atua;", "he is as though there was no redemption made, being an enemy to God;"], ["ma o le tiapolo foi o se fili i le Atua.", "and also is the devil an enemy to God."]]},
  {num:6,words:[["Ma o lenei a na fai e lē afio mai Keriso i le lalolagi,", "And now if Christ had not come into the world,"], ["i le tautala lea faatatau i mea o le a oo mai e peiseai ua uma ona oo mai,", "speaking of things to come as though they had already come,"], ["po ua leai se togiola.", "there could have been no redemption."]]},
  {num:7,words:[["Ma a na fai e lei toetu mai Keriso mai i e na oti,", "And if Christ had not risen from the dead,"], ["pe ua motusia e ia noataga o le oti ina ia lē manumalo le tuugamau,", "or have broken the bands of death that the grave should have no victory,"], ["ma ina ia leai se tui o le oti,", "and that death should have no sting,"], ["po ua leai se toetutu mai.", "there could have been no resurrection."]]},
  {num:8,words:[["Peitai ua i ai se toetutu ,", "But there is a resurrection,"], ["o lea ua leai ai se manumalo i le tuugamau, ma ua tofatumoanaina ia Keriso,", "therefore the grave hath no victory,"], ["le tui o le oti .", "and the sting of death is swallowed up in Christ."]]},
  {num:9,words:[["O ia o le malamalama ma le ola o le lalolagi;", "He is the light and the life of the world;"], ["ioe,", "yea,"], ["o se malamalama e lē gata,", "a light that is endless,"], ["e lē mafai lava ona faapouliuligia;", "that can never be darkened;"], ["ioe,", "yea,"], ["ma se ola foi e lē gata,", "and also a life which is endless,"], ["e lē mafai ona toe i ai se oti.", "that there can be no more death."]]},
  {num:10,words:[["E oo i lenei tino faaletino o le a faaofuina i le tino ola pea,", "Even this mortal shall put on immortality,"], ["ma o lenei tino pala o le a faaofuina i le tino lē pala,", "and this corruption shall put on incorruption,"], ["ma o le a aumai e tutu i luma o le nofoa faamasino a le Atua,", "and shall be brought to stand before the bar of God,"], ["e faamasino e ia e tusa ma a latou galuega pe lelei pe leaga.", "to be judged of him according to their works whether they be good or whether they be evil—"]]},
  {num:11,words:[["Afai e lelei a latou galuega,", "If they be good,"], ["e toetutu mai i le ola ma le fiafia e lē gata;", "to the resurrection of endless life and happiness;"], ["ae afai e leaga a latou galuega,", "and if they be evil,"], ["e toetutu mai i le malaia e lē gata,", "to the resurrection of endless damnation,"], ["ona ua tuuina atu i latou i le tiapolo,", "being delivered up to the devil,"], ["o lē ua pule ia te i latou,", "who hath subjected them,"], ["o le malaia lea—", "which is damnation—"]]},
  {num:12,words:[["Ona sa o i latou e tusa ma o latou lava loto ma manaoga faaletino;", "Having gone according to their own carnal wills and desires;"], ["ona sa latou lē valaau atu lava i le Alii a'o faaloloa mai aao o le alofa mutimutivale ia te i latou;", "having never called upon the Lord while the arms of mercy were extended towards them;"], ["ona sa faaloloa mai ia te i latou aao o le alofa mutimutivale,", "for the arms of mercy were extended towards them,"], ["ae sa latou lē mananao i ai;", "and they would not;"], ["sa lapataia i latou e uiga ia latou amioletonu ae sa latou lē fia o ese mai ai;", "they being warned of their iniquities and yet they would not depart from them;"], ["ma sa poloaiina i latou ia salamo ae sa latou lē fia salamo.", "and they were commanded to repent and yet they would not repent."]]},
  {num:13,words:[["Ma o lenei,", "And now,"], ["pe ua lē tatau ea ona outou tetete ma salamo ia outou agasala,", "ought ye not to tremble and repent of your sins,"], ["ma manatua ua nao Keriso lava e mafai ona faaolaina ai outou?", "and remember that only in and through Christ ye can be saved?"]]},
  {num:14,words:[["O lea,", "Therefore,"], ["afai ua outou aoao atu le tulafono a Mose,", "if ye teach the law of Moses,"], ["ia aoao atu foi o se ata lea o mea o le a oo mai—", "also teach that it is a shadow of those things which are to come—"]]},
  {num:15,words:[["Ia aoao atu ia te i latou o le togiola e ala mai ia Keriso le Alii,", "Teach them that redemption cometh through Christ the Lord,"], ["o lē o ia lava lea o le Tamā Faavavau. Amene.", "who is the very Eternal Father. Amen."]]},
];
renderVerseSet(mo_ch_16_Verses, 'mo-ch16-verses');

var mo_ch_17_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona faaiu atu e Apinati nei upu,", "And now it came to pass that when Abinadi had finished these sayings,"], ["sa poloai atu le tupu i faitaulaga ia latou ave o ia ma faia ia fasioti ia te ia.", "that the king commanded that the priests should take him and cause that he should be put to death."]]},
  {num:2,words:[["Peitai sa i ai se tasi i totonu o i latou o lona igoa o Alema ,", "But there was one among them whose name was Alma,"], ["o ia foi o se e tupuga mai ia Nifae. Ma o ia o se alii talavou,", "he also being a descendant of Nephi. And he was a young man,"], ["ma sa talitonu o ia i upu na tautalaina e Apinati,", "and he believed the words which Abinadi had spoken,"], ["ona sa iloa e ia e uiga i le amioletonu lea sa molimau atu ai Apinati e faasaga ia te i latou;", "for he knew concerning the iniquity which Abinadi has testified against them;"], ["o lea sa amata ai ona aioi atu o ia i le tupu ia aua ne'i ita o ia ia Apinati,", "therefore he began to plead with the king that he would not be angry with Abinadi,"], ["ae tuu o ia e alu ese atu i le filemu.", "but suffer that he might depart in peace."]]},
  {num:3,words:[["Peitai sa atili ita le tupu,", "But the king was more wroth,"], ["ma faia ia tuli i fafo Alema mai totonu o i latou,", "and caused that Alma should be cast out from among them,"], ["ma auina atu ana auauna e tuliloa ia te ia ina ia latou fasioti ia te ia.", "and sent his servants after him that they might slay him."]]},
  {num:4,words:[["Peitai sa sola o ia mai i o latou luma ma lafi o ia sa latou le maua ai o ia. Ma a'o lafi o ia mo ni aso e tele sa tusi e ia upu uma na tautalaina e Apinati.", "But he fled from before them and hid himself that they found him not. And he being concealed for many days did write all the words which Abinadi had spoken."]]},
  {num:5,words:[["Ma sa oo ina faia e le tupu ia si'o e ana leoleo Apinati ma pu'e o ia;", "And it came to pass that the king caused that his guards should surround Abinadi and take him;"], ["ma sa latou saisai o ia ma lafo i totonu o le falepuipui.", "and they bound him and cast him into prison."]]},
  {num:6,words:[["Ma ina ua mavae aso e tolu,", "And after three days,"], ["ina ua uma ona fono o ia faatasi ma ana faitaulaga,", "having counseled with his priests,"], ["sa faia e ia ia toe aumai o ia i ona luma.", "he caused that he should again be brought before him."]]},
  {num:7,words:[["Ma sa fai atu o ia ia te ia:", "And he said unto him:"], ["Apinati,", "Abinadi,"], ["ua matou maua se tuua'iga e faasaga ia te oe,", "we have found an accusation against thee,"], ["ma ua tatau le oti ia te oe.", "and thou art worthy of death."]]},
  {num:8,words:[["Ona sa e fai mai o le a afio mai le Atua lava ia i lalo i totonu o le fanauga a tagata;", "For thou hast said that God himself should come down among the children of men;"], ["ma o lenei,", "and now,"], ["ona o lenei pogai o le a fasioti ai oe vagana ai ua e toe faafo'ia upu leaga uma na e tautalagia e uiga ia te a'u ma lo'u nuu.", "for this cause thou shalt be put to death unless thou wilt recall all the words which thou hast spoken evil concerning me and my people."]]},
  {num:9,words:[["O lenei sa fai atu Apinati ia te ia:", "Now Abinadi said unto him:"], ["Ou te fai atu ia te oe,", "I say unto you,"], ["ou te lē faafo'ia upu na ou tautala atu ai ia te oe e uiga i lenei nuu,", "I will not recall the words which I have spoken unto you concerning this people,"], ["ona ua moni;", "for they are true;"], ["ma ina ia e iloa lo latou moni o lea ua ou tuu atu ai a'u lava ia ia ou pa'ū atu i o outou lima.", "and that ye may know of their surety I have suffered myself that I have fallen into your hands."]]},
  {num:10,words:[["Ioe,", "Yea,"], ["ma o le a ou tigaina e oo lava i le oti,", "and I will suffer even until death,"], ["ma ou te lē faafo'ia lava a'u upu,", "and I will not recall my words,"], ["ae o le a latou tutu o se molimau e faasaga ia te outou.", "and they shall stand as a testimony against you."], ["Ma afai tou te fasiotia a'u, o le a outou faamasaaina se toto lē sala ,", "And if ye slay me ye will shed innocent blood,"], ["ma o le a tu foi lea o se molimau e faasaga ia te outou i le aso gataaga.", "and this shall also stand as a testimony against you at the last day."]]},
  {num:11,words:[["Ma o lenei sa toeitiiti a tatala atu o ia e le tupu o Noa,", "And now king Noah was about to release him,"], ["ona sa mata'u o ia i ana upu;", "for he feared his word;"], ["ona sa fefe o ia ne'i oo mai i ona luga faamasinoga a le Atua.", "for he feared that the judgments of God would come upon him."]]},
  {num:12,words:[["Peitai sa sii i luga e faitaulaga o latou leo e faasaga ia te ia,", "But the priests lifted up their voices against him,"], ["ma amata ona latou tuua'i o ia,", "and began to accuse him,"], ["fai mai:", "saying:"], ["Ua upu leaga o ia i le tupu. O lea na oso ai le ita o le tupu e faasaga ia te ia,", "He has reviled the king. Therefore the king was stirred up in anger against him,"], ["ma sa tuu atu e ia o ia ina ia fasiotia.", "and he delivered him up that he might be slain."]]},
  {num:13,words:[["Ma sa oo ina latou ave o ia ma saisai ia te ia,", "And it came to pass that they took him and bound him,"], ["ma susunu lona tino i fusi laau,", "and scourged his skin with faggots,"], ["ioe,", "yea,"], ["seia oti.", "even unto death."]]},
  {num:14,words:[["Ma o lenei ina ua amata ona mu o ia i mumū o le afi,", "And now when the flames began to scorch him,"], ["sa alaga mai o ia ia te i latou,", "he cried unto them,"], ["fai mai:", "saying:"]]},
  {num:15,words:[["Faauta,", "Behold,"], ["e pei ona outou faia ia te a'u,", "even as ye have done unto me,"], ["o le a faapea lava ona oo ina faia e a outou fanau ia mafatia le toatele i tiga ua ou mafatia ai,", "so shall it come to pass that thy seed shall cause that many shall suffer the pains that I do suffer,"], ["o tiga lava ia o le oti i le afi;", "even the pains of death by fire;"], ["ma o lenei ona ua latou talitonu i le olataga a le Alii lo latou Atua.", "and this because they believe in the salvation of the Lord their God."]]},
  {num:16,words:[["Ma e oo ina o le a faapuapuagatiaina outou i ituaiga o faama'i eseese ona o a outou amioletonu.", "And it will come to pass that ye shall be afflicted with all manner of diseases because of your iniquities."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["ma o le a taia outou i itu uma lava,", "and ye shall be smitten on every hand,"], ["ma o le a tulia ma faataapeapeina outou i lea mea ma lea mea,", "and shall be driven and scattered to and fro,"], ["e pei lava ona tulia se lafu segisegi e manu 'aivao ma fe'ai.", "even as a wild flock is driven by wild and ferocious beasts."]]},
  {num:18,words:[["Ma i lena aso o le a tulia ai outou,", "And in that day ye shall be hunted,"], ["ma o le a ave outou e lima o o outou fili,", "and ye shall be taken by the hand of your enemies,"], ["ma ona outou mafatia ai lea,", "and then ye shall suffer,"], ["e pei lava ona ou mafatia,", "as I suffer,"], ["i tiga o le oti i le afi.", "the pains of death by fire."]]},
  {num:19,words:[["E faapena ona faaoo mai e le Atua le tauimasui i luga o i latou o e latou te faaumatiaina ona tagata. Le Atua e,", "Thus God executeth vengeance upon those that destroy his people. O God,"], ["talia mai ia lo'u agaga.", "receive my soul."]]},
  {num:20,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona fai atu e Apinati o nei upu,", "when Abinadi had said these words,"], ["sa pa'ū o ia i lalo,", "he fell,"], ["ina ua mafatia i le oti i le afi;", "having suffered death by fire;"], ["ioe,", "yea,"], ["ina ua fasiotia o ia ona sa lē faafitia e ia poloaiga a le Atua,", "having been put to death because he would not deny the commandments of God,"], ["ma faamau e ia le moni o ana upu i lona maliu.", "having sealed the truth of his words by his death."]]},
];
renderVerseSet(mo_ch_17_Verses, 'mo-ch17-verses');

var mo_ch_18_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo ina salamo Alema,", "it came to pass that Alma,"], ["o lē na sola mai auauna a le tupu o Noa,", "who had fled from the servants of king Noah,"], ["i ana agasala ma ana amioletonu,", "repented of his sins and iniquities,"], ["ma sa alu atu faalilolilo o ia i totonu o le nuu,", "and went about privately among the people,"], ["ma amata ona ia aoao atu upu a Apinati—", "and began to teach the words of Abinadi—"]]},
  {num:2,words:[["Ioe,", "Yea,"], ["e uiga i mea o le a oo mai,", "concerning that which was to come,"], ["ma e uiga foi i le toetutu mai o e ua oti,", "and also concerning the resurrection of the dead,"], ["ma le togiolaina o tagata,", "and the redemption of the people,"], ["lea o le a faataunuuina e ala i le mana ,", "which was to be brought to pass through the power,"], ["ma mafatiaga,", "and sufferings,"], ["ma le maliu o Keriso,", "and death of Christ,"], ["ma lona toetu mai ma lona afio ae i le lagi.", "and his resurrection and ascension into heaven."]]},
  {num:3,words:[["Ma o le toatele o e sa fia faalogo i ana upu sa aoaoina e ia. Ma sa ia aoaoina i latou faalilolilo,", "And as many as would hear his word he did teach. And he taught them privately,"], ["ina ia le iloa e le tupu. Ma e toatele sa talitonu i ana upu.", "that it might not come to the knowledge of the king. And many did believe his words."]]},
  {num:4,words:[["Ma sa oo o le toatele o i latou o e sa talitonu ia te ia sa o atu i se nofoaga sa ta'ua o Mamona,", "And it came to pass that as many as did believe him did go forth to a place which was called Mormon, having received its name from the king,"], ["o se igoa na faaigoa ai e le tupu,", "being in the borders of the land having been infested,"], ["ma sa i tuaoi o le laueleele sa i ai vaitaimi po o tau sa mau ai le tele o manu 'aivao.", "by times or at seasons, by wild beasts."]]},
  {num:5,words:[["O lenei,", "Now,"], ["sa i ai i Mamona se puna o vai manino,", "there was in Mormon a fountain of pure water,"], ["ma o iina sa alu atu i ai Alema,", "and Alma resorted thither,"], ["ona sa i ai i iina lata ane i le vai se vaovao o laau laiti,", "there being near the water a thicket of small trees,"], ["sa faalafi ai e ia o ia lava i le ao mai sailiga a le tupu.", "where he did hide himself in the daytime from the searches of the king."]]},
  {num:6,words:[["Ma sa oo ina o atu iina le toatele o i latou sa talitonu ia te ia e faalogologo i ana upu.", "And it came to pass that as many as believed him went thither to hear his words."]]},
  {num:7,words:[["Ma sa oo ina ua mavae ni aso e tele sa toatele se vaega o tagata sa faapotopoto atu i le nofoaga lea o Mamona,", "And it came to pass after many days there were a goodly number gathered together at the place of Mormon,"], ["e faalogologo i upu a Alema. Ioe,", "to hear the words of Alma. Yea,"], ["sa faapotopoto faatasi i latou uma o e na talitonu i ana upu,", "all were gathered together that believed on his word,"], ["e faalogologo ia te ia. Ma sa ia aoaoina i latou,", "to hear him. And he did teach them,"], ["ma talai atu ia te i latou le salamo,", "and did preach unto them repentance,"], ["ma le togiola,", "and redemption,"], ["ma le faatuatua i le Alii.", "and faith on the Lord."]]},
  {num:8,words:[["Ma sa oo ina fai atu o ia ia te i latou:", "And it came to pass that he said unto them:"], ["Faauta,", "Behold,"], ["o vai nei o Mamona (ona sa faapea ona ta'ua o ia vai) ma o lenei,", "here are the waters of Mormon (for thus were they called) and now,"], ["ona ua outou mananao e o mai i le lafu a le Atua,", "as ye are desirous to come into the fold of God,"], ["ma ta'ua o ona tagata,", "and to be called his people,"], ["ma outou loto e tauave avega a le tasi,", "and are willing to bear one another’s burdens,"], ["ina ia māmā;", "that they may be light;"]]},
  {num:9,words:[["Ioe,", "Yea,"], ["ma outou loto e faanoanoa faatasi ma e e faanoanoa;", "and are willing to mourn with those that mourn;"], ["ioe,", "yea,"], ["ma faamafanafana atu ia te i latou o e e manaomia le faamafanafanaga,", "and comfort those that stand in need of comfort,"], ["ma tutu o ni molimau a le Atua i taimi uma ma i mea uma,", "and to stand as witnesses of God at all times and in all things,"], ["ma i nofoaga uma atonu tou te i ai,", "and in all places that ye may be in,"], ["seia oo lava i le oti,", "even until death,"], ["ina ia mafai ona togiolaina outou e le Atua,", "that ye may be redeemed of God,"], ["ma faitauina faatasi ma i latou o le ulua'i toetutu,", "and be numbered with those of the first resurrection,"], ["ina ia mafai ona outou maua le ola e faavavau—", "that ye may have eternal life—"]]},
  {num:10,words:[["O lenei ou te fai atu ia te outou,", "Now I say unto you,"], ["afai o le manao lea o o outou loto,", "if this be the desire of your hearts,"], ["se a se mea tou te tetee ai i le papatisoina i le suafa o le Alii,", "what have you against being baptized in the name of the Lord,"], ["o se molimau i ona luma ua outou ulu atu i se feagaiga faatasi ma ia,", "as a witness before him that ye have entered into a covenant with him,"], ["o le a outou auauna atu ia te ia ma tausi ana poloaiga,", "that ye will serve him and keep his commandments,"], ["ina ia mafai ona liligi atili tele mai e ia lona agaga i luga o outou?", "that he may pour out his Spirit more abundantly upon you?"]]},
  {num:11,words:[["Ma o lenei ina ua faalogo mai tagata i nei upu,", "And now when the people had heard these words,"], ["sa pati o latou lima i le olioli,", "they clapped their hands for joy,"], ["ma alalaga mai:", "and exclaimed:"], ["O le manao lea o o matou loto.", "This is the desire of our hearts."]]},
  {num:12,words:[["Ma o lenei sa oo ina ave e Alema o Helama,", "And now it came to pass that Alma took Helam,"], ["o ia lea o se tasi o tagata muamua,", "he being one of the first,"], ["ma ua alu atu ma ua tu i totonu o le vai,", "and went and stood forth in the water,"], ["ma alaga,", "and cried,"], ["ua fai mai:", "saying:"], ["Le Alii e,", "O Lord,"], ["liligi mai lou Agaga i luga o lau auauna,", "pour out thy Spirit upon thy servant,"], ["ina ia mafai ona faia e ia lenei galuega ma le paia o le loto.", "that he may do this work with holiness of heart."]]},
  {num:13,words:[["Ma ina ua uma ona fai atu e ia o nei upu,", "And when he had said these words,"], ["sa oo mai i luga o ia le Agaga o le Alii,", "the Spirit of the Lord was upon him,"], ["ma sa fai atu o ia:", "and he said:"], ["Helama e,", "Helam,"], ["ona ua tuuina mai ia te a'u le pule mai le Atua Malosi Aoao,", "I baptize thee, having authority from the Almighty God,"], ["ou te papatiso atu ia te oe o se molimau ua e ulu atu i se feagaiga e auauna atu ia te ia seia oo ina e oti e tusa ai ma le tino faaletino;", "as a testimony that ye have entered into a covenant to serve him until you are dead as to the mortal body;"], ["ma ia liligi mai le Agaga o le Alii i ou luga;", "and may the Spirit of the Lord be poured out upon you;"], ["ma ia tuuina mai e ia ia te oe le ola e faavavau,", "and may he grant unto you eternal life,"], ["e ala i le togiola a Keriso,", "through the redemption of Christ,"], ["o lē na saunia e ia mai le faavaega o le lalolagi.", "whom he has prepared from the foundation of the world."]]},
  {num:14,words:[["Ma ina ua uma ona fai atu e Alema o nei upu,", "And after Alma had said these words,"], ["sa tatanumia uma Alema ma Helama i le vai;", "both Alma and Helam were buried in the water;"], ["ma sa laua tutu a'e ma o mai i fafo o le vai ma le olioli,", "and they arose and came forth out of the water rejoicing,"], ["ua tutumu i le Agaga.", "being filled with the Spirit."]]},
  {num:15,words:[["Ma sa toe ave e Alema se tasi tagata,", "And again,"], ["ma toe alu atu faalua i totonu o le vai,", "Alma took another,"], ["ma papatiso ia te ia e pei o lē na muamua,", "and went forth a second time into the water, and baptized him according to the first,"], ["ae sa lē toe tanumiaina e ia o ia lava i le vai.", "only he did not bury himself again in the water."]]},
  {num:16,words:[["Ma o le ala lenei sa papatiso ai e ia i latou uma taitoatasi o e na o atu i le nofoaga o Mamona;", "And after this manner he did baptize every one that went forth to the place of Mormon;"], ["ma o lo latou aofai pe tusa ma le lua selau ma le fa agaga;", "and they were in number about two hundred and four souls;"], ["ioe,", "yea,"], ["ma sa papatisoina i latou i vai o Mamona,", "and they were baptized in the waters of Mormon,"], ["ma sa faatumuina i latou i le alofa tunoa o le Atua.", "and were filled with the grace of God."]]},
  {num:17,words:[["Ma sa ta'ua i latou o le ekalesia a le Atua,", "And they were called the church of God,"], ["po o le ekalesia a Keriso,", "or the church of Christ,"], ["mai le taimi lena i luma. Ma sa oo ina o soo se tasi sa papatisoina i le mana ma le pule a le Atua sa faaopoopo i lana ekalesia.", "from that time forward. And it came to pass that whosoever was baptized by the power and authority of God was added to his church."]]},
  {num:18,words:[["Ma sa oo ina faauu e Alema ia faitaulaga,", "And it came to pass that Alma,"], ["ona sa ia te ia le pule mai le Atua;", "having authority from God,"], ["sa faauu e ia faitaulaga e taitoatasi i le taitoalimagafulu o i latou,", "ordained priests;"], ["e talai atu ia te i latou,", "even one priest to every fifty of their number did he ordain to preach unto them,"], ["ma aoao i latou e uiga i mea e faatatau i le malo o le Atua.", "and to teach them concerning the things pertaining to the kingdom of God."]]},
  {num:19,words:[["Ma sa ia poloaiina i latou ia latou lē aoao atu se mea, vagana ai mea na ia aoao atu,", "And he commanded them that they should teach nothing save it were the things which he had taught,"], ["ma mea na fetalai mai i fofoga o perofeta paia.", "and which had been spoken by the mouth of the holy prophets."]]},
  {num:20,words:[["Ioe,", "Yea,"], ["sa ia poloaiina lava i latou ia latou lē aoao atu se mea, vagana ai le salamo ma le faatuatua i le Alii,", "even he commanded them that they should preach nothing save it were repentance and faith on the Lord,"], ["o lē ua togiolaina lona nuu.", "who had redeemed his people."]]},
  {num:21,words:[["Ma sa ia poloaiina i latou ia lē tatau ona i ai se finau o le tasi ma le isi,", "And he commanded them that there should be no contention one with another,"], ["ae e tatau ona latou tagai i luma ma le mata e tasi,", "but that they should look forward with one eye,"], ["i le faatuatua e tasi ma le papatisoga e tasi,", "having one faith and one baptism,"], ["ua fili faatasi o latou loto i le lotogatasi ma le alofa o le tasi i le isi.", "having their hearts knit together in unity and in love one towards another."]]},
  {num:22,words:[["Ma sa faapea ona ia poloaiina o i latou e talai atu. Ma sa faapea ona avea ai i latou ma fanau a le Atua.", "And thus he commanded them to preach. And thus they became the children of God."]]},
  {num:23,words:[["Ma sa ia poloaiina i latou ia latou tausi le aso sapati,", "And he commanded them that they should observe the sabbath day,"], ["ma tausi lona paia,", "and keep it holy,"], ["ma ia latou avatu foi i aso uma le faafetai i le Alii lo latou Atua.", "and also every day they should give thanks to the Lord their God."]]},
  {num:24,words:[["Ma sa ia poloaiina foi i latou e tatau i faitaulaga o e na ia faauuina ona galulue i o latou lava lima mo lo latou lava tausiga.", "And he also commanded them that the priests whom he had ordained should labor with their own hands for their support."]]},
  {num:25,words:[["Ma sa i ai se aso e tasi i vaiaso taitasi sa tuu ese faapitoa latou te potopoto faatasi ai e aoao tagata,", "And there was one day in every week that was set apart that they should gather themselves together to teach the people,"], ["ma tapuai atu i le Alii lo latou Atua,", "and to worship the Lord their God,"], ["o lenei foi,", "and also,"], ["i soo se taimi latou te mafai ai,", "as often as it was in their power,"], ["ona latou faapotopoto faatasi i latou lava.", "to assemble themselves together."]]},
  {num:26,words:[["Ma o faitaulaga,", "And the priests were not to depend upon the people for their support;"], ["ia aua ne'i faalagolago i le nuu mo le tausiga o i latou;", "but for their labor they were to receive the grace of God,"], ["ae ia latou maua le alofa tunoa o le Atua mo a latou galuega, ina ia mafai ona latou tutupu malolosi i le Agaga,", "that they might wax strong in the Spirit,"], ["i lo latou maua o le malamalama o le Atua,", "having the knowledge of God,"], ["ina ia mafai ona latou aoao atu ma le mana ma le pule mai le Atua.", "that they might teach with power and authority from God."]]},
  {num:27,words:[["Ma sa toe poloaiina e Alema e tatau i tagata o le ekalesia ona faasoa atu a latou mea,", "And again Alma commanded that the people of the church should impart of their substance,"], ["ia taitasi le tagata e tusa ma mea ua maua e ia; afai e tele mea ua maua e ia,", "every one according to that which he had;"], ["e tatau ia te ia ona faasoa tele atu;", "if he have more abundantly he should impart more abundantly;"], ["ma o ia o lē ua itiiti mea ua i ai,", "and of him that had but little,"], ["ia itiiti mea e manaomia mai ia te ia; ma o ia o lē ua leai ni mea,", "but little should be required;"], ["e tatau ona foa'i atu i ai.", "and to him that had not should be given."]]},
  {num:28,words:[["Ma sa tatau ona faapea ona latou faasoa atu o a latou mea i o latou lava loto malilie ma naunauga lelei i le Atua,", "And thus they should impart of their substance of their own free will and good desires towards God,"], ["ma ia i latou o faitaulaga o e e manaomia le fesoasoani,", "and to those priests that stood in need,"], ["ioe,", "yea,"], ["ma i agaga taitasi uma ua manaomia le fesoasoani,", "and to every needy,"], ["ma ua lē lavalava.", "naked soul."]]},
  {num:29,words:[["Ma o mea ia sa fai atu ai o ia ia te i latou,", "And this he said unto them,"], ["ona sa poloaiina ai o ia e le Atua;", "having been commanded of God;"], ["ma sa latou savavali sa'o i luma o le Atua,", "and they did walk uprightly before God,"], ["ma faasoa atu le tasi i le isi faaletino ma faaleagaga e tusa ma mea sa latou manaomia ma o latou manaoga.", "imparting to one another both temporally and spiritually according to their needs and their wants."]]},
  {num:30,words:[["Ma o lenei sa oo o nei mea uma sa faia i Mamona,", "And now it came to pass that all this was done in Mormon,"], ["ioe,", "yea,"], ["i tafatafa o vai o Mamona,", "by the waters of Mormon,"], ["i totonu o le vao sa lata ane i vai o Mamona;", "in the forest that was near the waters of Mormon;"], ["ioe,", "yea,"], ["o le nofoaga o Mamona,", "the place of Mormon,"], ["o vai o Mamona,", "the waters of Mormon,"], ["o le vao o Mamona,", "the forest of Mormon,"], ["sa matua matagofie i latou i le vaai a i latou o e na o atu i le malamalama o lo latou Togiola iina;", "how beautiful are they to the eyes of them who there came to the knowledge of their Redeemer;"], ["ioe,", "yea,"], ["ma amuia lava i latou,", "and how blessed are they,"], ["ona o le a latou pepese i lona viiga e faavavau.", "for they shall sing to his praise forever."]]},
  {num:31,words:[["Ma o nei mea sa faia i tuaoi o le laueleele,", "And these things were done in the borders of the land,"], ["ina ia le iloa i latou e le tupu.", "that they might not come to the knowledge of the king."]]},
  {num:32,words:[["Ae faauta,", "But behold,"], ["sa oo ina ua iloa e le tupu se fegasoloa'iga i totonu o le nuu,", "it came to pass that the king, having discovered a movement among the people,"], ["sa auina atu e ia ana auauna e vaavaai i latou.", "sent his servants to watch them."], ["O lea o le aso na latou faapotopoto faatasi ai i latou lava e faalogologo i le afioga a le Alii na maua ai i latou ma faailoa atu ai i latou i le tupu.", "Therefore on the day that they were assembling themselves together to hear the word of the Lord they were discovered unto the king."]]},
  {num:33,words:[["Ma o lenei sa oo ina fai mai le tupu ua faaoso e Alema le nuu ia fouvale e faasaga ia te ia;", "And now the king said that Alma was stirring up the people to rebellion against him;"], ["o lea na auina atu ai e ia lana autau e faaumatia i latou.", "therefore he sent his army to destroy them."]]},
  {num:34,words:[["Ma sa oo ina logo Alema ma tagata o le Alii e uiga i le o mai o le autau a le tupu;", "And it came to pass that Alma and the people of the Lord were apprised of the coming of the king’s army;"], ["o lea sa latou ave ai o latou faleie ma o latou aiga ma o ese atu i le vao.", "therefore they took their tents and their families and departed into the wilderness."]]},
  {num:35,words:[["Ma o lo latou faitau aofai e tusa ma le fa selau ma le limagafulu agaga.", "And they were in number about four hundred and fifty souls."]]},
];
renderVerseSet(mo_ch_18_Verses, 'mo-ch18-verses');

var mo_ch_19_Verses = [
  {num:1,words:[["Ma sa oo ina toe foi mai le autau a le tupu,", "And it came to pass that the army of the king returned,"], ["i le sailiga o le nuu o le Alii ae lē maua.", "having searched in vain for the people of the Lord."]]},
  {num:2,words:[["Ma o lenei faauta,", "And now behold,"], ["sa toaitiiti le autau a le tupu,", "the forces of the king were small,"], ["ona ua faaitiitia,", "having been reduced,"], ["ma sa amata ona i ai o se fevaevaeaiga i totonu o e na totoe o le nuu.", "and there began to be a division among the remainder of the people."]]},
  {num:3,words:[["Ma sa amata ona manavaina e le vaega toaitiiti o le nuu upu faamata'u e faasaga i le tupu,", "And the lesser part began to breathe out threatenings against the king,"], ["ma sa amata ona i ai o se finauga tele i totonu o i latou.", "and there began to be a great contention among them."]]},
  {num:4,words:[["Ma o lenei sa i ai i totonu o i latou se tagata na igoa ia Kitiona,", "And now there was a man among them whose name was Gideon,"], ["ma ona o ia o se tagata malosi ma o se fili foi i le tupu,", "and he being a strong man and an enemy to the king,"], ["o lea na se'i ai e ia lana pelu, ma tauto i lona ita,", "therefore he drew his sword,"], ["o le a ia fasioti i le tupu.", "and swore in his wrath that he would slay the king."]]},
  {num:5,words:[["Ma sa oo ina tau o ia ma le tupu;", "And it came to pass that he fought with the king;"], ["ma ina ua vaai atu le tupu o le a toilalo o ia ia te ia,", "and when the king saw that he was about to overpower him,"], ["sa sola o ia ma ua momo'e ma alu a'e i luga o le olo sa latalata ane i le malumalu.", "he fled and ran and got upon the tower which was near the temple."]]},
  {num:6,words:[["Ma sa tuliloa o ia e Kitiona ma toeitiiti lava alu a'e o ia i luga o le olo e fasioti le tupu,", "And Gideon pursued after him and was about to get upon the tower to slay the king,"], ["ae vaai atu le tupu faataamilo agai i le laueleele o Semulona,", "and the king cast his eyes round about towards the land of Shemlon,"], ["ma faauta,", "and behold,"], ["ua i ai le autau a sa Lamanā i totonu o tuaoi o le laueleele.", "the army of the Lamanites were within the borders of the land."]]},
  {num:7,words:[["Ma o lenei sa oo ina aioi mai le tupu i le atuatuvale o lona agaga,", "And now the king cried out in the anguish of his soul,"], ["ua fai mai:", "saying:"], ["Kitiona e,", "Gideon,"], ["faaola mai ia te a'u,", "spare me,"], ["ona ua oo mai sa Lamanā i o tatou luga,", "for the Lamanites are upon us,"], ["ma o le a latou faaumatia i tatou;", "and they will destroy us;"], ["ioe,", "yea,"], ["o le a latou faaumatia lo'u nuu.", "they will destroy my people."]]},
  {num:8,words:[["Ma o lenei sa lē popole tele le tupu e uiga i lona nuu nai lo lona popole e uiga i lona lava ola;", "And now the king was not so much concerned about his people as he was about his own life;"], ["e ui i lea,", "nevertheless,"], ["sa faasaoina e Kitiona lona ola.", "Gideon did spare his life."]]},
  {num:9,words:[["Ma sa poloaiina e le tupu le nuu ia latou sosola ese ae lei oo mai sa Lamanā,", "And the king commanded the people that they should flee before the Lamanites,"], ["ma sa muamua atu o ia lava i o latou luma,", "and he himself did go before them,"], ["ma latou sosola i le vao,", "and they did flee into the wilderness,"], ["faatasi ma o latou fafine ma a latou fanau.", "with their women and their children."]]},
  {num:10,words:[["Ma sa oo ina tuliloa i latou e sa Lamanā,", "And it came to pass that the Lamanites did pursue them,"], ["ma latou maua i latou,", "and did overtake them,"], ["ma amata ona fasioti i latou.", "and began to slay them."]]},
  {num:11,words:[["O lenei sa oo ina poloai atu le tupu ia te i latou ia tuu e tane uma a latou avā ma a latou fanau,", "Now it came to pass that the king commanded them that all the men should leave their wives and their children,"], ["ma sosola mai luma o sa Lamanā.", "and flee before the Lamanites."]]},
  {num:12,words:[["O lenei e toatele i latou sa latou lē fia tuua i latou,", "Now there were many that would not leave them,"], ["ae sa sili ia te i latou le nonofo ma fano faatasi ma i latou. Ae o le vaega na totoe sa latou tuua a latou avā ma a latou fanau ae sosola.", "but had rather stay and perish with them. And the rest left their wives and their children and fled."]]},
  {num:13,words:[["Ma o i latou o e na nonofo e faatasi ma a latou avā ma a latou fanau sa latou faia ia tutu atu o latou afafine lalelei ma aioi atu i a sa Lamanā ia aua ne'i o latou fasiotia i latou.", "And it came to pass that those who tarried with their wives and their children caused that their fair daughters should stand forth and plead with the Lamanites that they would not slay them."]]},
  {num:14,words:[["Ma sa oo ina alolofa sa Lamanā ia te i latou,", "And it came to pass that the Lamanites had compassion on them,"], ["ona ua latou sioa i le lalelei o o latou fafine.", "for they were charmed with the beauty of their women."]]},
  {num:15,words:[["O lea na faasao ai e sa Lamanā o latou ola,", "Therefore the Lamanites did spare their lives,"], ["ma ave i latou faatagataotaua ma toe ave i latou i le laueleele o Nifae,", "and took them captives and carried them back to the land of Nephi,"], ["ma tuu atu ia te i latou ia fai mo i latou le laueleele,", "and granted unto them that they might possess the land,"], ["i lalo o tuutuuga ia latou tuu atu le tupu o Noa i lima o sa Lamanā,", "under the conditions that they would deliver up king Noah into the hands of the Lamanites,"], ["ma tuu atu a latou meatotino,", "and deliver up their property,"], ["po o le afa e tasi o mea uma ua latou maua,", "even one half of all they possessed,"], ["o le afa e tasi o a latou auro,", "one half of their gold,"], ["ma a latou ario,", "and their silver,"], ["ma a latou mea taua uma,", "and all their precious things,"], ["ma faapea ona tatau ona latou totogi atu o lafoga i le tupu o sa Lamanā mai lea tausaga i lea tausaga.", "and thus they should pay tribute to the king of the Lamanites from year to year."]]},
  {num:16,words:[["Ma o lenei sa i ai se tasi o atalii o le tupu sa faatasi ma e na ave faatagataotauaina,", "And now there was one of the sons of the king among those that were taken captive,"], ["o lona igoa o Limae .", "whose name was Limhi."]]},
  {num:17,words:[["Ma o lenei sa lē manao Limae ia faaumatiaina lona tamā;", "And now Limhi was desirous that his father should not be destroyed;"], ["e ui i lea,", "nevertheless,"], ["sa lē pouliuli Limae i amioletonu a lona tamā, ae o ia lava ia,", "Limhi was not ignorant of the iniquities of his father,"], ["o se tagata amiotonu.", "he himself being a just man."]]},
  {num:18,words:[["Ma sa oo ina auina atu faalilolilo e Kitiona ni tagata i le vao,", "And it came to pass that Gideon sent men into the wilderness secretly,"], ["e saili le tupu ma i latou o e na faatasi ma ia. Ma sa oo ina latou fetaui ma tagata uma i le vao,", "to search for the king and those that were with him. And it came to pass that they met the people in the wilderness,"], ["vagana ai le tupu ma ana faitaulaga.", "all save the king and his priests."]]},
  {num:19,words:[["O lenei sa latou tauto i o latou loto latou te foi atu i le laueleele o Nifae,", "Now they had sworn in their hearts that they would return to the land of Nephi,"], ["ma afai ua fasiotia a latou avā ma a latou fanau,", "and if their wives and their children were slain,"], ["ma i latou foi o e sa nonofo faatasi ma i latou,", "and also those that had tarried with them,"], ["o le a latou saili e tauimasui,", "that they would seek revenge,"], ["ma fano foi faatasi ma i latou.", "and also perish with them."]]},
  {num:20,words:[["Ae sa poloai atu le tupu ia te i latou ia aua ne'i o latou toe foi atu;", "And the king commanded them that they should not return;"], ["ae sa latou feitai i le tupu,", "and they were angry with the king,"], ["ma faia ia faamafatia o ia,", "and caused that he should suffer,"], ["i le oti lava i le afi.", "even unto death by fire."]]},
  {num:21,words:[["Ma sa toeitiiti foi o latou ave i faitaulaga ma fasioti ia te i latou,", "And they were about to take the priests also and put them to death,"], ["peitai sa sosola ese i latou mai o latou luma.", "and they fled before them."]]},
  {num:22,words:[["Ma sa oo o le a latou toe foi atu i le laueleele o Nifae,", "And it came to pass that they were about to return to the land of Nephi,"], ["ae latou fetaui loa ma tagata a Kitiona. Ma sa ta'u atu e tagata a Kitiona ia te i latou mea uma ua oo ia latou avā ma a latou fanau;", "and they met the men of Gideon. And the men of Gideon told them of all that had happened to their wives and their children;"], ["ma ua tuu mai e sa Lamana ia te i latou e mafai ona latou fai mo i latou le laueleele i le totogi atu o se lafoga ia sa Lamanā o le afa e tasi o mea uma latou te maua.", "and that the Lamanites had granted unto them that they might possess the land by paying a tribute to the Lamanites of one half of all they possessed."]]},
  {num:23,words:[["Ma sa ta'u atu e le nuu i tagata a Kitiona ua latou fasiotia le tupu,", "And the people told the men of Gideon that they had slain the king,"], ["ma ua sosola ana faitaulaga mai ia te i latou ua o mamao atu i totonu o le vao.", "and his priests had fled from them farther into the wilderness."]]},
  {num:24,words:[["Ma sa oo ina ua uma ona latou faaiu o le tu masani,", "And it came to pass that after they had ended the ceremony,"], ["sa latou toe foi atu i le laueleele o Nifae ma le olioli,", "that they returned to the land of Nephi,"], ["ona sa lei fasiotia a latou avā ma a latou fanau;", "rejoicing, because their wives and their children were not slain;"], ["ma sa latou ta'u atu ia Kitiona le mea ua latou faia i le tupu.", "and they told Gideon what they had done to the king."]]},
  {num:25,words:[["Ma sa oo ina faia e le tupu o sa Lamanā se tautoga ia te i latou,", "And it came to pass that the king of the Lamanites made an oath unto them,"], ["o le a lē fasiotia i latou e lona nuu.", "that his people should not slay them."]]},
  {num:26,words:[["Ma sa faia foi e Limae,", "And also Limhi,"], ["ona o ia o le atalii o le tupu,", "being the son of the king,"], ["ma ona ua faaee e le nuu i ona luga le malo, se tautoga i le tupu o sa Lamanā,", "having the kingdom conferred upon him by the people,"], ["o le a totogi atu e ona tagata se lafoga ia te ia,", "made oath unto the king of the Lamanites that his people should pay tribute unto him,"], ["o le afa lea e tasi o mea uma latou te maua.", "even one half of all they possessed."]]},
  {num:27,words:[["Ma sa oo ina amata e Limae ona faatu le malo ma faatu le filemu i totonu o lona nuu.", "And it came to pass that Limhi began to establish the kingdom and to establish peace among his people."]]},
  {num:28,words:[["Ma sa faatutu faataamilo e le tupu o sa Lamanā leoleo i le laueleele,", "And the king of the Lamanites set guards round about the land,"], ["ina ia mafai ona taofi ai e ia le nuu o Limae i totonu o le laueleele,", "that he might keep the people of Limhi in the land,"], ["ina ia latou lē o ese atu i le vao;", "that they might not depart into the wilderness;"], ["ma sa tausi e ia ana leoleo mai le lafoga lea sa maua e ia mai ia sa Nifaē.", "and he did support his guards out of the tribute which he did receive from the Nephites."]]},
  {num:29,words:[["Ma o lenei sa maua e le tupu o Limae le filemu alua'i pea i lona malo i le va o le lua tausaga, sa lē faalavelave mai ai sa Lamanā ia te i latou,", "And now king Limhi did have continual peace in his kingdom for the space of two years,"], ["pe saili e faaumatia i latou.", "that the Lamanites did not molest them nor seek to destroy them."]]},
];
renderVerseSet(mo_ch_19_Verses, 'mo-ch19-verses');

var mo_ch_20_Verses = [
  {num:1,words:[["O lenei sa i ai i Semulona se nofoaga sa faapotopoto faatasi i ai e afafine o sa Lamanā i latou lava e pepese,", "Now there was a place in Shemlon where the daughters of the Lamanites did gather them– selves together to sing,"], ["ma sisiva,", "and to dance,"], ["ma latou fiafia ai.", "and to make themselves merry."]]},
  {num:2,words:[["Ma sa oo ina sa i ai se tasi aso sa faapotopoto faatasi ai se vaega toaitiiti o i latou e pepese ma sisiva.", "And it came to pass that there was one day a small number of them gathered together to sing and to dance."]]},
  {num:3,words:[["Ma o lenei o faitaulaga a le tupu o Noa,", "And now the priests of king Noah,"], ["ona sa mamā e toe foi atu i le aai o Nifae,", "being ashamed to return to the city of Nephi,"], ["ioe,", "yea,"], ["ma sa fefefe foi ne'i fasioti i latou e le nuu,", "and also fearing that the people would slay them,"], ["o lea na latou fefefe ai e toe foi atu ia latou avā ma a latou fanau.", "therefore they durst not return to their wives and their children."]]},
  {num:4,words:[["Ma ona sa latou nonofo i le vao,", "And having tarried in the wilderness,"], ["ma ina ua latou iloa afafine o sa Lamanā,", "and having discovered the daughters of the Lamanites,"], ["sa latou faapupuna ma lamalama ia te i latou.", "they laid and watched them;"]]},
  {num:5,words:[["Ma ina ua nao se toaitiiti o i latou sa potopoto faatasi e sisiva,", "And when there were but few of them gathered together to dance,"], ["sa latou o mai i fafo mai o latou lafitaga ma pupu'e i latou ma ave i latou i le vao;", "they came forth out of their secret places and took them and carried them into the wilderness;"], ["ioe,", "yea,"], ["e lua sefulu ma le fa afafine o sa Lamanā sa latou ave i le vao.", "twenty and four of the daughters of the Lamanites they carried into the wilderness."]]},
  {num:6,words:[["Ma sa oo ina ua iloa e sa Lamanā ua leiloloa o latou afafine,", "And it came to pass that when the Lamanites found that their daughters had been missing,"], ["sa latou feitai i le nuu o Limae,", "they were angry with the people of Limhi,"], ["ona sa latou manatu o le nuu o Limae ua faia lenei mea.", "for they thought it was the people of Limhi."]]},
  {num:7,words:[["O lea na latou auina mai ai a latou autau;", "Therefore they sent their armies forth;"], ["ioe,", "yea,"], ["e oo i le tupu sa muamua mai i luma o ona tagata; ma sa latou o mai i le laueleele o Nifae,", "even the king himself went before his people;"], ["e faaumatia le nuu o Limae.", "and they went up to the land of Nephi to destroy the people of Limhi."]]},
  {num:8,words:[["Ma o lenei sa iloa mai i latou e Limae mai le olo,", "And now Limhi had discovered them from the tower,"], ["e oo ia latou sauniuniga uma mo le taua sa iloa mai e ia;", "even all their preparations for war did he discover;"], ["o lea na faapotopoto faatasi ai e ia ona tagata,", "therefore he gathered his people together,"], ["ma lalafi faatalitali mo i latou i fanua ma vaomatua.", "and laid wait for them in the fields and in the forests."]]},
  {num:9,words:[["Ma sa oo ina ua oo mai sa Lamanā,", "And it came to pass that when the Lamanites had come up,"], ["sa amata ona osofaia o i latou e tagata o Limae mai o latou nofoaga faatalitali,", "that the people of Limhi began to fall upon them from their waiting places,"], ["ma amata ona fasioti i latou.", "and began to slay them."]]},
  {num:10,words:[["Ma sa oo ina matua vevesi tele lava le taua,", "And it came to pass that the battle became exceedingly sore,"], ["ona sa latou tau e pei o leona mo a latou manu pu'e e 'ai.", "for they fought like lions for their prey."]]},
  {num:11,words:[["Ma sa oo ina amata ona tutuli e tagata o Limae sa Lamanā mai i o latou luma;", "And it came to pass that the people of Limhi began to drive the Lamanites before them;"], ["ae sa lē tusa lo latou toatele ma le 'afa o sa Lamanā. Peitai sa latou tau mo o latou ola,", "yet they were not half so numerous as the  Lamanites. But they fought for their lives,"], ["ma mo a latou avā,", "and for their wives,"], ["ma mo a latou fanau;", "and for their children;"], ["o lea sa latou faamalolosi atu ai ma latou tau e pei o ni tarako.", "therefore they exerted themselves and like dragons did they fight."]]},
  {num:12,words:[["Ma sa oo ina latou maua le tupu o sa Lamanā i totonu o o latou tagata oti;", "And it came to pass that they found the king of the Lamanites among the number of their dead;"], ["peitai sa lei oti o ia,", "yet he was not dead,"], ["ae sa manu'a ma ua tuua o ia i luga o le eleele,", "having been wounded and left upon the ground,"], ["ona o le vave tele o le sola'aga a ona tagata.", "so speedy was the flight of his people."]]},
  {num:13,words:[["Ma sa latou ave o ia ma fusi i ona manu'a,", "And they took him and bound up his wounds,"], ["ma aumai o ia i luma o Limae,", "and brought him before Limhi,"], ["ma fai mai:", "and said:"], ["Faauta,", "Behold,"], ["o le tupu lenei o sa Lamanā;", "here is the king of the Lamanites;"], ["sa pa'ū o ia faatasi ma o latou tagata oti ona ua manu'a o ia,", "he having received a wound has fallen among their dead,"], ["ma ua latou tuua ai o ia;", "and they have left him;"], ["ma faauta,", "and behold,"], ["ua matou aumai o ia i ou luma;", "we have brought him before you;"], ["ma o lenei ia tatou fasioti ia te ia.", "and now let us slay him."]]},
  {num:14,words:[["Peitai sa fai atu Limae ia te i latou:", "But Limhi said unto them:"], ["Tou te lē fasioti ia te ia,", "Ye shall not slay him,"], ["a ia aumai o ia iinei sei ou vaai atu ia te ia. Ma sa latou aumai o ia. Ma sa fai atu Limae ia te ia:", "but bring him hither that I may see him. And they brought him. And Limhi said unto him:"], ["O le a le pogai ua outou o mai ai e sii taua faasaga mai i lo'u nuu? Faauta,", "What cause have ye to come up to war against my people? Behold,"], ["e lei solia e lo'u nuu le tautoga na ou faia ia te oe;", "my people have not broken the oath that I made unto you;"], ["o lea,", "therefore,"], ["aisea ua outou solia ai le tautoga na e fai mai i lo'u nuu?", "why should ye break the oath which ye made unto my people?"]]},
  {num:15,words:[["Ma o lenei sa fai mai le tupu:", "And now the king said:"], ["Ua ou solia le tautoga ona ua ave e lou nuu afafine o lo'u nuu;", "I have broken the oath because thy people did carry away the daughters of my people;"], ["o lea,", "therefore,"], ["o lo'u ita na ou faia ai ia o mai lo'u nuu e tau faasaga i lou nuu.", "in my anger I did cause my people to come up to war against thy people."]]},
  {num:16,words:[["Ma o lenei sa lei faalogo lava Limae i se mea e uiga i lenei mataupu;", "And now Limhi had heard nothing concerning this matter;"], ["o lea na fai atu ai o ia: O le a ou suesue i totonu o lo'u nuu ma o ai lava se tasi na faia lenei mea,", "therefore he said:"], ["o le a fano.", "I will search among my people and whosoever has done this thing shall perish."], ["O lea na fai ai e ia ia faia se suesuega i totonu o lona nuu.", "Therefore he caused a search to be made among his people."]]},
  {num:17,words:[["O lenei ina ua faalogo Kitiona i nei mea,", "Now when Gideon had heard these things,"], ["ona o ia o le kapeteni a le tupu,", "he being the king’s captain,"], ["sa alu atu o ia i luma ma fai atu i le tupu:", "he went forth and said unto the king:"], ["Ou te aioi atu ia te oe sei taofi,", "I pray thee forbear,"], ["ma aua le suesueina lenei nuu,", "and do not search this people,"], ["ma aua le tuua'ia lenei mea ia te i latou.", "and lay not this thing to their charge."]]},
  {num:18,words:[["Ona e te lē manatua faitaulaga a lou tamā,", "For do ye not remember the priests of thy father,"], ["o e na saili lenei nuu e faaumatia? Ma e lē o i ai ea i latou i le vao? Ma e lē o i latou ea ia o e na gaoia afafine o sa Lamanā?", "whom this people sought to destroy? And are they not in the wilderness? And are not they the ones who have stolen the daughters of the Lamanites?"]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ta'u atu nei mea i le tupu, ina ia mafai ona ta'u atu e ia i lona nuu ina ia mafai ona faamalilieina i latou faasaga mai ia te i tatou;", "and tell the king of these things,"], ["aua faauta,", "that he may tell his people that they may be pacified towards us;"], ["ua latou sauniuni nei e o mai e faasagatau mai ia te i tatou;", "for behold they are already preparing to come against us;"], ["ma faauta foi ua toaitiiti lava i tatou.", "and behold also there are but few of us."]]},
  {num:20,words:[["Ma faauta,", "And behold,"], ["latou te o mai ma a latou autau e toatele; ma vagana ai ua faamalilieina i latou e le tupu e faasaga ia te i tatou,", "they come with their numerous hosts;"], ["o le a tatou fano.", "and except the king doth pacify them towards us we must perish."]]},
  {num:21,words:[["Ona pe lē ua faataunuuina ea upu a Apinati,", "For are not the words of Abinadi fulfilled,"], ["ia na vavalo ai o ia e faasaga mai ia te i tatou—ma o nei mea uma ona o lo tatou lē fia faalogo i afioga a le Alii,", "which he prophesied against us—and all this because we would not hearken unto the words of the Lord,"], ["ma liliu ese mai ia tatou amioletonu?", "and turn from our iniquities?"]]},
  {num:22,words:[["Ma o lenei sei tatou faamalieina le tupu,", "And now let us pacify the king,"], ["ma tatou faataunuu le tautoga na tatou faia ia te ia;", "and we fulfil the oath which we have made unto him;"], ["ona e sili lo tatou pologa nai lo le aveesea o o tatou ola;", "for it is better that we should be in bondage than that we  should lose our lives;"], ["o lea,", "therefore,"], ["ia tatou taofi ia le faamasaaina o le toto ua matua tele.", "let us put a stop to the shedding of so much blood."]]},
  {num:23,words:[["Ma o lenei sa oo ina ta'u atu e Limae i le tupu mea uma lava e uiga i lona tamā,", "And now Limhi told the king all the things concerning his father,"], ["ma faitaulaga na sosola i le vao,", "and the priests that had fled into the wilderness,"], ["ma tuua'i le aveina o o latou afafine ia te i latou.", "and attributed the carrying away of their daughters to them."]]},
  {num:24,words:[["Ma sa oo ina faamalieina le tupu e faasaga i le nuu o Limae;", "And it came to pass that the king was pacified towards his people;"], ["ma sa fai mai o ia ia te i latou:", "and he said unto them:"], ["Tatou o atu e feiloa'i ma lo'u nuu,", "Let us go forth to meet my people,"], ["e aunoa ma ni auupega;", "without arms;"], ["ma ou te tauto atu ia te oe i se tautoga o le a le fasiotia e lo'u nuu lou nuu.", "and I swear unto you with an oath that my people shall not slay thy people."]]},
  {num:25,words:[["Ma sa oo ina latou mulimuli atu i le tupu,", "And it came to pass that they followed the king,"], ["ma o atu e aunoa ma ni auupega e feiloa'i ma sa Lamanā. Ma sa oo ina latou feiloa'i ma sa Lamanā;", "and went forth without arms to meet the Lamanites. And it came to pass that they did meet the Lamanites;"], ["ma sa ifo atu i lalo le tupu lava ia o sa Lamanā i o latou luma,", "and the king of the Lamanites did bow himself down before them,"], ["ma aioi atu o ia mo le nuu o Limae.", "and did plead in behalf of the people of Limhi."]]},
  {num:26,words:[["Ma ina ua vaai mai sa Lamanā i tagata o Limae,", "And when the Lamanites saw the people of Limhi,"], ["ua leai ni a latou auupega,", "that they were without arms,"], ["sa latou alolofa ia te i latou ma ua faamalilieina e faasaga mai ia te i latou,", "they had compassion on them and were pacified towards them,"], ["ma toe foi atu faatasi ma lo latou tupu i le filemu i lo latou lava laueleele.", "and returned with their king in peace to their own land."]]},
];
renderVerseSet(mo_ch_20_Verses, 'mo-ch20-verses');

var mo_ch_21_Verses = [
  {num:1,words:[["Ma sa oo ina toe foi mai Limae ma ona tagata i le aai o Nifae,", "And it came to pass that Limhi and his people returned to the city of Nephi,"], ["ma amata ona latou toe nonofo i le laueleele i le filemu.", "and began to dwell in the land again in peace."]]},
  {num:2,words:[["Ma sa oo ina ua mavae aso e tele sa amata ona toe oso le ita o sa Lamanā e faasaga ia sa Nifaē,", "And it came to pass that after many days the Lamanites began again to be stirred up in anger against the Nephites,"], ["ma sa amata ona latou o mai i tuaoi o le laueleele faataamilo ai.", "and they began to come into the borders of the land round about."]]},
  {num:3,words:[["O lenei sa latou fefefe e fasioti ia te i latou,", "Now they durst not slay them,"], ["ona o le tautoga na fai e lo latou tupu ia Limae;", "because of the oath which their king had made unto Limhi;"], ["ae sa latou fepo o latou alafau ,", "but they would smite them on their cheeks,"], ["ma faaaoga le pule i luga o i latou;", "and exercise authority over them;"], ["ma amata ona latou tuu o avega mamafa i luga o o latou tua,", "and began to put heavy burdens upon their backs,"], ["ma tulituli i latou e pei ona latou faia i se asini gūgū.", "and drive them as they would a dumb ass—"]]},
  {num:4,words:[["Ioe,", "Yea,"], ["sa faia nei mea uma ina ia mafai ona faataunuuina o le afioga a le Alii.", "all this was done that the word of the Lord might be fulfilled."]]},
  {num:5,words:[["Ma o lenei sa matua tetele lava puapuaga o sa Nifaē,", "And now the afflictions of the Nephites were great,"], ["ma sa leai se auala sa mafai ona latou laveaiina ai i latou lava i fafo mai lima o sa Lamanā,", "and there was no way that they could deliver themselves out of their hands,"], ["ona sa siosiomia i latou e sa Lamanā i itu uma.", "for the Lamanites had surrounded them on every side."]]},
  {num:6,words:[["Ma sa oo ina amata ona muimui o tagata i le tupu ona o o latou puapuaga;", "And it came to pass that the people began to murmur with the king because of their afflictions;"], ["ma sa amata ona latou mananao ia latou o atu e tau ma i latou.", "and they began to be desirous to go against them to battle."], ["Ma sa latou faatiga tele i le tupu ia latou muimuiga; o lea na tuu atu ai e ia ia te i latou,", "And they did afflict the king sorely with their complaints;"], ["ia latou faia e tusa ma o latou manao.", "therefore he granted unto them that they should do according to their desires."]]},
  {num:7,words:[["Ma sa latou toe faapotopoto faatasi i latou lava,", "And they gathered themselves together again,"], ["ma oofu o latou ofutau,", "and put on their armor,"], ["ma ua o atu e tau ma sa Lamanā e tutuli ese i latou i fafo o lo latou laueleele.", "and went forth against the Lamanites to drive them out of their land."]]},
  {num:8,words:[["Ma sa oo ina faatoilalo i latou e sa Lamanā,", "And it came to pass that the Lamanites did beat them,"], ["ma toe tutuli mai i latou i tua,", "and drove them back,"], ["ma fasioti le toatele o i latou.", "and slew many of them."]]},
  {num:9,words:[["Ma o lenei sa i ai se faanoanoaga ma se auega tele i totonu o le nuu o Limae,", "And now there was a great mourning and lamentation among the people of Limhi,"], ["o le fafine ua oti lana tane ua faanoanoa mo lana tane,", "the widow mourning for her husband,"], ["o le atalii ma le afafine ua faanoanoa mo lo laua tamā,", "the son and the daughter mourning for their father,"], ["ma uso mo o latou uso.", "and the brothers for their brethren."]]},
  {num:10,words:[["O lenei sa toatele se aofai o fafine i le nuu sa feoti a latou tane,", "Now there were a great many widows in the land,"], ["ma sa latou fetagisi tele mai lea aso i lea aso,", "and they did cry mightily from day to day,"], ["ona ua oo mai i luga o i latou se mata'u tele ia sa Lamanā.", "for a great fear of the Lamanites had come upon them."]]},
  {num:11,words:[["Ma sa oo ina o lo latou tagi e lē aunoa na oso ai le ita o le vaega na totoe o le nuu o Limae e faasaga ia sa Lamanā;", "And it came to pass that their continual cries did stir up the remainder of the people of Limhi to anger against the Lamanites;"], ["ma sa latou toe o atu e tau,", "and they went again to battle,"], ["peitai sa toe tutuli mai i latou i tua,", "but they were driven back again,"], ["ma le mafatia i le toatele na maliliu.", "suffering much loss."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["sa latou toe o atu faatolu,", "they went again even the third time,"], ["ma faapena ona latou mafatia i le ala lava e tasi;", "and suffered in the like manner;"], ["ma o i latou o e sa lei fasiotia sa toe foi mai i le aai o Nifae.", "and those that were not slain returned again to the city of Nephi."]]},
  {num:13,words:[["Ma sa latou faamaualaloina i latou lava e oo ifo i le efuefu,", "And they did humble themselves even to the dust,"], ["ma tuu atu i latou lava i le amo o le pologa,", "subjecting themselves to the yoke of bondage,"], ["ma tuu atu i latou lava ia taia,", "submitting themselves to be smitten,"], ["ma tuli i lea mea ma lea mea,", "and to be driven to and fro,"], ["ma faafafa i avega mamafa,", "and burdened,"], ["e tusa ma manao o o latou fili.", "according to the desires of their enemies."]]},
  {num:14,words:[["Ma sa latou faamaualaloina i latou lava seia oo i le loloto o le lotomaualalo;", "And they did humble themselves even in the depths of humility;"], ["ma sa latou tagi malosi atu i le Atua;", "and they did cry mightily to God;"], ["ioe,", "yea,"], ["sa latou tagi atu lava i lo latou Atua i le aso atoa ia laveai e ia i latou mai i o latou puapuaga.", "even all the day long did they cry unto their God that he would deliver them out of their afflictions."]]},
  {num:15,words:[["Ma o lenei sa telegese ona faafofoga mai o le Alii i la latou tagi atu ona o a latou amioletonu;", "And now the Lord was slow to hear their cry because of their iniquities;"], ["e ui i lea sa faafofoga mai le Alii ia latou tagi,", "nevertheless the Lord did hear their cries,"], ["ma amata ona faamalūlū e ia o loto o sa Lamanā sa amata ona latou faamāmāina a latou avega;", "and began to soften the hearts of the Lamanites that they began to ease their burdens;"], ["peitai sa lei tusa ai ma le silafaga a le Alii ia laveaiina i latou mai le pologa.", "yet the Lord did not see fit to deliver them out of bondage."]]},
  {num:16,words:[["Ma sa oo ina amata ona latou solosolo manuia i le laueleele,", "And it came to pass that they began to prosper by degrees in the land,"], ["ma amata ona latou faatupu o le kuranuma sili atu ona tele,", "and began to raise grain more abundantly,"], ["ma lafu,", "and flocks,"], ["ma fagaga,", "and herds,"], ["sa latou lē mafatia ai i le fia aai.", "that they did not suffer with hunger."]]},
  {num:17,words:[["O lenei sa toatele le aofai o fafine,", "Now there was a great number of women,"], ["sa sili atu i lo tane;", "more than there was of men;"], ["o lea na poloaiina ai e le tupu o Limae e tatau i tane taitoatasi ona faasoa atu se vaega o ana mea mo le tausiga o fafine ua oti a latou tane ma a latou fanau,", "therefore king Limhi commanded that every man should impart to the support of the widows and their children,"], ["ina ia latou lē fano i le fia aai;", "that they might not perish with hunger;"], ["ma sa latou faia lenei mea ona o le toatele o lo latou aofai ua fasiotia.", "and this they did because of the greatness of their number that had been slain."]]},
  {num:18,words:[["O lenei sa faatasitasi le nuu o Limae i se vaega e tasi i taimi uma sa mafai ai,", "Now the people of Limhi kept together in a body as much as it was possible,"], ["e puipui a latou kuranuma ma a latou lafu;", "and secured their grain and their flocks;"]]},
  {num:19,words:[["Ma sa lē faatuatuaina e le tupu lava ia le i ai o lona tagata i tua o pa o le aai,", "And the king himself did not trust his person without the walls of the city,"], ["vagana ai ua ia ave ana leoleo faatasi ma ia,", "unless he took his guards with him,"], ["i le fefe ne'i i ai se ala atonu e pa'ū atu ai o ia i lima o sa Lamanā.", "fearing that he might by some means fall into the hands of the Lamanites."]]},
  {num:20,words:[["Ma sa faia e ia ia vaavaai faataamilo e lona nuu le laueleele,", "And he caused that his people should watch the land round about,"], ["atonu latou te maua ai se auala latou te pupu'e ai faitaulaga ia na sosola i le vao,", "that by some means they might take those priests that fled into the wilderness,"], ["o e na gaoia afafine o sa Lamanā,", "who had stolen the daughters of the Lamanites,"], ["ma ua mafua ai ona oo mai o se faafanoga tele faapea i o latou luga.", "and that had caused such a great destruction to come upon them."]]},
  {num:21,words:[["Ona sa latou mananao e pupu'e i latou ina ia mafai ona latou faasalaina i latou;", "For they were desirous to take them that they might punish them;"], ["ona sa latou o mai i le nuu o Nifae i le po,", "for they had come into the land of Nephi by night,"], ["ma ave a latou kuranuma ma le tele o a latou mea taua;", "and carried off their grain and many of their precious things;"], ["o lea na latou lamalama faatalitali ai i latou.", "therefore they laid wait for them."]]},
  {num:22,words:[["Ma sa oo ina lē toe i ai se faalavelave i le va o sa Lamanā ma le nuu o Limae,", "And it came to pass that there was no more disturbance between the Lamanites and the people of Limhi,"], ["e oo mai i le taimi na o mai ai Amona ma ona uso i le laueleele.", "even until the time that Ammon and his brethren came into the land."]]},
  {num:23,words:[["Ma a'o i ai le tupu i tua o pa o le aai faatasi ma ana leoleo,", "And the king having been without the gates of the city with his guard,"], ["sa latou maua Amona ma ona uso;", "discovered Ammon and his brethren;"], ["ma i le manatu o i latou ia o faitaulaga a Noa, o lea na faia ai e ia ia pupu'e i latou,", "and supposing them to be priests of Noah therefore he caused that they should be taken,"], ["ma saisai,", "and bound,"], ["ma lafo i le falepuipui .", "and cast into prison."], ["Ma a na fai o i latou ia o faitaulaga a Noa, po ua ia faatonu ia fasioti i latou.", "And had they been the priests of Noah he would have caused that they should be put to death."]]},
  {num:24,words:[["Ae ina ua iloa e ia e lē o i latou ia,", "But when he found that they were not,"], ["ae o i latou ia o ona uso,", "but that they were his brethren,"], ["ma na o mai mai le laueleele o Sara'emila,", "and had come from the land of Zarahemla,"], ["sa faatumulia o ia i le olioli sa matua tele.", "he was filled with exceedingly great joy."]]},
  {num:25,words:[["O lenei,", "Now king Limhi had sent,"], ["a'o lei sau Amona,", "previous to the coming of Ammon,"], ["sa auina atu e le tupu o Limae se vaega toaitiiti o tagata e sue le laueleele o Sara'emila;", "a small number of men to search for the land of Zarahemla;"], ["peitai sa latou lē mauaina,", "but they could not find it,"], ["ma sa se i latou i le vao.", "and they were lost in the wilderness."]]},
  {num:26,words:[["E ui i lea,", "Nevertheless,"], ["sa latou maua se laueleele sa ainā e ni tagata;", "they did find a land which had been peopled;"], ["ioe,", "yea,"], ["o se laueleele sa ufitia i ivi mamago;", "a land which was covered with dry bones;"], ["ioe,", "yea,"], ["o se laueleele sa ainā e ni tagata ma ua faaumatia;", "a land which had been peopled and which had been destroyed;"], ["ma o i latou,", "and they,"], ["i lo latou manatu o le laueleele lea o Sara'emila,", "having supposed it to be the land of Zarahemla,"], ["sa latou toe foi mai i le laueleele o Nifae,", "returned to the land of Nephi,"], ["ma latou taunuu mai ai i tuaoi o le laueleele i ni aso sa lei tele ae lei sau Amona.", "having arrived in the borders of the land not many days before the coming of Ammon."]]},
  {num:27,words:[["Ma sa latou aumai faatasi ma i latou se talafaamaumau,", "And they brought a record with them,"], ["o se talafaamaumau lava lea o tagata e ona ivi na latou maua;", "even a record of the people whose bones they had found;"], ["ma sa togitogia lea talafaamaumau i luga o papatusi 'oa.", "and it was engraven on plates of ore."]]},
  {num:28,words:[["Ma o lenei sa toe faatumulia Limae i le olioli ina ua iloa e ia mai le fofoga o Amona o loo i ai i le tupu o Mosaea se meaalofa mai le Atua,", "And now Limhi was again filled with joy in learning from the mouth of Ammon that king Mosiah had a gift from God,"], ["e mafai ona faaliliu ai e ia togitogiga faapea;", "whereby he could interpret such engravings;"], ["ioe,", "yea,"], ["ma sa olioli foi Amona.", "and Ammon also did rejoice."]]},
  {num:29,words:[["Peitai sa faatumulia Amona ma ona uso i le faanoanoa, ona o le toatele o o latou uso ua fasiotia;", "Yet Ammon and his brethren were filled with sorrow because so many of their brethren had been slain;"]]},
  {num:30,words:[["Ma le faaosoina foi e le tupu o Noa ma ana faitaulaga le nuu i le faia o agasala ma amioletonu e tele e faasaga i le Atua;", "And also that king Noah and his priests had caused the people to commit so many sins and iniquities against God;"], ["ma sa latou faanoanoa foi i le maliu o Apinati;", "and they also did mourn for the death of Abinadi;"], ["ma le o ese atu foi o Alema ma tagata o e sa o atu faatasi ma ia,", "and also for the departure of Alma and the people that went with him,"], ["o lē na faatuina se ekalesia a le Atua e ala i le malosi ma le mana o le Atua,", "who had formed a church of God through the strength and power of God,"], ["ma le faatuatua i upu na tautala i ai Apinati.", "and faith on the words which had been spoken by Abinadi."]]},
  {num:31,words:[["Ioe,", "Yea,"], ["sa latou faanoanoa i lo latou o ese atu,", "they did mourn for their departure,"], ["ona sa latou lē iloa le mea ua latou sosola atu i ai. O lenei semanu ua latou fiafia e auai faatasi ma i latou,", "for they knew not whither they had fled. Now they would have gladly joined with them,"], ["ona ua ulu atu foi i latou lava i se feagaiga ma le Atua e auauna atu ia te ia ma tausi i ana poloaiga.", "for they themselves had entered into a covenant with God to serve him and keep his commandments."]]},
  {num:32,words:[["Ma o lenei talu mai le sau o Amona,", "And now since the coming of Ammon,"], ["ua ulu atu foi le tupu o Limae i se feagaiga ma le Atua,", "king Limhi had also entered into a covenant with God,"], ["ma le toatele foi o lona nuu,", "and also many of his people,"], ["e auauna atu ia te ia ma tausi i ana poloaiga.", "to serve him and keep his commandments."]]},
  {num:33,words:[["Ma sa oo ina mananao le tupu o Limae ma le toatele o lona nuu ia papatisoina i latou;", "And it came to pass that king Limhi and many of his people were desirous to be baptized;"], ["peitai sa leai se tasi i le nuu sa i ai le pule mai le Atua. Ma sa teena e Amona lona faia o lenei mea,", "but there was none in the land that had authority from God. And Ammon declined doing this thing,"], ["i le manatu ifo ia te ia lava o ia o se auauna lē agavaa.", "considering himself an unworthy servant."]]},
  {num:34,words:[["O lea sa latou lē faatulagaina ai i latou lava i lena taimi i se ekalesia,", "Therefore they did not at that time form themselves into a church,"], ["a ua faatalitali i le Agaga o le Alii. O lenei sa latou mananao ia avea i latou e pei o Alema ma ona uso,", "waiting upon the Spirit of the Lord. Now they were desirous to become even as Alma and his brethren,"], ["o e na sosola i le vao.", "who had fled into the wilderness."]]},
  {num:35,words:[["Sa latou mananao ia papatisoina i latou o se mau ma se molimau ua latou loto e auauna atu i le Atua ma o latou loto atoa;", "They were desirous to be baptized as a witness and a testimony that they were willing to serve God with all their hearts;"], ["e ui i lea sa latou tolopo le taimi;", "nevertheless they did prolong the time;"], ["ma o le a tuuina atu i se taimi mulimuli mai se tala o lo latou papatisoga.", "and an account of their baptism shall be given hereafter."]]},
  {num:36,words:[["Ma o lenei o suesuega uma a Amona ma ona tagata,", "And now all the study of Ammon and his people,"], ["ma le tupu o Limae ma lona nuu,", "and king Limhi and his people,"], ["o le laveaiina lea o i latou lava mai lima o sa Lamanā ma mai le pologa.", "was to deliver themselves out of the hands of the Lamanites and from bondage."]]},
];
renderVerseSet(mo_ch_21_Verses, 'mo-ch21-verses');

var mo_ch_22_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina amata ona soalaupule o Amona ma le tupu o Limae faatasi ma le nuu pe faapefea ona latou laveai i latou lava mai le pologa;", "And now it came to pass that Ammon and king Limhi began to consult with the people how they should deliver themselves out of bondage;"], ["ma sa oo ina faia e i laua ia faapotopoto mai faatasi e tagata uma i latou lava;", "and even they did cause that all the people should gather themselves together;"], ["ma sa faia e i laua lenei mea ina ia mafai ona maua e i laua le leo o le nuu e uiga i lenei mataupu.", "and this they did that they might have the voice of the people concerning the matter."]]},
  {num:2,words:[["Ma sa oo ina latou lē maua se ala e laveai ai i latou lava mai le pologa,", "And it came to pass that they could find no way to deliver themselves out of bondage,"], ["vagana ai ua latou ave o latou fafine ma a latou fanau,", "except it were to take their women and children,"], ["ma a latou lafu,", "and their flocks,"], ["ma a latou fagaga,", "and their herds,"], ["ma o latou faleie,", "and their tents,"], ["ma o ese atu i le vao;", "and depart into the wilderness;"], ["ona sa matua toatele lava sa Lamanā,", "for the Lama– nites being so numerous,"], ["sa lē mafai e le nuu o Limae ona tau ma i latou,", "it was impossible for the people of Limhi to contend with them,"], ["pe afai latou te manatu latou te laveai i latou lava mai le pologa i le pelu.", "thinking to deliver themselves out of bondage by the sword."]]},
  {num:3,words:[["O lenei sa oo ina alu atu Kitiona ma tu i luma o le tupu,", "Now it came to pass that Gideon went forth and stood before the king,"], ["ma fai atu ia te ia:", "and said unto him:"], ["O lenei le tupu e,", "Now O king,"], ["e oo mai i le taimi nei o e faafofoga mai pea i a'u upu i le tele o taimi sa tatou tau ai ma o tatou uso,", "thou hast hitherto hearkened unto my words many times when we have been contending with our brethren,"], ["o sa Lamanā.", "the Lamanites."]]},
  {num:4,words:[["Ma o lenei le tupu e,", "And now O king,"], ["afai e te lei maua a'u o se auauna lē aoga,", "if thou hast not found me to be an unprofitable servant,"], ["pe afai foi sa e faafofoga mai i a'u upu i soo se tulaga e oo mai i le taimi nei,", "or if thou hast hitherto listened to my words in any degree,"], ["ma afai sa aoga ia te oe,", "and they have been of service to thee,"], ["ua faapea lava ona ou manao ia e faafofoga mai i a'u upu i le taimi nei,", "even so I desire that thou wouldst listen to my words at this time,"], ["ma o le a avea a'u ma au auauna ma laveai lenei nuu mai le pologa.", "and I will be thy servant and deliver this people out of bondage."]]},
  {num:5,words:[["Ma sa tuu atu e le tupu ia te ia ia saunoa mai. Ma sa fai atu Kitiona ia te ia:", "And the king granted unto him that he might speak. And Gideon said unto him:"]]},
  {num:6,words:[["Faauta i le ala i tua,", "Behold the back pass,"], ["e ui atu i le pa i tua,", "through the back wall,"], ["o loo i le itu i tua o le aai. O sa Lamanā,", "on the back side of the city. The Lamanites,"], ["po o leoleo o sa Lamanā,", "or the guards of the Lamanites,"], ["e onanā i le po;", "by night are drunken;"], ["o lea ia tatou auina atu se folafolaga i totonu o lenei nuu atoa ia latou faapotopoto faatasi a latou lafu ma a latou fagaga,", "therefore let us send a proclamation  among all this people that they gather together their flocks and herds,"], ["ina ia mafai ona latou tulituli atu i latou i le vao i le po.", "that they may drive them into the wilderness by night."]]},
  {num:7,words:[["Ma o le a ou alu atu e tusa ma lau poloaiga ma totogi le lafoga mulimuli o uaina ia sa Lamanā,", "And I will go according to thy command and pay the last tribute of wine to the Lamanites,"], ["ma o le a latou onanā ai; ma o le a tatou ui atu i le ala faalilolilo e i le itu agavale o la latou togalauapi,", "and they will be drunken;"], ["pe a latou onanā ma momoe.", "and we will pass through the secret pass on the left of their camp when they are drunken and asleep."]]},
  {num:8,words:[["O le a faapea ona tatou o ese atu ai ma o tatou fafine,", "Thus we will depart with our women and our children,"], ["ma a tatou fanau,", "our flocks,"], ["ma a tatou lafu, ma a tatou fagaga i le vao;", "and our herds into the wilderness;"], ["ma o le a tatou malaga taamilo atu i le laueleele o Seloma.", "and we will travel around the land of Shilom."]]},
  {num:9,words:[["Ma sa oo ina faafofoga le tupu i upu a Kitiona.", "And it came to pass that the king hearkened unto the words of Gideon."]]},
  {num:10,words:[["Ma sa faia e le tupu o Limae ia faapotopoto faatasi e lona nuu a latou lafu;", "And king Limhi caused that his people should gather their flocks together;"], ["ma sa auina atu e ia le lafoga o uaina ia sa Lamanā;", "and he sent the tribute of wine to the Lamanites;"], ["ma sa auina atu foi e ia ni uaina faasili,", "and he also sent more wine,"], ["e fai ma meaalofa ia te i latou;", "as a present unto them;"], ["ma sa latou inu saoloto i le uaina na auina atu e le tupu o Limae ia te i latou.", "and they did drink freely of the wine which king Limhi did send unto them."]]},
  {num:11,words:[["Ma sa oo ina o ese atu le nuu o le tupu o Limae i le po i le vao faatasi ma a latou lafu ma a latou fagaga,", "And it came to pass that the people of king Limhi did depart by night into the wilderness with their flocks and their herds,"], ["ma sa latou o i le vao e taamilo atu i le laueleele o Seloma,", "and they went round about the land of Shilom in the wilderness,"], ["ma faapi'o ane lo latou ala agai i le laueleele o Sara'emila,", "and bent their course towards the land of Zarahemla,"], ["ua taitaia e Amona ma ona uso.", "being led by Ammon and his brethren."]]},
  {num:12,words:[["Ma sa latou ave a latou auro,", "And they had taken all their gold,"], ["ma ario,", "and silver,"], ["ma a latou mea taua uma,", "and their precious things,"], ["sa mafai ona latou ave,", "which they could carry,"], ["ma a latou tapenapenaga uma foi faatasi ma i latou,", "and also their provisions with them,"], ["i le vao;", "into the wilderness;"], ["ma sa latou tuli loa la latou malaga.", "and they pursued their journey."]]},
  {num:13,words:[["Ma ina ua mavae aso e tele o i ai i le vao sa latou taunuu i le laueleele o Sara'emila,", "And after being many days in the wilderness they arrived in the land of Zarahemla,"], ["ma auai faatasi ma le nuu o Mosaea,", "and joined Mosiah’s people,"], ["ma avea ma ona tagata.", "and became his subjects."]]},
  {num:14,words:[["Ma sa oo ina talia i latou e Mosaea ma le olioli;", "And it came to pass that Mosiah received them with joy;"], ["ma sa talia foi e ia a latou talafaamaumau ,", "and he also received their records,"], ["ma talafaamaumau foi na maua e le nuu o Limae.", "and also the records which had been found by the people of Limhi."]]},
  {num:15,words:[["Ma o lenei sa oo ina ua iloa e sa Lamanā ua o ese atu le nuu o Limae i fafo o le laueleele i le po,", "And now it came to pass when the Lamanites had found that the people of Limhi had departed out of the land by night,"], ["sa latou auina atu se autau i le vao e tuliloa i latou.", "that they sent an army into the wilderness to pursue them;"]]},
  {num:16,words:[["Ma ina ua mavae aso e lua o latou tuliloa i latou,", "And after they had pursued them two days,"], ["sa oo ina lē mafai ona latou toe iloa o latou tulagavae;", "they could no longer follow their tracks;"], ["o lea na latou se ai i le vao.", "therefore they were lost in the wilderness."]]},
];
renderVerseSet(mo_ch_22_Verses, 'mo-ch22-verses');

var mo_ch_23_Verses = [
  {num:1,words:[["O lenei o Alema,", "Now Alma,"], ["ina ua lapataia o ia e le Alii o le a o mai autau a le tupu o Noa i luga ia i latou,", "having been warned of the Lord that the armies of king Noah would come upon them,"], ["ma ina ua uma ona faailoa atu i ona tagata,", "and having made it known to his people,"], ["o lea na latou faapotopoto faatasi ai a latou lafu,", "therefore they gathered together their flocks,"], ["ma ave ni isi o a latou kuranuma,", "and took of their grain,"], ["ma o ese atu i le vao ae lei oo mai autau a le tupu o Noa.", "and departed into the wilderness before the armies of king Noah."]]},
  {num:2,words:[["Ma sa faamalolosi i latou e le Alii,", "And the Lord did strengthen them,"], ["ma sa lē mafai e tagata a le tupu o Noa ona maua mai i latou e faaumatia i latou.", "that the people of king Noah could not overtake them to destroy them."]]},
  {num:3,words:[["Ma sa latou sosola i le vao i se malaga i aso e valu.", "And they fled eight days’ journey into the wilderness."]]},
  {num:4,words:[["Ma sa latou taunuu i se laueleele,", "And they came to a land,"], ["ioe,", "yea,"], ["o se laueleele matagofie tele ma lafulemu,", "even a very beautiful and pleasant land,"], ["o se laueleele o vai mamā.", "a land of pure water."]]},
  {num:5,words:[["Ma sa latou faatutu o latou faleie,", "And they pitched their tents,"], ["ma amata ona galueaiina le eleele,", "and began to till the ground,"], ["ma amata ona fausia fale;", "and began to build buildings;"], ["ioe,", "yea,"], ["sa latou toaaga,", "they were industrious,"], ["ma galulue malolosi.", "and did labor exceedingly."]]},
  {num:6,words:[["Ma sa mananao le nuu ia avea Alema ma o latou tupu,", "And the people were desirous that Alma should be their king,"], ["ona sa pele o ia i lona nuu.", "for he was beloved by his people."]]},
  {num:7,words:[["Peitai sa fai atu o ia ia te i latou:", "But he said unto them:"], ["Faauta e lē tatau ona i ai o se tupu ia te i tatou;", "Behold,"], ["ona ua faapea ona fetalai mai o le Alii:", "it is not expedient that we should have a king; for thus saith the Lord:"], ["'Aua tou te faasili i o outou manatu le tasi tagata i le isi tagata;", "Ye shall not esteem one flesh above another,"], ["pe manatu se tagata e toatasi ua sili o ia lava i luga atu o se isi tagata;", "or one man shall not think himself above another;"], ["o lea Ou te fai atu ai ia te outou e lē tatau ona i ai so outou tupu.", "therefore I say unto you it is not expedient that ye should have a king."]]},
  {num:8,words:[["E ui i lea,", "Nevertheless,"], ["a na faapea e mafai ona outou maua pea ni tagata amiotonu e avea mo o outou tupu e lelei ona fai o so outou tupu.", "if it were possible that ye could always have just men to be your kings it would be well for you to have a king."]]},
  {num:9,words:[["Ae ia manatua le amioletonu o le tupu o Noa ma ana faitaulaga;", "But remember the iniquity of king Noah and his priests;"], ["ma sa maua foi a'u lava ia i se mailei,", "and I myself was caught in a snare,"], ["ma ou faia mea e tele sa inosia i le silafaga a le Alii,", "and did many things which were abominable in the sight of the Lord,"], ["na oo mai ai ia te a'u le salamo tiga.", "which caused me sore repentance;"]]},
  {num:10,words:[["E ui i lea,", "Nevertheless,"], ["ina ua mavae lo'u puapuaga tele,", "after much tribulation,"], ["sa oo ina faafofoga mai le Alii i a'u tagi,", "the Lord did hear my cries,"], ["ma tali mai i a'u talosaga,", "and did answer my prayers,"], ["ma ua faia e ia a'u o se meafaigaluega i ona aao i le aumai o le toatele o outou i se malamalama o lana upumoni.", "and has made me an instrument in his hands in bringing so many of you to a knowledge of his truth."]]},
  {num:11,words:[["E ui i lea,", "Nevertheless,"], ["ou te lē mitamita i lenei mea,", "in this I do not glory,"], ["ona ua ou lē agavaa ou te mitamita ia te a'u lava ia.", "for I am unworthy to glory of myself."]]},
  {num:12,words:[["Ma o lenei ou te fai atu ia te outou,", "And now I say unto you,"], ["sa sauaina outou e le tupu o Noa,", "ye have been oppressed by king Noah,"], ["ma sa outou pologa ia te ia ma ana faitaulaga,", "and have been in bondage to him and his priests,"], ["ma sa aumai outou i le amioletonu e i latou;", "and have been brought into iniquity by them;"], ["o lea na noanoa ai outou i noanoaga o le amioletonu.", "therefore ye were bound with the bands of iniquity."]]},
  {num:13,words:[["Ma o lenei e pei ona laveaiina outou e le mana a le Atua mai nei noanoaga;", "And now as ye have been delivered by the power of God out of these bonds;"], ["ioe,", "yea,"], ["i fafo lava mai lima o le tupu o Noa ma ona tagata,", "even out of the hands of king Noah and his people,"], ["ma mai noanoaga foi o le amioletonu,", "and also from the bonds of iniquity,"], ["ua faapea foi ona ou manao ia outou tutu mausalī i lenei saolotoga ua faasaolotoina ai outou,", "even so I desire that ye should stand fast in this liberty wherewith ye have been made free,"], ["ma ia outou lē faalagolago i se tagata ia avea ma tupu i o outou luga.", "and that ye trust no man to be a king over you."]]},
  {num:14,words:[["O lenei foi ia outou lē faalagolago i se tasi e avea ma o outou aoao po o so outou faifeau,", "And also trust no one to be your teacher nor your minister,"], ["vagana ai o ia o se tagata o le Atua,", "except he be a man of God,"], ["o loo savali i ona ala ma tausi i ana poloaiga.", "walking in his ways and keeping his commandments."]]},
  {num:15,words:[["Sa faapea ona aoao e Alema lona nuu,", "Thus did Alma teach his people,"], ["ia alofa tagata taitoatasi i lē la te tuaoi e pei o ia lava ia te ia,", "that every man should love his neighbor as himself,"], ["ina ia leai se finauga i totonu o i latou.", "that there should be no contention among them."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["sa avea Alema ma o latou faitaulaga sili,", "Alma was their high priest,"], ["ona o ia na faavaeina la latou ekalesia.", "he being the founder of their church."]]},
  {num:17,words:[["Ma sa oo ina sa leai se tasi na maua e ia le pule e talai pe aoao atu ai vagana ai ua mai ia te ia mai le Atua. O lea sa faauu ai e ia o latou faitaulaga uma ma o latou aoao uma;", "And it came to pass that none received authority to preach or to teach except it were by him from God. Therefore he consecrated all their priests and all their teachers;"], ["ma sa leai ni isi na faauuina vagana ai o i latou o ni tagata amiotonu.", "and none were consecrated except they were just men."]]},
  {num:18,words:[["O lea sa latou leoleo i luga o lo latou nuu,", "Therefore they did watch over their people,"], ["ma fafaga i latou i mea tau i le amiotonu.", "and did nourish them with things pertaining to righteousness."]]},
  {num:19,words:[["Ma sa oo ina amata ona latou manuia tele i le laueleele;", "And it came to pass that they began to prosper exceedingly in the land;"], ["ma sa latou faaigoaina le laueleele o Helama.", "and they called the land Helam."]]},
  {num:20,words:[["Ma sa oo ina latou uluola ma manuia tele i le laueleele o Helama;", "And it came to pass that they did multiply and prosper exceedingly in the land of Helam;"], ["ma sa latou faatuina se aai,", "and they built a city,"], ["lea sa latou faaigoaina o le aai o Helama.", "which they called the city of Helam."]]},
  {num:21,words:[["E ui i lea sa tatau ai i le finagalo o le Alii ona aoaiina ona tagata;", "Nevertheless the Lord seeth fit to chasten his people;"], ["ioe,", "yea,"], ["sa ia tofotofoina lo latou onosai ma lo latou faatuatua.", "he trieth their patience and their faith."]]},
  {num:22,words:[["E ui i lea—soo se tasi e tuu atu lona faalagolago ia te ia o ia lava lea o le a sii a'e i le aso gataaga. Ioe,", "Nevertheless—whosoever putteth his trust in him the same shall be lifted up at the last day. Yea,"], ["ma sa faapea lava ona faia i lenei nuu.", "and thus it was with this people."]]},
  {num:23,words:[["Aua faauta,", "For behold,"], ["o le a ou faaali atu ia te outou sa aumai i latou i le pologa,", "I will show unto you that they were brought into bondage,"], ["ma sa leai se tasi sa mafai ona lavea'ia i latou sa nao le Alii lava lo latou Atua,", "and none could deliver them but the Lord their God,"], ["ioe,", "yea,"], ["le Atua lava lea o Aperaamo ma Isaako ma Iakopo.", "even the God of Abraham and Isaac and of Jacob."]]},
  {num:24,words:[["Ma sa oo ina laveaiina lava i latou e ia,", "And it came to pass that he did deliver them,"], ["ma faaali mai e ia lona mana malosi ia te i latou,", "and he did show forth his mighty power unto them,"], ["ma sa tele lava lo latou olioli.", "and great were their rejoicings."]]},
  {num:25,words:[["Aua faauta,", "For behold,"], ["sa oo ina a'o i ai i latou i le laueleele o Helama,", "it came to pass that while they were in the land of Helam,"], ["ioe, i le aai o Helama,", "yea,"], ["a'o latou galueaiina le laueleele faataamilo ai,", "in the city of Helam,"], ["faauta,", "while tilling the land round about,"], ["sa i ai se autau a sa Lamanā i tuaoi o le laueleele.", "behold an army of the Lamanites was in the borders of the land."]]},
  {num:26,words:[["Ma o lenei sa oo ina sosola uso o Alema mai o latou fanua,", "Now it came to pass that the brethren of Alma fled from their fields,"], ["ma latou faapotopoto faatasi i latou lava i le aai o Helama;", "and gathered themselves together in the city of Helam;"], ["ma sa latou fefefe tele ona o le tutu mai o sa Lamanā.", "and they were much frightened because of the appearance of the Lamanites."]]},
  {num:27,words:[["Peitai sa alu atu Alema ma ua tu i totonu o i latou,", "But Alma went forth and stood among them,"], ["ma apoapoai atu ia te i latou ia aua ne'i o latou fefefe,", "and exhorted them that they should not be frightened,"], ["ae ia latou manatua le Alii lo latou Atua ma o le a ia laveaiina i latou.", "but that they should remember the Lord their God and he would deliver them."]]},
  {num:28,words:[["O lea na latou faafilemu ai lo latou matata'u,", "Therefore they hushed their fears,"], ["ma amata ona latou tagi atu i le Alii ia faamalūlūina e ia loto o sa Lamanā,", "and began to cry unto the Lord that he would soften the hearts of the Lamanites,"], ["ina ia latou faaolaina i latou,", "that they would spare them,"], ["ma a latou avā,", "and their wives,"], ["ma a latou fanau.", "and their children."]]},
  {num:29,words:[["Ma sa oo ina faamalūlūina e le Alii loto o sa Lamanā. Ma sa o atu Alema ma ona uso ma tuu atu i latou lava i o latou lima;", "And it came to pass that the Lord did soften the hearts of the Lamanites. And Alma and his brethren went forth and delivered themselves up into their hands;"], ["ma sa ave e sa Lamanā le laueleele o Helama mo i latou.", "and the Lamanites took possession of the land of Helam."]]},
  {num:30,words:[["O lenei o autau a sa Lamanā,", "Now the armies of the Lamanites,"], ["ia sa tuliloaina mai le nuu o le tupu o Limae,", "which had followed after the people of king Limhi,"], ["sa se i le vao mo aso e tele.", "had been lost in the wilderness for many days."]]},
  {num:31,words:[["Ma faauta sa latou maua faitaulaga na a le tupu o Noa,", "And behold,"], ["i se nofoaga sa latou faaigoaina o Amulona;", "they had found those priests of king Noah, in a place which they called Amulon;"], ["ma sa amata ona latou fai mo i latou le laueleele o Amulona ma amata ona latou galueaiina le laueleele.", "and they had begun to possess the land of Amulon and had begun to till the ground."]]},
  {num:32,words:[["O lenei o le igoa o le taitai o faitaulaga na, o Amulona.", "Now the name of the leader of those priests was Amulon."]]},
  {num:33,words:[["Ma sa oo ina aioi atu Amulona ia sa Lamanā;", "And it came to pass that Amulon did plead with the Lamanites;"], ["ma sa auina atu foi e ia a latou avā,", "and he also sent forth their wives,"], ["o e o afafine o sa Lamanā,", "who were the daughters of the  Lamanites,"], ["e aioi atu i o latou tuagane,", "to plead with their brethren,"], ["ia latou lē faaumatiaina a latou tane.", "that they should not destroy their husbands."]]},
  {num:34,words:[["Ma sa alofagia Amulona ma ona uso e sa Lamanā,", "And the Lamanites had compassion on Amulon and his brethren,"], ["ma sa latou lē faaumatiaina i latou,", "and did not destroy them,"], ["ona o a latou avā.", "because of their wives."]]},
  {num:35,words:[["Ma sa 'au atu Amulona ma ona uso faatasi ma sa Lamanā,", "And Amulon and his brethren did join the Lamanites,"], ["ma sa latou malaga atu i le vao e sue le laueleele o Nifae ae latou maua ai le laueleele o Helama,", "and they were traveling in the wilderness in search of the land of Nephi when they discovered the land of Helam,"], ["lea sa nonofo ai Alema ma ona uso.", "which was possessed by Alma and his brethren."]]},
  {num:36,words:[["Ma sa oo ina folafola mai e sa Lamanā ia Alema ma ona uso, afai latou te faaali atu ia te i latou le ala e alu i le laueleele o Nifae,", "And it came to pass that the Lamanites promised unto Alma and his brethren,"], ["o le a latou tuu atu ia te i latou o latou ola ma lo latou saolotoga.", "that if they would show them the way which led to the land of Nephi that they would grant unto them their lives and their liberty."]]},
  {num:37,words:[["Ae ina ua uma ona faaali atu e Alema ia te i latou le ala i le laueleele o Nifae,", "But after Alma had shown them the way that led to the land of Nephi the Lamanites would not keep their promise;"], ["sa lē tausia e sa Lamanā la latou folafolaga; a ua latou faatutu faataamilo leoleo i le laueleele o Helama,", "but they set guards round about the land of Helam,"], ["i luga o Alema ma ona uso.", "over Alma and his brethren."]]},
  {num:38,words:[["Ma o le vaega na totoe o i latou sa o atu i le laueleele o Nifae;", "And the remainder of them went to the land of Nephi;"], ["ma o se vaega o i latou ia, sa toe foi mai i le laueleele o Helama,", "and a part of them returned to the land of Helam,"], ["ma sa latou aumai foi faatasi ma i latou avā ma fanau a leoleo o e sa tuu i le laueleele.", "and also brought with them the wives and the children of the guards who had been left in the land."]]},
  {num:39,words:[["Ma sa tuu atu e le tupu o sa Lamanā ia Amulona, ia avea o ia ma tupu ma pule i luga o ona tagata,", "And the king of the Lamanites had granted unto Amulon that he should be a king and a ruler over his people,"], ["o e sa i le laueleele o Helama; e ui i lea,", "who were in the land of Helam;"], ["sa lē ia te ia se mana na te faia ai soo se mea, e lē tusa ai ma le finagalo o le tupu o sa Lamanā.", "nevertheless he should have no power to do anything contrary to the will of the king of the Lamanites."]]},
];
renderVerseSet(mo_ch_23_Verses, 'mo-ch23-verses');

var mo_ch_24_Verses = [
  {num:1,words:[["Ma sa oo ina maua e Amulona le fiafia o le tupu o sa Lamanā ia te ia;", "And it came to pass that Amulon did gain favor in the eyes of the king of the Lamanites;"], ["o lea na tuu atu ai e le tupu o sa Lamanā ia te ia ma ona uso ia tofia i latou e avea ma aoao i lona nuu,", "therefore,"], ["ioe,", "the king of the Lamanites granted unto him and his brethren that they should be appointed teachers over his people, yea,"], ["e oo lava i tagata sa i le laueleele o Semulona,", "even over the people who were in the land of Shemlon,"], ["ma i le laueleele o Seloma,", "and in the land of Shilom,"], ["ma i le laueleele o Amulona.", "and in the land of Amulon."]]},
  {num:2,words:[["Ona ua ave uma e sa Lamanā nei laueleele mo i latou;", "For the Lamanites had taken possession of all these lands; therefore,"], ["o lea na tofi ai e le tupu o sa Lamanā ni tupu e pule i ia laueleele uma.", "the king of the Lamanites had appointed kings over all these lands."]]},
  {num:3,words:[["Ma o lenei o le igoa o le tupu o sa Lamanā o Lamana,", "And now the name of the king of the Lamanites was Laman,"], ["ua faaigoa o ia i le igoa o lona tamā;", "being called after the name of his father;"], ["o lea na ta'ua ai o ia o Lamana le tupu. Ma sa tupu o ia i luga o se nuu toatele lava.", "and therefore he was called king Laman. And he was king over a numerous people."]]},
  {num:4,words:[["Ma sa tofi e ia ni aoao mai uso o Amulona i laueleele uma sa nonofo ai ona tagata;", "And he appointed teachers of the brethren of Amulon in every land which was possessed by his people;"], ["ma sa faapea ona amata ona aoao atu ai o le gagana a Nifae i totonu o tagata uma o sa Lamanā.", "and thus the language of Nephi began to be taught among all the people of the Lamanites."]]},
  {num:5,words:[["Ma o i latou o ni tagata sa fiafia le tasi i le isi;", "And they were a people friendly one with another;"], ["e ui i lea sa latou lē iloa le Atua;", "nevertheless they knew not God;"], ["sa lei aoao atu foi e uso o Amulona ia te i latou se mea e uiga i le Alii lo latou Atua,", "neither did the brethren of Amulon teach them anything concerning the Lord their God,"], ["po o le tulafono a Mose;", "neither  the law of Moses;"], ["pe sa latou aoao atu foi ia te i latou upu a Apinati;", "nor did they teach them the words of Abinadi;"]]},
  {num:6,words:[["Ae sa latou aoao atu ia te i latou ia latou tausia la latou talafaamaumau,", "But they taught them that they should keep their record,"], ["ma ia mafai ona latou fetusia'i o le tasi i le isi.", "and that they might write one to another."]]},
  {num:7,words:[["Ma sa faapea ona amata ona faateleina o 'oa a sa Lamanā,", "And thus the Lamanites began to increase in riches,"], ["ma amata ona fefaataua'i o le tasi ma le isi ma faasolo maoa'e ai,", "and began to trade one with another and wax great,"], ["ma amata ona avea ai ma ni tagata popoto ma atamamai,", "and began to be a cunning and a wise people,"], ["e tusa ma le poto o le lalolagi,", "as to the wisdom of the world,"], ["ioe,", "yea,"], ["o ni tagata popoto tele,", "a very cunning people,"], ["e fiafia i ituaiga o amioleaga eseese uma ma le faomea,", "delighting in all manner of wickedness and plunder,"], ["vagana ai i totonu o o latou lava uso.", "except it were among their own brethren."]]},
  {num:8,words:[["Ma o lenei sa oo ina amata ona faaaoga e Amulona le pule i luga o Alema ma ona uso,", "And now it came to pass that Amulon began to exercise authority over Alma and his brethren,"], ["ma amata ona sauaina o ia,", "and began to persecute him,"], ["ma faia ia sauaina e lana fanau a latou fanau.", "and cause that his children should persecute their children."]]},
  {num:9,words:[["Aua sa iloa e Amulona ia Alema,", "For Amulon knew Alma,"], ["o ia o se tasi sa avea ma faitaulaga a le tupu,", "that he had been one of the king’s priests,"], ["ma o ia lea sa talitonu i upu a Apinati ma tuli ese i fafo mai luma o le tupu,", "and that it was he that believed the words of Abinadi and was driven out before the king,"], ["ma o lea na ita ai o ia ia te ia;", "and therefore he was wroth with him;"], ["ona sa pule le tupu o Lamana ia te ia,", "for he was subject to king Laman,"], ["peitai sa ia faaaoga le pule i luga o i latou,", "yet he exercised authority over them,"], ["ma tuu galuega mamafa i o latou luga,", "and put tasks upon them,"], ["ma tuu pule-galuega i luga o i latou.", "and put task– masters over them."]]},
  {num:10,words:[["Ma sa oo ina matua tele lava o latou puapuaga sa amata ona latou tagi malosi atu i le Atua.", "And it came to pass that so great were their afflictions that they began to cry mightily to God."]]},
  {num:11,words:[["Ma sa poloaiina i latou e Amulona ia tuu a latou tagi;", "And Amulon commanded them that they should stop their cries;"], ["ma sa tuu e ia leoleo i luga o i latou e vaaia i latou, ma o soo se tasi e maua o valaau atu i le Atua,", "and he put guards over them to watch them,"], ["o le a fasiotia.", "that whosoever should be found calling upon God should be put to death."]]},
  {num:12,words:[["Ma sa lē sii a'e e Alema ma ona tagata o latou leo i le Alii lo latou Atua,", "And Alma and his people did not raise their voices to the Lord their God,"], ["ae sa latou sasaa atu o latou loto ia te ia;", "but did pour out their hearts to him;"], ["ma sa silafia e ia mafaufauga o o latou loto.", "and he did know the thoughts of their hearts."]]},
  {num:13,words:[["Ma sa oo ina oo mai le siufofoga o le Alii ia te i latou i o latou puapuaga,", "And it came to pass that the voice of the Lord came to them in their afflictions,"], ["ua fetalai mai:", "saying:"], ["Inā ea ia o outou ulu ma ia faamafanafanaina outou;", "Lift up your heads and be of good comfort,"], ["ona ua Ou iloa le feagaiga na outou faia mai ia te a'u;", "for I know of the covenant which ye have made unto me;"], ["ma o le a Ou osifeagaiga ma o'u tagata ma laveai i latou mai le pologa.", "and I will covenant with my people and deliver them out of bondage."]]},
  {num:14,words:[["Ma o le a Ou faamāmāina foi avega ua tuu i o outou tau'au,", "And I will also ease the burdens which are put upon your shoulders,"], ["e oo ia te outou tou te lē lagonaina i latou i luga o o outou tua,", "that even you cannot feel them upon your backs,"], ["a'o outou i ai lava i le pologa;", "even while you are in bondage;"], ["ma o le a Ou faia lenei mea ina ia mafai ona outou tutu e avea o ni molimau mo a'u i le lumanai,", "and this will I do that ye may stand as witnesses for me hereafter,"], ["ma ina ia mafai ona outou iloa ma le mautinoa o A'u,", "and that ye may know of a surety that I,"], ["o le Alii le Atua,", "the Lord God,"], ["e asiasi atu i o'u tagata i o latou puapuaga .", "do visit my people in their afflictions."]]},
  {num:15,words:[["Ma o lenei sa oo ina faamāmāina avega sa tuu i luga o Alema ma ona uso;", "And now it came to pass that the burdens which were laid upon Alma and his brethren were made light;"], ["ioe,", "yea,"], ["sa faamalosia i latou e le Alii ina ia mafai ona latou tauave ma le faigofie a latou avega ,", "the Lord did strengthen them that they could bear up their burdens with ease,"], ["ma sa latou gaua'i atu ma le fiafia ma le onosai i le finagalo atoa o le Alii.", "and they did submit cheerfully and with patience to all the will of the Lord."]]},
  {num:16,words:[["Ma sa oo ina matua tele lava lo latou faatuatua ma lo latou onosai sa oo ina toe oo mai le siufofoga o le Alii ia te i latou,", "And it came to pass that so great was their faith and their patience that the voice of the Lord came unto them again,"], ["ua fetalai mai:", "saying:"], ["Ia faamafanafanaina outou,", "Be of good comfort,"], ["ona o le aso a taeao o le a Ou laveai ai outou mai le pologa.", "for on the morrow I will deliver you out of bondage."]]},
  {num:17,words:[["Ma sa fetalai mai o ia ia Alema:", "And he said unto Alma:"], ["Ia e muamua atu i luma o lenei nuu,", "Thou shalt go before this people,"], ["ma o le a Ou alu atu faatasi ma oe ma laveai lenei nuu mai le pologa .", "and I will go with thee and deliver this people out of bondage."]]},
  {num:18,words:[["O lenei sa oo ina faapotopoto faatasi e Alema ma ona tagata a latou lafu i le po,", "Now it came to pass that Alma and his people in the night– time gathered their flocks together,"], ["ma a latou kuranamua foi;", "and also of their grain;"], ["ioe,", "yea,"], ["sa latou faapotopoto faatasi a latou lafu i le po atoa.", "even all the night– time were they gathering the flocks together."]]},
  {num:19,words:[["Ma i le taeao sa faia e le Alii ia oo mai se moe gase i luga o sa Lamanā,", "And in the morning the Lord caused a deep sleep to come upon the Lamanites,"], ["ioe, ma o o latou pule-galuega uma,", "yea,"], ["sa matua momoe gase lava.", "and all their task– masters were in a profound sleep."]]},
  {num:20,words:[["Ma sa o ese atu Alema ma ona tagata i le vao;", "And Alma and his people departed into the wilderness;"], ["ma ina ua mavae ona latou malaga i le aso atoa sa latou faatutu o latou faleie i se vanu,", "and when they had traveled all day they pitched their tents in a valley,"], ["ma sa latou faaigoaina le vanu o Alema,", "and they called the valley Alma,"], ["ona sa taitai e ia lo latou ala i le vao.", "because he led their way in the wilderness."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["ma i le vanu o Alema sa latou sa'ati atu ai a latou faafetai i le Atua ona sa alofa mutimutivale mai o ia ia te i latou,", "and in the valley of Alma they poured out their thanks to God because he had been merciful unto them,"], ["ma faamāmā e ia a latou avega,", "and eased their burdens,"], ["ma ua laveai e ia i latou mai le pologa;", "and had delivered them out of bondage;"], ["ona sa latou i ai i le pologa,", "for they were in bondage,"], ["ma sa leai se tasi sa mafai ona lavea'ia i latou vagana ai le Alii lo latou Atua.", "and none could deliver them except it were the Lord their God."]]},
  {num:22,words:[["Ma sa latou avatu le faafetai i le Atua,", "And they gave thanks to God,"], ["ioe, o o latou tane uma ma o latou fafine uma ma a latou fanau uma o e sa mafafai ona tautatala,", "yea,"], ["sa sisi'i a'e o latou leo i viiga o lo latou Atua.", "all their men and all their women and all their children that could speak lifted their voices in the praises of their God."]]},
  {num:23,words:[["Ma o lenei sa fetalai mai le Alii ia Alema:", "And now the Lord said unto Alma:"], ["Ia e faavave ma aveese atu oe ma nei tagata i fafo mai lenei laueleele,", "Haste thee and get thou and this people out of this land,"], ["ona ua feala mai sa Lamanā ma ua latou tuliloa mai oe; o lea ia e alu ese atu ai i fafo mai lenei laueleele,", "for the Lamanites have awakened and do pursue thee;"], ["ma o le a Ou taofi sa Lamanā i le vanu lenei,", "therefore get thee out of this land,"], ["ina ia latou lē o mai sili atu e tuliloa lenei nuu.", "and I will stop the Lamanites in this valley that they come no further in pursuit of this people."]]},
  {num:24,words:[["Ma sa oo ina latou o ese atu i fafo o le vanu,", "And it came to pass that they departed out of the valley,"], ["ma alu la latou malaga i le vao.", "and took their journey into the wilderness."]]},
  {num:25,words:[["Ma ina ua mavae aso e sefulu lua o latou i ai i le vao, sa latou taunuu i le laueleele o Sara'emila;", "And after they had been in the wilderness twelve days they arrived in the land of Zarahemla;"], ["ma sa talia foi i latou ma le olioli e le tupu o Mosaea.", "and king Mosiah did also receive them with joy."]]},
];
renderVerseSet(mo_ch_24_Verses, 'mo-ch24-verses');

var mo_ch_25_Verses = [
  {num:1,words:[["Ma o lenei sa faia e le tupu o Mosaea ia faapotopoto faatasi le nuu.", "And now king Mosiah caused that all the people should be gathered together."]]},
  {num:2,words:[["O lenei sa lē toatele naua fanau a Nifae,", "Now there were not so many of the children of Nephi,"], ["pe sa toatele naua i latou o e na tupuga mai ia Nifae,", "or so many of those who were descendants of Nephi,"], ["e pei o tagata sa i ai o Sara'emila,", "as there were of the people of Zarahemla,"], ["o lē na tupuga mai ia Moleka ,", "who was a descendant of Mulek,"], ["ma i latou o e na o mai faatasi ma ia i le vao.", "and those who came with him into the wilderness."]]},
  {num:3,words:[["Ma sa lē toatele naua tagata o Nifae ma tagata o Sara'emila e pei o tagata sa Lamanā sa i ai;", "And there were not so many of the people of Nephi and of the people of Zarahemla as there were of the Lamanites;"], ["ioe,", "yea,"], ["sa lē tusa ma le afa o sa Lamanā lo latou toatele.", "they were not half so numerous."]]},
  {num:4,words:[["Ma o lenei sa faapotopoto faatasi tagata uma o Nifae,", "And now all the people of Nephi were assembled together,"], ["ma tagata uma foi o Sara'emila,", "and also all the people of Zarahemla,"], ["ma sa latou faapotopoto faatasi i ni tino se lua.", "and they were gathered together in two bodies."]]},
  {num:5,words:[["Ma sa oo ina faitau atu e Mosaea,", "And it came to pass that Mosiah did read,"], ["ma ia faia ia faitau atu i lona nuu,", "and caused to be read,"], ["talafaamaumau a Senifa;", "the records of Zeniff to his people;"], ["ioe,", "yea,"], ["sa faitau atu e ia talafaamaumau a le nuu o Senifa,", "he read the records of the people of Zeniff,"], ["mai le taimi na latou tuua ai le laueleele o Sara'emila seia oo ina latou toe foi mai.", "from the time they left the land of Zarahemla until they returned again."]]},
  {num:6,words:[["Ma sa faitau atu foi e ia le tala a Alema ma ona uso,", "And he also read the account of Alma and his brethren,"], ["ma o latou puapuaga uma,", "and all their afflictions,"], ["mai le taimi na latou tuua ai le laueleele o Sara'emila seia oo i le taimi na latou toe foi mai ai.", "from the time they left the land of Zarahemla until the time they returned again."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona faitau atu e Mosaea talafaamaumau,", "when Mosiah had made an end of reading the records,"], ["sa to'ia ona tagata o e sa nonofo pea i le laueleele i le ofo ma le meia.", "his people who tarried in the land were struck with wonder and amazement."]]},
  {num:8,words:[["Ona sa latou lē iloa se mea e mafaufau i ai;", "For they knew not what to think;"], ["ona ina ua latou vaai atu ia i latou o e na laveaiina mai le pologa sa faatutumulia i latou i le olioli tele lava.", "for when they beheld those that had been delivered out of bondage they were filled with exceedingly great joy."]]},
  {num:9,words:[["O lenei foi,", "And again,"], ["ina ua latou mafaufau ifo i o latou uso o e ua fasiotia e sa Lamanā sa faatutumulia i latou i le faanoanoa,", "when they thought of their brethren who had been slain by the Lamanites they were filled with sorrow,"], ["ma oo ina maligi o latou loimata e tele i le faanoanoa.", "and even shed many tears of sorrow."]]},
  {num:10,words:[["O lenei foi,", "And again,"], ["ina ua latou mafaufau ifo i le agalelei vave o le Atua,", "when they thought of the immediate goodness of God,"], ["ma lona mana i le laveaiina o Alema ma ona uso mai lima o sa Lamanā ma le pologa,", "and his power in delivering Alma and his brethren out of the hands of the Lamanites and of bondage,"], ["sa latou si'i a'e o latou leo ma momoli atu le faafetai i le Atua.", "they did raise their voices and give thanks to God."]]},
  {num:11,words:[["O lenei foi,", "And again,"], ["ina ua latou mafaufau ifo ia sa Lamanā,", "when they thought upon the Lamanites,"], ["o e o o latou uso,", "who were their brethren,"], ["e uiga i lo latou tulaga agasala ma le eleelea,", "of their sinful and polluted state,"], ["sa faatutumulia i latou i le tiga ma le mafatia mo le manuia o o latou agaga .", "they were filled with pain and anguish for the welfare of their souls."]]},
  {num:12,words:[["Ma sa oo ina o i latou o e o fanau a Amulona ma ona uso,", "And it came to pass that those who were the children of Amulon and his brethren,"], ["o e na latou ave afafine o sa Lamanā e avea ma a latou avā,", "who had taken to wife the daughters of the Lamanites,"], ["sa lē fiafia i amioga a o latou tamā,", "were displeased with the conduct of their fathers,"], ["ma sa latou lē mananao ia toe ta'ua i latou i igoa o o latou tamā;", "and they would no longer be called by the names of their fathers,"], ["o lea na latou ave ai ia te i latou lava le igoa o Nifae,", "therefore they took upon themselves the name of Nephi,"], ["ina ia mafai ona ta'ua i latou o fanau a Nifae ma faitauina i latou i totonu o i latou o e ua ta'ua o sa Nifaē.", "that they might be called the children of Nephi and be numbered among those who were called Nephites."]]},
  {num:13,words:[["Ma o lenei sa faitauina tagata uma o Sara'emila faatasi ma sa Nifaē,", "And now all the people of Zarahemla were numbered with the Nephites,"], ["ma sa faia lenei mea ona sa lē faaee atu le malo i luga o se tasi ae nao i latou o e na tupuga mai ia Nifae.", "and this because the kingdom had been conferred upon none but those who were descendants of Nephi."]]},
  {num:14,words:[["Ma o lenei sa oo ina ua uma ona faai'u e Mosaea le tautala atu ma le faitau atu i le nuu,", "And now it came to pass that when Mosiah had made an end of speaking and reading to the people,"], ["sa manao o ia ia tautala atu foi Alema i le nuu.", "he desired that Alma should also speak to the people."]]},
  {num:15,words:[["Ma sa tautala atu Alema ia te i latou,", "And Alma did speak unto them,"], ["a'o latou potopoto faatasi i ni tino potopoto tetele,", "when they were assembled together in large bodies,"], ["ma sa alu atu o ia mai le tasi tino potopoto i le tasi,", "and he went from one body to another,"], ["ma talai atu i tagata le salamo ma le faatuatua i le Alii.", "preaching unto the people repentance and faith on the Lord."]]},
  {num:16,words:[["Ma sa apoapoa'i atu o ia i tagata o Limae ma ona uso,", "And he did exhort the people of Limhi and his brethren,"], ["i latou uma ia o e na laveaiina mai le pologa,", "all those that had been delivered out of bondage,"], ["ina ia latou manatua o le Alii lava na laveaiina i latou.", "that they should remember that it was the Lord that did deliver them."]]},
  {num:17,words:[["Ma sa oo ina ua uma ona aoaoina e Alema le nuu i mea e tele,", "And it came to pass that after Alma had taught the people many things,"], ["ma faaiu e ia le tautala atu ia te i latou,", "and had made an end of speaking to them,"], ["sa oo ina manao le tupu o Limae ia papatiso o ia;", "that king Limhi was desirous  that he might be baptized;"], ["ma sa mananao foi lona nuu uma ia papatisoina i latou.", "and all his people were desirous that they might be baptized also."]]},
  {num:18,words:[["O lea na alu atu ai Alema i totonu o le vai ma papatiso i latou;", "Therefore,"], ["ioe,", "Alma did go forth into the water and did baptize them;"], ["sa papatiso e ia i latou i le ala na papatiso ai e ia ona uso i vai o Mamona;", "yea, he did baptize them after the manner he did his brethren in the waters of Mormon;"], ["ioe,", "yea,"], ["ma o le toatele o e na papatiso e ia na auai i le ekalesia a le Atua;", "and as many as he did baptize did belong to the church of God;"], ["ma sa latou faia lenei mea ona o lo latou talitonu i upu a Alema.", "and this because of their belief on the words of Alma."]]},
  {num:19,words:[["Ma sa oo ina tuu atu e le tupu o Mosaea ia Alema ia faatutu e ia ni aulotu i le laueleele atoa o Sara'emila;", "And it came to pass that king Mosiah granted unto Alma that he might establish churches throughout all the land of Zarahemla;"], ["ma tuu atu ia te ia le mana e faauu ai faitaulaga ma aoao i luga o aulotu taitasi.", "and gave him power to ordain priests and teachers over every church."]]},
  {num:20,words:[["O lenei sa faia lenei mea ona o le toatele naua o tagata sa lē mafai ona pulea i latou uma e se aoao e toatasi;", "Now this was done because there were so many people that they could not all be governed by one teacher;"], ["pe mafai foi ona latou lagona le afioga atoa a le Atua i se faapotoptoga e tasi;", "neither could they all hear the word of God in one assembly;"]]},
  {num:21,words:[["O lea na latou faapotopoto ai i latou lava i ni tino potopoto eseese,", "Therefore they did assemble them– selves together in different bodies,"], ["ua ta'ua o aulotu;", "being called churches;"], ["sa tofu aulotu taitasi ma o latou faitaulaga ma o latou aoao,", "every church having their priests and their teachers,"], ["ma sa taitasi le faitaulaga ma talai atu le afioga e pei ona tuuina mai ia te ia e le fofoga o Alema.", "and every priest preaching the word according as it was delivered to him by the mouth of Alma."]]},
  {num:22,words:[["Ma o lea,", "And thus,"], ["e ui ina sa tele aulotu sa i ai ae o i latou uma o le ekalesia e tasi;", "notwithstanding there being many churches they were all one church,"], ["ioe,", "yea,"], ["o le ekalesia lava a le Atua;", "even the church of God;"], ["ona sa leai se mea sa tala'ia i aulotu uma vagana ai le salamo ma le faatuatua i le Atua.", "for there was nothing preached in all the churches except it were repentance and faith in God."]]},
  {num:23,words:[["Ma o lenei e fitu aulotu sa i ai i le laueleele o Sara'emila. Ma sa oo o soo ni isi sa manao latou te ave i o latou luga le suafa o Keriso,", "And now there were seven churches in the land of Zarahemla. And it came to pass that whosoever were desirous to take upon them the name of Christ,"], ["po o le Atua,", "or of God,"], ["sa latou auai i aulotu a le Atua.", "they did join the churches of God;"]]},
  {num:24,words:[["Ma sa ta'ua i latou o le nuu o le Atua. Ma sa liligi mai e le Alii lona Agaga i luga o i latou,", "And they were called the people of God. And the Lord did pour out his Spirit upon them,"], ["ma sa faamanuiaina i latou,", "and they were blessed,"], ["ma uluola i le laueleele.", "and prospered in the land."]]},
];
renderVerseSet(mo_ch_25_Verses, 'mo-ch25-verses');

var mo_ch_26_Verses = [
  {num:1,words:[["O lenei sa oo ina sa toatele tupulaga faia'e sa lē mafai ona malamalama i upu a le tupu o Peniamina,", "Now it came to pass that there were many of the rising generation that could not understand the words of king Benjamin,"], ["ona o ni fanau laiti i latou i le taimi na saunoa mai ai o ia i lona nuu;", "being little children at the time he spake unto his people;"], ["ma sa latou lē talitonu i uputuu a o latou tamā.", "and they did not believe the tradition of their fathers."]]},
  {num:2,words:[["Sa latou lē talitonu i mea sa tautalagia e uiga i le toetutu mai o e ua oti,", "They did not believe what had been said concerning the resurrection of the dead,"], ["pe sa latou talitonu foi e uiga i le afio mai o Keriso.", "neither did they believe concerning the coming of Christ."]]},
  {num:3,words:[["Ma o lenei ona o lo latou lē talitonu sa lē mafai ai ona latou malamalama i le afioga a le Atua;", "And now because of their unbelief they could not understand the word of God;"], ["ma sa faamaaa o latou loto.", "and their hearts were hardened."]]},
  {num:4,words:[["Ma sa latou lē fia papatiso;", "And they would not be baptized;"], ["pe sa latou fia auai foi i le ekalesia. Ma sa avea i latou o ni tagata ese e tusa ma lo latou faatuatuaga,", "neither would they join the church. And they were a separate people as to their faith,"], ["ma sa faapea ona latou tumau ai mai lena taimi,", "and remained so ever after,"], ["i lo latou tulaga faaletino ma tumu i le agasala;", "even in their carnal and sinful state;"], ["ona sa latou lē fia valaau atu i le Alii lo latou Atua.", "for they would not call upon the Lord their God."]]},
  {num:5,words:[["Ma o lenei i le nofoaiga a Mosaea, sa lē tusa lo latou toatele ma le afa o tagata o le Atua;", "And now in the reign of Mosiah they were not half so numerous as the people of God;"], ["ae ona o fevaevaeaiga sa i ai i totonu o le au uso, sa oo ina atili faatoateleina ai i latou.", "but because of the dissensions among the brethren they became more numerous."]]},
  {num:6,words:[["Ona sa oo ina latou faaseseina le toatele o e sa i ai i le ekalesia,", "For it came to pass that they did deceive many with their flattering words,"], ["ia latou upu taufaasee,", "who were in the church,"], ["ma faaoso i latou ia latou faia agasala e tele;", "and did cause them to commit many sins;"], ["o lea sa tatau ai ia te i latou o e na faia le agasala,", "therefore it became expedient that those who committed sin,"], ["o e sa i ai i le ekalesia,", "that were in the church,"], ["ona a'oa'ia e le ekalesia.", "should be admonished by the church."]]},
  {num:7,words:[["Ma sa oo ina aumai i latou i luma o faitaulaga,", "And it came to pass that they were brought before the priests,"], ["ma sa tuu atu i latou i luga i faitaulaga e aoao;", "and delivered up unto the priests by the teachers;"], ["ma sa aumai i latou e faitaulaga i luma o Alema,", "and the priests brought them before Alma,"], ["o ia o le faitaulaga sili.", "who was the high priest."]]},
  {num:8,words:[["O lenei sa tuu atu e le tupu o Mosaea ia Alema le pule i luga o le ekalesia.", "Now king Mosiah had given Alma the authority over the church."]]},
  {num:9,words:[["Ma sa oo sa lē iloa e Alema e uiga ia te i latou;", "And it came to pass that Alma did not know concerning them;"], ["peitai sa i ai ni molimau e toatele faasaga ia te i latou;", "but there were many witnesses against them;"], ["ioe,", "yea,"], ["sa tutu le nuu ma molimau atu i le tele o a latou amioletonu.", "the people stood and testified of their iniquity in abundance."]]},
  {num:10,words:[["O lenei sa lei i ai se mea faapea na tupu muamua mai i le ekalesia;", "Now there had not any such thing happened before in the church;"], ["o lea na atuatuvale ai Alema i lona agaga,", "therefore Alma was troubled in his spirit,"], ["ma sa faia e ia ia aumai i latou i luma o le tupu.", "and he caused that they should be brought before the king."]]},
  {num:11,words:[["Ma sa fai atu o ia i le tupu:", "And he said unto the king:"], ["Faauta,", "Behold,"], ["o le toatele nei o e ua matou aumai i ou luma,", "here are many whom we have brought before thee,"], ["o e ua tuua'i e o latou uso;", "who are accused of their brethren;"], ["ioe,", "yea,"], ["ma sa maua i latou o latou faia amioletonu eseese. Ma ua latou lē salamo ia latou amioletonu;", "and they have been taken in divers iniquities. And they do not repent of their iniquities;"], ["o lea ua matou aumai ai i latou i ou luma,", "therefore we have brought them before thee,"], ["ina ia mafai ona e faamasino i latou e tusa ma a latou solitulafono.", "that thou mayest judge them according to their crimes."]]},
  {num:12,words:[["Peitai sa fai atu le tupu o Mosaea ia Alema:", "But king Mosiah said unto Alma:"], ["Faauta,", "Behold,"], ["ou te lē faamasinoina i latou;", "I judge them not;"], ["o lea ou te tuu atu ai i latou i ou lima ia faamasinoina.", "therefore I deliver them into thy hands to be judged."]]},
  {num:13,words:[["Ma o lenei sa toe atuatuvale le agaga o Alema;", "And now the spirit of Alma was again troubled;"], ["ma sa alu atu o ia ma ole atu i le Alii po o le a le mea e tatau ona ia faia e uiga i lenei mataupu,", "and he went and inquired of the Lord what he should do concerning this matter,"], ["ona sa mata'u o ia ne'i fai e ia se mea sese i le silafaga a le Atua.", "for he feared that he should do wrong in the sight of God."]]},
  {num:14,words:[["Ma sa oo ina ua uma ona ia sasaa atu lona agaga atoa i le Atua,", "And it came to pass that after he had poured out his whole soul to God,"], ["sa oo mai le siufofoga o le Alii ia te ia,", "the voice of the Lord came to him,"], ["ua fetalai mai:", "saying:"]]},
  {num:15,words:[["Amuia lava oe,", "Blessed art thou,"], ["Alema,", "Alma,"], ["ma amuia foi i latou o e na papatiso i vai o Mamona. Ua e manuia ona o lou faatuatua tele i nao upu a la'u auauna o Apinati.", "and blessed are they who were baptized in the waters of Mormon. Thou art blessed because of thy exceeding faith in the words alone of my servant Abinadi."]]},
  {num:16,words:[["Ma amuia foi i latou ona o lo latou faatuatua tele i nao upu na e tautala atu ia te i latou.", "And blessed are they because of their exceeding faith in the words alone which thou hast spoken unto them."]]},
  {num:17,words:[["Ma amuia lava oe ona ua e faatuina se ekalesia i totonu o lenei nuu;", "And blessed art thou because thou hast established a church among this people;"], ["ma o le a faatumauina i latou,", "and they shall be established,"], ["ma o le a avea i latou ma o'u nuu.", "and they shall be my people."]]},
  {num:18,words:[["Ioe,", "Yea,"], ["amuia lava lenei nuu o e ua loto e tauave lo'u igoa ;", "blessed is this people who are willing to bear my name;"], ["ona o lo'u igoa o le a valaau ai i latou;", "for in my name shall they be called;"], ["ma o ā a'u i latou.", "and they are mine."]]},
  {num:19,words:[["Ma ona ua e fesili mai ia te a'u e uiga i lē ua solitulafono,", "And because thou hast inquired of me concerning the transgressor,"], ["ua e manuia.", "thou art blessed."]]},
  {num:20,words:[["O oe o la'u auauna;", "Thou art my servant;"], ["ma Ou te osifeagaiga ma oe o le a e maua le ola e faavavau;", "and I covenant with thee that thou shalt have eternal life;"], ["ma ia e auauna mai ia te a'u ma alu atu i lo'u igoa,", "and thou shalt serve me and go forth in my name,"], ["ma faapotopoto faatasi mai a'u mamoe.", "and shalt gather together my sheep."]]},
  {num:21,words:[["Ma o ia o lē e faalogo mai i lo'u leo o le a avea ma a'u mamoe ;", "And he that will hear my voice shall be my sheep;"], ["ma o ia ia outou talia i le ekalesia,", "and him shall ye receive into the church,"], ["ma o le a Ou talia foi o ia.", "and him will I also receive."]]},
  {num:22,words:[["Aua faauta,", "For behold,"], ["o la'u ekalesia lenei;", "this is my church;"], ["soo se tasi e papatiso ia papatisoina i le salamo.", "whosoever is baptized shall be baptized unto repentance."], ["Ma o soo se tasi tou te talia, ia talitonu i lo'u igoa;", "And whomsoever ye receive shall believe in my name;"], ["ma o ia o le a Ou faamagalofuaina .", "and him will I freely forgive."]]},
  {num:23,words:[["Ona o A'u o lē ua aveina i o'u luga agasala a le lalolagi;", "For it is I that taketh upon me the sins of the world;"], ["ona o A'u o lē na foafoaina i latou; ma o A'u o lē na te tuu atu ia te ia o lē e talitonu e oo i le iuga,", "for it is I that hath created them;"], ["se nofoaga i lo'u lima taumatau.", "and it is I that granteth unto him that believeth unto the end a place at my right hand."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["o lo'u igoa ua valaau ai i latou;", "in my name are they called;"], ["ma afai latou te iloa a'u o le a latou o mai,", "and if they know me they shall come forth,"], ["ma o le a latou maua se nofoaga e faavavau i lo'u lima taumatau.", "and shall have a place eternally at my right hand."]]},
  {num:25,words:[["Ma e oo a ili mai le pu lona lua , ona o mai lea o i latou o e sa lē iloaina lava a'u ma o le a tutu i o'u luma.", "And it shall come to pass that when the second trump shall sound then shall they that never knew me come forth and shall stand before me."]]},
  {num:26,words:[["Ma o le a latou iloa i le taimi lena o A'u o le Alii lo latou Atua,", "And then shall they know that I am the Lord their God,"], ["o A'u o lo latou Togiola;", "that I am their Redeemer;"], ["peitai sa latou lē mananao e togiolaina i latou.", "but they would not be redeemed."]]},
  {num:27,words:[["Ma o le a Ou ta'utino atu ia te i latou i le taimi lena sa Ou lē iloaina lava i latou;", "And then I will confess unto them that I never knew them;"], ["ma o le a latou o atu i le afi e faavavau ua saunia mo le tiapolo ma ana agelu.", "and they shall depart into ever lasting fire prepared for the devil and his angels."]]},
  {num:28,words:[["O lea Ou te fai atu ai ia te oe,", "Therefore I say unto you,"], ["o ia o lē e lē faalogo mai i lo'u leo,", "that he that will not hear my voice,"], ["o ia lava lea ia outou lē taliaina i la'u ekalesia,", "the same shall ye not receive into my church,"], ["ona o ia lea o le a Ou lē taliaina i le aso gataaga.", "for him I will not receive at the last day."]]},
  {num:29,words:[["O lea Ou te fai atu ai ia te oe,", "Therefore I say unto you,"], ["Alu ia;", "Go;"], ["ma o soo se tasi e solitulafono faasaga mai ia te a'u,", "and whosoever transgresseth against me,"], ["ia e faamasinoina o ia e tusa ma agasala ua faia e ia;", "him shall ye judge according to the sins which he has committed;"], ["ma afai e ta'utino mai e ia ana agasala i luma o oe ma a'u,", "and if he confess his sins before thee and me,"], ["ma salamo ma le faamaoni o lona loto,", "and repenteth in the sincerity of his heart,"], ["ia e faamagaloina o ia,", "him shall ye forgive,"], ["ma o le a Ou faamagaloina foi o ia.", "and I will forgive him also."]]},
  {num:30,words:[["Ioe,", "Yea,"], ["ma o le tele o taimi e salamo ai lo'u nuu 'Ou te faamagalo ai i latou ia latou solitulafono faasaga mai ia te a'u.", "and as often as my people repent will I forgive them their trespasses against me."]]},
  {num:31,words:[["Ma ia outou faamagalo foi le tasi i le isi ia outou solitulafono;", "And ye shall also forgive one another your trespasses;"], ["aua e moni Ou te fai atu ia te oe,", "for verily I say unto you,"], ["o ia o lē e lē faamagalo atu i solitulafono a lē la te tuaoi ae fai mai o ia ua salamo o ia,", "he that forgiveth not his neighbor’s trespasses when he says that he repents,"], ["o ia lava lea ua aumai e ia o ia lava i lalo i le ta'usalaga.", "the same hath brought himself under condemnation."]]},
  {num:32,words:[["O lenei Ou te fai atu ia te oe,", "Now I say unto you,"], ["Alu ia;", "Go;"], ["ma o soo se tasi e lē fia salamo i ana agasala, o ia lava lea ia lē faitauina i totonu o lo'u nuu;", "and whosoever will not repent of his sins the same shall not be numbered among my people;"], ["ma ia tausia lenei mea mai le taimi nei i luma.", "and this shall be observed from this time forward."]]},
  {num:33,words:[["Ma sa oo ina ua uma ona faalogo o Alema i nei upu sa tusi e ia i lalo ina ia mafai ona maua e ia,", "And it came to pass when Alma had heard these words he wrote them down that he might have them,"], ["ma ina ia mafai ona faamasino e ia tagata o lena ekalesia e tusa ma poloaiga a le Atua.", "and that he might judge the people of that church according to the command– ments of God."]]},
  {num:34,words:[["Ma sa oo ina alu atu Alema ma faamasino i latou o e na maua i le amioletonu,", "And it came to pass that Alma went and judged those that had been taken in iniquity,"], ["e tusa ma le afioga a le Alii.", "according to the word of the Lord."]]},
  {num:35,words:[["Ma soo se isi sa salamo ia latou agasala ma ta'utino mai i latou,", "And whosoever repented of their sins and did confess them,"], ["o i latou ia na faitau e ia i totonu o tagata o le ekalesia.", "them he did number among the people of the church;"]]},
  {num:36,words:[["Ma o i latou o e sa lē fia ta'utino mai a latou agasala ma salamo ia latou amioletonu,", "And those that would not confess their sins and repent of their iniquity,"], ["o i latou lava ia sa lē faitauina i totonu o tagata o le ekalesia,", "the same were not numbered among the people of the church,"], ["ma sa soloiesea o latou igoa.", "and their names were blotted out."]]},
  {num:37,words:[["Ma sa oo ina pulea e Alema mataupu uma o le ekalesia;", "And it came to pass that Alma did regulate all the affairs of the church;"], ["ma sa amata ona latou toe maua o le filemu ma le manuia tele i mataupu o le ekalesia,", "and they began again to have peace and to prosper exceedingly in the affairs of the church,"], ["ma savavali ma le faaeteete i luma o le Atua,", "walking circumspectly before God,"], ["ma talia le toatele,", "receiving many,"], ["ma papatiso le toatele.", "and baptizing many."]]},
  {num:38,words:[["Ma o lenei o nei mea uma sa faia e Alema ma ona uso-a-auauna o e sa taitai i luga o le ekalesia,", "And now all these things did Alma and his fellow laborers do who were over the church,"], ["ma savavali ma le filiga atoa,", "walking in all diligence,"], ["ma aoao atu le afioga a le Atua i mea uma,", "teaching the word of God in all things,"], ["ma mafatia i ituaiga uma o puapuaga eseese,", "suffering all manner of afflictions,"], ["ma sauaina e i latou uma o e sa lē auai i le ekalesia a le Atua.", "being persecuted by all those who did not belong to the church of God."]]},
  {num:39,words:[["Ma sa latou tima'ia o latou uso;", "And they did admonish their brethren;"], ["ma sa tima'ia foi i latou uma taitoatasi,", "and they were also admonished,"], ["i le afioga a le Atua,", "every one by the word of God,"], ["e tusa ma ana agasala,", "according to his sins,"], ["po o agasala na ia faia,", "or to the sins which he had committed,"], ["ma poloaiina e le Atua ia tatalo e lē aunoa,", "being commanded of God to pray without ceasing,"], ["ma ia avatu le faafetai i mea uma.", "and to give thanks in all things."]]},
];
renderVerseSet(mo_ch_26_Verses, 'mo-ch26-verses');

var mo_ch_27_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina matua faateteleina sauaga na faia i le ekalesia e tagata sa lē talitonu, sa amata ona muimui le ekalesia,", "And now it came to pass that the persecutions which were inflicted on the church by the unbelievers became so great that the church began to murmur,"], ["ma faaseā atu i o latou taitai,", "and complain to their leaders concerning the matter;"], ["e uiga i le mataupu; ma sa latou faaseā atu ia Alema.", "and they did complain to Alma."], ["Ma sa tuu atu e Alema le mataupu i luma o lo latou tupu,", "And Alma laid the case before their king,"], ["o Mosaea.", "Mosiah."], ["Ma sa soalaupule faatasi Mosaea ma ana faitaulaga.", "And Mosiah consulted with his priests."]]},
  {num:2,words:[["Ma sa oo ina auina atu e le tupu o Mosaea se folafolaga i le nuu faataamilo atoa, ia lē tatau ona sauaina e soo se tasi ua lē talitonu, soo se tasi o i latou o e ua auai i le ekalesia a le Atua.", "And it came to pass that king Mosiah sent a proclamation throughout the land round about that there should not any unbeliever persecute any of those who belonged to the church of God."]]},
  {num:3,words:[["Ma sa i ai se poloaiga sa'olele i aulotu uma lava, ia lē tatau ona i ai ni sauaga i totonu o i latou,", "And there was a strict command throughout all the churches that there should be no persecutions among them,"], ["ma ia i ai le tutusa i totonu o tagata uma;", "that there should be an equality among all men;"]]},
  {num:4,words:[["Ia leai se faamaualuga po o se faasausili e tatau ona latou tuu e faalavelavea lo latou filemu ;", "That they should let no pride nor haughtiness disturb their peace;"], ["ma ia tatau i tagata taitoatasi ona manatu taua i lē la te tuaoi e pei o ia lava,", "that every man should esteem his neighbor as himself,"], ["ma galulue i o latou lava lima mo lo latou tausiga.", "laboring with their own hands for their support."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["ma e tatau i o latou faitaulaga ma aoao uma ona galulue i o latou lava lima mo lo latou tausiga,", "and all their priests and teachers should labor with their own hands for their support,"], ["i tulaga uma lava, vagana ai i le gasegase,", "in all cases save it were in sickness,"], ["po o i le mativa tele;", "or in much want;"], ["ma o le faia o nei mea,", "and doing these things,"], ["sa latou mau tele ai i le alofa tunoa o le Atua.", "they did abound in the grace of God."]]},
  {num:6,words:[["Ma sa amata ona toe i ai o le filemu tele i le nuu;", "And there began to be much peace again in the land;"], ["ma sa amata ona faatoateleina tele o tagata,", "and the people began to be very numerous,"], ["ma amata ona salalau solo atu i luga o le lalolagi,", "and began to scatter abroad upon the face of the earth,"], ["ioe,", "yea,"], ["i le itu i matu ma le itu i saute,", "on the north and on the south,"], ["i le itu i sasa'e ma le itu i sisifo,", "on the east and on the west,"], ["ma faatutu aai ma nuu tetele i itu uma o le laueleele.", "building large cities and villages in all quarters of the land."]]},
  {num:7,words:[["Ma sa asiasi mai le Alii ia te i latou ma faauluola i latou,", "And the Lord did visit them and prosper them,"], ["ma sa oo ina avea i latou ma se nuu tele ma le mau'oa.", "and they became a large and wealthy people."]]},
  {num:8,words:[["O lenei sa faitauina i totonu o e sa lē talitonu atalii o Mosaea;", "Now the sons of Mosiah were numbered among the unbelievers;"], ["ma sa faitauina foi i totonu o i latou se tasi o atalii o Alema,", "and also one of the sons of Alma was numbered among them,"], ["sa ta'ua o ia o Alema,", "he being  called Alma,"], ["i le igoa o lona tamā;", "after his father;"], ["e ui i lea,", "nevertheless,"], ["sa avea o ia ma tagata sili ona amioleaga ma le ifo i tupua. Ma o ia o se tagata sa mau upu,", "he became a very wicked and an idolatrous man. And he was a man of many words,"], ["ma sa tautala atu e ia le taufaasee tele i tagata;", "and did speak much flattery to the people;"], ["o lea na taitai atu ai e ia le toatele o tagata e fai e tusa ma ana amioletonu.", "therefore he led many of the people to do after the manner of his iniquities."]]},
  {num:9,words:[["Ma sa avea o ia ma puniala tele i le alualu i luma o le ekalesia a le Atua;", "And he became a great hinderment to the prosperity of the church of God;"], ["i le gaoi ese o loto o tagata;", "stealing away the hearts of the people;"], ["ma tutupu mai ai finauga e tele i totonu o le nuu;", "causing much dissension among the people;"], ["ma tuu atu ai se avanoa i le fili o le Atua e faaaoga ai lona mana i luga o i latou.", "giving a chance for the enemy of God to exercise his power over them."]]},
  {num:10,words:[["Ma o lenei sa oo ina o alu atu o ia i lea mea ma lea mea e lepeti le ekalesia a le Atua,", "And now it came to pass that while he was going about to destroy the church of God,"], ["ona sa alu atu o ia faalilolilo faatasi ma atalii o Mosaea e saili e lepeti le ekalesia,", "for he did go about secretly with the sons of Mosiah seeking to destroy the church,"], ["ma taitai ese tagata o le Alii,", "and to lead astray the people of the Lord,"], ["e lē tusa ai ma poloaiga a le Atua,", "contrary to the commandments of God,"], ["po o a le tupu foi—", "or even the king—"]]},
  {num:11,words:[["Ma e pei ona ou fai atu ia te outou,", "And as I said unto you,"], ["a'o latou o atu i lea mea ma lea mea ma le fouvale faasaga i le Atua,", "as they were going about rebelling against God,"], ["faauta,", "behold,"], ["ua afio ifo le agelu a le Alii ia te i latou;", "the angel of the Lord appeared unto them;"], ["ma sa afio ifo o ia e peiseai i totonu o se ao;", "and he descended as it were in a cloud;"], ["ma sa fetalai mai o ia e pei o se leo o se faititili,", "and he spake as it were with a voice of thunder,"], ["sa luluina ai le eleele sa latou tutu ai;", "which caused the earth to shake upon which they stood;"]]},
  {num:12,words:[["Ma sa matua tele lava lo latou meia,", "And so great was their astonishment,"], ["sa latou pauu i le eleele,", "that they fell to the earth,"], ["ma lē malamalama i upu na fetalai mai ai o ia ia te i latou.", "and understood not the words which he spake unto them."]]},
  {num:13,words:[["E ui i lea sa toe fetalai mai o ia,", "Nevertheless he cried again,"], ["fai mai:", "saying:"], ["Alema e,", "Alma,"], ["tulai ma tu mai,", "arise and stand forth,"], ["aua aisea ua e sauaina ai le ekalesia a le Atua? Aua ua fetalai mai le Alii:", "for why persecutes thou the church of God? For the Lord hath said:"], ["O la'u ekalesia lenei,", "This is my church,"], ["ma o le a Ou faatumauina;", "and I will establish it;"], ["ma e leai se mea e faatoilaloina,", "and nothing shall overthrow it,"], ["vagana ai o le solitulafono o lo'u nuu.", "save it is the transgression of my people."]]},
  {num:14,words:[["Ma lea foi,", "And again,"], ["sa fetalai mai le agelu: Faauta,", "the angel said:"], ["ua faafofogaina e le Alii talosaga a lona nuu,", "Behold,"], ["ma talosaga foi a lana auauna,", "the Lord hath heard the prayers of his people,"], ["o Alema,", "and also the prayers of his servant,"], ["o lē o lou tamā; ona sa tatalo atu o ia ma le faatuatua tele e uiga ia te oe,", "Alma,"], ["ina ia mafai ona aumai o oe i le malamalama o le upumoni;", "who is thy father;"], ["o lea,", "for he has prayed with much faith concerning thee that thou mightest be brought to the knowledge of the truth;"], ["o le pogai lenei ua ou sau ai,", "therefore,"], ["e faatalitonu oe i le mana ma le pule a le Atua, ina ia talia talosaga a ana auauna,", "for this purpose have I come to convince thee of the power and authority of God,"], ["e tusa ma lo latou faatuatua.", "that the prayers of his servants might be answered according to their faith."]]},
  {num:15,words:[["Ma o lenei faauta,", "And now behold,"], ["e mafai ea ona e masalogia le mana o le Atua? Aua faauta,", "can ye dispute the power of God? For behold,"], ["pe ua lē luluina ea le eleele i lo'u leo? Ma pe ua lē mafai ea foi ona e vaai mai ia te a'u i ou luma? Ma ua auina mai a'u mai le Atua.", "doth not my voice shake the earth? And can ye not also behold me before you? And I am sent from God."]]},
  {num:16,words:[["O lenei ou te fai atu ia te oe:", "Now I say unto thee:"], ["Alu ia,", "Go,"], ["ma ia e manatua le faatagataotauaina o ou tamā i le laueleele o Helama,", "and remember the captivity of thy fathers in the land of Helam,"], ["ma i le laueleele o Nifae;", "and in the land of Nephi;"], ["ma manatua mea tetele na fai e ia mo i latou;", "and remember how great things he has done for them;"], ["ona sa i ai i latou i le pologa,", "for they were in bondage,"], ["ma ua laveaiina i latou e ia. Ma o lenei ou te fai atu ia te oe,", "and he has delivered them. And now I say unto thee,"], ["Alema,", "Alma,"], ["alu ia i lou ala,", "go thy way,"], ["ma ia lē toe saili e lepeti le ekalesia,", "and seek to destroy the church no more,"], ["ina ia talia a latou talosaga,", "that their prayers may be answered,"], ["ma ia lē toe faia lenei mea e tusa pe e te manao ia lafoa'i ese oe lava ia.", "and this even if thou wilt of thyself be cast off."]]},
  {num:17,words:[["Ma o lenei o upu mulimuli ia sa fetalai mai e le agelu ia Alema,", "And now it came to pass that these were the last words which the angel spake unto Alma,"], ["ma maliu ese atu o ia.", "and he departed."]]},
  {num:18,words:[["Ma o lenei sa oo ina toe pauu i le eleele Alema ma i latou o e na faatasi ma ia, ona sa tele lava lo latou meia;", "And now Alma and those that were with him fell again to the earth,"], ["ona sa latou vaai i se agelu a le Alii i o latou lava mata;", "for great was their astonishment;"], ["ma o lona siufofoga sa pei o se faititili,", "for with their own eyes they had beheld an angel of the Lord;"], ["sa luluina ai le eleele; ma sa latou iloa e leai se mea vagana ai le mana o le Atua,", "and his voice was as thunder,"], ["e mafai ona luluina le eleele, ma faagatete ai e peiseai a vaeluaina,", "which shook the earth;"], ["vagana ai le mana o le Atua.", "and they knew that there was nothing save the power of God that could shake the earth and cause it to tremble as though it would part asunder."]]},
  {num:19,words:[["Ma o lenei sa matua tele lava le meia o Alema,", "And now the astonishment of Alma was so great that he became dumb,"], ["sa oo ina gūgū o ia,", "that he could not open his mouth;"], ["sa lē mafai ona tatala lona gutu;", "yea,"], ["ioe,", "and he became weak,"], ["ma sa oo ina vaivai o ia, sa oo ina lē mafai ona faagaoioi e ia ona lima;", "even that he could not move his hands;"], ["o lea na avatu ai o ia e i latou o e na faatasi ma ia,", "therefore he was taken by those that were with him,"], ["ma sii lē gaoioi atu o ia,", "and carried helpless,"], ["seia oo ina faataatia o ia i luma o lona tamā.", "even until he was laid before his father."]]},
  {num:20,words:[["Ma sa latou faamatala atu i lona tamā mea uma na oo ia te i latou;", "And they rehearsed unto his father all that had happened unto them;"], ["ma sa olioli lona tamā,", "and his father rejoiced,"], ["aua sa iloa e ia o le mana lea a le Atua.", "for he knew that it was the power of God."]]},
  {num:21,words:[["Ma sa faia e ia ia faapotopoto mai faatasi se motu o tagata, ina ia mafai ona latou molimauina le mea ua faia e le Alii i lona atalii,", "And he caused that a multitude should be gathered together that they might witness what the Lord had done for his son,"], ["ma i latou foi o e na faatasi ma ia.", "and also for those that were with him."]]},
  {num:22,words:[["Ma sa faia e ia ia faapotopoto faatasi faitaulaga;", "And he caused that the priests should assemble themselves together;"], ["ma sa amata ona latou anapopogi, ma tatalo atu i le Alii lo latou Atua,", "and they began to fast,"], ["ia tatalaina e ia le gutu o Alema,", "and to pray to the Lord their God that he would open the mouth of Alma,"], ["ina ia mafai ona tautala o ia, ma ia mafai foi ona maua e ona lima ma ona vae lo latou malosi—ina ia mafai ona faapupulaina mata o le nuu,", "that he might speak,"], ["e vaai ma latou iloa ai le agalelei ma le mamalu o le Atua.", "and also that his limbs might receive their strength—that the eyes of the people might be opened to see and know of the goodness and glory of God."]]},
  {num:23,words:[["Ma sa oo ina ua mavae ona latou anapopogi ma tatalo mo le va o aso e lua ma po e lua,", "And it came to pass after they had fasted and prayed for the space of two days and two nights,"], ["sa toe maua e lima ma vae o Alema lo latou malosi,", "the limbs of Alma received their strength,"], ["ma sa tulai o ia i luga ma amata ona tautala mai ia te i latou, ua fai mai ia te i latou,", "and he stood up and began to speak unto them,"], ["ia faamafanafanaina i latou:", "bidding them to be of good comfort:"]]},
  {num:24,words:[["Ona,", "For,"], ["ua fai mai o ia,", "said he,"], ["ua ou salamo i a'u agasala, ma ua togiolaina a'u e le Alii;", "I have repented of my sins,"], ["faauta,", "and have been redeemed of the Lord;"], ["ua fanauina a'u i le Agaga.", "behold I am born of the Spirit."]]},
  {num:25,words:[["Ma sa fetalai mai le Alii ia te a'u:", "And the Lord said unto me:"], ["Aua e te ofo e ao i le fanauga uma a tagata,", "Marvel not that all mankind,"], ["ioe,", "yea,"], ["o tane ma fafine,", "men and women,"], ["o atunuu uma,", "all nations,"], ["ituaiga,", "kindreds,"], ["gagana eseese ma nuu,", "tongues and people,"], ["ona toe fanauina ;", "must be born again;"], ["ioe,", "yea,"], ["fananauina i le Atua,", "born of God,"], ["ma suia mai lo latou tulaga faaletino ma pa'ū,", "changed from their carnal and fallen state,"], ["i se tulaga o le amiotonu,", "to a state of righteous– ness,"], ["ua togiolaina e le Atua,", "being redeemed of God,"], ["ma avea ma ona atalii ma afafine.", "becoming his sons and daughters;"]]},
  {num:26,words:[["Ma faapea ona avea ai o i latou ma tagata fou;", "And thus they become new creatures;"], ["ma vagana ai ua latou faia lenei mea, e leai se ala latou te mafai ai,", "and unless they do this,"], ["ona fai mo o latou tofi le malo o le Atua.", "they can in nowise inherit the kingdom of God."]]},
  {num:27,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["a lē o le tulaga lea,", "unless this be the case,"], ["e ao ina lafoa'i ese i latou;", "they must be cast off;"], ["ma ua ou iloa lenei mea,", "and this I know,"], ["ona sa toetoe lava a lafoaiina ese a'u.", "because I was like to be cast off."]]},
  {num:28,words:[["E ui i lea,", "Nevertheless,"], ["ina ua mavae ona ou tauasa mai i puapuaga e tele,", "after wading through much tribulations,"], ["ma ou salamo toetoe a ou oti, sa tonu i le finagalo alofa mutimutivale o le Alii,", "repenting nigh unto death,"], ["ia se'i ese a'u i fafo mai se mu e faavavau,", "the Lord in mercy hath seen fit to snatch me out of an everlasting burning,"], ["ma ua fanauina a'u i le Atua.", "and I am born of God."]]},
  {num:29,words:[["Ua togiolaina lo'u agaga mai le au oona ma pologa o le amioletonu. Sa ou i ai i se lua loloto sili ona pogisa;", "My soul hath been redeemed from the gall of bitterness and bonds of iniquity. I was in the darkest abyss;"], ["ae o lenei ua ou vaaia le malamalama ofoofogia o le Atua. Sa puapuagatia lo'u agaga i le mafatia e faavavau,", "but now I behold the marvelous light of God. My soul was racked with eternal  torment;"], ["ae ua se'ia ese a'u,", "but I am snatched,"], ["ma ua lē toe tiga lo'u agaga.", "and my soul is pained no more."]]},
  {num:30,words:[["Sa ou teena lo'u Togiola,", "I rejected my Redeemer,"], ["ma faafitia mea na tautatala mai ai o tatou tamā;", "and denied that which had been spoken of by our fathers;"], ["ae o lenei, ina ia latou mua'i iloa o le a afio mai o ia,", "but now that they may foresee that he will come,"], ["ma e manatua e ia tagata uma na ia foafoaina,", "and that he remembereth every creature of his creating,"], ["o le a faaali mai ai e ia o ia lava i tagata uma.", "he will make himself manifest unto all."]]},
  {num:31,words:[["Ioe,", "Yea,"], ["o le a tootuli tulivae uma,", "every knee shall bow,"], ["ma tautino atu laulaufaiva uma i ona luma.", "and every tongue confess before him."], ["Ioe,", "Yea,"], ["o le aso mulimuli lava,", "even at the last day,"], ["pe a laulaututu tagata uma e faamasino e ia,", "when all men shall stand to be judged of him,"], ["o le a latou tautino atu ai o ia o le Atua;", "then shall they confess that he is God;"], ["ona tautino atu ai lea e i latou uma o e sa ola e aunoa ma le Atua i le lalolagi,", "then shall they confess, who live without God in the world,"], ["ua tonu le famasinoga o le faasalaga e faavavau i luga o i latou;", "that the judgment of an everlasting punishment is just upon them;"], ["ma o le a latou galulu,", "and they shall quake,"], ["ma tetete,", "and tremble,"], ["ma mā'e'e i lalo i luma o lana silafaga ati i mea uma.", "and shrink beneath the glance of his all– searching eye."]]},
  {num:32,words:[["Ma o lenei sa oo ina amata e Alema mai lea lava taimi agai i luma,", "And now it came to pass that Alma began from this time forward to teach the people,"], ["faapea ma i latou o e na faatasi ma Alema i le taimi na afio ifo ai le agelu ia te i latou,", "and those who were with Alma at the time the angel appeared unto them,"], ["ona aoao atu i le nuu,", "traveling round about through all the land,"], ["ma malaga faataamilo i le laueleele atoa, ua tala atu i tagata uma mea sa latou faalogoina ma vaaia,", "publishing to all the people the things which they had heard and seen,"], ["ma talai atu le afioga a le Atua i le puapuaga tele,", "and preaching the word of God in much tribulation,"], ["ona o le sauaina tele o i latou e i latou o e sa lē talitonu,", "being greatly persecuted by those who were unbelievers,"], ["ma taia e le toatele o i latou.", "being smitten by many of them."]]},
  {num:33,words:[["Ae e ui i nei mea uma,", "But notwithstanding all this,"], ["sa latou avatu se faamafanafanaga tele i le ekalesia,", "they did impart much consolation to the church,"], ["sa faamautuina ai lo latou faatuatua, ma apoapoaiina i latou ma le tali-tiga ma le tautiga tele,", "confirming their faith,"], ["ia latou tausi i poloaiga a le Atua.", "and exhorting them with long– suffering and much travail to keep the commandments of God."]]},
  {num:34,words:[["Ma o le toafa o i latou o atalii ia o Mosaea;", "And four of them were the sons of Mosiah;"], ["ma o o latou igoa o Amona,", "and their names were Ammon,"], ["ma Arona,", "and Aaron,"], ["ma Ominea,", "and Omner,"], ["ma Himinae;", "and Himni;"], ["o igoa ia o atalii o Mosaea.", "these were the names of the sons of Mosiah."]]},
  {num:35,words:[["Ma sa latou malaga atu i le laueleele atoa o Sara'emila,", "And they traveled throughout all the lands of Zarahemla,"], ["ma i totonu o tagata uma o e sa i lalo o le puleaga a le tupu o Mosaea,", "and among all the people who were under the reign of king Mosiah,"], ["ma taumafai ma le vilivilitai e toe faalelei manu'a uma sa latou faia i le ekalesia, ma tautino atu a latou agasala uma,", "zealously striving to repair all the injuries which they had done to the church,"], ["ma tala atu mea uma sa latou vaaia,", "confessing all their sins,"], ["ma faamalamalama atu valoaga ma tusitusiga paia ia te i latou uma,", "and publishing all the things which they had seen,"], ["o e sa fia faalogo mai ia te i latou.", "and explaining the prophecies and the scriptures to all who desired to hear them."]]},
  {num:36,words:[["Ma sa faapea ona avea o i latou ma meafaigaluega i aao o le Atua,", "And thus they were instruments in the hands of God in bringing many to the knowledge of the truth,"], ["i le aumaia o le toatele i le malamalama o le upumoni, ioe,", "yea,"], ["i le malamalama o lo latou Togiola.", "to the knowledge of their Redeemer."]]},
  {num:37,words:[["Ma amuia lava i latou! Ona sa latou tala atu le filemu;", "And how blessed are they! For they did publish peace;"], ["sa latou tala atu tala e lelei o mea lelei;", "they did publish good tidings of good;"], ["ma sa latou tautino atu i tagata o loo nofotupu le Alii.", "and they did declare unto the people that the Lord reigneth."]]},
];
renderVerseSet(mo_ch_27_Verses, 'mo-ch27-verses');

var mo_ch_28_Verses = [
  {num:1,words:[["O lenei sa oo ina ua uma ona faia e atalii o Mosaea nei mea uma, sa latou ave se vaega toaitiiti faatasi ma i latou,", "Now it came to pass that after the sons of Mosiah had done all these things,"], ["ma toe foi atu i lo latou tamā,", "they took a small number with them and returned to their father,"], ["o le tupu,", "the king,"], ["ma mananao ia te ia 'ia faataga mai e ia ia te i latou, ina ia mafai e i latou,", "and desired of him that he would grant unto them that they might,"], ["faatasi ma i latou ia o e ua latou filifilia, ona o a'e i le laueleele o Nifae ,", "with these whom they had selected,"], ["ina ia mafai ona latou talai atu o mea sa latou faalogoina,", "go up to the land of Nephi that they might preach the things which  they had heard,"], ["ma ina ia mafai ona latou faailoa atu le afioga a le Atua,", "and that they might impart the word of God to their brethren,"], ["i o latou uso, o sa Lamanā—", "the Lamanites—"]]},
  {num:2,words:[["Ina ia atonu e mafai ona latou aumaia ai o i latou i le malamalama o le Alii lo latou Atua,", "That perhaps they might bring them to the knowledge of the Lord their God,"], ["ma faatalitonu i latou i le amioletonu o o latou tamā;", "and convince them of the iniquity of their fathers;"], ["ma ina ia atonu e mafai ai ona latou fo'ia i latou mai lo latou ita e faasaga i sa Nifaē,", "and that perhaps they might cure them of their hatred towards the Nephites,"], ["ina ia mafai ai foi ona aumai o i latou ia olioli i le Alii lo latou Atua,", "that they might also be brought to rejoice in the Lord their God,"], ["ina ia mafai ona latou fiafia i le tasi,", "that they might become friendly to one another,"], ["ma ina ia lē toe i ai ni finauga i le laueleele atoa ua tuu mai e le Alii lo latou Atua ia te i latou.", "and that there should be no more contentions in all the land which the Lord their God had given them."]]},
  {num:3,words:[["O lenei sa latou mananao ia talai atu le olataga i tagata uma,", "Now they were desirous that salvation should be declared to every creature,"], ["ona sa lē mafai ona latou talitalia le fano o le agaga o soo se tagata;", "for they could not bear that any human soul should perish;"], ["ioe,", "yea,"], ["e oo lava i le mafaufau ifo e faapea o le a oo i se agaga le mafatia e lē gata sa galulu ma tetete ai i latou.", "even the very thoughts that any soul should endure endless torment did cause them to quake and tremble."]]},
  {num:4,words:[["Ma sa faapea ona galue le Agaga o le Alii i luga o i latou,", "And thus did the Spirit of the Lord work upon them,"], ["ona sa avea i latou ma tagata agasala sili ona leaga . Ma sa tonu i le Alii i lona alofa mutimutivale aoao ia faasaoina i latou;", "for they were the very vilest of sinners. And the Lord saw fit in his infinite mercy to spare them;"], ["e ui i lea sa mafatia tele i latou i le atuatuvale o le agaga ona o a latou amioletonu,", "nevertheless they suffered much anguish of soul because of their iniquities,"], ["ma mafatia tele ma matata'u ina ne'i lafoina ese i latou e faavavau.", "suffering much and fearing that they should be cast off forever."]]},
  {num:5,words:[["Ma sa oo ina latou aioi atu i lo latou tamā i aso e tele ina ia mafai ona latou o a'e i le laueleele o Nifae.", "And it came to pass that they did plead with their father many days that they might go up to the land of Nephi."]]},
  {num:6,words:[["Ma sa alu atu le tupu o Mosaea ma ole atu i le Alii pe tatau ona tuu atu e ia ona atalii e o a'e i totonu o sa Lamanā e talai atu le afioga.", "And king Mosiah went and inquired of the Lord if he should let his sons go up among the Lamanites to preach the word."]]},
  {num:7,words:[["Ma sa fetalai mai le Alii ia Mosaea:", "And the Lord said unto Mosiah:"], ["Tuu atu i latou e o a'e,", "Let them go up,"], ["ona e toatele o le a talitonu ia latou upu,", "for many shall believe on their words,"], ["ma o le a latou maua le ola e faavavau;", "and they shall have eternal life;"], ["ma o le a Ou laveaiina ou atalii mai lima o sa Lamanā.", "and I will deliver thy sons out of the hands of the Lamanites."]]},
  {num:8,words:[["Ma sa oo ina faataga atu e Mosaea e mafai ona latou o atu ma faia e tusa ma lo latou manao.", "And it came to pass that Mosiah granted that they might go and do according to their request."]]},
  {num:9,words:[["Ma sa alu la latou malaga i le vao e o a'e e talai atu le afioga i totonu o sa Lamanā; ma o le a ou tuu atu se tala o a latou taualumaga,", "And they took their journey into the wilder– ness to go up to preach the word among the Lamanites;"], ["i se taimi o mulimuli mai.", "and I shall give an account of their proceedings hereafter."]]},
  {num:10,words:[["O lenei sa leai se tasi i le tupu o Mosaea e faaee atu i ai i ona luga le malo,", "Now king Mosiah had no one to confer the kingdom upon,"], ["ona sa leai se tasi o ona atalii sa fia taliaina le malo.", "for there was not any of his sons who would accept of the kingdom."]]},
  {num:11,words:[["O lea na ave ai e ia talafaamaumau sa togitogia i luga o papatusi apamemea,", "Therefore he took the records which were engraven on the plates of brass,"], ["ma papatusi foi a Nifae,", "and also the plates of Nephi,"], ["ma mea uma na tausi ma faasaoina e ia e tusa ma poloaiga a le Atua,", "and all the things which he had kept and preserved according to the command– ments of God,"], ["ina ua uma ona ia faaliliu ma faia ia tusia talafaamaumau sa i luga o papatusi auro na maua e le nuu o Limae,", "after having translated and caused to be written the records which were on the plates of gold which had been found by the people of Limhi,"], ["ia na tuu mai ia te ia e le lima o Limae;", "which were delivered to him by the hand of Limhi;"]]},
  {num:12,words:[["Ma sa fai e ia lenei mea ona o le manao tele o lona nuu;", "And this he did because of the great anxiety of his people;"], ["ona sa latou naunau tele e fia iloa e uiga i ia tagata ua faaumatia.", "for they were desirous beyond measure to know concerning those people who had been destroyed."]]},
  {num:13,words:[["Ma o lenei sa faaliliu e ia papatusi e ala i ia ma'a e lua sa faamau i totonu o ni faavaa se lua.", "And now he translated them by the means of those two stones which were fastened into the two rims of a bow."]]},
  {num:14,words:[["O lenei o nei mea sa saunia mai i le amataga,", "Now these things were prepared from the beginning,"], ["ma sa tuulima faasolo mai i lalo mai lea tupulaga i lea tupulaga,", "and were handed down from generation to generation,"], ["mo le faamoemoe o le faaliliuina o gagana.", "for the purpose of interpreting languages;"]]},
  {num:15,words:[["Ma sa tausia ma faasaoina ia mea e le aao o le Alii, ina ia faailoa mai ai e ia i tagata uma o e e mau i le laueleele,", "And they have been kept and preserved by the hand of the Lord,"], ["amioletonu ma mea inosia a ona tagata;", "that he should discover to every creature who should possess the land the iniquities and abominations of his people;"]]},
  {num:16,words:[["Ma o soo se tasi e i ai ia mea, ua ta'ua o le tagatavāai ,", "And whosoever has these things is called seer,"], ["e tusa ma tu i taimi anamua.", "after the manner of old times."]]},
  {num:17,words:[["O lenei ina ua uma ona faaliliu e Mosaea ia talafaamaumau,", "Now after Mosiah had finished translating these records,"], ["faauta, sa tuuina mai i ia talafaamaumau se tala o ni tagata o e ua faaumatia ,", "behold,"], ["mai le taimi na faaumatia ai i latou e oo atu i tua i le fausiaina o le 'olo tele,", "it gave an account of the people who were destroyed,"], ["i le taimi na faaeseese ai e le Alii le gagana a tagata,", "from the time that they were destroyed back to the building of the great tower,"], ["ma faataapeape solo i latou i luga o le lalolagi atoa,", "at the time the Lord confounded the language of the people and they were scattered abroad upon the face of all the earth,"], ["ioe, mai le taimi lena i tua,", "yea,"], ["seia oo atu lava i le foafoaga o Atamu.", "and even from that time back until the creation of Adam."]]},
  {num:18,words:[["O lea o lenei tala sa tupu ai le faanoanoa tele i le nuu o Mosaea,", "Now this account did cause the people of Mosiah to mourn exceedingly,"], ["ioe,", "yea,"], ["sa faatumulia i latou i le faanoanoa;", "they were filled with sorrow;"], ["e ui i lea sa latou maua mai ai le malamalama tele,", "nevertheless it gave them much knowledge,"], ["o se mea sa latou olioli ai.", "in the which they did rejoice."]]},
  {num:19,words:[["Ma o lenei tala o le a tusia i se taimi o mulimuli mai;", "And this account shall be written hereafter;"], ["aua faauta,", "for behold,"], ["e tatau i tagata uma ona iloa mea ua tusia i lenei tala.", "it is expedient that all people should know the things which are written in this account."]]},
  {num:20,words:[["Ma o lenei,", "And now,"], ["e pei ona sa ou fai atu ia te outou,", "as I said unto you,"], ["ina ua uma ona faia e le tupu o Mosaea nei mea,", "that after king Mosiah had done these things,"], ["sa ave e ia papatusi apamemea ,", "he took the plates of brass,"], ["ma mea uma sa tausi e ia,", "and all the things which he had kept,"], ["ma faaee atu i latou i luga o Alema,", "and conferred them upon Alma,"], ["o lē o le atalii o Alema;", "who was the son of Alma;"], ["ioe,", "yea,"], ["o talafaamaumau uma,", "all the records,"], ["ma ma'a faaliliu foi,", "and also the interpreters,"], ["ma faaee atu i luga o ia,", "and conferred them upon him,"], ["ma poloai atu ia te ia ia tausi ma faasaoina e ia nei mea,", "and commanded him that he should keep and preserve them,"], ["ma ia tausi foi se talafaamaumau o le nuu,", "and also keep a record of the people,"], ["ma tuulima faasolo atu ia mea i lalo mai le tasi tupulaga i le isi tupulaga,", "handing them down from one generation to another,"], ["e pei lava ona tuulima faasolo mai i latou i lalo mai le taimi na tuua ai e Liae Ierusalema.", "even as they had been handed down from the time that Lehi left Jerusalem."]]},
];
renderVerseSet(mo_ch_28_Verses, 'mo-ch28-verses');

var mo_ch_29_Verses = [
  {num:1,words:[["O lenei ina ua uma ona faia e Mosaea lenei mea,", "Now when Mosiah had done this he sent out throughout all the land,"], ["sa auina atu e ia se savali i le nuu atoa, i totonu o tagata uma,", "among all the people,"], ["i lona fia iloa o lo latou loto e faatatau i se e tatau ona avea ma o latou tupu.", "desiring to know their will concerning who should be their king."]]},
  {num:2,words:[["Ma sa oo ina oo mai le leo o le nuu,", "And it came to pass that the voice of the people came,"], ["fai mai:", "saying:"], ["Matou te mananao ia avea Arona lou atalii ma o matou tupu ma o matou pule.", "We are desirous that Aaron thy son should be our king and our ruler."]]},
  {num:3,words:[["O lenei sa alu Arona i luga i le laueleele o Nifae,", "Now Aaron had gone up to the land of Nephi,"], ["o lea na lē mafai ai e le tupu ona faaee atu o le malo i luga o ia;", "therefore the king could not confer the kingdom upon him;"], ["pe na manao foi Arona e ave e ia i ona luga le malo; pe na manao foi soo se tasi o atalii o Mosaea,", "neither would Aaron take upon him the kingdom;"], ["latou te ave i luga o i latou le malo.", "neither were any of the sons of Mosiah willing to take upon them the kingdom."]]},
  {num:4,words:[["O lea na toe auina atu ai e le tupu o Mosaea se savali i totonu o le nuu;", "Therefore king Mosiah sent again among the people;"], ["ioe,", "yea,"], ["o se savali tusia lava sa auina atu e ia i totonu o le nuu. Ma o upu nei sa tusia,", "even a written word sent he among  the people. And these were the words that were written,"], ["ua fai atu:", "saying:"]]},
  {num:5,words:[["Faauta,", "Behold,"], ["E,", "O ye my people,"], ["outou e lo'u nuu, po o o'u uso,", "or my brethren,"], ["ona ua faapena ona ou manatu ia te outou,", "for I esteem you as such,"], ["ou te manao ia outou manatunatu i le savali ua valaaulia outou tou te mafaufau i ai—ona ua outou mananao ia i ai se tupu .", "I desire that ye should consider the cause which ye are called to consider—for ye are desirous to have a king."]]},
  {num:6,words:[["O lenei ou te tautino atu ia te outou, o ia o lē ua i ai tonu le aiā i le malo,", "Now I declare unto you that he to whom the kingdom doth rightly belong has declined,"], ["ua teena e ia, ma o le a lē avea e ia i ona luga le malo.", "and will not take upon him the kingdom."]]},
  {num:7,words:[["Ma o lenei afai e tofia se tasi e suitulaga ia te ia,", "And now if there should be another appointed in his stead,"], ["faauta ou te fefe o le a tutupu mai ai finauga i totonu o outou. Ma o ai na te iloa ae lē liliu ai i le ita lo'u atalii,", "behold I fear there would rise contentions among you. And who knoweth but what my son,"], ["o lē tonu ua a ia le malo,", "to whom the kingdom doth belong,"], ["ma taitai ese ai e ia se vaega o lenei nuu ia mulimuli atu ia te ia,", "should turn to be angry and draw away a part of this people after him,"], ["o le a tutupu mai ai taua ma finauga i totonu o outou,", "which would cause wars and contentions among you,"], ["ia o le a avea ma pogai o le a faamasaa ai le toto tele ma faapi'opi'o ai ala o le Alii,", "which would be the cause of shedding much blood and perverting the way of the Lord,"], ["ioe,", "yea,"], ["ma faaumatia ai agaga o tagata e toatele.", "and destroy the souls of many people."]]},
  {num:8,words:[["O lenei ou te fai atu ia te outou, ia tatou atamamai ma manatunatu i nei mea,", "Now I say unto you let us be wise and consider these things,"], ["ona e leai sa tatou aiā e faaumatia ai lo'u atalii,", "for we have no right to destroy my son,"], ["pe tatau foi ona i ai sa tatou aiā e faaumatia ai se isi tagata, pe a tofia o ia e suitulaga ia te ia.", "neither should we have any right to destroy another if he should be appointed in his stead."]]},
  {num:9,words:[["Ma afai ae toe liliu lo'u atalii i lona faamaualuga ma mea lē aoga, o le a toe faafoi e ia mea na fai mai ai o ia,", "And if my son should turn again to his pride and vain things he would recall the things which he had said,"], ["ma ave lana aiā i le malo,", "and claim his right to the kingdom,"], ["lea o le a fai ai e ia ma lenei nuu foi, le agasala tele.", "which would cause him and also this people to commit much sin."]]},
  {num:10,words:[["Ma o lenei ia tatou atamamai, ma tagai i luma e uiga i nei mea,", "And now let us be wise and look forward to these things,"], ["ma fai le mea e maua ai e lenei nuu le filemu.", "and do that which will make for the peace of this people."]]},
  {num:11,words:[["O lea o le a avea ai a'u ma o outou tupu i o'u aso o totoe;", "Therefore I will be your king the remainder of my days;"], ["e ui i lea,", "nevertheless,"], ["ia tatou tofia ni faamasino ,", "let us appoint judges,"], ["e faamasino i lenei nuu e tusa ma a tatou tulafono;", "to judge this people according to our law;"], ["ma o le a tatou faatulaga fou mataupu o lenei nuu,", "and we will newly arrange the affairs of this people,"], ["ona o le a tatou tofia tagata popoto e avea ma faamasino,", "for we will appoint wise men to be judges,"], ["e faamasino lenei nuu e tusa ma poloaiga a le Atua.", "that will judge this people according to the commandments of God."]]},
  {num:12,words:[["O lenei e sili ona lelei ona faamasino o se tagata e le Atua, nai lo e se tagata,", "Now it is better that a man should be judged of God than of man,"], ["ona o faamasinoga a le Atua e tonu pea lava,", "for the judgments of God are always just,"], ["ae o faamasinoga a tagata, e lē tonu pea.", "but the judgments of man are not always just."]]},
  {num:13,words:[["O lea, a na fai e mafai ona outou maua o ni tagata amiotonu e avea ma o outou tupu,", "Therefore,"], ["o e latou te faamautuina tulafono a le Atua,", "if it were possible that you could have just men to be your kings,"], ["ma faamasino i lenei nuu e tusa ma ana poloaiga, ioe,", "who would establish the laws of God,"], ["a na mafai ona outou maua o ni tagata, o e latou te faia e pei ona faia e lo'u tamā,", "and judge this people according to his commandments,"], ["o Peniamina , mo lenei nuu,", "yea,"], ["e avea ma o outou tupu—ou te fai atu ia te outou,", "if ye could have men for your kings who would do even as my father Benjamin did for this people—I say unto you,"], ["a na fai o le tulaga lea i taimi uma, ona tatau ai lea ona outou maua o ni tupu i taimi uma e pule i luga o outou.", "if this could always be the case then it would be expedient that ye should always have kings to rule over you."]]},
  {num:14,words:[["Ma e oo ia te a'u lava ia,", "And even I myself have labored with all the power and faculties which I have possessed,"], ["sa ou galue ma le mana atoa ma le poto uma sa ia te a'u,", "to teach you the commandments of God,"], ["e aoao atu ia te outou poloaiga a le Atua,", "and to establish peace throughout the land,"], ["ma faatu le filemu i le laueleele atoa,", "that there should be no wars nor contentions,"], ["ina ia leai ni taua po o ni finauga, leai se gaoi,", "no stealing,"], ["po o se fai o le vete,", "nor plundering,"], ["po o se fasioti tagata,", "nor murdering,"], ["po o soo se ituaiga o le amioletonu;", "nor any manner of iniquity;"]]},
  {num:15,words:[["Ma o soo se tasi sa faia le amioletonu,", "And whosoever has committed iniquity,"], ["sa ou faasalaina o ia e tusa ma le solitulafono na fai e ia, e tusa ma le tulafono na tuuina mai ia te i tatou,", "him have I punished according to the crime which he has committed,"], ["e o tatou tamā.", "according to the law which has been given to us by our fathers."]]},
  {num:16,words:[["O lenei ou te fai atu ia te outou, ona e lē amiotonu tagata uma,", "Now I say unto you,"], ["ua lē tatau ai ona i ai o se tupu po o ni tupu, e pule i luga o outou.", "that because all men are not just it is not expedient that ye should have a king or kings to rule over you."]]},
  {num:17,words:[["Aua faauta,", "For behold,"], ["i le tele o le amioletonu e mafai ona faaoso e se tupu amioleaga e toatasi ia faia,", "how much iniquity doth one wicked king cause to be committed,"], ["ioe,", "yea,"], ["ma le faafanoga tele e oo mai ai!", "and what great destruction!"]]},
  {num:18,words:[["Ioe,", "Yea,"], ["ia manatua le tupu o Noa,", "remember king Noah,"], ["lona amioleaga ma ana mea inosia,", "his wickedness and his abominations,"], ["ma le amioleaga ma mea inosia foi a lona nuu.", "and also the wickedness and abominations of his people."], ["Faauta i le faafanoga tele na oo mai i o latou luga; ma ona o a latou amioletonu foi,", "Behold what great destruction did come upon them;"], ["na aumai ai i latou i le pologa .", "and also because of their iniquities they were brought into bondage."]]},
  {num:19,words:[["Ma a na leai le faalava mai o lo latou Foafoa poto-aoao,", "And were it not for the interposition of their all– wise Creator,"], ["ma o lea ona o lo latou salamo faamaoni,", "and this because of their sincere repentance,"], ["po ua lē ma'alofia lo latou tumau ai pea i le pologa sei oo mai i le taimi nei.", "they must unavoidably remain in bondage until now."]]},
  {num:20,words:[["Ae faauta sa lavea'i e ia i latou ona sa latou faamaualalo i latou lava i ona luma;", "But behold,"], ["ma ona sa latou tagi malosi atu ia te ia,", "he did deliver them because they did humble themselves before him;"], ["o lea na lavea'i ai e ia i latou i fafo mai le pologa; ma ua faapea lava ona galue o le Alii ma lona mana i tulaga uma i totonu o le fanauga a tagata,", "and because they cried mightily unto him he did deliver them out of bondage;"], ["ma faaloaloa mai le aao o le alofa mutimutivale ia te i latou,", "and thus doth the Lord work with his power in all cases among the children of men,"], ["o e e tuu atu lo latou faalagolago ia te ia.", "extending the arm of mercy towards them that put their trust in him."]]},
  {num:21,words:[["Ma faauta,", "And behold,"], ["ou te fai atu nei ia te outou,", "now I say unto you,"], ["tou te lē mafafai ona aveesea mai le nofoalii se tupu amioletonu, vagana ai e ala i finauga tetele,", "ye cannot dethrone an iniquitous king save it be through much contention,"], ["ma le faamasaa toto tele.", "and the shedding of much blood."]]},
  {num:22,words:[["Aua faauta,", "For behold,"], ["e i ai ni ana uo i le amioletonu,", "he has his friends in iniquity,"], ["ma e tuu e ia ana leoleo e siosiomia o ia;", "and he keepeth his guards about him;"], ["ma e saei e ia tulafono a i latou o e na nonofotupu i le amiotonu i luma atu o ia;", "and he teareth up the laws of those who have reigned in righteousness before him;"], ["ma e soli e ia i lalo o ona vae poloaiga a le Atua;", "and he trampleth under his feet the commandments of God;"]]},
  {num:23,words:[["Ma e fai e ia tulafono,", "And he enacteth laws,"], ["ma auina atu i totonu o lona nuu, ioe,", "and sendeth them forth among his people,"], ["o tulafono e tusa ai ma lona lava amioleaga ;", "yea,"], ["ma o soo se tasi e lē usiusitai i ana tulafono, e faatonu e ia ia faaumatiaina;", "laws after the manner of his own wickedness;"], ["ma o soo se tasi e fouvale faasaga atu ia te ia,", "and whosoever doth not obey his laws he causeth to be destroyed;"], ["e auina atu e ia lana autau e faasaga ia te i latou i le taua,", "and whosoever doth rebel against him he will send his armies against them to war,"], ["ma afai e mafaia ona fai e ia, o le a ia faaumatiaina i latou;", "and if he can he will destroy them;"], ["ma e faapea ona faapi'opi'o e se tupu amioletonu ala o le amiotonu uma.", "and thus an unrighteous king doth pervert the ways of all righteousness."]]},
  {num:24,words:[["Ma o lenei faauta ou te fai atu ia te outou,", "And now behold I say unto you,"], ["e lē tatau ona oo mai mea inosia faapea i o outou luga.", "it is not expedient that such abominations should come upon you."]]},
  {num:25,words:[["O lea,", "Therefore,"], ["ia outou filifili ai e ala i le leo o lenei nuu,", "choose you by the voice of this people,"], ["ni faamasino,", "judges,"], ["ina ia mafai ona faamasinoina outou e tusa ai ma tulafono ua tuu mai ia te outou e o tatou tamā,", "that ye may be judged according to the laws which have been given you by our fathers,"], ["o ni tulafono ua sa'o,", "which are correct,"], ["ma o ni tulafono na tuu mai ia te i latou e le aao o le Alii.", "and which were given them by the hand of the Lord."]]},
  {num:26,words:[["O lenei e lē masani ona manao le leo o le nuu i soo se mea e lē talafeagai ma le mea sa'o;", "Now it is not common that the voice of the people desireth anything contrary to that which is right;"], ["ae e masani i se vaega toaitiiti o le nuu ona mananao i le mea ua lē sa'o;", "but it is common for the lesser part of the people to desire that which is not right;"], ["o lea o le mea lenei ia outou tausi ma fai ma a outou tulafono—ia fai a outou mataupu i le leo o le nuu.", "therefore this shall ye observe and make it your  law—to do your business by the voice of the people."]]},
  {num:27,words:[["Ma afai e oo mai se taimi e filifili ai e le leo o le nuu le amioletonu,", "And if the time comes that the voice of the people doth choose iniquity,"], ["o le taimi lena o le a oo mai ai faamasinoga a le Atua i o outou luga;", "then is the time that the judgments of God will come upon you;"], ["ioe, o le taimi lena o le a asiasi mai ai o ia ia te outou i le faafanoga tele,", "yea,"], ["e pei lava ona asia e ia lenei laueleele seia oo mai i le taimi nei.", "then is the time he will visit you with great destruction even as he has hitherto visited this land."]]},
  {num:28,words:[["Ma o lenei afai e i ai ni o outou faamasino,", "And now if ye have judges,"], ["ma e latou te lē faamasinoina outou e tusa ai ma le tulafono ua tuuina mai,", "and they do not judge you according to the law which has been given,"], ["e mafai ona outou faia ia faamasinoina i latou e se faamasino maualuga atu.", "ye can cause that they may be judged of a higher judge."]]},
  {num:29,words:[["Afai e lē faia e o outou faamasino maualuluga faamasinoga amiotonu,", "If your higher judges do not judge righteous judgments,"], ["ia outou faia ia faapotopoto faatasi se aofai toatiiti o o outou faamasino maualalalo,", "ye shall cause that a small number of your lower judges should be gathered together,"], ["ma latou faamasino o outou faamasino maualuluga,", "and they shall judge your higher judges,"], ["e tusa ma le leo o le nuu.", "according to the voice of the people."]]},
  {num:30,words:[["Ma ou te poloai atu ia te outou ia outou faia nei mea ma le mata'u i le Alii;", "And I command you to do these things in the fear of the Lord;"], ["ma ou te poloai atu ia te outou ia outou faia nei mea,", "and I command you to do these things,"], ["ma ia lē i ai so outou tupu; aua afai ai e faia e nei tagata agasala ma amioletonu,", "and that ye have no king;"], ["o le a tauia i latou i luga o o latou lava ulu.", "that if these people commit sins and iniquities they shall be answered upon their own heads."]]},
  {num:31,words:[["Aua faauta ou te fai atu ia te outou,", "For behold I say unto you,"], ["o agasala a le toatele o tagata na pogai mai i amioletonu a o latou tupu;", "the sins of many people have been caused by the iniquities of their kings;"], ["o lea o a latou amioletonu o le a tauia i luga o ulu o o latou tupu.", "therefore their iniquities are answered upon the heads of their kings."]]},
  {num:32,words:[["Ma o lenei ou te manao ia lē toe i ai lenei lē tutusa i lenei laueleele,", "And now I desire that this inequality should be no more in this land,"], ["aemaise lava i totonu o o'u nei tagata;", "especially among this my people;"], ["ae ou te manao ia avea lenei laueleele ma laueleele o le saolotoga ,", "but I desire that this land be a land of liberty,"], ["ma ia mafai ona maua tutusa e tagata taitoatasi le fiafia i ana aiā ma ona avanoa,", "and every man may enjoy his rights and privileges alike,"], ["e tusa ai ma le umi e tonu i le silafaga a le Alii e mafai ona tatou ola ai ma fai ai mo o tatou tofi le laueleele,", "so long as the Lord sees fit that we may live and inherit the land,"], ["ioe,", "yea,"], ["e oo lava i le umi e i ai a tatou fanau i luga o le laueleele.", "even as long as any of our posterity remains upon the face of the land."]]},
  {num:33,words:[["Ma e tele ni isi mea sa tusi atu ai le tupu o Mosaea ia te i latou,", "And many more things did king Mosiah write unto them,"], ["na faailoa atu ai ia te i latou tofotofoga ma faalavelave uma o se tupu amiotonu,", "unfolding unto them all the trials and troubles of a righteous king,"], ["ioe,", "yea,"], ["o mafatiaga uma o le agaga mo o latou tagata,", "all the travails of soul for their people,"], ["ma muimuiga uma foi a tagata i lo latou tupu;", "and also all the murmurings of the people to their king;"], ["ma sa faamalamalama atu atoa e ia lenei mea ia te i latou.", "and he explained it all unto them."]]},
  {num:34,words:[["Ma sa ta'u atu e ia ia te i latou e lē tatau ona i ai ia mea;", "And he told them that these things ought not to be;"], ["ae e tatau ona oo i luga o tagata uma le avega,", "but that the burden should come upon all the people,"], ["ina ia mafai e tagata taitoatasi ona tauave lana vaega.", "that every man might bear his part."]]},
  {num:35,words:[["Ma sa faailoa atu foi e ia ia te i latou, faaletonu uma latou te galulue ai i lalo,", "And he also unfolded unto them all the disadvantages they labored under,"], ["i le i ai o se tupu amioletonu e pule i luga o i latou;", "by having an unrighteous king to rule over them;"]]},
  {num:36,words:[["Ioe,", "Yea,"], ["o ana amioletonu uma ma mea inosia,", "all his iniquities and abominations,"], ["ma taua uma,", "and all the wars,"], ["ma finauga,", "and contentions,"], ["ma le faamasaatoto,", "and bloodshed,"], ["ma le gaoi,", "and the stealing,"], ["ma le fai o le vete,", "and the plun– dering,"], ["ma le fai o le faitaaga,", "and the committing of whoredoms,"], ["ma ituaiga amioletonu eseese uma e lē mafai ona faitaulia—ma ta'u atu ia te i latou e lē tatau ona i ai ia mea,", "and all manner of iniquities which cannot be enumerated—telling them that these things ought not to be,"], ["ua manino ona ta'u mai le inosia o i latou i poloaiga a le Atua.", "that they were expressly repugnant to the command– ments of God."]]},
  {num:37,words:[["Ma o lenei sa oo ina ua uma ona auina atu e le tupu o Mosaea ia mea i totonu o le nuu,", "And now it came to pass,"], ["sa latou talitonu i le moni o ana upu.", "after king Mosiah had sent these things forth among the people they were convinced of the truth of his words."]]},
  {num:38,words:[["O lea na latou tuu ai o latou manao i se tupu,", "Therefore they relinquished their desires for a king,"], ["ma oso lo latou naunau tele ia maua e tagata taitoatasi le avanoa tutusa i le laueleele atoa;", "and became exceedingly anxious that every man should have an equal chance throughout all the land;"], ["ioe,", "yea,"], ["ma sa faaali mai e tagata taitoatasi lona loto malie e tali mo ana lava agasala.", "and every man expressed a willingness to answer for his own sins."]]},
  {num:39,words:[["O lea,", "Therefore,"], ["sa oo ina latou faapotopoto faatasi i latou lava i ni tino potopoto i le laueleele atoa,", "it came to pass that they assembled themselves together in bodies throughout the land,"], ["e lafo mai o latou leo e uiga i e e tatau ona avea ma o latou faamasino,", "to cast in their voices concerning who should be their judges,"], ["e faamasino i latou e tusa ma le tulafono ua tuu mai ia te i latou;", "to judge them according to the law which had been given them;"], ["ma sa latou olioli tele lava ona o le saolotoga ua tuu mai ia te i latou.", "and they were exceedingly rejoiced because of the liberty which had been granted unto them."]]},
  {num:40,words:[["Ma sa faateteleina lo latou alolofa ia Mosaea;", "And they did wax strong in love towards Mosiah;"], ["ioe,", "yea,"], ["sa latou manatu maualuga ia te ia e sili atu i lo se isi lava tagata;", "they did esteem him more than any other man;"], ["ona sa latou lē vaai a'e ia te ia o se tagata sauā o se sa saili mo le 'oa,", "for they did not look upon him as a tyrant who was seeking for gain,"], ["ioe,", "yea,"], ["mo lena 'oa e faaleaga ai le agaga;", "for that lucre which doth corrupt the soul;"], ["ona sa lei aveeseina e ia se 'oa mai ia te i latou,", "for he had not exacted riches of them,"], ["sa lē fiafia foi o ia i le faamasaaina o le toto;", "neither had he delighted in the shedding of blood;"], ["ae sa faatupuina e ia le filemu i le laueleele,", "but he had established peace in the land,"], ["ma sa tuu atu e ia i lona nuu ina ia laveaiina i latou mai ituaiga o pologa eseese uma;", "and he had granted unto his people that they should be delivered from all manner of bondage;"], ["o lea sa latou faaaloalogia ai o ia,", "there fore they did esteem him,"], ["ioe,", "yea,"], ["silisili lava,", "exceedingly,"], ["e lē mafuatiaina.", "beyond measure."]]},
  {num:41,words:[["Ma sa oo ina latou tofia faamasino e pule i luga o i latou,", "And it came to pass that they did appoint judges to rule over them,"], ["pe faamasino i latou e tusa ma le tulafono;", "or to judge them according to the law;"], ["ma sa latou faia lenei mea i le laueleele atoa.", "and this they did throughout all the land."]]},
  {num:42,words:[["Ma sa oo ina tofia Alema e avea ma faamasino sili muamua,", "And it came to pass that Alma was appointed to be the first  chief judge,"], ["ma o ia foi o le faitaulaga sili,", "he being also the high priest,"], ["ona sa faaee e lona tamā le tofi i luga o ia,", "his father having  conferred the office upon him,"], ["ma ona sa tuu atu e ia ia te ia le matafaioi e faatatau i mataupu uma o le ekalesia.", "and having given him the charge  concerning all the affairs of the church."]]},
  {num:43,words:[["Ma o lenei sa oo ina savali Alema i ala o le Alii,", "And now it came to pass that Alma did walk in the ways of the  Lord,"], ["ma sa tausi o ia i ana poloaiga,", "and he did keep his commandments,"], ["ma sa faamasino atu o ia i faamasinoga amiotonu;", "and he did judge  righteous judgments;"], ["ma sa i ai le filemu e lē aunoa i le laueleele atoa.", "and there was continual peace through the  land."]]},
  {num:44,words:[["Ma sa faapea ona amata o le nofoaiga a faamasino i le laueleele atoa o Sara'emila,", "And thus commenced the reign of the judges throughout all the  land of Zarahemla,"], ["i totonu o tagata uma o e sa ta'ua o sa Nifaē;", "among all the people who were called the  Nephites;"], ["ma sa avea Alema ma ulua'i faamasino sili.", "and Alma was the first and chief judge."]]},
  {num:45,words:[["Ma o lenei sa oo ina maliu lona tamā,", "And now it came to pass that his father died,"], ["i le valu sefulu ma le lua o ona tausaga,", "being eighty  and two years old,"], ["ina ua mavae ona soifua e faataunuu poloaiga a le Atua.", "having lived to fulfil the commandments of  God."]]},
  {num:46,words:[["Ma sa oo foi ina maliu Mosaea,", "And it came to pass that Mosiah died also,"], ["i le tolu sefulu ma le tolu o tausaga o lana nofoaiga,", "in the thirty and  third year of his reign,"], ["i le ono sefulu ma le tolu lea o ona tausaga;", "being sixty and three years old;"], ["o le atoa ai lea,", "making  in the whole,"], ["o le lima selau ma le iva o tausaga mai le taimi na tuua ai e Liae Ierusalema.", "five hundred and nine years from the time Lehi left  Jerusalem."]]},
  {num:47,words:[["Ma sa faapea ona i'u o le nofoaiga a tupu i le nuu o Nifae;", "And thus ended the reign of the kings over the people of  Nephi;"], ["ma sa faapea foi ona i'u o aso o Alema,", "and thus ended the days of Alma,"], ["o lē na faavaeina la latou ekalesia.", "who was the founder of  their church."]]},
];
renderVerseSet(mo_ch_29_Verses, 'mo-ch29-verses');

})();